/**
 * 소셜 로그인 통합 테스트
 * @description 카카오/네이버/구글 전체 로그인 흐름 통합 테스트
 * @regression
 *   - 로그인 후 Store 동기화 확인
 *   - 에러 처리 흐름 확인
 *   - 계정 전환 기능 확인
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, waitFor, fireEvent } from '@testing-library/react'
import { MemoryRouter, Routes, Route } from 'react-router-dom'
import { createElement } from 'react'

// vi.hoisted로 Mock 함수 선언 (hoisting 문제 해결)
const {
  mockNavigate,
  mockSetToken,
  mockSetUser,
  mockSetLoading,
  mockLogout,
  mockUpdateCurrentUser,
  mockSyncUserIdFromStorage,
  mockGetCurrentUser,
  mockStartKakaoLogin,
  mockStartKakaoLoginSwitch,
  mockStartNaverLogin,
  mockStartNaverLoginSwitch,
  mockStartGoogleLogin,
  mockStartGoogleLoginSwitch,
  mockShowAlert
} = vi.hoisted(() => ({
  mockNavigate: vi.fn(),
  mockSetToken: vi.fn(),
  mockSetUser: vi.fn(),
  mockSetLoading: vi.fn(),
  mockLogout: vi.fn(),
  mockUpdateCurrentUser: vi.fn(),
  mockSyncUserIdFromStorage: vi.fn(),
  mockGetCurrentUser: vi.fn(),
  mockStartKakaoLogin: vi.fn(),
  mockStartKakaoLoginSwitch: vi.fn(),
  mockStartNaverLogin: vi.fn(),
  mockStartNaverLoginSwitch: vi.fn(),
  mockStartGoogleLogin: vi.fn(),
  mockStartGoogleLoginSwitch: vi.fn(),
  mockShowAlert: vi.fn()
}))

let mockHref = ''

// Mock 설정
vi.mock('react-router-dom', async () => {
  const actual = await vi.importActual('react-router-dom')
  return {
    ...actual,
    useNavigate: () => mockNavigate
  }
})

vi.mock('@/shared/stores/authStore', () => ({
  useAuthStore: () => ({
    setToken: mockSetToken,
    setUser: mockSetUser,
    setLoading: mockSetLoading,
    logout: mockLogout,
    isAuthenticated: false,
    user: null,
    token: null
  })
}))

vi.mock('@/stores/user', () => ({
  useUserStore: () => ({
    updateCurrentUser: mockUpdateCurrentUser,
    currentUser: null,
    userId: null
  }),
  syncUserIdFromStorage: mockSyncUserIdFromStorage
}))

vi.mock('@/shared/store/useDevModeStore', () => ({
  useDevModeStore: () => ({
    isDevMode: false,
    toggleDevMode: vi.fn()
  })
}))

vi.mock('@/contexts/AppleConfirmProvider', () => ({
  useAppleConfirm: () => ({
    showAlert: mockShowAlert,
    showConfirm: vi.fn()
  })
}))

vi.mock('@/entities/auth/api', () => ({
  getCurrentUser: mockGetCurrentUser,
  processAuthToken: vi.fn(async (token: string, deps: Record<string, Function>) => {
    deps.setToken(token);
    const user = await mockGetCurrentUser(token);
    deps.setUser(user);
    deps.updateCurrentUser({ id: user._id, name: user.name || '', email: user.email || '', role: user.role, avatarUrl: user.avatarUrl || undefined });
    localStorage.setItem('aims-current-user-id', user._id);
    deps.syncUserIdFromStorage();
    deps.navigate('/', { replace: true });
    return user;
  }),
  startKakaoLogin: mockStartKakaoLogin,
  startKakaoLoginSwitch: mockStartKakaoLoginSwitch,
  startNaverLogin: mockStartNaverLogin,
  startNaverLoginSwitch: mockStartNaverLoginSwitch,
  startGoogleLogin: mockStartGoogleLogin,
  startGoogleLoginSwitch: mockStartGoogleLoginSwitch
}))

// SFSymbol Mock
vi.mock('@/components/SFSymbol', () => ({
  SFSymbol: ({ name }: { name: string }) => createElement('span', { 'data-testid': 'sf-symbol' }, name),
  SFSymbolSize: { xSmall: 12, small: 14, medium: 17 },
  SFSymbolWeight: { regular: 400, medium: 500, semibold: 600 }
}))

// Toast Mock
vi.mock('@/components/Toast', () => ({
  toast: {
    error: vi.fn(),
    success: vi.fn()
  }
}))

import LoginPage from '../pages/LoginPage'
import AuthCallbackPage from '../pages/AuthCallbackPage'

// localStorage Mock
let localStorageMock: Record<string, string> = {}

describe('소셜 로그인 통합 테스트', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockHref = ''
    localStorageMock = {}

    // Mock implementations for social login functions
    mockStartKakaoLogin.mockImplementation(() => { mockHref = '/api/auth/kakao' })
    mockStartKakaoLoginSwitch.mockImplementation(() => { mockHref = '/api/auth/kakao/switch' })
    mockStartNaverLogin.mockImplementation(() => { mockHref = '/api/auth/naver' })
    mockStartNaverLoginSwitch.mockImplementation(() => { mockHref = '/api/auth/naver/switch' })
    mockStartGoogleLogin.mockImplementation(() => { mockHref = '/api/auth/google' })
    mockStartGoogleLoginSwitch.mockImplementation(() => { mockHref = '/api/auth/google/switch' })

    vi.stubGlobal('localStorage', {
      getItem: vi.fn((key: string) => localStorageMock[key] || null),
      setItem: vi.fn((key: string, value: string) => { localStorageMock[key] = value }),
      removeItem: vi.fn((key: string) => { delete localStorageMock[key] }),
      clear: vi.fn(() => { localStorageMock = {} }),
      length: 0,
      key: vi.fn()
    })
  })

  afterEach(() => {
    vi.unstubAllGlobals()
  })

  const renderApp = (initialPath: string) => {
    return render(
      <MemoryRouter initialEntries={[initialPath]}>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/auth/callback" element={<AuthCallbackPage />} />
          <Route path="/" element={<div data-testid="main-page">Main Page</div>} />
        </Routes>
      </MemoryRouter>
    )
  }

  describe('카카오 로그인 전체 흐름', () => {
    const mockKakaoUser = {
      _id: 'kakao_123456',
      name: '카카오사용자',
      email: 'kakao@test.com',
      role: 'agent',
      avatarUrl: 'https://k.kakaocdn.net/avatar.jpg',
      authProvider: 'kakao',
      profileCompleted: true
    }

    it('1. 카카오 로그인 버튼 클릭 시 OAuth 시작', async () => {
      renderApp('/login')

      const kakaoButton = screen.getByText('카카오 로그인')
      fireEvent.click(kakaoButton)

      expect(mockStartKakaoLogin).toHaveBeenCalled()
      expect(mockHref).toContain('/api/auth/kakao')
    })

    it('2. 콜백 처리 → 토큰 저장', async () => {
      mockGetCurrentUser.mockResolvedValue(mockKakaoUser)

      renderApp('/auth/callback?token=kakao-jwt-token')

      await waitFor(() => {
        expect(mockSetToken).toHaveBeenCalledWith('kakao-jwt-token')
      })
    })

    it('3. 사용자 정보 조회 → Store 동기화', async () => {
      mockGetCurrentUser.mockResolvedValue(mockKakaoUser)

      renderApp('/auth/callback?token=kakao-jwt-token')

      await waitFor(() => {
        // authStore 동기화
        expect(mockSetUser).toHaveBeenCalledWith(mockKakaoUser)

        // userStore 동기화
        expect(mockUpdateCurrentUser).toHaveBeenCalledWith({
          id: mockKakaoUser._id,
          name: mockKakaoUser.name,
          email: mockKakaoUser.email,
          role: mockKakaoUser.role,
          avatarUrl: mockKakaoUser.avatarUrl
        })
      })
    })

    it('4. localStorage에 사용자 ID 저장', async () => {
      mockGetCurrentUser.mockResolvedValue(mockKakaoUser)

      renderApp('/auth/callback?token=kakao-jwt-token')

      await waitFor(() => {
        expect(localStorage.setItem).toHaveBeenCalledWith('aims-current-user-id', mockKakaoUser._id)
      })
    })

    it('5. 메인 페이지로 리다이렉트', async () => {
      mockGetCurrentUser.mockResolvedValue(mockKakaoUser)

      renderApp('/auth/callback?token=kakao-jwt-token')

      await waitFor(() => {
        expect(mockNavigate).toHaveBeenCalledWith('/', { replace: true })
      })
    })
  })

  describe('네이버 로그인 전체 흐름', () => {
    const mockNaverUser = {
      _id: 'naver_789012',
      name: '네이버사용자',
      email: 'naver@test.com',
      role: 'agent',
      avatarUrl: 'https://ssl.pstatic.net/avatar.jpg',
      authProvider: 'naver',
      profileCompleted: true
    }

    it('1. 개발 환경에서 네이버 로그인 버튼이 활성 상태임', async () => {
      renderApp('/login')

      const naverButton = screen.getByText('네이버 로그인').closest('button')
      expect(naverButton).not.toBeDisabled()

      fireEvent.click(screen.getByText('네이버 로그인'))
      expect(mockStartNaverLogin).toHaveBeenCalled()
    })

    it('2. 네이버 콜백 처리 → Store 동기화', async () => {
      mockGetCurrentUser.mockResolvedValue(mockNaverUser)

      renderApp('/auth/callback?token=naver-jwt-token')

      await waitFor(() => {
        expect(mockSetToken).toHaveBeenCalledWith('naver-jwt-token')
        expect(mockSetUser).toHaveBeenCalledWith(mockNaverUser)
        expect(mockUpdateCurrentUser).toHaveBeenCalled()
      })
    })

    it('3. 네이버 인증 실패 시 에러 처리', async () => {
      vi.useFakeTimers()

      renderApp('/auth/callback?error=naver_auth_failed')

      expect(screen.getByText('네이버 로그인에 실패했습니다')).toBeInTheDocument()

      // 3초 후 /login으로 리다이렉트
      await vi.runAllTimersAsync()

      expect(mockNavigate).toHaveBeenCalledWith('/login', { replace: true })

      vi.useRealTimers()
    })
  })

  describe('구글 로그인 전체 흐름', () => {
    const mockGoogleUser = {
      _id: 'google_345678',
      name: '구글사용자',
      email: 'google@test.com',
      role: 'agent',
      avatarUrl: 'https://lh3.googleusercontent.com/avatar.jpg',
      authProvider: 'google',
      profileCompleted: true
    }

    it('1. 개발 환경에서 구글 로그인 버튼이 활성 상태임', async () => {
      renderApp('/login')

      const googleButton = screen.getByText('구글 로그인').closest('button')
      expect(googleButton).not.toBeDisabled()

      fireEvent.click(screen.getByText('구글 로그인'))
      expect(mockStartGoogleLogin).toHaveBeenCalled()
    })

    it('2. 콜백 처리 → 토큰 저장', async () => {
      mockGetCurrentUser.mockResolvedValue(mockGoogleUser)

      renderApp('/auth/callback?token=google-jwt-token')

      await waitFor(() => {
        expect(mockSetToken).toHaveBeenCalledWith('google-jwt-token')
      })
    })

    it('3. 사용자 정보 조회 → Store 동기화', async () => {
      mockGetCurrentUser.mockResolvedValue(mockGoogleUser)

      renderApp('/auth/callback?token=google-jwt-token')

      await waitFor(() => {
        // authStore 동기화
        expect(mockSetUser).toHaveBeenCalledWith(mockGoogleUser)

        // userStore 동기화
        expect(mockUpdateCurrentUser).toHaveBeenCalledWith({
          id: mockGoogleUser._id,
          name: mockGoogleUser.name,
          email: mockGoogleUser.email,
          role: mockGoogleUser.role,
          avatarUrl: mockGoogleUser.avatarUrl
        })
      })
    })

    it('4. localStorage에 사용자 ID 저장', async () => {
      mockGetCurrentUser.mockResolvedValue(mockGoogleUser)

      renderApp('/auth/callback?token=google-jwt-token')

      await waitFor(() => {
        expect(localStorage.setItem).toHaveBeenCalledWith('aims-current-user-id', mockGoogleUser._id)
      })
    })

    it('5. 메인 페이지로 리다이렉트', async () => {
      mockGetCurrentUser.mockResolvedValue(mockGoogleUser)

      renderApp('/auth/callback?token=google-jwt-token')

      await waitFor(() => {
        expect(mockNavigate).toHaveBeenCalledWith('/', { replace: true })
      })
    })

    it('6. 구글 인증 실패 시 에러 처리', async () => {
      vi.useFakeTimers()

      renderApp('/auth/callback?error=google_auth_failed')

      expect(screen.getByText('구글 로그인에 실패했습니다')).toBeInTheDocument()

      // 3초 후 /login으로 리다이렉트
      await vi.runAllTimersAsync()

      expect(mockNavigate).toHaveBeenCalledWith('/login', { replace: true })

      vi.useRealTimers()
    })
  })

  describe('계정 전환', () => {
    it('"다른 카카오 계정으로 로그인" 클릭 시 switch 엔드포인트 사용', async () => {
      renderApp('/login')

      const switchButton = screen.getByText('다른 카카오 계정으로 로그인')
      fireEvent.click(switchButton)

      expect(mockStartKakaoLoginSwitch).toHaveBeenCalled()
      expect(mockHref).toContain('/api/auth/kakao/switch')
    })

    it('개발 환경에서는 "다른 네이버 계정", "다른 구글 계정" 옵션이 표시됨', () => {
      renderApp('/login')

      expect(screen.getByText('다른 네이버 계정')).toBeInTheDocument()
      expect(screen.getByText('다른 구글 계정')).toBeInTheDocument()
    })
  })

  describe('에러 복구', () => {
    it('API 호출 실패 시 에러 메시지 표시', async () => {
      mockGetCurrentUser.mockRejectedValue(new Error('네트워크 오류'))

      renderApp('/auth/callback?token=test-token')

      await waitFor(() => {
        expect(screen.getByText('네트워크 오류')).toBeInTheDocument()
      })
    })

    it('토큰 없이 콜백 페이지 접근 시 에러 표시', async () => {
      renderApp('/auth/callback')

      await waitFor(() => {
        expect(screen.getByText('토큰을 받지 못했습니다')).toBeInTheDocument()
      })
    })

    it('에러 후 3초 대기 후 로그인 페이지로 복귀', async () => {
      vi.useFakeTimers()

      renderApp('/auth/callback?error=kakao_auth_failed')

      // 에러 메시지 확인
      expect(screen.getByText('카카오 로그인에 실패했습니다')).toBeInTheDocument()

      // 3초 경과
      await vi.runAllTimersAsync()

      expect(mockNavigate).toHaveBeenCalledWith('/login', { replace: true })

      vi.useRealTimers()
    })
  })

  describe('레거시 시스템 호환성', () => {
    it('로그인 성공 시 syncUserIdFromStorage 호출', async () => {
      mockGetCurrentUser.mockResolvedValue({
        _id: 'user123',
        name: '테스트',
        email: 'test@test.com',
        role: 'agent',
        avatarUrl: null
      })

      renderApp('/auth/callback?token=test-token')

      await waitFor(() => {
        expect(mockSyncUserIdFromStorage).toHaveBeenCalled()
      })
    })

    it('aims-current-user-id가 localStorage에 저장됨', async () => {
      const userId = 'legacy-user-123'
      mockGetCurrentUser.mockResolvedValue({
        _id: userId,
        name: '테스트',
        email: 'test@test.com',
        role: 'agent',
        avatarUrl: null
      })

      renderApp('/auth/callback?token=test-token')

      await waitFor(() => {
        expect(localStorage.setItem).toHaveBeenCalledWith('aims-current-user-id', userId)
      })
    })
  })

  describe('로딩 상태 관리', () => {
    it('처리 시작 시 setLoading(true) 호출', () => {
      mockGetCurrentUser.mockImplementation(() => new Promise(() => {})) // 무한 대기

      renderApp('/auth/callback?token=test-token')

      expect(mockSetLoading).toHaveBeenCalledWith(true)
    })

    it('처리 완료 시 setLoading(false) 호출', async () => {
      mockGetCurrentUser.mockResolvedValue({
        _id: 'user123',
        name: '테스트',
        email: 'test@test.com',
        role: 'agent',
        avatarUrl: null
      })

      renderApp('/auth/callback?token=test-token')

      await waitFor(() => {
        expect(mockSetLoading).toHaveBeenCalledWith(false)
      })
    })

    it('에러 발생 시에도 setLoading(false) 호출', async () => {
      mockGetCurrentUser.mockRejectedValue(new Error('API 오류'))

      renderApp('/auth/callback?token=test-token')

      await waitFor(() => {
        expect(mockSetLoading).toHaveBeenCalledWith(false)
      })
    })
  })
})

/**
 * useDocumentExplorerKeyboard Hook
 * @description 문서 탐색기 키보드 네비게이션
 *
 * 키 동작:
 * - ↑↓: 이전/다음 노드로 이동
 * - Enter: 프리뷰 열기 (싱글클릭)
 * - Space: 모달 프리뷰 (더블클릭)
 * - ←: 폴더 접기 / 부모 폴더로 이동
 * - →: 폴더 펼치기 / 첫 자식으로 이동
 */

import { useState, useCallback, useMemo, useRef, useEffect } from 'react'
import type { DocumentTreeNode } from '../types/documentExplorer'
import type { Document } from '@/types/documentStatus'

export interface FlattenedNode {
  node: DocumentTreeNode
  parentKey: string | null
  level: number
}

export interface UseDocumentExplorerKeyboardOptions {
  nodes: DocumentTreeNode[]
  expandedKeys: Set<string>
  selectedDocumentId: string | null
  onToggleNode: (key: string) => void
  onDocumentClick: (doc: Document) => void
  onDocumentDoubleClick: (doc: Document) => void
}

export interface UseDocumentExplorerKeyboardResult {
  focusedKey: string | null
  setFocusedKey: (key: string | null) => void
  handleKeyDown: (e: React.KeyboardEvent) => void
  flattenedNodes: FlattenedNode[]
  /** 키보드 탐색으로 포커스 변경 시 true (스크롤 필요), 마우스 클릭 시 false */
  needsScroll: boolean
  clearNeedsScroll: () => void
}

/**
 * 트리 노드를 평탄화하여 순차적 탐색 가능하게 변환
 */
function flattenTree(
  nodes: DocumentTreeNode[],
  expandedKeys: Set<string>,
  parentKey: string | null = null,
  level: number = 0
): FlattenedNode[] {
  const result: FlattenedNode[] = []

  for (const node of nodes) {
    result.push({ node, parentKey, level })

    // 그룹 노드가 펼쳐져 있으면 자식도 포함
    if (node.type !== 'document' && expandedKeys.has(node.key) && node.children) {
      result.push(...flattenTree(node.children, expandedKeys, node.key, level + 1))
    }
  }

  return result
}

export function useDocumentExplorerKeyboard({
  nodes,
  expandedKeys,
  selectedDocumentId,
  onToggleNode,
  onDocumentClick,
  onDocumentDoubleClick,
}: UseDocumentExplorerKeyboardOptions): UseDocumentExplorerKeyboardResult {
  // 포커스된 노드 키 (항상 유효한 값 유지)
  const [focusedKeyState, setFocusedKeyState] = useState<string | null>(null)
  const focusedKeyRef = useRef<string | null>(null)

  // 트리를 평탄화
  const flattenedNodes = useMemo(
    () => flattenTree(nodes, expandedKeys),
    [nodes, expandedKeys]
  )

  // flattenedNodes를 ref로 추적 (useEffect에서 의존성 없이 최신 값 참조)
  const flattenedNodesRef = useRef(flattenedNodes)
  flattenedNodesRef.current = flattenedNodes

  // 포커스 키 계산 (항상 유효한 값 반환)
  const focusedKey = useMemo(() => {
    if (flattenedNodes.length === 0) return null

    // 1. 현재 state가 유효하면 사용
    if (focusedKeyState && flattenedNodes.some(fn => fn.node.key === focusedKeyState)) {
      return focusedKeyState
    }

    // 2. ref가 유효하면 사용
    if (focusedKeyRef.current && flattenedNodes.some(fn => fn.node.key === focusedKeyRef.current)) {
      return focusedKeyRef.current
    }

    // 3. selectedDocumentId fallback 제거 — useEffect에서 단일 처리
    // (flattenedNodes 변경 시마다 이전 선택 문서로 포커스가 되돌아가는 버그 방지)

    // 4. 첫 번째 노드로 폴백
    return flattenedNodes[0].node.key
  }, [flattenedNodes, focusedKeyState])

  // focusedKey가 변경되면 ref와 state 동기화
  useEffect(() => {
    if (focusedKey && focusedKey !== focusedKeyRef.current) {
      focusedKeyRef.current = focusedKey
    }
  }, [focusedKey])

  // selectedDocumentId 변경 시 해당 문서로 포커스 이동 (검색 시 자동 포커스)
  // 주의: flattenedNodes를 의존성에서 제거 — ref로 참조
  // flattenedNodes가 의존성에 있으면, 다른 폴더 토글 시에도 이전 선택 문서로
  // 포커스가 되돌아가는 버그 발생 (스크롤이 엉뚱한 문서로 점프)
  useEffect(() => {
    if (!selectedDocumentId) return

    const currentNodes = flattenedNodesRef.current
    const selectedNode = currentNodes.find(
      fn => fn.node.document?._id === selectedDocumentId || fn.node.document?.id === selectedDocumentId
    )
    if (selectedNode) {
      focusedKeyRef.current = selectedNode.node.key
      setFocusedKeyState(selectedNode.node.key)
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedDocumentId])

  // 포커스 설정 함수
  const setFocusedKey = useCallback((key: string | null) => {
    focusedKeyRef.current = key
    setFocusedKeyState(key)
  }, [])

  // 키보드 탐색에 의한 포커스 변경 시 스크롤 필요 플래그
  const needsScrollRef = useRef(false)
  const [needsScroll, setNeedsScroll] = useState(false)

  const clearNeedsScroll = useCallback(() => {
    needsScrollRef.current = false
    setNeedsScroll(false)
  }, [])

  // 특정 인덱스의 노드로 포커스 이동 (키보드 전용 → 스크롤 트리거)
  const focusNode = useCallback((index: number) => {
    if (index < 0 || index >= flattenedNodes.length) return

    needsScrollRef.current = true
    setNeedsScroll(true)
    const node = flattenedNodes[index].node
    setFocusedKey(node.key)
  }, [flattenedNodes, setFocusedKey])

  // 키보드 이벤트 핸들러
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      // 입력 필드에서는 무시
      if (
        e.target instanceof HTMLInputElement ||
        e.target instanceof HTMLTextAreaElement
      ) {
        return
      }

      const currentIndex = flattenedNodes.findIndex(fn => fn.node.key === focusedKey)
      if (currentIndex === -1) return

      const currentNode = flattenedNodes[currentIndex]

      switch (e.key) {
        case 'ArrowUp': {
          e.preventDefault()
          if (currentIndex > 0) {
            focusNode(currentIndex - 1)
          }
          break
        }

        case 'ArrowDown': {
          e.preventDefault()
          if (currentIndex < flattenedNodes.length - 1) {
            focusNode(currentIndex + 1)
          }
          break
        }

        case 'ArrowLeft': {
          e.preventDefault()
          if (currentNode.node.type !== 'document') {
            // 그룹 노드: 펼쳐져 있으면 접기, 이미 접혀있으면 부모로 이동
            if (expandedKeys.has(currentNode.node.key)) {
              onToggleNode(currentNode.node.key)
            } else if (currentNode.parentKey) {
              // 부모 노드로 포커스 이동
              const parentIndex = flattenedNodes.findIndex(
                fn => fn.node.key === currentNode.parentKey
              )
              if (parentIndex !== -1) {
                focusNode(parentIndex)
              }
            }
          } else {
            // 문서 노드: 부모 그룹으로 이동
            if (currentNode.parentKey) {
              const parentIndex = flattenedNodes.findIndex(
                fn => fn.node.key === currentNode.parentKey
              )
              if (parentIndex !== -1) {
                focusNode(parentIndex)
              }
            }
          }
          break
        }

        case 'ArrowRight': {
          e.preventDefault()
          if (currentNode.node.type !== 'document') {
            // 그룹 노드: 접혀있으면 펼치기, 펼쳐져 있으면 첫 자식으로 이동
            if (!expandedKeys.has(currentNode.node.key)) {
              onToggleNode(currentNode.node.key)
            } else if (currentIndex < flattenedNodes.length - 1) {
              // 다음 노드가 자식이면 이동
              const nextNode = flattenedNodes[currentIndex + 1]
              if (nextNode.parentKey === currentNode.node.key) {
                focusNode(currentIndex + 1)
              }
            }
          }
          break
        }

        case 'Enter': {
          e.preventDefault()
          if (currentNode.node.type === 'document' && currentNode.node.document) {
            // 문서 노드: 싱글클릭 (RightPane 프리뷰)
            onDocumentClick(currentNode.node.document)
          } else {
            // 그룹 노드: 토글
            onToggleNode(currentNode.node.key)
          }
          break
        }

        case ' ': {
          e.preventDefault()
          if (currentNode.node.type === 'document' && currentNode.node.document) {
            // 문서 노드: 더블클릭 (모달 프리뷰)
            onDocumentDoubleClick(currentNode.node.document)
          } else {
            // 그룹 노드: 토글
            onToggleNode(currentNode.node.key)
          }
          break
        }

        case 'Home': {
          e.preventDefault()
          if (flattenedNodes.length > 0) {
            focusNode(0)
          }
          break
        }

        case 'End': {
          e.preventDefault()
          if (flattenedNodes.length > 0) {
            focusNode(flattenedNodes.length - 1)
          }
          break
        }
      }
    },
    [flattenedNodes, focusedKey, expandedKeys, focusNode, onToggleNode, onDocumentClick, onDocumentDoubleClick]
  )

  return {
    focusedKey,
    setFocusedKey,
    handleKeyDown,
    flattenedNodes,
    needsScroll,
    clearNeedsScroll,
  }
}

/**
 * DocumentManagementView Component
 * @since 1.0.0
 *
 * 문서 관리 대시보드
 * 통계, 빠른 액션, 최근 활동을 포함
 */

import React, { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { CenterPaneView } from '../../CenterPaneView/CenterPaneView';
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../SFSymbol';
import { StatCard } from '@/shared/ui/StatCard';
import { UsageGuide } from '@/shared/ui/UsageGuide';
import type { GuideSection } from '@/shared/ui/UsageGuide';
import { getDocumentStatistics } from '@/services/DocumentService';
import { DocumentStatusService } from '@/services/DocumentStatusService';
import { DocumentUtils, type DocumentTypeInput } from '@/entities/document';
import { Tooltip } from '@/shared/ui';
import { FileTypePieChart } from '@/shared/ui/FileTypePieChart';
import type { FileTypeData } from '@/shared/ui/FileTypePieChart';
import { HorizontalBarChart } from '@/shared/ui/HorizontalBarChart';
import { Dropdown } from '@/shared/ui/Dropdown';
import { formatDate } from '@/shared/lib/timeUtils';
import './DocumentManagementView.css';
import './DocumentManagementView.mobile.css';

type ActivityPeriod = '1week' | '1month' | '3months' | '6months' | '1year';

interface DocumentManagementViewProps {
  /** View 표시 여부 */
  visible: boolean;
  /** View 닫기 핸들러 */
  onClose: () => void;
  /** 메뉴 네비게이션 핸들러 */
  onNavigate?: (menuKey: string) => void;
}

/**
 * DocumentManagementView React 컴포넌트
 *
 * 문서 관리 대시보드 - Mock 데이터 사용 (Phase 1)
 * Phase 2에서 실제 API 연동 예정
 *
 * @example
 * ```tsx
 * <DocumentManagementView
 *   visible={isVisible}
 *   onClose={handleClose}
 * />
 * ```
 */
export const DocumentManagementView: React.FC<DocumentManagementViewProps> = ({
  visible,
  onClose,
  onNavigate,
}) => {
  // 최근 활동 기간 선택 상태
  const [activityPeriod, setActivityPeriod] = useState<ActivityPeriod>('1month');

  /**
   * OCR 신뢰도를 5단계로 분류
   */
  const getOcrConfidenceLevel = (confidence: number): {
    color: string
    label: string
  } => {
    if (confidence >= 0.95) {
      return { color: 'excellent', label: '매우 높음' }
    } else if (confidence >= 0.85) {
      return { color: 'high', label: '높음' }
    } else if (confidence >= 0.70) {
      return { color: 'medium', label: '보통' }
    } else if (confidence >= 0.50) {
      return { color: 'low', label: '낮음' }
    } else {
      return { color: 'very-low', label: '매우 낮음' }
    }
  }

  /**
   * Document에서 OCR confidence 추출
   */
  const getOcrConfidence = (document: DocumentTypeInput): number | null => {
    // 1. document.ocr?.confidence 먼저 시도
    if (document.ocr && typeof document.ocr !== 'string') {
      const directConfidence = document.ocr.confidence
      if (directConfidence) {
        const parsed = parseFloat(String(directConfidence))
        if (!isNaN(parsed)) return parsed
      }
    }

    // 2. stages.ocr.message에서 파싱 시도
    const stageOcr = document.stages?.ocr
    if (stageOcr && typeof stageOcr !== 'string') {
      const ocrMessage = stageOcr.message
      if (ocrMessage && typeof ocrMessage === 'string') {
        const match = ocrMessage.match(/신뢰도:\s*([\d.]+)/)
        if (match && match[1]) {
          const parsed = parseFloat(match[1])
          if (!isNaN(parsed)) return parsed
        }
      }
    }

    return null
  }

  // 문서 통계 API 연동
  const {
    data: stats,
    isLoading: isStatsLoading,
    isError: isStatsError,
  } = useQuery({
    queryKey: ['documentStatistics'],
    queryFn: getDocumentStatistics,
    enabled: visible,
  });

  // 📊 최근 활동 문서 조회 (서버사이드 기간 필터링, 최대 200건)
  const {
    data: recentDocumentsData,
    isLoading: isRecentLoading,
    isError: isRecentError,
  } = useQuery({
    queryKey: ['recentDocumentsForManagement', activityPeriod],
    queryFn: () =>
      DocumentStatusService.getRecentDocuments(1, 200, 'uploadTime_desc', undefined, undefined, undefined, undefined, activityPeriod),
    enabled: visible,
  });


  /**
   * 문서 활동 정보 생성
   */
  const getActivityInfo = (status: string) => {
    if (status === 'completed') {
      return {
        text: '처리 완료',
        icon: (
          <svg width="13" height="13" viewBox="0 0 20 20" fill="currentColor" style={{ color: 'var(--color-success)' }}>
            <circle cx="10" cy="10" r="9" fill="currentColor" opacity="0.2"/>
            <path d="M6 10l3 3 5-6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
          </svg>
        ),
      };
    } else if (status === 'processing') {
      return {
        text: '처리 중',
        icon: (
          <svg width="13" height="13" viewBox="0 0 20 20" style={{ color: 'var(--color-text-secondary)' }}>
            <circle cx="10" cy="10" r="8" fill="none" stroke="currentColor" strokeWidth="2" opacity="0.3"/>
            <path d="M10 2 A 8 8 0 0 1 18 10" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
              <animateTransform
                attributeName="transform"
                type="rotate"
                from="0 10 10"
                to="360 10 10"
                dur="1s"
                repeatCount="indefinite"
              />
            </path>
          </svg>
        ),
      };
    } else if (status === 'error') {
      return {
        text: '처리 실패',
        icon: (
          <svg width="13" height="13" viewBox="0 0 20 20" fill="currentColor" style={{ color: 'var(--color-error)' }}>
            <circle cx="10" cy="10" r="9" fill="currentColor" opacity="0.2"/>
            <path d="M7 7l6 6M13 7l-6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
          </svg>
        ),
      };
    } else {
      return {
        text: '문서 등록',
        icon: (
          <svg width="13" height="13" viewBox="0 0 20 20" fill="currentColor" style={{ color: 'var(--color-text-secondary)' }}>
            <rect x="4" y="2" width="10" height="14" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.5"/>
            <line x1="7" y1="6" x2="11" y2="6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
            <line x1="7" y1="9" x2="11" y2="9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
            <circle cx="15" cy="15" r="4" fill="var(--color-success)"/>
            <path d="M15 13v4M13 15h4" stroke="var(--color-text-inverse)" strokeWidth="1.5" strokeLinecap="round"/>
          </svg>
        ),
      };
    }
  };

  /**
   * 문서의 날짜 추출 (created_at, uploaded_at, 또는 MongoDB ObjectId에서)
   */
  const getDocumentDate = (doc: DocumentTypeInput): Date | null => {
    // 1. created_at 시도
    if (doc.created_at) {
      return new Date(doc.created_at);
    }

    // 2. uploaded_at 시도
    if (doc.uploaded_at) {
      return new Date(doc.uploaded_at);
    }

    // 3. MongoDB ObjectId에서 타임스탬프 추출
    if (doc._id && typeof doc._id === 'string' && doc._id.length === 24) {
      const timestamp = parseInt(doc._id.substring(0, 8), 16) * 1000; // 밀리초로 변환
      return new Date(timestamp);
    }

    return null;
  };

  // 📊 기간별 문서 개수 (서버사이드 totalCount 사용)
  const recentDocumentCount = recentDocumentsData?.pagination?.totalCount ?? recentDocumentsData?.documents?.length ?? 0;

  // 📊 최근 문서 목록 (서버사이드 기간 필터 + 정렬 완료)
  const recentDocumentList = recentDocumentsData?.documents ?? [];

  /**
   * 시간 표시 포맷 (상대 시간)
   */
  const formatRelativeTime = (date: Date): string => {
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return '방금 전';
    if (diffMins < 60) return `${diffMins}분 전`;
    if (diffHours < 24) return `${diffHours}시간 전`;
    if (diffDays < 7) return `${diffDays}일 전`;

    return formatDate(date);
  };

  /**
   * 파일 크기 포맷 (바이트 → KB/MB)
   */
  const formatFileSize = (bytes: number | undefined): string => {
    if (!bytes || bytes === 0) return '-';

    if (bytes < 1024) {
      return `${bytes}B`;
    } else if (bytes < 1024 * 1024) {
      return `${(bytes / 1024).toFixed(1)}KB`;
    } else {
      return `${(bytes / (1024 * 1024)).toFixed(1)}MB`;
    }
  };

  /**
   * 문서 타입 분류 헬퍼 - 확장자 기반
   */
  const getFileTypeCategory = (mimeType: string | undefined, filename: string | undefined): string => {
    const name = (filename || '').toLowerCase();

    // 확장자 추출
    const match = name.match(/\.([a-z0-9]+)$/);
    if (match && match[1]) {
      return match[1].toUpperCase(); // 'pdf' -> 'PDF', 'docx' -> 'DOCX'
    }

    // 확장자 없으면 MIME type으로 추정
    const mime = (mimeType || '').toLowerCase();
    if (mime.includes('pdf')) return 'PDF';
    if (mime.includes('word')) return 'DOCX';
    if (mime.includes('excel')) return 'XLSX';
    if (mime.includes('powerpoint')) return 'PPTX';
    if (mime.includes('image/')) return 'IMAGE';

    return 'UNKNOWN';
  };

  // 문서 유형 파이 차트 데이터
  const fileTypePieData: FileTypeData[] = useMemo(() => {
    if (!stats?.badgeTypes) return [];

    return [
      {
        label: 'TXT',
        count: stats.badgeTypes.TXT ?? 0,
        color: 'var(--color-success)',
        description: '텍스트 추출 가능 문서'
      },
      {
        label: 'OCR',
        count: stats.badgeTypes.OCR ?? 0,
        color: 'var(--color-primary-500)',
        description: '이미지 문서로 OCR 처리됨, 신뢰도별 색상 표시'
      },
      {
        label: 'BIN',
        count: stats.badgeTypes.BIN ?? 0,
        color: 'var(--color-neutral-600)',
        description: '텍스트 추출 불가능한 바이너리 파일'
      }
    ];
  }, [stats]);

  // 처리 상태 파이 차트 데이터
  const statusPieData: FileTypeData[] = useMemo(() => {
    if (!stats) return [];

    return [
      {
        label: '완료',
        count: stats.completed ?? 0,
        color: 'var(--color-success)',
        description: '모든 처리 단계가 완료된 문서'
      },
      {
        label: '처리중',
        count: stats.processing ?? 0,
        color: 'var(--color-primary-500)',
        description: '현재 처리 중인 문서'
      },
      {
        label: '대기',
        count: stats.pending ?? 0,
        color: 'var(--color-warning)',
        description: '처리 대기 중인 문서'
      },
      {
        label: '실패',
        count: stats.error ?? 0,
        color: 'var(--color-error)',
        description: '처리 실패한 문서'
      }
    ].filter(item => item.count > 0); // 0인 항목은 제외
  }, [stats]);

  // 📊 문서 타입 분포 (서버사이드 집계 사용)
  const actualFileTypePieData: FileTypeData[] = useMemo(() => {
    if (!stats?.fileTypeDistribution?.length) return [];

    const typeColors: Record<string, string> = {
      'PDF': 'var(--color-error)',
      'DOCX': 'var(--color-primary-500)',
      'DOC': 'var(--color-ios-blue)',
      'XLSX': 'var(--color-success)',
      'XLS': 'var(--color-ios-green)',
      'PPTX': 'var(--color-warning)',
      'PPT': 'var(--color-ios-orange)',
      'JPG': 'var(--color-ios-blue)',
      'JPEG': 'var(--color-ios-blue)',
      'PNG': 'var(--color-ios-teal)',
      'GIF': 'var(--color-ios-purple)',
      'BMP': 'var(--color-ios-indigo)',
      'WEBP': 'var(--color-ios-cyan)',
      'TIFF': 'var(--color-ios-purple)',
      'IMAGE': 'var(--color-ios-blue)',
      'ZIP': 'var(--color-ios-purple)',
      'RAR': 'var(--color-ios-purple)',
      '7Z': 'var(--color-ios-purple)',
      'TAR': 'var(--color-ios-indigo)',
      'GZ': 'var(--color-ios-indigo)',
      'PS': 'var(--color-ios-orange)',
      'EPS': 'var(--color-ios-orange)',
      'TXT': 'var(--color-neutral-600)',
      'UNKNOWN': 'var(--color-text-tertiary)'
    };

    return stats.fileTypeDistribution
      .map(({ label, count }) => ({
        label,
        count,
        color: typeColors[label] || 'var(--color-text-tertiary)',
        description: `${label.toLowerCase()} 파일`
      }))
      .filter(item => item.count > 0);
  }, [stats]);

  // 사용 가이드 섹션
  const guideSections: GuideSection[] = [
    {
      icon: (
        <SFSymbol
          name="doc-badge-plus"
          size={SFSymbolSize.CALLOUT}
          weight={SFSymbolWeight.MEDIUM}
          style={{ color: 'var(--color-icon-doc-register)' }}
        />
      ),
      title: '문서 등록',
      description: '새로운 문서를 업로드하고 자동 분류 및 OCR 처리를 시작합니다. PDF, 이미지, 텍스트 파일 등 다양한 형식을 지원합니다.',
      ...(onNavigate && { onClick: () => onNavigate('documents-register') }),
    },
    {
      icon: (
        <SFSymbol
          name="books-vertical"
          size={SFSymbolSize.CALLOUT}
          weight={SFSymbolWeight.MEDIUM}
          style={{ color: 'var(--color-icon-doc-library)' }}
        />
      ),
      title: '문서 라이브러리',
      description: '등록된 모든 문서를 검색하고 관리합니다. 파일명, 태그, 고객 연결 등 다양한 조건으로 필터링하고 정렬할 수 있습니다.',
      ...(onNavigate && { onClick: () => onNavigate('documents-library') }),
    },
    {
      icon: (
        <SFSymbol
          name="search-bold"
          size={SFSymbolSize.CALLOUT}
          weight={SFSymbolWeight.MEDIUM}
          style={{ color: 'var(--color-icon-doc-search)' }}
        />
      ),
      title: '상세 문서검색',
      description: '키워드, 태그, 고객, 문서 유형 등 다양한 조건으로 문서를 검색합니다. AI 기반 시맨틱 검색으로 정확한 문서를 빠르게 찾을 수 있습니다.',
      ...(onNavigate && { onClick: () => onNavigate('documents-search') }),
    },
  ];

  return (
    <CenterPaneView
      visible={visible}
      title="문서 관리"
      titleIcon={<SFSymbol name="doc" size={SFSymbolSize.CALLOUT} weight={SFSymbolWeight.MEDIUM} />}
      onClose={onClose}
      marginTop={5}
      marginBottom={5}
      marginLeft={5}
      marginRight={5}
      className="document-management-view"
    >
      <div className="document-management-view__content">
        {/* 통계 섹션 */}
        <section className="document-management-view__section">
          <h2 className="document-management-view__section-title">
            <svg width="14" height="14" viewBox="0 0 20 20">
              <rect x="2" y="12" width="4" height="6" rx="1" fill="var(--color-primary-500)"/>
              <rect x="8" y="7" width="4" height="11" rx="1" fill="var(--color-primary-500)"/>
              <rect x="14" y="3" width="4" height="15" rx="1" fill="var(--color-primary-500)"/>
            </svg>
            문서 통계
          </h2>
          <div className="document-management-view__stats-grid">
            <StatCard
              title="전체 문서"
              value={stats?.total ?? 0}
              icon={
                <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
                  <rect x="4" y="4" width="12" height="14" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.5" opacity="0.4"/>
                  <rect x="2" y="2" width="12" height="14" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.5"/>
                  <line x1="5" y1="6" x2="11" y2="6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  <line x1="5" y1="9" x2="11" y2="9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  <line x1="5" y1="12" x2="9" y2="12" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              }
              color="primary"
              isLoading={isStatsLoading}
              {...(isStatsError && { error: '통계 조회 실패' })}
            />
            <StatCard
              title="처리 대기"
              value={stats?.pending ?? 0}
              icon={
                <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
                  <circle cx="10" cy="10" r="8.5" fill="none" stroke="currentColor" strokeWidth="1.5"/>
                  <path d="M10 5v5l3 3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" fill="none"/>
                  <circle cx="10" cy="10" r="1.5"/>
                </svg>
              }
              color="warning"
              isLoading={isStatsLoading}
              {...(isStatsError && { error: '통계 조회 실패' })}
            />
            <StatCard
              title="OCR 완료"
              value={stats?.badgeTypes.OCR ?? 0}
              icon={
                <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
                  <rect x="3" y="2" width="14" height="16" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.5"/>
                  <line x1="6" y1="6" x2="14" y2="6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  <line x1="6" y1="9" x2="14" y2="9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  <line x1="6" y1="12" x2="11" y2="12" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              }
              color="success"
              isLoading={isStatsLoading}
              {...(isStatsError && { error: '통계 조회 실패' })}
            />
            <StatCard
              title="태그 완료"
              value={stats?.completed ?? 0}
              icon={
                <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M2 2l8 0 8 8-8 8-8-8z" fill="none" stroke="currentColor" strokeWidth="1.5"/>
                  <circle cx="7" cy="7" r="1.5"/>
                  <circle cx="15" cy="15" r="4" fill="var(--color-success)"/>
                  <path d="M13.5 15l1 1 2.5-2.5" stroke="var(--color-text-inverse)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
                </svg>
              }
              color="success"
              isLoading={isStatsLoading}
              {...(isStatsError && { error: '통계 조회 실패' })}
            />
          </div>

          {/* 파이 차트 그리드 */}
          {!isStatsLoading && !isStatsError && stats && stats.total > 0 && (
            <div className="document-management-view__pie-charts-grid">
              {/* 문서 유형 차트 */}
              {fileTypePieData.length > 0 && (
                <div className="pie-chart-item">
                  <h3 className="pie-chart-title">문서 유형</h3>
                  <FileTypePieChart
                    data={fileTypePieData}
                    size={150}
                    innerRadius={38}
                  />
                </div>
              )}

              {/* 처리 상태 차트 */}
              {statusPieData.length > 0 && (
                <div className="pie-chart-item">
                  <h3 className="pie-chart-title">처리 상태</h3>
                  <FileTypePieChart
                    data={statusPieData}
                    size={150}
                    innerRadius={38}
                  />
                </div>
              )}

              {/* 문서 타입 차트 */}
              {actualFileTypePieData.length > 0 && (
                <div className="pie-chart-item">
                  <h3 className="pie-chart-title">문서 타입</h3>
                  <HorizontalBarChart
                    categories={[
                      {
                        title: '문서 타입',
                        data: actualFileTypePieData
                      }
                    ]}
                  />
                </div>
              )}
            </div>
          )}
        </section>

        {/* 사용 가이드 */}
        <UsageGuide
          title="문서관리 사용 가이드"
          sections={guideSections}
          defaultExpanded={true}
        />

        {/* 최근 활동 섹션 */}
        <section className="document-management-view__section">
          <div className="document-management-view__section-header">
            <h2 className="document-management-view__section-title">
              <svg width="14" height="14" viewBox="0 0 20 20">
                <circle cx="10" cy="10" r="9" fill="var(--color-success)"/>
                <path d="M10 5v5l3.5 3.5" stroke="var(--color-text-inverse)" strokeWidth="1.5" strokeLinecap="round" fill="none"/>
              </svg>
              최근 활동 ({recentDocumentCount}개)
            </h2>
            <Dropdown
              value={activityPeriod}
              onChange={(value) => setActivityPeriod(value as ActivityPeriod)}
              options={[
                { value: '1week', label: '최근 1주일' },
                { value: '1month', label: '최근 1개월' },
                { value: '3months', label: '최근 3개월' },
                { value: '6months', label: '최근 6개월' },
                { value: '1year', label: '최근 1년' }
              ]}
            />
          </div>
          <div className="document-management-view__recent-activity">
            {isRecentLoading ? (
              <div className="recent-activity-loading">최근 활동을 불러오는 중...</div>
            ) : isRecentError ? (
              <div className="recent-activity-error">최근 활동 조회 실패</div>
            ) : recentDocumentList.length === 0 ? (
              <div className="recent-activity-empty">최근 활동이 없습니다</div>
            ) : (
              <div className="recent-activity-table">
                {/* 테이블 헤더 */}
                <div className="recent-activity-header">
                  <div className="recent-header-activity">활동</div>
                  <div className="recent-header-name">문서명</div>
                  <div className="recent-header-size">크기</div>
                  <div className="recent-header-type">유형</div>
                  <div className="recent-header-customer">고객</div>
                  <div className="recent-header-time">시간</div>
                </div>

                {/* 데이터 행 */}
                {recentDocumentList.map((doc) => {
                  const fileIcon = DocumentUtils.getFileIcon(doc.mimeType, doc.filename || doc.originalName);
                  const fileTypeClass = DocumentUtils.getFileTypeClass(doc.mimeType, doc.filename || doc.originalName);
                  const activityInfo = getActivityInfo(doc.status || 'pending');
                  const fileType = getFileTypeCategory(doc.mimeType, doc.filename || doc.originalName);
                  const timestamp = getDocumentDate(doc as any) || new Date();

                  // 파일 크기 추출 (여러 소스에서 시도)
                  const fileSize = doc.size || doc.fileSize || doc.file_size;

                  // 연결된 고객 정보
                  const linkedCustomer = doc.customer_relation?.customer_name || null;

                  // AR 뱃지 확인
                  const isAnnualReport = doc.is_annual_report === true;

                  // OCR/TXT/BIN 뱃지 확인
                  const ocrConfidence = getOcrConfidence(doc as any);
                  const ocrLevel = ocrConfidence !== null ? getOcrConfidenceLevel(ocrConfidence) : null;
                  const typeLabel = ocrConfidence === null ? DocumentUtils.getDocumentTypeLabel(doc as any) : null;
                  const showTxtBadge = typeLabel === 'TXT';
                  const showBinBadge = typeLabel === 'BIN';

                  return (
                    <div key={doc._id || String(Math.random())} className="recent-activity-row">
                      {/* 활동 (아이콘 + 텍스트) */}
                      <div className="recent-cell-activity">
                        {activityInfo.icon}
                        <span className="activity-text">{activityInfo.text}</span>
                      </div>

                      {/* 문서명 (파일 아이콘 + 뱃지 포함) */}
                      <div className="recent-cell-name">
                        <div className="document-icon-wrapper">
                          <div className={`document-icon ${fileTypeClass}`}>
                            <SFSymbol
                              name={fileIcon}
                              size={SFSymbolSize.CAPTION_1}
                              weight={SFSymbolWeight.REGULAR}
                              decorative={true}
                            />
                          </div>

                          {/* AR 뱃지 */}
                          {isAnnualReport && (
                            <Tooltip content="연간보고서">
                              <div className="document-ar-badge">
                                AR
                              </div>
                            </Tooltip>
                          )}

                          {/* CR 뱃지 */}
                          {doc.is_customer_review === true && !isAnnualReport && (
                            <Tooltip content="변액 리뷰">
                              <div className="document-cr-badge">
                                CR
                              </div>
                            </Tooltip>
                          )}

                          {/* OCR, TXT, BIN 뱃지 */}
                          {ocrConfidence !== null && ocrLevel ? (
                            <Tooltip content={`OCR 신뢰도: ${(ocrConfidence * 100).toFixed(1)}% (${ocrLevel.label})`}>
                              <div className={`document-ocr-badge ocr-${ocrLevel.color}`}>
                                OCR
                              </div>
                            </Tooltip>
                          ) : showTxtBadge ? (
                            <Tooltip content="TXT 기반 문서">
                              <div className="document-txt-badge">
                                TXT
                              </div>
                            </Tooltip>
                          ) : showBinBadge ? (
                            <Tooltip content="BIN 기반 문서 (텍스트 추출 불가)">
                              <div className="document-bin-badge">
                                BIN
                              </div>
                            </Tooltip>
                          ) : null}
                        </div>
                        <span className="document-filename">
                          {doc.filename || doc.originalName || '제목 없음'}
                        </span>
                      </div>

                      {/* 파일크기 */}
                      <div className="recent-cell-size">{formatFileSize(fileSize)}</div>

                      {/* 유형 */}
                      <div className="recent-cell-type">{fileType}</div>

                      {/* 연결고객 */}
                      <div className="recent-cell-customer">
                        {linkedCustomer || '-'}
                      </div>

                      {/* 시간 */}
                      <div className="recent-cell-time">
                        {formatRelativeTime(timestamp)}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </section>
      </div>
    </CenterPaneView>
  );
};

export default DocumentManagementView

/**
 * CustomerFileUploadArea Component
 * @since 1.0.0
 * @updated 2025-12-29 - 문서 유형 수동 선택 UI 제거 (자동 분류로 대체)
 *
 * 고객 파일 등록 시 고객 선택 UI
 * - 고객 선택 (최근 고객 드롭다운 + 고객 검색 모달)
 * - 문서 유형은 업로드 후 자동 분류 → 프리뷰 모달에서 수정 가능
 */

import React, { useState, useCallback, useMemo } from 'react'
import { Button, Dropdown, Tooltip, type DropdownOption } from '@/shared/ui'
import { CustomerSelectorModal } from '@/shared/ui/CustomerSelectorModal'
import type { Customer } from '@/entities/customer'
import { useRecentCustomersStore } from '@/shared/store/useRecentCustomersStore'
import './CustomerFileUploadArea.css'

interface CustomerFileUploadAreaProps {
  /** 선택된 고객 */
  selectedCustomer: Customer | null
  /** 고객 선택 핸들러 */
  onCustomerSelect: (customer: Customer | null) => void
  /** 비활성화 여부 */
  disabled: boolean
  /** 초기화 버튼 표시 여부 */
  showResetButton?: boolean
  /** 초기화 핸들러 */
  onReset?: () => void
}

/**
 * CustomerFileUploadArea React 컴포넌트
 */
export const CustomerFileUploadArea: React.FC<CustomerFileUploadAreaProps> = ({
  selectedCustomer,
  onCustomerSelect,
  disabled,
  showResetButton = false,
  onReset
}) => {
  // 고객 선택 모달 상태
  const [isCustomerSelectorOpen, setIsCustomerSelectorOpen] = useState(false)
  // 최근 선택한 고객 목록 (전역 상태)
  const { recentCustomers, addRecentCustomer, getRecentCustomers } = useRecentCustomersStore()

  /**
   * 최근 고객 드롭다운 옵션 생성 (DocumentLinkModal과 동일)
   */
  const recentCustomerOptions = useMemo(() => {
    const options: DropdownOption[] = [
      {
        value: '',
        label: '고객 미선택'
      }
    ]

    // 전역 상태에서 최근 고객 목록 가져오기
    const recent = getRecentCustomers()
    recent.forEach(customer => {
      options.push({
        value: customer._id,
        label: customer.name
      })
    })

    return options
  }, [recentCustomers, getRecentCustomers])

  /**
   * 최근 고객 드롭다운에서 선택 핸들러
   */
  const handleRecentCustomerSelect = useCallback((customerId: string) => {
    if (!customerId) {
      // "고객 미선택" 선택
      onCustomerSelect(null)
      return
    }

    // 전역 상태에서 최근 고객 목록 가져와서 찾기
    const recent = getRecentCustomers()
    const recentCustomer = recent.find(c => c._id === customerId)
    if (recentCustomer) {
      // Customer 객체 재구성
      onCustomerSelect({
        _id: recentCustomer._id,
        personal_info: {
          name: recentCustomer.name
        }
      } as Customer)
    }
  }, [getRecentCustomers, onCustomerSelect])

  /**
   * 고객 선택 모달에서 고객 선택 핸들러
   */
  const handleCustomerSelected = useCallback((customer: Customer) => {
    onCustomerSelect(customer)
    setIsCustomerSelectorOpen(false)

    // 최근 고객 목록에 추가 (전역 상태 자동 업데이트)
    addRecentCustomer(customer)
  }, [onCustomerSelect, addRecentCustomer])

  return (
    <div className="customer-file-upload-area">
      {/* 하나의 경계 박스: 고객 선택 + 고객 정보 + 문서 유형 + 메모 */}
      <div className="customer-file-upload-area__content-box">
        {/* 첫 번째 행: 고객 선택 버튼 + 고객 정보 */}
        <div className="customer-file-upload-area__main-row">
          {/* 고객 선택 버튼 */}
          <Button
            variant="secondary"
            size="sm"
            onClick={() => setIsCustomerSelectorOpen(true)}
            disabled={disabled}
          >
            고객 선택
          </Button>

          {/* 선택된 고객 표시 또는 최근 고객 드롭다운 */}
          <div className="customer-file-upload-area__selected-customer">
            {selectedCustomer ? (
              <div className="selected-customer-name">
                <span className="selected-customer-text">
                  {selectedCustomer.personal_info?.name || '이름 없음'}
                </span>
                <button
                  className="clear-customer-button"
                  onClick={() => onCustomerSelect(null)}
                  aria-label="고객 선택 해제"
                  disabled={disabled}
                >
                  ✕
                </button>
              </div>
            ) : (
              <Dropdown
                value=""
                options={recentCustomerOptions}
                onChange={handleRecentCustomerSelect}
                width="100%"
                aria-label="최근 선택한 고객"
              />
            )}
          </div>

          {/* 초기화 버튼 - 업로드 결과가 있을 때만 표시 */}
          {showResetButton && onReset && (
            <Tooltip content="처음부터 다시 시작">
              <button
                type="button"
                className="customer-file-upload-area__reset-button"
                onClick={onReset}
                aria-label="처음부터 다시 시작"
              >
                ↻
              </button>
            </Tooltip>
          )}
        </div>

      </div>

      {/* 고객 선택 모달 */}
      <CustomerSelectorModal
        visible={isCustomerSelectorOpen}
        onClose={() => setIsCustomerSelectorOpen(false)}
        onSelect={handleCustomerSelected}
      />
    </div>
  )
}

export default CustomerFileUploadArea

/**
 * DocumentRegistrationView Component
 * @since 1.0.0
 *
 * 문서 등록 View 컴포넌트
 * 애플 스타일의 파일 업로드 시스템 구현
 */

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react'
import { CenterPaneView } from '../../CenterPaneView/CenterPaneView'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../SFSymbol'
import FileUploadArea from './FileUploadArea/FileUploadArea'
import CustomerFileUploadArea from './CustomerFileUploadArea/CustomerFileUploadArea'
import ProcessingLog from './ProcessingLog/ProcessingLog'
import { Modal, Tooltip } from '@/shared/ui'
import { showAppleConfirm, showOversizedFilesModal } from '../../../utils/appleConfirm'
import { UploadFile, UploadState, UploadStatus, UploadProgressEvent } from './types/uploadTypes'
import { ProcessingLog as Log, LogLevel } from './types/logTypes'
import { uploadService } from './services/uploadService'
import { uploadConfig } from './services/userContextService'
import { api, API_CONFIG, getAuthToken } from '@/shared/lib/api'
import { cachedRequest } from '@/shared/lib/requestCache'
import { waitForDocumentProcessing } from '@/shared/lib/waitForDocumentProcessing'
import { checkAnnualReportFromPDF } from '@/features/customer'
import type { Customer } from '@/entities/customer/model'
import type { Document } from '../../../types/documentStatus'
import { processAnnualReportFile, registerArDocument, formatIssueDateKorean, clearDuplicateCheckCache, prefetchCustomerData, precomputeFileHashes } from './utils/annualReportProcessor'
import { processCustomerReviewFile, formatIssueDateKorean as formatIssueDateKoreanCR } from './utils/customerReviewProcessor'
import { CustomerSelectionModal, NewCustomerInputModal } from '@/features/annual-report'
import { AnnualReportApi } from '@/features/customer'
import CustomerService from '@/services/customerService'
import { getMyStorageInfo, type StorageInfo } from '@/services/userService'
import {
  validateFile,
  checkStorageWithInfo,
  getCustomerFileHashes,
  checkDuplicateFile,
  checkSystemDuplicate,
  type ExistingFileHash,
} from '@/shared/lib/fileValidation'
import { StorageExceededDialog, DuplicateDialog, type DuplicateAction, type DuplicateFile } from '@/features/batch-upload'
import { errorReporter } from '@/shared/lib/errorReporter'
import { autoClassifyDocument } from '@/services/documentTypesService'
import { useArBatchAnalysis } from './hooks/useArBatchAnalysis'
import { useCrBatchAnalysis } from './hooks/useCrBatchAnalysis'
import { BatchArMappingModal } from './components/BatchArMappingModal'
import { BatchCrMappingModal } from './components/BatchCrMappingModal'
import { getEffectiveMapping } from './utils/arGroupingUtils'
import { getEffectiveMapping as getCrEffectiveMapping } from './utils/crGroupingUtils'
import { BatchUploadApi } from '@/features/batch-upload'
import type { ArFileTableRow } from './types/arBatchTypes'
import type { CrFileTableRow } from './types/crBatchTypes'
import { getBatchId, setBatchId, addBatchExpectedTotal, useBatchId } from '@/hooks/useBatchId'
import { useDocumentStatistics } from '@/hooks/useDocumentStatistics'
import { DocumentProcessingStatusBar } from '../DocumentLibraryView/DocumentProcessingStatusBar'
import './DocumentRegistrationView.css'
import './DocumentRegistrationView.mobile.css'

interface DocumentRegistrationViewProps {
  /** View 표시 여부 */
  visible: boolean
  /** View 닫기 핸들러 */
  onClose: () => void
}

/**
 * DocumentRegistrationView React 컴포넌트
 *
 * 애플 스타일의 문서 업로드 시스템
 * - 드래그앤드롭 파일 선택
 * - 실시간 업로드 진행률
 * - 에러 처리 및 재시도
 * - 사용자별 업로드 지원 (미래 확장)
 *
 * @example
 * ```tsx
 * <DocumentRegistrationView
 *   visible={isVisible}
 *   onClose={handleClose}
 * />
 * ```
 */
export const DocumentRegistrationView: React.FC<DocumentRegistrationViewProps> = ({
  visible,
  onClose
}) => {
  // 고객 파일 등록 상태
  const [customerFileCustomer, setCustomerFileCustomer] = useState<Customer | null>(null)
  // 고객 ID 변경 추적용 (이전 고객 ID)
  const prevCustomerIdRef = useRef<string | null>(null)

  // 🔴 현재 업로드 배치 ID (실시간 추적 - 파이프라인 처리 진행률 표시용)
  const currentBatchId = useBatchId()
  const { statistics: docStats, isLoading: statsLoading } = useDocumentStatistics({ enabled: visible })
  const { statistics: batchStats, isLoading: batchLoading } = useDocumentStatistics({
    enabled: visible && !!currentBatchId,
    batchId: currentBatchId
  })

  // 🍎 처리 로그 표시 상태 (업로드 시작 전에는 숨김)
  const [isLogVisible, setIsLogVisible] = useState<boolean>(false)

  // 🍎 AR/CRS 일괄등록 완료 후 네비게이션 버튼 표시
  const [showBatchCompletionNav, setShowBatchCompletionNav] = useState(false)

  // 🍎 도움말 모달 상태
  const [helpModalVisible, setHelpModalVisible] = useState(false)

  // 🍎 스토리지 용량 초과 다이얼로그 상태
  const [storageInfo, setStorageInfo] = useState<StorageInfo | null>(null)
  const [showStorageExceededDialog, setShowStorageExceededDialog] = useState(false)
  const [storageExceededInfo, setStorageExceededInfo] = useState<{
    selectedFilesSize: number
    selectedFilesCount: number
    partialUploadInfo: { fileCount: number; totalSize: number } | null
  } | null>(null)
  const [pendingFilesForUpload, setPendingFilesForUpload] = useState<File[]>([])

  // 🔴 중복 파일 처리 다이얼로그 상태
  const [showDuplicateDialog, setShowDuplicateDialog] = useState(false)
  const [currentDuplicateFile, setCurrentDuplicateFile] = useState<DuplicateFile | null>(null)
  const duplicateResolverRef = useRef<((action: DuplicateAction) => void) | null>(null)
  const duplicateApplyAllRef = useRef<{ action: DuplicateAction } | null>(null)

  // 🎯 AR 고객 선택 모달 상태
  const [arCustomerSelectionState, setArCustomerSelectionState] = useState<{
    isOpen: boolean
    arFile: File | null
    arMetadata: { customer_name: string; issue_date: string } | null
    matchingCustomers: Customer[]
    fileId: string
    existingHashes: ExistingFileHash[]
    newlyCreatedCustomerId: string | null
  }>({
    isOpen: false,
    arFile: null,
    arMetadata: null,
    matchingCustomers: [],
    fileId: '',
    existingHashes: [],
    newlyCreatedCustomerId: null
  })
  const [showNewCustomerModal, setShowNewCustomerModal] = useState(false)

  // 🎯 AR 파일 미발견 경고 메시지 (3초 후 자동 사라짐)
  const [noArFoundWarning, setNoArFoundWarning] = useState<string | null>(null)

  // 🎯 CRS 파일 미발견 경고 메시지 (3초 후 자동 사라짐)
  const [noCrFoundWarning, setNoCrFoundWarning] = useState<string | null>(null)

  // 경고 메시지 자동 사라짐 타이머 (AR)
  useEffect(() => {
    if (noArFoundWarning) {
      const timer = setTimeout(() => {
        setNoArFoundWarning(null)
      }, 3000) // 3초 후 사라짐
      return () => clearTimeout(timer)
    }
    return undefined
  }, [noArFoundWarning])

  // 경고 메시지 자동 사라짐 타이머 (CRS)
  useEffect(() => {
    if (noCrFoundWarning) {
      const timer = setTimeout(() => {
        setNoCrFoundWarning(null)
      }, 3000) // 3초 후 사라짐
      return () => clearTimeout(timer)
    }
    return undefined
  }, [noCrFoundWarning])

  // 🎯 AR 파일 큐 - 다중 AR 파일 순차 처리용
  // 문제: 여러 AR 파일 업로드 시 두 번째 파일이 첫 번째를 덮어씀
  // 해결: 큐에 저장 후 한 파일씩 순차 처리
  interface PendingArFile {
    file: File
    arMetadata: { customer_name: string; issue_date: string }
    matchingCustomers: Customer[]
    fileId: string
    existingHashes: ExistingFileHash[]
  }
  const pendingArFilesQueueRef = useRef<PendingArFile[]>([])

  // 🎯 CRS 고객 선택 모달 상태 (AR과 동일한 패턴)
  const [crCustomerSelectionState, setCrCustomerSelectionState] = useState<{
    isOpen: boolean
    crFile: File | null
    crMetadata: { customer_name?: string; product_name?: string; issue_date?: string; contractor_name?: string; insured_name?: string; fsr_name?: string; policy_number?: string } | null
    matchingCustomers: Customer[]
    fileId: string
    existingHashes: ExistingFileHash[]
  }>({
    isOpen: false,
    crFile: null,
    crMetadata: null,
    matchingCustomers: [],
    fileId: '',
    existingHashes: []
  })
  const [showNewCustomerModalForCR, setShowNewCustomerModalForCR] = useState(false)

  // 🎯 AR 일괄 매핑용 새 고객 등록 모달 상태
  const [batchNewCustomerModal, setBatchNewCustomerModal] = useState<{
    isOpen: boolean
    fileId: string | null  // '__BULK__'면 일괄 매핑, 아니면 개별 파일
    defaultName: string
  }>({ isOpen: false, fileId: null, defaultName: '' })

  // 🎯 CRS 일괄 매핑용 새 고객 등록 모달 상태
  const [crBatchNewCustomerModal, setCrBatchNewCustomerModal] = useState<{
    isOpen: boolean
    fileId: string | null  // '__BULK__'면 일괄 매핑, 아니면 개별 파일
    defaultName: string
  }>({ isOpen: false, fileId: null, defaultName: '' })

  // 🎯 문서 유형 선택 상태 (AR/CRS는 고객 선택 불필요 - 업로드 후 모달로 선택)
  type DocumentTypeMode = 'normal' | 'annual_report' | 'customer_review' | null
  const [documentTypeMode, setDocumentTypeMode] = useState<DocumentTypeMode>(null)

  // UI 상태 (localStorage에서 복원)
  const [isGuideExpanded, setIsGuideExpanded] = useState(() => {
    const saved = localStorage.getItem('doc-reg-guide-expanded')
    return saved === null ? true : saved === 'true' // 기본값: 펼친 상태
  })

  // 가이드 접기/펼치기 토글
  const toggleGuide = useCallback(() => {
    setIsGuideExpanded(prev => {
      const newValue = !prev
      localStorage.setItem('doc-reg-guide-expanded', String(newValue))
      return newValue
    })
  }, [])

  // SessionStorage 키
  const SESSION_KEY = 'document-upload-state'

  // 초기 상태 복원 또는 기본값
  const getInitialState = (): UploadState => {
    try {
      const saved = sessionStorage.getItem(SESSION_KEY)
      if (saved) {
        const parsed = JSON.parse(saved) as StoredUploadState
        const restoredFiles: UploadFile[] = parsed.files?.map((savedFile) => {
          // 더미 File 객체 생성 (실제 파일은 복원 불가)
          const dummyFile = new File(
            [''], // 빈 내용
            savedFile.fileInfo?.name ?? 'unknown',
            {
              type: savedFile.fileInfo?.type ?? 'application/octet-stream',
              lastModified: savedFile.fileInfo?.lastModified ?? Date.now()
            }
          )

          // 실제 업로드 프로세스(XHR)는 리마운트 시 소멸하므로
          // 'uploading' 상태 파일은 중단된 것으로 처리
          const wasUploading = savedFile.status === 'uploading' || savedFile.status === 'pending'

          return {
            id: savedFile.id,
            file: dummyFile,
            fileSize: savedFile.fileSize ?? savedFile.fileInfo?.size ?? 0,
            status: wasUploading ? 'error' as const : savedFile.status,
            progress: wasUploading ? 0 : savedFile.progress,
            error: wasUploading ? '업로드가 중단되었습니다 (페이지 새로고침)' : savedFile.error,
            completedAt: savedFile.completedAt ? new Date(savedFile.completedAt) : undefined,
          }
        }) ?? []

        return {
          ...parsed,
          files: restoredFiles,
          uploading: false // 실제 업로드 프로세스는 리마운트 시 소멸 — 항상 false
        }
      }
    } catch (error) {
      console.warn('[DocumentRegistrationView] Failed to restore state:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.restoreState' })
    }

    return {
      files: [],
      uploading: false,
      totalProgress: 0,
      completedCount: 0,
      errors: [],
      context: {
        identifierType: 'userId',
        identifierValue: typeof window !== 'undefined' ? localStorage.getItem('aims-current-user-id') || 'tester' : 'tester'
      }
    }
  }

  // 업로드 상태 관리
  const [uploadState, setUploadState] = useState<UploadState>(getInitialState)


  // 🏷️ AR 파일명 추적 (업로드 완료 후 DB 플래그 설정용)
  const arFilenamesRef = useRef<Set<string>>(new Set())

  // 🔗 AR 파일명 → 고객 ID 매핑 (자동 연결용)
  const arCustomerMappingRef = useRef<Map<string, string>>(new Map())

  // 📝 AR 파일명 → metadata 매핑 (발행일 등 DB 저장용)
  const arMetadataMappingRef = useRef<Map<string, { issue_date?: string; report_title?: string }>>(new Map())

  // 🔗 AR 문서 ID → 고객 ID 매핑 (더 확실한 연결용)
  const arDocumentCustomerMappingRef = useRef<Map<string, string>>(new Map())

  // 👤 고객 ID → 고객명 매핑 (로그 표시용)
  const customerNameMappingRef = useRef<Map<string, string>>(new Map())

  // 📊 AR 처리 성공 카운터 (중복 건너뛴 건 제외)
  const arProcessedCountRef = useRef<number>(0)

  // 🚀 진행률 스로틀: 파일당 최소 300ms 간격으로만 UI 업데이트
  const progressThrottleRef = useRef<Map<string, number>>(new Map())

  // 🚀 로그 배치 버퍼: 대량 등록 시 addLog 호출마다 배열 복사 방지
  const pendingLogsRef = useRef<Log[]>([])
  const logFlushTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // 🏷️ CRS 파일명 추적 (업로드 완료 후 DB 플래그 설정용)
  const crFilenamesRef = useRef<Set<string>>(new Set())

  // 🔗 CRS 파일명 → 고객 ID 매핑 (자동 연결용)
  const crCustomerMappingRef = useRef<Map<string, string>>(new Map())

  // 📝 CRS 파일명 → metadata 매핑 (발행일 등 DB 저장용)
  const crMetadataMappingRef = useRef<Map<string, { product_name?: string; issue_date?: string; contractor_name?: string; insured_name?: string; fsr_name?: string; policy_number?: string }>>(new Map())

  // 📄 일반 문서 파일명 → 문서 ID 매핑 (백그라운드 처리 완료 확인용)
  const normalDocumentMappingRef = useRef<Map<string, string>>(new Map())

  // 🔗 고객 파일 등록 탭에서 업로드된 파일 추적 (파일명 → 고객 정보 매핑)
  const customerFileUploadMappingRef = useRef<Map<string, {
    customerId: string
    customerName: string
    documentType: string
  }>>(new Map())

  // 📝 처리 로그 상태 (sessionStorage에서 복원)
  const getInitialLogs = (): Log[] => {
    try {
      const LOGS_KEY = 'document-upload-logs'
      const saved = sessionStorage.getItem(LOGS_KEY)
      if (saved) {
        const parsed = JSON.parse(saved) as Log[]
        // timestamp를 Date 객체로 변환
        return parsed.map(log => ({
          ...log,
          timestamp: new Date(log.timestamp)
        }))
      }
    } catch (error) {
      console.warn('[DocumentRegistrationView] Failed to restore logs:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.restoreLogs' })
    }
    return []
  }

  const [processingLogs, setProcessingLogs] = useState<Log[]>(getInitialLogs)
  const logCounterRef = useRef(0) // 로그 카운터 (고유 ID 보장)

  /**
   * 로그 추가 헬퍼 함수
   * 고객명이 지정되면 메시지 앞에 [고객명]을 자동으로 추가
   *
   * @param level - 로그 레벨
   * @param message - 로그 메시지
   * @param details - 상세 정보 (선택)
   * @param customerName - 고객명 (선택)
   */
  // 로그 버퍼 플러시: 버퍼에 쌓인 로그를 한 번에 state에 반영
  const flushPendingLogs = useCallback(() => {
    if (pendingLogsRef.current.length === 0) return
    const batch = pendingLogsRef.current.splice(0)
    // 최신 로그가 앞에 오도록 reverse
    setProcessingLogs(prev => [...batch.reverse(), ...prev])
  }, [])

  const addLog = useCallback((level: LogLevel, message: string, details?: string, customerName?: string) => {
    logCounterRef.current += 1
    const counter = logCounterRef.current

    // 고객명이 있으면 메시지 앞에 [고객명] 추가
    const finalMessage = customerName ? `[${customerName}] ${message}` : message

    // 🔒 보안: crypto.randomUUID 사용 (Math.random은 예측 가능)
    const newLog: Log = {
      id: `log_${Date.now()}_${counter}_${crypto.randomUUID().slice(0, 8)}`,
      timestamp: new Date(),
      level,
      message: finalMessage,
      details
    }

    // 버퍼에 추가, 20개마다 즉시 플러시 (대량 등록 시 배열 복사 횟수 20배 감소)
    pendingLogsRef.current.push(newLog)
    if (pendingLogsRef.current.length >= 20) {
      flushPendingLogs()
      return
    }

    // 소량 호출 시 100ms 후 자동 플러시 (일반 사용 시 즉각적 피드백)
    if (logFlushTimerRef.current) clearTimeout(logFlushTimerRef.current)
    logFlushTimerRef.current = setTimeout(flushPendingLogs, 100)
  }, [flushPendingLogs])

  // 🎯 AR 일괄 처리 훅
  const currentUserId = localStorage.getItem('aims-current-user-id') || 'tester'
  const arBatch = useArBatchAnalysis({
    userId: currentUserId,
    addLog: (type, message, detail) => {
      addLog(type as LogLevel, message, detail)
    },
  })

  // 🎯 CRS 일괄 처리 훅
  const crBatch = useCrBatchAnalysis({
    userId: currentUserId,
    addLog: (type, message, detail) => {
      addLog(type as LogLevel, message, detail)
    },
  })

  /**
   * 상태를 sessionStorage에 저장
   */
  useEffect(() => {
    try {
      // File 객체는 직렬화할 수 없으므로 파일 정보만 저장
      const stateToSave = {
        ...uploadState,
        files: uploadState.files.map(file => ({
          id: file.id,
          status: file.status,
          progress: file.progress,
          error: file.error,
          completedAt: file.completedAt,
          // File 객체 정보만 저장 (실제 File 객체는 저장 불가)
          fileInfo: {
            name: file.file.name,
            size: file.fileSize,
            type: file.file.type,
            lastModified: file.file.lastModified
          }
        }))
      }
      sessionStorage.setItem(SESSION_KEY, JSON.stringify(stateToSave))
    } catch (error) {
      console.warn('[DocumentRegistrationView] Failed to save state:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.saveState' })
    }
  }, [uploadState, SESSION_KEY])

  /**
   * 처리 로그를 sessionStorage에 저장
   */
  useEffect(() => {
    try {
      const LOGS_KEY = 'document-upload-logs'
      sessionStorage.setItem(LOGS_KEY, JSON.stringify(processingLogs))
    } catch (error) {
      console.warn('[DocumentRegistrationView] Failed to save logs:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.saveLogs' })
    }
  }, [processingLogs])

  /**
   * 고유 ID 생성
   * 🔒 보안: crypto.randomUUID 사용 (Math.random은 예측 가능)
   */
  const generateFileId = useCallback((): string => {
    return `file_${Date.now()}_${crypto.randomUUID().slice(0, 8)}`
  }, [])

  /**
   * 🔴 중복 파일 처리 다이얼로그 핸들러
   */
  const handleDuplicateAction = useCallback((action: DuplicateAction, applyToAll: boolean) => {
    if (applyToAll) {
      duplicateApplyAllRef.current = { action }
    }
    if (duplicateResolverRef.current) {
      duplicateResolverRef.current(action)
      duplicateResolverRef.current = null
    }
    setShowDuplicateDialog(false)
    setCurrentDuplicateFile(null)
  }, [])

  /**
   * 🔴 중복 파일 처리 다이얼로그 취소 핸들러
   */
  const handleDuplicateCancel = useCallback(() => {
    // 🔴 resolver가 있으면 반드시 resolve하여 Promise 해소 (무한 대기 방지)
    if (duplicateResolverRef.current) {
      duplicateResolverRef.current('skip' as DuplicateAction)
      duplicateResolverRef.current = null
    }
    duplicateApplyAllRef.current = null
    setShowDuplicateDialog(false)
    setCurrentDuplicateFile(null)
  }, [])

  /**
   * 🔴 중복 파일 발견 시 다이얼로그 표시 및 사용자 액션 대기
   */
  const promptDuplicateAction = useCallback((
    file: File,
    existingDoc: { uploadedAt?: string; size?: number },
    customerName: string
  ): Promise<DuplicateAction | 'cancel'> => {
    return new Promise((resolve) => {
      // 이미 일괄 적용 설정이 있으면 바로 반환
      if (duplicateApplyAllRef.current) {
        resolve(duplicateApplyAllRef.current.action)
        return
      }

      const duplicateFile: DuplicateFile = {
        fileName: file.name,
        folderName: '',
        customerName,
        existingFileDate: existingDoc.uploadedAt
          ? new Date(existingDoc.uploadedAt).toLocaleString('ko-KR')
          : undefined,
        newFileSize: file.size,
        existingFileSize: existingDoc.size
      }

      setCurrentDuplicateFile(duplicateFile)
      setShowDuplicateDialog(true)

      duplicateResolverRef.current = (action: DuplicateAction) => {
        resolve(action)
      }
    })
  }, [])

  /**
   * 🔄 컴포넌트 레벨 파일 상태 업데이트 (AR 핸들러용)
   */
  const updateFileStatusByFile = useCallback((file: File, status: UploadStatus, error?: string) => {
    setUploadState(prev => ({
      ...prev,
      files: prev.files.map(f =>
        f.file.name === file.name && f.file.size === file.size
          ? { ...f, status, error }
          : f
      )
    }));
  }, []);

  /**
   * 파일 선택 핸들러
   */
  const handleFilesSelected = useCallback(async (files: File[]) => {

    // 🧹 새 업로드 시작 시 기존 로그 클리어
    setProcessingLogs([])
    logCounterRef.current = 0
    setShowBatchCompletionNav(false)

    // 🔴 중복 처리 일괄 적용 설정 초기화
    duplicateApplyAllRef.current = null

    // 🔴 업로드 묶음 ID: 활성 배치가 있으면 재사용 (AR 처리중 CRS 업로드 시 누적 표시)
    // 항상 setBatchId 호출 → StatusBar의 cleanup 타이머를 취소하여 경쟁 조건 방지
    const existingBatchId = getBatchId()
    const newBatchId = existingBatchId || `batch_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`
    setBatchId(newBatchId)
    // 🔴 업로드 예정 파일 수 등록 — 서버 total이 이 수에 도달하기 전까지 프로그레스바 cleanup 차단
    addBatchExpectedTotal(files.length)
    if (import.meta.env.DEV) {
      console.log(`[DocumentRegistrationView] 배치 ID: ${newBatchId}${existingBatchId ? ' (기존 재사용)' : ' (신규)'}, 파일 수: ${files.length}`)
    }

    // 🎯🎯🎯 AR 배치 모드: 제일 먼저 체크! (uploadState 건드리기 전에 처리)
    // 이유: setUploadState → useEffect → uploadService.queueFiles 자동 호출 방지
    if (documentTypeMode === 'annual_report') {
      // 🔴🔴🔴 자동 업로드 완전 차단!
      // 1. uploadState.files를 빈 배열로 설정 (이전 파일 제거)
      // 2. uploadService 큐 취소 (혹시 큐에 있던 파일도 취소)
      setUploadState(prev => ({ ...prev, files: [] }))
      uploadService.cancelAllUploads()

      // PDF 파일만 필터링
      const pdfFiles = files.filter(f => f.type === 'application/pdf')

      if (pdfFiles.length === 0) {
        addLog('warning', 'PDF 파일이 없습니다', 'Annual Report는 PDF 파일만 지원합니다.')
        return
      }

      if (pdfFiles.length < files.length) {
        const nonPdfCount = files.length - pdfFiles.length
        addLog('warning', `${nonPdfCount}개 파일 제외`, 'PDF가 아닌 파일은 AR 등록에서 제외됩니다.')
      }

      // 배치 분석 시작 (모달이 자동으로 열림)
      addLog('info', `${pdfFiles.length}개 AR 파일 배치 분석 시작...`)
      setNoArFoundWarning(null) // 이전 경고 초기화
      const arAnalysisResult = await arBatch.analyzeArFiles(pdfFiles)

      // AR 파일이 하나도 발견되지 않은 경우
      if (!arAnalysisResult) {
        setNoArFoundWarning('Annual Report가 아닙니다.')
        return
      }

      return // 이후 처리는 BatchArMappingModal에서 진행
    }

    // 🎯🎯🎯 CRS 배치 모드: AR과 동일한 패턴
    if (documentTypeMode === 'customer_review') {
      // 🔴🔴🔴 자동 업로드 완전 차단!
      setUploadState(prev => ({ ...prev, files: [] }))
      uploadService.cancelAllUploads()

      // PDF 파일만 필터링
      const pdfFiles = files.filter(f => f.type === 'application/pdf')

      if (pdfFiles.length === 0) {
        addLog('warning', 'PDF 파일이 없습니다', 'Customer Review는 PDF 파일만 지원합니다.')
        return
      }

      if (pdfFiles.length < files.length) {
        const nonPdfCount = files.length - pdfFiles.length
        addLog('warning', `${nonPdfCount}개 파일 제외`, 'PDF가 아닌 파일은 CRS 등록에서 제외됩니다.')
      }

      // 배치 분석 시작 (모달이 자동으로 열림)
      addLog('info', `${pdfFiles.length}개 CRS 파일 배치 분석 시작...`)
      const crAnalysisResult = await crBatch.analyzeCrFiles(pdfFiles)

      // CRS 파일이 하나도 발견되지 않은 경우
      if (!crAnalysisResult) {
        setNoCrFoundWarning('Customer Review가 아닙니다.')
        return
      }

      return // 이후 처리는 BatchCrMappingModal에서 진행
    }

    // 🚀 [UX 개선] 파일 선택 즉시 목록 표시 (analyzing 상태) - AR/CRS 모드 아닐 때만!
    const initialUploadFiles: UploadFile[] = files.map(file => ({
      id: generateFileId(),
      file,
      fileSize: file.size,
      status: 'analyzing' as const,
      progress: 0,
      error: undefined,
      completedAt: undefined,
      batchId: newBatchId  // 🔴 업로드 묶음 ID 추가
    }))

    // 즉시 UI 업데이트 - 파일 목록 표시
    setUploadState(prev => ({
      ...prev,
      files: initialUploadFiles
    }))
    setIsLogVisible(true)
    addLog('info', `${files.length}개 파일 분석 시작...`)

    // 🍎 스토리지 용량 체크 (공통 모듈 사용)
    try {
      const storage = await getMyStorageInfo()
      console.log('[DocumentRegistration] Storage info:', storage)
      setStorageInfo(storage)

      // 공통 모듈로 스토리지 검사
      const storageCheck = checkStorageWithInfo(files, storage)

      // 용량 초과 시 다이얼로그 표시
      if (!storageCheck.canUpload) {
        console.log('[DocumentRegistration] Storage exceeded, showing dialog')

        // 파일 목록 초기화 (다이얼로그 표시 전)
        setUploadState(prev => ({ ...prev, files: [] }))
        setIsLogVisible(false)

        // 다이얼로그 상태 설정
        setPendingFilesForUpload(files)
        setStorageExceededInfo({
          selectedFilesSize: storageCheck.requestedBytes,
          selectedFilesCount: files.length,
          partialUploadInfo: storageCheck.partialUploadInfo
            ? { fileCount: storageCheck.partialUploadInfo.fileCount, totalSize: storageCheck.partialUploadInfo.totalSize }
            : null
        })
        setShowStorageExceededDialog(true)
        return // 업로드 진행하지 않음
      }
    } catch (error) {
      console.error('스토리지 정보 조회 실패:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.handleFilesSelected.getStorage' })
      // 에러 시에도 정상 진행 (서버에서 최종 검증)
    }

    // 🔴 중복 파일 검사 (고객이 선택된 경우에만)
    let existingHashes: ExistingFileHash[] = []
    if (customerFileCustomer) {
      try {
        console.log('[DocumentRegistration] 🔍 중복 파일 검사 시작:', customerFileCustomer._id)
        existingHashes = await getCustomerFileHashes(customerFileCustomer._id)
        console.log('[DocumentRegistration] 기존 파일 해시 조회 완료:', existingHashes.length, '개')
      } catch (error) {
        console.error('[DocumentRegistration] 중복 검사용 해시 조회 실패:', error)
        errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.handleFilesSelected.getHashes' })
        // 에러 시에도 정상 진행 (중복 검사 건너뜀)
      }
    }

    // 🔄 파일 ID 매핑 (초기 파일 → 분석 후 상태 업데이트용)
    const fileIdMap = new Map<File, string>()
    initialUploadFiles.forEach(uf => fileIdMap.set(uf.file, uf.id))

    const newUploadFiles: UploadFile[] = []
    const systemFileNames: string[] = []

    // 🔄 개별 파일 상태 업데이트 헬퍼
    const updateFileStatus = (file: File, status: UploadStatus, error?: string) => {
      const fileId = fileIdMap.get(file)
      if (fileId) {
        setUploadState(prev => ({
          ...prev,
          files: prev.files.map(f => f.id === fileId ? { ...f, status, error } : f)
        }))
      }
    }

    // 🔍 PDF 파일 중 Annual Report 체크 (파일 선택 직후, 업로드 전!)
    for (const file of files) {
      const fileId = fileIdMap.get(file) || generateFileId()

      // 파일 검증 (공통 모듈 사용: 확장자, 크기, MIME 검증)
      const validation = validateFile(file)

      if (validation.valid) {
        // 🔴🔴🔴 해당 고객에게 해시 중복 검사 (일반 문서일 때만! AR/CRS는 고객 결정 후 체크) 🔴🔴🔴
        // AR/CRS 탭에서는 시스템 중복 체크 건너뜀 - 고객이 결정된 후에 해당 고객 문서로 중복 체크함
        if (documentTypeMode === 'normal') {
          try {
            const systemDupResult = await checkSystemDuplicate(file, customerFileCustomer?._id)
            if (systemDupResult.isDuplicate && systemDupResult.existingDocument) {
              const existingInfo = systemDupResult.existingDocument
              const customerInfo = existingInfo.customerName
                ? `"${existingInfo.customerName}" 고객에게`
                : '시스템에'

              addLog(
                'info',
                `⊘ 중복 파일 건너뜀: ${file.name}`,
                `이미 ${customerInfo} 동일한 파일이 등록되어 있습니다. (${existingInfo.fileName})`
              )
              console.warn(`[DocumentRegistration] 시스템 해시 중복 건너뜀: ${file.name} (기존: ${existingInfo.fileName})`)
              updateFileStatus(file, 'skipped', `중복 파일 - 이미 ${customerInfo} 등록됨`)
              continue
            }
          } catch (error) {
            console.error('[DocumentRegistration] 시스템 해시 중복 검사 실패:', error)
            // 검사 실패 시 업로드 계속 진행 (백엔드에서 최종 차단)
          }
        }

        // PDF 파일이면 Annual Report 체크
        if (file.type === 'application/pdf') {
          try {
            addLog('info', `[1/4] PDF 분석 중: ${file.name}`)
            console.log('[DocumentRegistrationView] 🔍 PDF 파일 감지, Annual Report 체크:', file.name);
            const checkResult = await checkAnnualReportFromPDF(file);

            if (checkResult.is_annual_report) {
              console.log('[DocumentRegistrationView] ✅ Annual Report 감지!', checkResult.metadata);

              // 🎯 AR 고객 매칭 플로우
              let targetCustomerId: string;
              let targetCustomerName: string;

              if (customerFileCustomer) {
                // 사전 선택된 고객이 있으면 그대로 사용
                targetCustomerId = customerFileCustomer._id;
                targetCustomerName = customerFileCustomer.personal_info?.name || '알 수 없음';
              } else {
                // 사전 선택된 고객이 없으면 AR 메타데이터에서 고객명 추출 후 검색
                const arCustomerName = checkResult.metadata?.customer_name;

                if (!arCustomerName) {
                  addLog('warning', `AR 문서 감지됨: ${file.name}`, '고객명을 추출할 수 없습니다. 고객을 먼저 선택해주세요');
                  updateFileStatus(file, 'error', '고객명 추출 실패');
                  continue;
                }

                addLog('info', `[2/5] AR 고객 검색 중: "${arCustomerName}"`);

                // 고객명으로 부분 일치 검색
                const currentUserId = localStorage.getItem('aims-current-user-id') || 'tester';
                const matchingCustomers = await AnnualReportApi.searchCustomersByName(arCustomerName, currentUserId);

                if (matchingCustomers.length === 0) {
                  // Case 1: 유사 이름 고객 0명 → 자동 등록
                  addLog('info', `[3/5] 유사 고객 없음 → "${arCustomerName}" 자동 등록`);

                  try {
                    const newCustomer = await CustomerService.createCustomer({
                      personal_info: { name: arCustomerName },
                      insurance_info: { customer_type: '개인' },
                      contracts: [],
                      documents: [],
                      consultations: [],
                    });

                    targetCustomerId = newCustomer._id;
                    targetCustomerName = arCustomerName;

                    addLog('success', `[3/5] 새 고객 등록 완료: ${arCustomerName}`);
                  } catch (error) {
                    console.error('[DocumentRegistrationView] 고객 자동 등록 실패:', error);
                    addLog('error', `고객 등록 실패: ${file.name}`, String(error));
                    updateFileStatus(file, 'error', '고객 등록 실패');
                    continue;
                  }
                } else {
                  // Case 2: 유사 이름 고객 1명 이상 → 큐에 추가 후 순차 처리
                  addLog('info', `[3/5] ${matchingCustomers.length}명의 유사 고객 발견 → 선택 필요`);

                  // 🎯 AR 파일을 큐에 추가 (다중 파일 순차 처리)
                  const pendingArFile: PendingArFile = {
                    file,
                    arMetadata: {
                      customer_name: arCustomerName,
                      issue_date: checkResult.metadata?.issue_date || '',
                    },
                    matchingCustomers,
                    fileId,
                    existingHashes,
                  };
                  pendingArFilesQueueRef.current.push(pendingArFile);

                  // 현재 파일은 큐에서 순차 처리될 예정
                  updateFileStatus(file, 'pending', '고객 선택 대기 중');
                  continue;
                }
              }

              const customerId = targetCustomerId;
              const customerName = targetCustomerName;

              // 중복 문서 체크 (해시 + 발행일)
              const processResult = await processAnnualReportFile(file, customerId, checkResult.metadata?.issue_date);
              if (processResult.isDuplicateDoc) {
                addLog(
                  'warning',
                  `🔴 중복 파일 건너뜀: ${file.name}`,
                  `이미 등록된 파일입니다. 업로드를 건너뜁니다.`
                );
                updateFileStatus(file, 'skipped', '중복 파일 - 이미 등록됨')
                continue;
              }
              if (processResult.isDuplicateIssueDate) {
                const formattedDate = formatIssueDateKorean(processResult.duplicateIssueDate);
                addLog(
                  'warning',
                  `🔴 ${formattedDate} 발행일 보고서 이미 존재`,
                  `${file.name} 업로드를 건너뜁니다.`
                );
                updateFileStatus(file, 'skipped', `${formattedDate} 발행일 보고서 이미 존재`)
                continue;
              }

              addLog('success', `[1/4] PDF 분석 완료: ${file.name}`)
              addLog(
                'ar-detect',
                `[2/5] Annual Report 감지`,
                `사전 선택된 고객: ${customerName} → AR 전용 처리로 전환`
              )

              addLog(
                'ar-auto',
                `AR 자동 등록: ${file.name}`,
                `사전 선택된 고객: ${customerName}`
              );

              // ✅ 사전 선택된 고객으로 AR 등록
              const result = await registerArDocument(file, customerId, checkResult.metadata?.issue_date, {
                addLog,
                generateFileId: () => fileId, // 기존 ID 유지
                addToUploadQueue: (uploadFile) => {
                  // 기존 파일의 상태를 pending으로 업데이트
                  updateFileStatus(file, 'pending')
                  newUploadFiles.push({ ...uploadFile, id: fileId, batchId: newBatchId });
                },
                trackArFile: (fileName, custId) => {
                  arFilenamesRef.current.add(fileName);
                  arCustomerMappingRef.current.set(fileName, custId);
                  if (checkResult.metadata) {
                    arMetadataMappingRef.current.set(fileName, checkResult.metadata);
                  }
                  // 고객명 매핑 저장 (자동 연결 로그에서 사용)
                  customerNameMappingRef.current.set(custId, customerName);
                }
              });

              if (result.success) {
                console.log('[DocumentRegistrationView] AR 문서 등록 성공:', file.name);
                arProcessedCountRef.current += 1;
              }

              continue;
            } else {
              // 🔴 CRS 개별 처리는 이제 배치 처리(BatchCrMappingModal)로 대체됨
              // documentTypeMode === 'customer_review'는 handleFilesSelected 초반에서 return됨
              // AR 탭에서 업로드했지만 AR이 아닌 경우 - 일반 문서로 처리
              addLog('info', `[1/4] PDF 분석 완료: ${file.name}`, 'Annual Report 아님 - 일반 문서로 처리');
            }
          } catch (error) {
            console.error('[DocumentRegistrationView] Annual Report 체크 실패:', error);
            errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.handleFilesSelected.arCheck', payload: { fileName: file.name } })
            addLog('warning', `PDF 분석 실패: ${file.name}`, error instanceof Error ? error.message : String(error))
            // 체크 실패 시 일반 문서로 처리
          }
        } else {
          // 이미지 등 PDF가 아닌 일반 파일
          addLog('info', `[1/4] 일반 파일 감지: ${file.name}`, file.type || '알 수 없는 형식')
        }

        // 🔴 중복 파일 검사 (일반 문서용) - 모달로 사용자에게 선택권 제공
        if (existingHashes.length > 0 && customerFileCustomer) {
          try {
            const duplicateResult = await checkDuplicateFile(file, existingHashes)
            if (duplicateResult.isDuplicate && duplicateResult.existingDoc) {
              const customerName = customerFileCustomer.personal_info?.name || '알 수 없음'

              // 🔴 중복 파일 발견 — DuplicateDialog로 사용자에게 선택권 제공 (일괄등록과 동일)
              const duplicateAction = await promptDuplicateAction(
                file,
                { uploadedAt: duplicateResult.existingDoc.uploadedAt, size: duplicateResult.existingDoc.fileSize },
                customerName
              )

              if (duplicateAction === 'skip' || duplicateAction === 'cancel') {
                addLog(
                  'info',
                  `⊘ 중복 파일 건너뜀: ${file.name}`,
                  `"${customerName}" 고객에게 이미 동일한 파일이 등록되어 있습니다.`
                )
                updateFileStatus(file, 'skipped', `중복 파일 - "${customerName}" 고객에게 이미 등록됨`)
                continue
              }
            }
          } catch (error) {
            console.error('[DocumentRegistration] 중복 검사 실패:', error)
            errorReporter.reportApiError(error as Error, { component: 'DocumentRegistrationView.handleFilesSelected.duplicateCheck' })
            // 중복 검사 실패 시에도 업로드 진행
          }
        }

        // 일반 문서 또는 Annual Report가 아닌 PDF - 상태를 pending으로 업데이트
        updateFileStatus(file, 'pending')
        newUploadFiles.push({
          id: fileId,
          file,
          fileSize: file.size,
          status: 'pending',
          progress: 0,
          error: undefined,
          completedAt: undefined,
          customerId: customerFileCustomer?._id,  // 🔗 고객 선택 시 자동 연결
          batchId: newBatchId  // 🔴 업로드 묶음 ID (진행률 추적용)
        })
      } else if (validation.reason === 'system_file') {
        // 시스템/임시 파일은 에러 목록에 넣지 않고 조용히 제외 + 경고 로그
        systemFileNames.push(file.name)
      } else {
        // 검증 실패한 파일은 에러로 표시 - 🔄 개별 파일 상태 업데이트
        updateFileStatus(file, 'error', validation.message || '파일 검증 실패')
        const errorFile: UploadFile = {
          id: fileId,
          file,
          fileSize: file.size,
          status: 'error',
          progress: 0,
          error: validation.message || '파일 검증 실패'
        }
        newUploadFiles.push(errorFile)
      }
    }

    // 시스템/임시 파일 제외 알림
    if (systemFileNames.length > 0) {
      addLog('warning', `편집 중 자동 생성된 파일 ${systemFileNames.length}개가 제외되었습니다`, systemFileNames.join(', '))
    }

    // 검증 실패한 파일 개수 확인 및 팝업 표시 (크기 초과, 차단 확장자, MIME 불일치 등)
    const invalidFiles = newUploadFiles.filter(f => f.status === 'error')

    if (invalidFiles.length > 0) {
      const invalidCount = invalidFiles.length

      // 🍎 애플 스타일 확인 모달 - 검증 실패 파일 안내
      const confirmed = await showAppleConfirm(
        `총 ${newUploadFiles.length}개의 파일 중 ${invalidCount}개의 파일이 검증에 실패했습니다 (차단된 확장자, 위조 파일 등). 해당 파일들은 업로드에서 제외됩니다.`,
        undefined, // 타이틀 없음
        {
          linkText: '검증 실패 파일들',
          onLinkClick: async () => {
            // 파일 정보를 올바른 형식으로 변환
            const fileList = invalidFiles.map((uploadFile: UploadFile) => ({
              name: uploadFile.file.name,
              size: uploadFile.fileSize
            }))

            // 검증 실패 파일 목록 모달 표시
            await showOversizedFilesModal(fileList, 0)

            // 링크 클릭 후에는 아무것도 하지 않음 (모달이 열린 상태 유지)
          },
          showConfirmButton: true // "취소" "확인" 두 버튼 유지
        }
      )

      if (!confirmed) {
        // 사용자가 취소하면 파일 목록 초기화
        setUploadState(prev => ({ ...prev, files: [] }))
        setIsLogVisible(false)
        return
      }
    }

    // 🔄 유효한 파일들만 업로드 큐에 추가 (상태는 이미 개별적으로 업데이트됨)
    const validFiles = newUploadFiles.filter(f => f.status === 'pending')
    if (validFiles.length > 0) {
      // Phase 3: 완료 추적 (await하면 AR큐 블로킹되므로 .then()으로 비동기 추적)
      uploadService.queueFiles(validFiles).then((results) => {
        const failCount = results.filter(r => !r.success).length
        if (failCount > 0) {
          addLog('warning', `일반 문서 업로드 완료: ${results.length - failCount}/${results.length} 성공`)
        }
      })
      addLog('info', `[2/4] 일반 문서 ${validFiles.length}개 업로드 시작`)

      // 🔗 고객이 선택되어 있으면 추적 목록에 추가 (업로드 후 자동 연결)
      // 문서유형은 자동 분류로 처리되므로 'unspecified'로 설정
      if (customerFileCustomer) {
        validFiles.forEach(f => {
          customerFileUploadMappingRef.current.set(f.file.name, {
            customerId: customerFileCustomer._id,
            customerName: customerFileCustomer.personal_info?.name || '이름 없음',
            documentType: 'unspecified'
          })
          console.log(`🔗 [고객 파일 자동 연결] 추적 추가: ${f.file.name} → 고객: ${customerFileCustomer.personal_info?.name}`)
        })
      }
    }

    // 🎯 AR 큐에 파일이 있으면 첫 번째 파일부터 순차 처리 시작
    if (pendingArFilesQueueRef.current.length > 0) {
      const firstArFile = pendingArFilesQueueRef.current.shift()!;
      console.log('[DocumentRegistrationView] 🎯 AR 큐 처리 시작:', firstArFile.file.name, '(대기:', pendingArFilesQueueRef.current.length, '개)');
      setArCustomerSelectionState({
        isOpen: true,
        arFile: firstArFile.file,
        arMetadata: firstArFile.arMetadata,
        matchingCustomers: firstArFile.matchingCustomers,
        fileId: firstArFile.fileId,
        existingHashes: firstArFile.existingHashes,
        newlyCreatedCustomerId: null,
      });
    }

  }, [generateFileId, addLog, customerFileCustomer, promptDuplicateAction, documentTypeMode, arBatch.analyzeArFiles])

  /**
   * 파일 재시도 핸들러
   */
  const handleRetryFile = useCallback((fileId: string) => {
    setUploadState(prev => ({
      ...prev,
      files: prev.files.map(f =>
        f.id === fileId
          ? { ...f, status: 'pending' as UploadStatus, progress: 0, error: undefined, completedAt: undefined }
          : f
      )
    }))

    const file = uploadState.files.find(f => f.id === fileId)
    if (file) {
      uploadService.queueFiles([{ ...file, status: 'pending', progress: 0, error: undefined, completedAt: undefined }])
    }
  }, [uploadState.files])

  /**
   * 전체 업로드 취소
   */
  const handleCancelAll = useCallback(() => {
    uploadService.cancelAllUploads()
    setUploadState(prev => ({
      ...prev,
      uploading: false,
      files: prev.files.map(f =>
        f.status === 'uploading' || f.status === 'pending'
          ? { ...f, status: 'cancelled' as UploadStatus }
          : f
      )
    }))
  }, [])

  /**
   * 🍎 스토리지 초과 다이얼로그: "기존 파일 정리" 클릭
   */
  const handleStorageCleanupFiles = useCallback(() => {
    setShowStorageExceededDialog(false)
    setPendingFilesForUpload([])
    // 전체 문서 보기로 이동
    onClose()
    const url = new URL(window.location.href)
    url.searchParams.set('view', 'documents-library')
    window.history.pushState({}, '', url.toString())
    window.dispatchEvent(new PopStateEvent('popstate'))
  }, [onClose])

  /**
   * 🍎 스토리지 초과 다이얼로그: "일부만 업로드" 클릭
   */
  const handleStoragePartialUpload = useCallback(async () => {
    if (!storageInfo || !pendingFilesForUpload.length) return

    // 용량 내 파일만 필터링 (크기 작은 순)
    const sortedFiles = [...pendingFilesForUpload].sort((a, b) => a.size - b.size)
    const filteredFiles: File[] = []
    let currentSize = 0

    for (const file of sortedFiles) {
      if (currentSize + file.size <= storageInfo.remaining_bytes) {
        filteredFiles.push(file)
        currentSize += file.size
      }
    }

    setShowStorageExceededDialog(false)
    setPendingFilesForUpload([])

    if (filteredFiles.length > 0) {
      // 필터링된 파일로 업로드 진행 (재귀 호출 방지를 위해 직접 처리)
      // handleFilesSelected를 다시 호출하면 무한 루프 가능성 있으므로
      // 여기서는 다이얼로그만 닫고, 사용자가 다시 파일을 선택하도록 안내
      addLog('info', `용량 내 ${filteredFiles.length}개 파일을 선택해주세요`, `${filteredFiles.map(f => f.name).join(', ')}`)
    }
  }, [storageInfo, pendingFilesForUpload, addLog])

  /**
   * 🍎 스토리지 초과 다이얼로그 닫기
   */
  const handleStorageDialogClose = useCallback(() => {
    setShowStorageExceededDialog(false)
    setPendingFilesForUpload([])
  }, [])

  /**
   * 업로드 진행률 콜백 (스로틀: 파일당 300ms 간격, 100%는 즉시 반영)
   * 대량 등록 시 수백 개 파일의 progress event가 연속 발생 →
   * 매번 files.map() 전체 순회 + React 리렌더 = 심각한 병목
   */
  const handleProgress = useCallback((event: UploadProgressEvent) => {
    const now = Date.now()
    const lastUpdate = progressThrottleRef.current.get(event.fileId) || 0
    if (event.progress < 100 && now - lastUpdate < 300) return
    progressThrottleRef.current.set(event.fileId, now)

    setUploadState(prev => ({
      ...prev,
      files: prev.files.map(f =>
        f.id === event.fileId
          ? { ...f, progress: event.progress }
          : f
      )
    }))
  }, [])

  /**
   * 업로드 완료 후 AR DB 플래그 설정 + 문서 처리 완료 대기 후 자동 연결
   */
  const setAnnualReportFlag = useCallback(async (fileName: string) => {
    // 🔒 중복 실행 방지: 이미 처리 중이면 건너뛰기
    if (!arFilenamesRef.current.has(fileName)) {
      console.log(`⚠️ [AR] 이미 처리 중이거나 완료된 파일: ${fileName}`);
      return;
    }

    // 🔒 즉시 추적 목록에서 제거 (중복 실행 방지)
    arFilenamesRef.current.delete(fileName);
