describe('DocumentRegistrationView - 고객 변경 시 드래그존 표시', () => {
  const SESSION_KEY = 'document-upload-state'
  const LOGS_KEY = 'document-upload-logs'

  beforeEach(() => {
    sessionStorage.clear()
    localStorage.clear()
    vi.clearAllMocks()
