import type { SearchResultItem, SemanticSearchResultItem, SearchMode, KeywordMode } from '@/entities/search'
import { DocumentUtils, DocumentProcessingModule } from '@/entities/document'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../SFSymbol'
import { Dropdown, Tooltip, BackButton, type DropdownOption, ContextMenu, useContextMenu, type ContextMenuSection } from '@/shared/ui'
import { FilenameModeToggle } from '@/shared/ui/FilenameModeToggle'
import { api } from '@/shared/lib/api'
import DownloadHelper from '../../../utils/downloadHelper'
import { DraggableModal } from '@/shared/ui/DraggableModal'
import {
  DocumentIcon,
  EyeIcon,
  LinkIcon,
  SummaryIcon
} from '../components/DocumentActionIcons'
import FullTextModal from './FullTextModal'
import DocumentDetailModal from '../DocumentStatusView/components/DocumentDetailModal'
import DocumentSummaryModal from '../DocumentStatusView/components/DocumentSummaryModal'
import DocumentFullTextModal from '../DocumentStatusView/components/DocumentFullTextModal'
import DocumentLinkModal from '../DocumentStatusView/components/DocumentLinkModal'
import { DocumentNotesModal } from '../DocumentStatusView/components/DocumentNotesModal'
import { CustomerSelectorModal } from '@/shared/ui/CustomerSelectorModal'
import { DocumentService } from '@/services/DocumentService'
import { DocumentStatusService } from '@/services/DocumentStatusService'
import type { Customer } from '@/entities/customer'
import type { DocumentCustomerRelation, Document } from '../../../types/documentStatus'
import { getRecentSearchQueries, addRecentSearchQuery, type RecentSearchQuery } from '../../../utils/recentSearchQueries'
import { useRecentCustomersStore } from '@/shared/store/useRecentCustomersStore'
import { useDevModeStore } from '@/shared/store/useDevModeStore'
import { errorReporter } from '@/shared/lib/errorReporter'
import { useDocumentActions } from '@/hooks/useDocumentActions'
import { RenameModal } from '@/shared/ui/RenameModal/RenameModal'
import './DocumentSearchView.search.css';
import './DocumentSearchView.results.css';
import './DocumentSearchView.table.css';
import './DocumentSearchView.controls.css';
import './DocumentSearchView.guide.css';
import './DocumentSearchView.responsive.css';

interface DocumentSearchViewProps {
  /** View 표시 여부 */
  visible: boolean
  /** View 닫기 핸들러 */
  onClose: () => void
  /** 문서 클릭 핸들러 (RightPane 프리뷰) */
  onDocumentClick?: (documentId: string) => void
  /** 문서 더블클릭 핸들러 (모달 프리뷰) */
  onDocumentDoubleClick?: (document: SearchResultItem) => void
  /** 문서 삭제 완료 핸들러 (삭제된 문서 ID 전달) */
  onDocumentDeleted?: (deletedIds: string | string[]) => void
  /** 고객 클릭 핸들러 (RightPane) */
  onCustomerClick?: (customerId: string) => void
  /** 고객 더블클릭 핸들러 (전체 정보 페이지) */
  onCustomerDoubleClick?: (customerId: string) => void
  /** RP에서 보고 있는 문서 ID (프리뷰 하이라이트용) */
  previewDocumentId?: string | null
}

/**
 * DocumentSearchView React 컴포넌트
 *
 * iOS Spotlight 스타일의 검색 UI를 제공합니다.
 * Progressive Disclosure 원칙에 따라 필요한 옵션만 단계적으로 표시됩니다.
 *
 * @example
 * ```tsx
 * <DocumentSearchView
 *   visible={isVisible}
 *   onClose={handleClose}
 *   onDocumentClick={handleDocumentClick}
 * />
 * ```
 */
// 검색 모드 옵션 정의
const SEARCH_MODE_OPTIONS: DropdownOption[] = [
  { value: 'keyword', label: '키워드 검색' },
  { value: 'semantic', label: 'AI 검색' },
]

// 키워드 모드 옵션 정의
const KEYWORD_MODE_OPTIONS: DropdownOption[] = [
  { value: 'AND', label: '모두 포함' },
  { value: 'OR', label: '하나라도 포함' },
]


export const DocumentSearchView: React.FC<DocumentSearchViewProps> = ({
  visible,
  onClose,
  onDocumentClick,
  onDocumentDoubleClick,
  onDocumentDeleted,
  onCustomerClick,
  onCustomerDoubleClick,
  previewDocumentId,
}) => {
  // 🍎 애플 스타일 알림 모달
  const { showAlert } = useAppleConfirm()

  // 🍎 모바일 레이아웃 감지 (드롭다운 width 조건부 적용)
  const { isMobileLayout } = useDeviceOrientation()

  // 🍎 DEV 모드 상태
  const isDevMode = useDevModeStore((state) => state.isDevMode)

  const {
    query,
    searchMode,
    keywordMode,
    customerId,
    results,
    answer,
    isLoading,
    error,
    lastSearchMode,
    totalCount,
    handleSearch,
    handleKeywordPageSearch,
    handleQueryChange,
    handleSearchModeChange,
    handleKeywordModeChange,
    handleCustomerIdChange,
    handleReset,
    handleCancel,
  } = useDocumentSearch()

  // 🍎 파일명 표시 모드: 'display' = displayName 우선, 'original' = 원본 파일명
  const [filenameMode, setFilenameMode] = React.useState<'display' | 'original'>(() => {
    if (typeof window === 'undefined') return 'display'
    return (localStorage.getItem('aims-filename-mode') as 'display' | 'original') ?? 'display'
  })

  // 호버 액션: 문서 삭제/이름변경 — reload 대신 검색 재실행으로 UI 상태 유지
  const onRefreshSearch = useCallback(() => { handleSearch() }, [handleSearch])
  const lastDeletedDocIdRef = React.useRef<string | null>(null)
  const onDeleteSuccessWithNotify = useCallback(() => {
    onRefreshSearch()
    if (lastDeletedDocIdRef.current) {
      onDocumentDeleted?.(lastDeletedDocIdRef.current)
      lastDeletedDocIdRef.current = null
    }
  }, [onRefreshSearch, onDocumentDeleted])
  const documentActions = useDocumentActions({
    onRenameSuccess: onRefreshSearch,
    onDeleteSuccess: onDeleteSuccessWithNotify,
  })
  const [renamingDoc, setRenamingDoc] = useState<{ _id: string; originalName: string; displayName?: string } | null>(null)

  const getSearchItemId = useCallback((item: SearchResultItem): string | undefined => {
    return ('_id' in item ? item._id : undefined) || ('id' in item ? item.id : undefined)
  }, [])

  const handleRenameClick = useCallback((item: SearchResultItem) => {
    const docId = getSearchItemId(item)
    if (docId) {
      const origName = ('originalName' in item ? item.originalName : undefined) || ''
      const dispName = ('displayName' in item ? item.displayName : undefined)
      setRenamingDoc({ _id: docId, originalName: origName as string, displayName: dispName as string | undefined })
    }
  }, [getSearchItemId])

  const handleRenameConfirm = useCallback(async (newName: string) => {
    if (!renamingDoc) return
    setRenamingDoc(null)
    const field = filenameMode === 'original' ? 'originalName' as const : 'displayName' as const
    await documentActions.renameDocument(renamingDoc._id, newName, field)
  }, [documentActions, filenameMode, renamingDoc])

  const handleRenameCancel = useCallback(() => {
    setRenamingDoc(null)
  }, [])

  const handleHoverDeleteClick = useCallback((item: SearchResultItem) => {
    const docId = getSearchItemId(item)
    const docName = ('displayName' in item ? item.displayName : undefined) || DocumentStatusService.extractOriginalFilename(item as unknown as Record<string, unknown>)
    if (docId) {
      lastDeletedDocIdRef.current = docId
      documentActions.deleteDocument(docId, docName)
    }
  }, [documentActions, getSearchItemId])

  // Full Text 모달 상태 (기존 - 검색 결과용)
  const [isFullTextModalVisible, setIsFullTextModalVisible] = useState(false)
  const [selectedDocument, setSelectedDocument] = useState<{
    name: string
    fullText: string
  } | null>(null)

  // 🍎 새로운 모달 상태 관리 (DocumentLibrary와 동일한 구조)
  // Detail 모달은 API를 통해 가공된 Document 타입을 사용
  const [selectedDocumentForDetail, setSelectedDocumentForDetail] = useState<Document | null>(null)
  const [isDetailModalVisible, setDetailModalVisible] = useState(false)
  const [selectedDocumentForSummary, setSelectedDocumentForSummary] = useState<SearchResultItem | null>(null)
  const [isSummaryModalVisible, setSummaryModalVisible] = useState(false)
  const [selectedDocumentForFullTextNew, setSelectedDocumentForFullTextNew] = useState<SearchResultItem | null>(null)
  const [isFullTextModalVisibleNew, setFullTextModalVisibleNew] = useState(false)
  const [selectedDocumentForLink, setSelectedDocumentForLink] = useState<SearchResultItem | null>(null)
  const [isLinkModalVisible, setLinkModalVisible] = useState(false)
  // 🍎 메모 모달 상태
  const [notesModalVisible, setNotesModalVisible] = useState(false)
  const [selectedNotes, setSelectedNotes] = useState<{
    documentName: string
    customerName?: string | undefined
    customerId?: string | undefined
    documentId?: string | undefined
    notes: string
  } | null>(null)

  // 🍎 검색어 위치 모달 상태 (키워드 검색 전용)
  const [keywordLocationModalVisible, setKeywordLocationModalVisible] = useState(false)
  const [selectedDocumentForKeywordLocation, setSelectedDocumentForKeywordLocation] = useState<SearchResultItem | null>(null)
  // 🍎 검색어 위치 탐색 상태
  const [keywordMatchIndex, setKeywordMatchIndex] = useState(0)  // 현재 보고 있는 매칭 인덱스

  // 🍎 고객 선택 모달 상태
  const [isCustomerSelectorOpen, setIsCustomerSelectorOpen] = useState(false)
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null)
  // 🍎 검색 실행 시점의 고객 정보 (검색 결과 설명에 사용)
  const [lastSearchCustomer, setLastSearchCustomer] = useState<Customer | null>(null)
  // 🍎 최근 선택한 고객 목록 (전역 상태)
  const { recentCustomers, addRecentCustomer, getRecentCustomers } = useRecentCustomersStore()
  // 🍎 최근 검색어 목록
  const [recentSearchQueries, setRecentSearchQueries] = useState<RecentSearchQuery[]>([])
  // 🍎 검색어 입력 필드 포커스 상태
  const [isSearchInputFocused, setIsSearchInputFocused] = useState(false)
  // 🍎 검색 입력 필드 ref (자동 포커스용)
  const searchInputRef = useRef<HTMLInputElement>(null)
  // 🍎 프로그래밍적 포커스 시 최근 검색어 드롭다운 억제용 플래그
  const suppressRecentDropdown = useRef(false)
  // 🍎 문서 행 싱글클릭/더블클릭 구분용 타이머
  const documentClickTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  // 🍎 고객명 싱글클릭/더블클릭 구분용 타이머
  const customerClickTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  // 🍎 검색창 blur 타이머 (드롭다운 클릭 허용)
  const blurTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  // 🍎 문서 컨텍스트 메뉴 상태
  const documentContextMenu = useContextMenu()
  const [contextMenuDocument, setContextMenuDocument] = useState<SearchResultItem | null>(null)
  const [, setIsDeleting] = useState(false)

  const handleFilenameModeChange = React.useCallback((mode: 'display' | 'original') => {
    setFilenameMode(mode)
    localStorage.setItem('aims-filename-mode', mode)
  }, [])

  // 🍎 정렬 상태
  type SortField = 'filetype' | 'filename' | 'customer' | 'status' | 'similarity' | null
  type SortOrder = 'asc' | 'desc'
  const [sortField, setSortField] = usePersistedState<SortField>('doc-search-sort-field', 'filename')
  const [sortOrder, setSortOrder] = usePersistedState<SortOrder>('doc-search-sort-order', 'asc')

  // 🍎 파일 유형 라벨 추출
  const getFileTypeLabel = useCallback((item: SearchResultItem) => {
    const name = SearchService.getOriginalName(item)
    const ext = name.split('.').pop()?.toLowerCase() || ''
    if (ext === 'pdf') return 'PDF'
    if (ext === 'hwp' || ext === 'hwpx') return 'HWP'
    if (ext === 'xlsx' || ext === 'xls') return 'XLS'
    if (ext === 'docx' || ext === 'doc') return 'DOC'
    if (ext === 'jpg' || ext === 'jpeg' || ext === 'png') return 'IMG'
    return ext.toUpperCase().slice(0, 3) || 'ETC'
  }, [])

  // 🍎 페이지네이션 상태
  const SEARCH_PAGE_SIZE = 20
  const [searchPage, setSearchPage] = useState(1)

  // 🍎 AI 검색 결과가 올 때 자동으로 유사도 내림차순 정렬
  useEffect(() => {
    if (lastSearchMode === 'semantic' && results.length > 0) {
      setSortField('similarity')
      setSortOrder('desc')
    } else if (lastSearchMode === 'keyword' && results.length > 0) {
      setSortField('filename')
      setSortOrder('asc')
    }
  }, [lastSearchMode, results.length])

  // 🍎 페이지 표시 시 검색 입력창에 자동 포커스
  useEffect(() => {
    if (!visible) return

    // 약간의 지연을 두어 DOM이 완전히 렌더링된 후 포커스
    // 프로그래밍적 포커스 시 최근 검색어 드롭다운 열리지 않도록 플래그 설정
    suppressRecentDropdown.current = true
    const timer = setTimeout(() => {
      searchInputRef.current?.focus()
    }, 100)
    return () => clearTimeout(timer)
  }, [visible])

  // 🍎 blur 타이머 cleanup (테스트 환경 cleanup 경고 방지)
  useEffect(() => {
    return () => {
      if (blurTimer.current) {
        clearTimeout(blurTimer.current)
      }
    }
  }, [])

  // 🍎 Context의 customerId가 설정되면 해당 고객 자동 선택 (상세 문서 검색 이동 시)
  useEffect(() => {
    if (customerId && !selectedCustomer) {
      // 최근 고객 목록에서 해당 고객 찾기
      const recent = getRecentCustomers()
      const recentCustomer = recent.find(c => c._id === customerId)
      if (recentCustomer) {
        // Customer 객체 재구성 (화면 표시용)
        setSelectedCustomer({
          _id: recentCustomer._id,
          personal_info: {
            name: recentCustomer.name
          }
        } as Customer)
      }
    }
  }, [customerId, selectedCustomer, getRecentCustomers])

  /**
   * 정렬 핸들러
   */
  const handleSort = useCallback((field: Exclude<SortField, null>) => {
    if (sortField === field) {
      // 같은 필드 클릭 시 정렬 순서 토글
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')
    } else {
      // 다른 필드 클릭 시 오름차순으로 시작 (유사도는 내림차순)
      setSortField(field)
      setSortOrder(field === 'similarity' ? 'desc' : 'asc')
    }
  }, [sortField, sortOrder])

  /**
   * 정렬된 결과 생성
   */
  const sortedResults = useMemo(() => {
    if (!sortField || !results) return results

    const sorted = [...results].sort((a, b) => {
      let compareValue = 0

      if (sortField === 'filetype') {
        compareValue = getFileTypeLabel(a).localeCompare(getFileTypeLabel(b))
      } else if (sortField === 'filename') {
        // 🍎 filenameMode에 따라 정렬 기준 변경
        const nameA = (filenameMode === 'display' && SearchService.getDisplayName(a)) || SearchService.getOriginalName(a)
        const nameB = (filenameMode === 'display' && SearchService.getDisplayName(b)) || SearchService.getOriginalName(b)
        compareValue = nameA.toLowerCase().localeCompare(nameB.toLowerCase(), 'ko-KR')
      } else if (sortField === 'customer') {
        const customerA = ('customer_relation' in a && a.customer_relation?.customer_name) || ''
        const customerB = ('customer_relation' in b && b.customer_relation?.customer_name) || ''
        // 고객 없음은 항상 마지막
        if (!customerA && customerB) return 1
        if (customerA && !customerB) return -1
        compareValue = customerA.localeCompare(customerB, 'ko-KR')
      } else if (sortField === 'status') {
        const statusA = DocumentProcessingModule.getProcessingStatus(a as Document).status
        const statusB = DocumentProcessingModule.getProcessingStatus(b as Document).status
        // 상태 우선순위: completed > processing > failed
        const statusPriority: Record<string, number> = {
          completed: 3,
          processing: 2,
          failed: 1
        }
        compareValue = (statusPriority[statusA] || 0) - (statusPriority[statusB] || 0)
      } else if (sortField === 'similarity') {
        // 유사도 정렬 (시맨틱 검색 결과만 해당)
        // P1-3: 정렬에도 final_score 우선 사용
        const scoreA = ('final_score' in a && a.final_score != null ? a.final_score : ('score' in a ? a.score : 0)) || 0
        const scoreB = ('final_score' in b && b.final_score != null ? b.final_score : ('score' in b ? b.score : 0)) || 0
        compareValue = scoreA - scoreB
      }

      return sortOrder === 'asc' ? compareValue : -compareValue
    })

    return sorted
  }, [results, sortField, sortOrder, filenameMode, getFileTypeLabel])

  // 🍎 페이지네이션: 키워드 검색은 백엔드 페이지네이션, 시맨틱은 클라이언트 페이지네이션
  const isKeywordBackendPagination = lastSearchMode === 'keyword' && totalCount != null
  const totalSearchPages = isKeywordBackendPagination
    ? Math.max(1, Math.ceil(totalCount / SEARCH_PAGE_SIZE))
    : Math.max(1, Math.ceil(sortedResults.length / SEARCH_PAGE_SIZE))
  const rawPaginatedResults = useMemo(() => {
    if (isKeywordBackendPagination) {
      // 키워드 검색: 백엔드가 이미 해당 페이지 결과만 반환 → 그대로 사용
      return sortedResults
    }
    // 시맨틱 검색: 클라이언트 슬라이싱
    const start = (searchPage - 1) * SEARCH_PAGE_SIZE
    return sortedResults.slice(start, start + SEARCH_PAGE_SIZE)
  }, [sortedResults, searchPage, isKeywordBackendPagination])

  // 🍎 Lazy Enrichment: 시맨틱 검색 결과를 페이지 단위로 보강
  // enrichment 캐시: docId → enriched SearchResultItem (페이지 복귀 시 즉시 사용)
  const enrichCacheRef = useRef<Map<string, SearchResultItem>>(new Map())
  // enrichment 진행 중 AbortController
  const enrichAbortRef = useRef<AbortController | null>(null)
  // enrichment 로딩 상태
  const [, setIsEnriching] = useState(false)
  // 현재 페이지의 enriched 결과 (React 렌더 보장)
  const [enrichedPage, setEnrichedPage] = useState<SearchResultItem[]>([])

  // 검색 결과 변경 시 enrichment 캐시 초기화
  useEffect(() => {
    enrichCacheRef.current = new Map()
    setEnrichedPage([])
    // 진행 중인 enrichment 취소
    if (enrichAbortRef.current) {
      enrichAbortRef.current.abort()
      enrichAbortRef.current = null
    }
  }, [results])

  // 컴포넌트 언마운트 시 진행 중인 enrichment 취소
  useEffect(() => {
    return () => {
      if (enrichAbortRef.current) {
        enrichAbortRef.current.abort()
        enrichAbortRef.current = null
      }
      setIsEnriching(false)
    }
  }, [])

  // 페이지 변경 시 enrichedPage 초기화
  useEffect(() => {
    setEnrichedPage([])
  }, [searchPage])

  // rawPaginatedResults 변경 시 해당 페이지 건만 enrich (시맨틱 검색만)
  useEffect(() => {
    if (lastSearchMode !== 'semantic' || rawPaginatedResults.length === 0) return

    // 캐시에 없는 건만 필터링
    const unenrichedItems = rawPaginatedResults.filter((item) => {
      const docId = SearchService.getDocumentId(item)
      return docId && !enrichCacheRef.current.has(docId)
    })

    if (unenrichedItems.length === 0) return

    // 이전 enrichment 취소
    if (enrichAbortRef.current) {
      enrichAbortRef.current.abort()
    }
    const controller = new AbortController()
    enrichAbortRef.current = controller

    setIsEnriching(true)

    SearchService.enrichPageResults(
      unenrichedItems as SemanticSearchResultItem[],
      controller.signal
    )
      .then((enrichedItems) => {
        if (controller.signal.aborted) return

        // 캐시에 저장 (페이지 복귀 시 즉시 사용)
        enrichedItems.forEach((enrichedItem) => {
          const docId = SearchService.getDocumentId(enrichedItem)
          if (docId) {
            enrichCacheRef.current.set(docId, enrichedItem)
          }
        })

        // React 렌더 보장: useState로 현재 페이지 enriched 결과 설정
        setEnrichedPage(enrichedItems)
        setIsEnriching(false)
      })
      .catch((error) => {
        if (error instanceof DOMException && error.name === 'AbortError') {
          // AbortError 시에도 로딩 해제
          setIsEnriching(false)
          return
        }
        console.error('[DocumentSearchView] enrichment 오류:', error)
        setIsEnriching(false)
      })

    return () => {
      controller.abort()
      setIsEnriching(false)
      if (enrichAbortRef.current === controller) {
        enrichAbortRef.current = null
      }
    }
  }, [rawPaginatedResults, lastSearchMode])

  // 🍎 enriched 결과: 현재 페이지 enriched → 캐시 → raw 우선순위로 병합
  const paginatedResults = useMemo(() => {
    return rawPaginatedResults.map((item) => {
      const docId = SearchService.getDocumentId(item)
      if (!docId) return item
      // 현재 페이지 enriched 결과 우선
      const fromPage = enrichedPage.find(
        (e) => SearchService.getDocumentId(e) === docId
      )
      if (fromPage) return fromPage
      // 캐시에서 조회 (이전 페이지에서 보강된 결과)
      return enrichCacheRef.current.get(docId) ?? item
    })
  }, [rawPaginatedResults, enrichedPage])

  // 🍎 정렬 변경 시 1페이지로 리셋
  useEffect(() => { setSearchPage(1) }, [sortField, sortOrder])
