  /**
   * P3-1: 유사도 점수를 3단계 도트 시스템으로 분류
   * - Apple HIG, Nielsen 3~4단계 권장에 따라 5단계 → 3단계로 단순화
   * - emoji 대신 CSS dot 사용 (6px border-radius: 50%)
   */
  const getSimilarityLevel = (score: number): {
    label: string
    color: string
    percentage: string
  } => {
    const percentage = `${Math.round(score * 100)}%`
    if (score >= 0.70) {
      return { label: '높음', color: 'high', percentage }
    } else if (score >= 0.40) {
      return { label: '보통', color: 'medium', percentage }
    } else {
      return { label: '낮음', color: 'low', percentage }
    }
  }

  /**
   * OCR 신뢰도를 5단계로 분류
   * 0.0 ~ 1.0 범위의 신뢰도를 색상 레벨로 변환
   */
  const getOcrConfidenceLevel = (confidence: number): {
    color: string
    label: string
  } => {
    if (confidence >= 0.95) {
      return { color: 'excellent', label: '매우 높음' }
    } else if (confidence >= 0.85) {
      return { color: 'high', label: '높음' }
    } else if (confidence >= 0.70) {
      return { color: 'medium', label: '보통' }
    } else if (confidence >= 0.50) {
      return { color: 'low', label: '낮음' }
    } else {
      return { color: 'very-low', label: '매우 낮음' }
    }
  }

  /**
   * 🍎 모든 키워드 매칭 위치 찾기 (검색어 위치 탐색용)
   * 문서에서 검색어가 나타나는 모든 위치 인덱스를 반환
   */
  const getAllKeywordMatches = useCallback((item: SearchResultItem): number[] => {
    const fullText = (item as any).ocr?.full_text ||
                     (item as any).meta?.full_text ||
                     (item as any).text?.full_text ||
                     ''

    if (!fullText) return []

    const keywords = query.trim().split(/\s+/).filter(k => k.length > 0)
    if (keywords.length === 0) return []

    const searchLower = fullText.toLowerCase()
    const matches: number[] = []

    // 모든 키워드의 모든 위치를 찾기
    keywords.forEach(keyword => {
      const keywordLower = keyword.toLowerCase()
      let startIndex = 0
      let idx = searchLower.indexOf(keywordLower, startIndex)

      while (idx !== -1) {
        matches.push(idx)
        startIndex = idx + 1
        idx = searchLower.indexOf(keywordLower, startIndex)
      }
    })

    // 위치 순으로 정렬하고 중복 제거
    return [...new Set(matches)].sort((a, b) => a - b)
  }, [query])

  /**
   * 🍎 파일명(제목)에서 매칭된 키워드 — 별칭/원본 분리 반환
   */
  const getFilenameKeywordMatchesDetailed = useCallback((item: SearchResultItem): {
    displayMatches: string[]
    originalMatches: string[]
    displayName: string
    originalName: string
  } => {
    const displayName = SearchService.getDisplayName(item) || ''
    const originalName = SearchService.getOriginalName(item) || ''
    const keywords = query.trim().split(/\s+/).filter(k => k.length > 0)
    const displayLower = displayName.toLowerCase()
    const originalLower = originalName.toLowerCase()
    return {
      displayMatches: displayName ? keywords.filter(k => displayLower.includes(k.toLowerCase())) : [],
      originalMatches: originalName ? keywords.filter(k => originalLower.includes(k.toLowerCase())) : [],
      displayName,
      originalName,
    }
  }, [query])

  /**
   * 🍎 특정 매칭 인덱스의 스니펫 추출 (검색어 위치 탐색용)
   * matchIdx번째 매칭 위치 주변 텍스트와 현재 키워드의 스니펫 내 위치를 반환
   */
  const getTextSnippetAtIndex = useCallback((item: SearchResultItem, matchIdx: number): {
    snippet: string
    currentKeywordOffset: number  // 스니펫 내에서 현재 키워드의 시작 위치
    currentKeywordLength: number  // 현재 키워드의 길이
  } => {
    const fullText = (item as any).ocr?.full_text ||
                     (item as any).meta?.full_text ||
                     (item as any).text?.full_text ||
                     ''

    if (!fullText) return { snippet: '텍스트를 찾을 수 없습니다.', currentKeywordOffset: -1, currentKeywordLength: 0 }

    const matches = getAllKeywordMatches(item)
    if (matches.length === 0 || matchIdx >= matches.length) {
      return { snippet: fullText.substring(0, 300) + '...', currentKeywordOffset: -1, currentKeywordLength: 0 }
    }

    const idx = matches[matchIdx]
    const keywords = query.trim().split(/\s+/).filter(k => k.length > 0)

    // 현재 위치에서 실제로 매칭된 키워드 찾기
    const fullTextLower = fullText.toLowerCase()
    let matchedKeyword = keywords[0] || ''
    let matchedLength = matchedKeyword.length
    for (const kw of keywords) {
      if (fullTextLower.substring(idx, idx + kw.length).toLowerCase() === kw.toLowerCase()) {
        matchedKeyword = fullText.substring(idx, idx + kw.length)
        matchedLength = kw.length
        break
      }
    }

    const start = Math.max(0, idx - 100)
    const end = Math.min(fullText.length, idx + matchedLength + 200)
    let snippet = fullText.substring(start, end)

    // "..." prefix 추가 여부에 따른 오프셋 계산
    let currentKeywordOffset = idx - start
    if (start > 0) {
      snippet = '...' + snippet
      currentKeywordOffset += 3  // "..." 길이
    }
    if (end < fullText.length) snippet = snippet + '...'

    return { snippet, currentKeywordOffset, currentKeywordLength: matchedLength }
  }, [query, getAllKeywordMatches])

  /**
   * 🍎 현재 키워드를 특별히 강조하는 하이라이트 (검색어 위치 탐색용)
   * 현재 보고 있는 키워드는 다른 스타일로 표시
   */
  const highlightKeywordsWithCurrent = useCallback((
    text: string,
    currentOffset: number,
    currentLength: number
  ): React.ReactNode => {
    const keywords = query.trim().split(/\s+/).filter(k => k.length > 0)
    if (keywords.length === 0) return text

    // 현재 키워드 위치가 유효한 경우, 특별 처리
    if (currentOffset >= 0 && currentLength > 0) {
      const before = text.substring(0, currentOffset)
      const current = text.substring(currentOffset, currentOffset + currentLength)
      const after = text.substring(currentOffset + currentLength)

      // 앞부분과 뒷부분은 일반 하이라이트, 현재 키워드는 특별 하이라이트
      return (
        <>
          {highlightKeywordsNormal(before, keywords)}
          <mark className="doc-search-highlight doc-search-highlight--current">{current}</mark>
          {highlightKeywordsNormal(after, keywords)}
        </>
      )
    }

    return highlightKeywordsNormal(text, keywords)
  }, [query])

  /**
   * 🍎 일반 키워드 하이라이트 (내부 헬퍼)
   */
  const highlightKeywordsNormal = (text: string, keywords: string[]): React.ReactNode => {
    if (!text || keywords.length === 0) return text

    const pattern = new RegExp(`(${keywords.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|')})`, 'gi')
    const parts = text.split(pattern)

    return parts.map((part, index) => {
      const isMatch = keywords.some(kw => part.toLowerCase() === kw.toLowerCase())
      return isMatch ? (
        <mark key={index} className="doc-search-highlight">{part}</mark>
      ) : (
        <span key={index}>{part}</span>
      )
    })
  }

  return (
    <CenterPaneView
      visible={visible}
      suppressAutoBackButton
      title="상세 문서검색"
      titleIcon={<SFSymbol name="search-bold" size={SFSymbolSize.CALLOUT} weight={SFSymbolWeight.MEDIUM} style={{ color: 'var(--color-icon-doc-search)' }} />}
      titleAccessory={
        <BackButton
          onClick={() => window.history.back()}
          tooltipContent="이전 페이지로 돌아가기"
        />
      }
      onClose={onClose}
      marginTop={6}
      marginBottom={6}
      marginLeft={6}
      marginRight={6}
      className="document-search-view"
    >
      <div className="document-search-container">
        {/* 🍎 iOS Spotlight 검색바 - 한 줄 레이아웃 */}
        <div className={`search-bar-wrapper${isLoading ? ' search-bar-wrapper--loading' : ''}`}>
          {/* 🍎 고객 선택 버튼 (모든 검색 모드에서 표시) */}
          <Tooltip content="고객 선택">
          <button
            className="customer-select-button"
            onClick={() => setIsCustomerSelectorOpen(true)}
            aria-label="고객 선택"
            disabled={isLoading}
          >
            고객선택
          </button>
          </Tooltip>

          {/* 🍎 선택된 고객명 표시 또는 최근 고객 드롭다운 */}
          <div className="selected-customer-display">
            {selectedCustomer ? (
              <>
                <span className="selected-customer-name">
                  {selectedCustomer.personal_info?.name}
                </span>
                <button
                  className="clear-customer-button"
                  onClick={() => {
                    setSelectedCustomer(null)
                    handleCustomerIdChange(null)
                  }}
                  aria-label="고객 선택 해제"
                  disabled={isLoading}
                >
                  ✕
                </button>
              </>
            ) : (
              <Dropdown
                value=""
                options={recentCustomerOptions}
                onChange={handleRecentCustomerSelect}
                width={isMobileLayout ? undefined : 115}
                aria-label="최근 선택한 고객"
                disabled={isLoading}
              />
            )}
          </div>

          {/* A: 검색 입력 필드 (flex-grow) */}
          <div className="search-input-wrapper">
            <button
              className="search-icon"
              onClick={() => {
                // 최근 검색어 드롭다운 토글
                const newFocusState = !isSearchInputFocused
                setIsSearchInputFocused(newFocusState)
                if (newFocusState) {
                  // 드롭다운 열 때 최근 검색어 다시 불러오기
                  const recent = getRecentSearchQueries()
                  setRecentSearchQueries(recent)
                }
              }}
              aria-label="최근 검색어 보기"
              type="button"
            >
              <SFSymbol name="magnifyingglass" size={SFSymbolSize.CALLOUT} weight={SFSymbolWeight.MEDIUM} decorative />
            </button>
            <input
              ref={searchInputRef}
              type="text"
              className="search-input"
              value={query}
              onChange={(e) => handleQueryChange(e.target.value)}
              onKeyPress={handleKeyPress}
              disabled={isLoading}
              onFocus={() => {
                // 프로그래밍적 포커스(페이지 진입 시 자동 포커스)에서는 드롭다운 열지 않음
                if (suppressRecentDropdown.current) {
                  suppressRecentDropdown.current = false
                  return
                }
                // 사용자 클릭에 의한 포커스 시에만 최근 검색어 드롭다운 열기
                setIsSearchInputFocused(true)
                const recent = getRecentSearchQueries()
                setRecentSearchQueries(recent)
              }}
              onBlur={() => {
                // 드롭다운 클릭 시간을 주기 위해 지연 (cleanup 가능하도록 ref 사용)
                if (blurTimer.current) clearTimeout(blurTimer.current)
                blurTimer.current = setTimeout(() => setIsSearchInputFocused(false), 200)
              }}
              placeholder="상세 문서검색"
              aria-label="상세 문서검색"
            />
            {/* 🍎 검색어 지우기 버튼 (Progressive Disclosure) */}
            {query.trim() && (
              <button
                className="clear-search-button"
                onClick={() => {
                  handleQueryChange('')
                }}
                aria-label="검색어 지우기"
                type="button"
              >
                ✕
              </button>
            )}
            {/* 🍎 최근 검색어 드롭다운 — 검색 결과가 있으면 표시하지 않음 */}
            {isSearchInputFocused && recentSearchQueries.length > 0 && results.length === 0 && !answer && (
              <div className="recent-search-dropdown">
                <div className="recent-search-header">최근 검색어</div>
                <div className="recent-search-list">
                  {recentSearchQueries.map((item, index) => (
                    <button
                      key={index}
                      className="recent-search-item"
                      onClick={() => {
                        handleQueryChange(item.query)
                        setIsSearchInputFocused(false)
                      }}
                      type="button"
                    >
                      <span className="recent-search-text">{item.query}</span>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* B: 검색 모드 드롭다운 */}
          <Dropdown
            value={searchMode}
            options={SEARCH_MODE_OPTIONS}
            onChange={(value) => handleSearchModeChange(value as SearchMode)}
            aria-label="검색 모드 선택"
            width={isMobileLayout ? undefined : 120}
            disabled={isLoading}
          />

          {/* 🍎 Progressive Disclosure: 키워드 검색 시 드롭다운으로 AND/OR 선택 */}
          {searchMode === 'keyword' && (
            <Dropdown
              value={keywordMode}
              options={KEYWORD_MODE_OPTIONS}
              onChange={(value) => handleKeywordModeChange(value as KeywordMode)}
              aria-label="키워드 모드 선택"
              width={isMobileLayout ? undefined : 100}
              disabled={isLoading}
            />
          )}

          {/* 🍎 Progressive Disclosure: 검색 결과 초기화 버튼 (검색어나 결과가 있을 때만 표시) */}
          {(query || results.length > 0) && (
            <Tooltip content="검색 초기화">
              <button
                className="reset-button"
                onClick={() => {
                  handleReset()
                  setLastSearchCustomer(null)
                }}
                aria-label="검색 초기화"
              >
                <SFSymbol
                  name="xmark.circle.fill"
                  size={SFSymbolSize.CALLOUT}
                  weight={SFSymbolWeight.REGULAR}
                  decorative={true}
                />
              </button>
            </Tooltip>
          )}

          {/* 검색/취소 버튼 */}
          {isLoading ? (
            <button
              className="search-button search-button--cancel"
              onClick={() => {
                handleCancel()
              }}
              aria-label="검색 취소"
            >
              취소
            </button>
          ) : (
            <button
              className="search-button"
              onClick={() => {
                // 검색 실행 시 현재 선택된 고객 저장
                setLastSearchCustomer(selectedCustomer)
                // 검색어를 최근 목록에 추가
                if (query.trim()) {
                  addRecentSearchQuery(query.trim())
                  setRecentSearchQueries(getRecentSearchQueries())
                }
                handleSearch()
                // 드롭다운 닫기
                setIsSearchInputFocused(false)
              }}
              aria-label="검색 실행"
            >
              검색
            </button>
          )}
        </div>

        {/* 에러 메시지 */}
        {error && (
          <div className="search-error" role="alert" aria-live="assertive">
            {error}
          </div>
        )}

        {/* 검색 결과 영역 */}
        <div className="search-results-section">
          {isLoading ? (
            <div className="search-loading" role="status" aria-live="polite">
              <div className="search-loading__animation">
                <div className="search-loading__rings">
                  <div className="search-loading__ring search-loading__ring--outer" />
                  <div className="search-loading__ring search-loading__ring--inner" />
                  <svg className="search-loading__icon" width="20" height="20" viewBox="0 0 20 20" fill="none">
                    <path d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.45 4.39l3.58 3.58a.75.75 0 1 1-1.06 1.06l-3.58-3.58A7 7 0 0 1 2 9Z" fill="currentColor"/>
                  </svg>
                </div>
              </div>
              <p className="search-loading__text">문서를 검색하고 있습니다</p>
              <p className="search-loading__subtext">
                {searchMode === 'semantic' ? 'AI가 질문을 분석하고 관련 문서를 찾고 있습니다' : '키워드와 일치하는 문서를 찾고 있습니다'}
              </p>
            </div>
          ) : results.length > 0 ? (
            <>
              {/* AI 답변 (시맨틱 검색시) - 기본적으로 펼쳐짐, 접기 가능 */}
              {answer && answer.trim() && (
                <details className="search-answer" open>
                  <summary className="answer-title">
                    <span className="answer-arrow">▶</span> AI 답변 (클릭하여 숨기기)
                  </summary>
                  <p className="answer-content">{
                    (() => {
                      const fileEntries = results
                        .map(r => ({
                          name: ('payload' in r ? r.payload?.original_name : ('filename' in r ? r.filename : undefined)) || r.upload?.originalName || '',
                          docId: ('payload' in r ? r.payload?.doc_id : ('_id' in r ? r._id : undefined)) || undefined,
                          result: r
                        }))
                        .filter(e => e.name)

                      return parseAnswerLinks(answer, fileEntries).map((seg, i) =>
                        seg.type === 'file'
                          ? <button
                              key={i}
                              type="button"
                              className="answer-source-ref answer-source-ref--clickable"
                              onClick={() => { if (onDocumentDoubleClick) onDocumentDoubleClick(seg.result) }}
                            >[{seg.name}]</button>
                          : seg.value
                      )
                    })()
                  }</p>
                </details>
              )}

              {/* P3-2: 검색 결과 헤더 — 간결하게 "N건 검색됨" */}
              <div className="search-results-header">
                <div className="results-header-text">
                  {lastSearchMode === 'semantic' ? (
                    <p>{results.length}건 검색됨</p>
                  ) : (
                    <p>
                      {lastSearchCustomer
                        ? `${lastSearchCustomer.personal_info?.name}에 대하여 검색한 결과, 총 ${results.length}건의 파일이 검색되었습니다.`
                        : `모든 고객에 대하여 검색한 결과, 총 ${results.length}건의 파일이 검색되었습니다.`}
                    </p>
                  )}
                </div>
              </div>

              {/* P3-2: 범례 제거 — 3단계 도트면 자명하므로 제거 (기존 5단계 범례 불필요) */}
              {false && searchMode === 'semantic' && results.length > 0 && (
                <div className="similarity-legend">
                  <div className="legend-title">유사도 점수:</div>
                  <div className="legend-items">
                    <div className="legend-item">
                      <span className="legend-icon">placeholder</span>
                      <span className="legend-label">placeholder</span>
                    </div>
                  </div>
                </div>
              )}

              {/* P3-5: # 칼럼 제거 — 정렬 순서가 이미 순위를 나타냄 */}
              <div className="search-results-column-header" data-search-mode={searchMode}>
                <div
                  className={`header-filetype sortable ${sortField === 'filetype' ? 'sorted' : ''}`}
                  onClick={() => handleSort('filetype')}
                  role="button"
                  tabIndex={0}
                  onKeyPress={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handleSort('filetype') } }}
                  aria-label={`형식으로 정렬 ${sortField === 'filetype' ? (sortOrder === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                >
                  <span>형식</span>
                  <SortIndicator field="filetype" currentSortField={sortField} sortDirection={sortOrder} />
                </div>
                <div className="header-filename">
                  <div
                    className={`header-filename__sort-area sortable ${sortField === 'filename' ? 'sorted' : ''}`}
                    onClick={() => handleSort('filename')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('filename')
                      }
                    }}
                    aria-label={`파일명으로 정렬 ${sortField === 'filename' ? (sortOrder === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <path d="M4 1h5l3 3v9a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1z" fill="currentColor"/>
                      <path className="pdf-icon-fold" d="M9 1v3h3" strokeWidth="0.8" fill="none"/>
                    </svg>
                    <span>파일명</span>
                    <SortIndicator field="filename" currentSortField={sortField} sortDirection={sortOrder} />
                  </div>
                  {/* 🍎 파일명 표시 모드 토글: 원본 ↔ 별칭 */}
                  <FilenameModeToggle filenameMode={filenameMode} onModeChange={handleFilenameModeChange} />
                </div>
                <div
                  className={`header-customer sortable ${sortField === 'customer' ? 'sorted' : ''}`}
                  onClick={() => handleSort('customer')}
                  role="button"
                  tabIndex={0}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault()
                      handleSort('customer')
                    }
                  }}
                  aria-label={`연결된 고객으로 정렬 ${sortField === 'customer' ? (sortOrder === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                >
                  <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                    <circle cx="8" cy="5" r="3" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                    <path d="M2 14c0-3.3 2.7-6 6-6s6 2.7 6 6" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                  </svg>
                  <span>연결된 고객</span>
                  <SortIndicator field="customer" currentSortField={sortField} sortDirection={sortOrder} />
                </div>
                <div
                  className={`header-status sortable ${sortField === 'status' ? 'sorted' : ''}`}
                  onClick={() => handleSort('status')}
                  role="button"
                  tabIndex={0}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault()
                      handleSort('status')
                    }
                  }}
                  aria-label={`상태로 정렬 ${sortField === 'status' ? (sortOrder === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                >
                  <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                    <rect x="2" y="3" width="12" height="10" rx="1.5" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                    <path d="M5 7l2 2 4-4" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                  <span>상태</span>
                  <SortIndicator field="status" currentSortField={sortField} sortDirection={sortOrder} />
                </div>
                {/* 🍎 유사도 헤더 (시맨틱 검색 시만 표시) */}
                {searchMode === 'semantic' && (
                  <div
                    className={`header-similarity sortable ${sortField === 'similarity' ? 'sorted' : ''}`}
                    onClick={() => handleSort('similarity')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('similarity')
                      }
                    }}
                    aria-label={`유사도로 정렬 ${sortField === 'similarity' ? (sortOrder === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <path d="M8 3v10M5 8h6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                      <circle cx="8" cy="8" r="6" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                    </svg>
                    <span>유사도</span>
                    <SortIndicator field="similarity" currentSortField={sortField} sortDirection={sortOrder} />
                  </div>
                )}
                <div className="header-actions">
                  <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                    <circle cx="5" cy="8" r="1.5" fill="currentColor"/>
                    <circle cx="11" cy="8" r="1.5" fill="currentColor"/>
                  </svg>
                  <span>액션</span>
                </div>
              </div>

              {/* 🍎 iOS Table View 스타일 결과 리스트 */}
              <div className="search-results-table" role="list">
                {paginatedResults.map((item, index) => {
                  const originalName = SearchService.getOriginalName(item)
                  const displayName = SearchService.getDisplayName(item)
                  const hasDisplay = Boolean(displayName)
                  const isAlias = filenameMode === 'display' && hasDisplay
                  // 🍎 filenameMode에 따라 표시할 파일명 결정
                  const showName = isAlias
                    ? displayName!
                    : originalName
                  // 🍎 툴팁용 대체 파일명
                  const altName = filenameMode === 'display' && hasDisplay
                    ? `원본: ${originalName}`
                    : (hasDisplay ? `별칭: ${displayName}` : '')
                  const summary = SearchService.getSummary(item)
                  const confidence = SearchService.getOCRConfidence(item)
                  // P1-3: final_score 우선 사용 + 0~1 clamp
                  const rawScore = 'final_score' in item && item.final_score != null
                    ? item.final_score
                    : ('score' in item ? item.score : null)
                  const score = rawScore != null ? Math.min(Math.max(rawScore, 0), 1) : null
                  const mimeType = SearchService.getMimeType(item)

                  // 🍎 문서 처리 상태 정보 추출
                  const status = DocumentProcessingModule.getProcessingStatus(item as Document)
                  const linkStatus = DocumentProcessingModule.getCustomerLinkStatus(item as Document)
                  const canLink = linkStatus.canLink
                  const linkTooltip = linkStatus.isLinked ? '이미 고객과 연결됨' : '고객에게 연결'
                  const docId = SearchService.getDocumentId(item)
                  const isPreview = !!(previewDocumentId && docId && previewDocumentId === docId)

                  return (
                    <div
                      key={index}
                      className={`search-result-row${isPreview ? ' search-result-row--preview' : ''}`}
                      data-search-mode={searchMode}
                      onClick={() => handleItemClick(item)}
                      onDoubleClick={() => handleItemDoubleClick(item)}
                      onContextMenu={(e) => handleDocumentContextMenu(item, e)}
                      role="listitem"
                      tabIndex={0}
                      onKeyPress={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.preventDefault()
                          handleItemClick(item)
                        }
                      }}
                      aria-label={`문서: ${originalName}`}
                    >
                      {/* P3-5: # 칼럼 제거 */}

                      {/* 형식 */}
                      <div className="row-filetype">
                        <span className={`filetype-badge filetype-badge--${getFileTypeLabel(item).toLowerCase()}`}>
                          {getFileTypeLabel(item)}
                        </span>
                      </div>

                      {/* 파일명 */}
                      <div className="row-filename">
                        <div className="row-title-wrapper">
                          {/* 🍎 파일 타입 아이콘 */}
                          <div className="document-icon-wrapper">
                            <div className={`document-icon ${DocumentUtils.getFileTypeClass(mimeType, originalName)}`}>
                              <SFSymbol
                                name={DocumentUtils.getFileIcon(mimeType, originalName)}
                                size={SFSymbolSize.CAPTION_1}
                                weight={SFSymbolWeight.REGULAR}
                                decorative={true}
                              />
                            </div>
                            {/* 🍎 AR BADGE: Annual Report 표시 */}
                            {('is_annual_report' in item && item.is_annual_report) ? (
                              <Tooltip content="연간보고서">
                                <div className="document-ar-badge">
                                  AR
                                </div>
                              </Tooltip>
                            ) : null}
                            {/* 🍎 CR BADGE: Customer Review (변액 리포트) 표시 */}
                            {('is_customer_review' in item && item.is_customer_review) && !('is_annual_report' in item && item.is_annual_report) ? (
                              <Tooltip content="변액 리뷰">
                                <div className="document-cr-badge">
                                  CR
                                </div>
                              </Tooltip>
                            ) : null}
                            {/* 🍎 OCR BADGE: OCR 처리 완료 문서 신뢰도 표시 */}
                            {confidence !== null && confidence !== undefined ? (
                              <Tooltip content={`OCR 신뢰도: ${(confidence * 100).toFixed(1)}% (${getOcrConfidenceLevel(confidence).label})`}>
                                <div className={`document-ocr-badge ocr-${getOcrConfidenceLevel(confidence).color}`}>
                                  OCR
                                </div>
                              </Tooltip>
                            ) : (() => {
                              // OCR 뱃지가 없는 경우, TXT 또는 BIN 타입 표시
                              const typeLabel = DocumentUtils.getDocumentTypeLabel(item);
                              if (typeLabel === 'TXT') {
                                return (
                                  <Tooltip content="TXT 기반 문서">
                                    <div className="document-txt-badge">
                                      TXT
                                    </div>
                                  </Tooltip>
                                );
                              }
                              if (typeLabel === 'BIN') {
                                return (
                                  <Tooltip content="바이너리 파일 (텍스트 추출 불가)">
                                    <div className="document-bin-badge">
                                      BIN
                                    </div>
                                  </Tooltip>
                                );
                              }
                              return null;
                            })()}
                          </div>
                          <div className="row-title-container">
                            {/* 🍎 filenameMode에 따라 별칭/원본 전환 표시 */}
                            {(() => {
                              return (
                                <>
                                  {altName ? (
                                    <Tooltip content={altName}>
                                      <span className={`row-title${isAlias ? ' document-name--alias' : ''}`}>{showName}</span>
                                    </Tooltip>
                                  ) : (
                                    <span className={`row-title${isAlias ? ' document-name--alias' : ''}`}>{showName}</span>
                                  )}
                                  <span className="search-hover-actions" onClick={(e) => e.stopPropagation()}>
                                    <Tooltip content="이름 변경">
                                      <button
                                        type="button"
                                        className="hover-action-btn hover-action-btn--rename"
                                        onClick={(e) => { e.stopPropagation(); handleRenameClick(item) }}
                                        aria-label="이름 변경"
                                      >
                                        <svg width="12" height="12" viewBox="0 0 16 16" fill="none">
                                          <path d="M11.5 1.5l3 3L5 14H2v-3L11.5 1.5z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                                        </svg>
                                      </button>
                                    </Tooltip>
                                    <Tooltip content="삭제">
                                      <button
                                        type="button"
                                        className="hover-action-btn hover-action-btn--delete"
                                        onClick={(e) => { e.stopPropagation(); handleHoverDeleteClick(item) }}
                                        aria-label="삭제"
                                      >
                                        <svg width="12" height="12" viewBox="0 0 16 16" fill="none">
                                          <path d="M2 4h12M5.33 4V2.67a1.33 1.33 0 011.34-1.34h2.66a1.33 1.33 0 011.34 1.34V4m2 0v9.33a1.33 1.33 0 01-1.34 1.34H4.67a1.33 1.33 0 01-1.34-1.34V4h9.34z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
                                        </svg>
                                      </button>
                                    </Tooltip>
                                  </span>
                                </>
                              )
                            })()}
                            {/* 메모 버튼: customer_relation에 notes가 있는 경우에만 표시 */}
                            {('customer_relation' in item && item.customer_relation?.notes &&
                             typeof item.customer_relation.notes === 'string' &&
                             item.customer_relation.notes.trim() !== '') && (
                              <Tooltip
                                content={
                                  item.customer_relation.notes.length > 50
                                    ? `${item.customer_relation.notes.substring(0, 50)}...`
                                    : item.customer_relation.notes
                                }
                              >
                                <button
                                  className="document-notes-btn"
                                  onClick={(e) => {
                                    e.stopPropagation()
                                    setSelectedNotes({
                                      documentName: originalName,
                                      customerName: item.customer_relation?.customer_name,
                                      customerId: item.customer_relation?.customer_id,
                                      documentId: SearchService.getDocumentId(item),
                                      notes: item.customer_relation?.notes || ''
                                    })
                                    setNotesModalVisible(true)
                                  }}
                                  aria-label="메모 보기"
                                >
                                  📝
                                </button>
                              </Tooltip>
                            )}
                          </div>
                        </div>
                        <div className="row-subtitle">{summary}</div>
                      </div>

                      {/* 연결된 고객 */}
                      <div className="row-customer">
                        {('customer_relation' in item && item.customer_relation?.customer_name) ? (
                          item.customer_relation.customer_type === MY_STORAGE_MARKER ? (
                            // 🆕 내 보관함: 클릭 불가, 폴더 아이콘 (SFSymbol 사용)
                            <span className="customer-name-label customer-name-label--storage">
                              <SFSymbol
                                name="folder"
                                size={SFSymbolSize.CALLOUT}
                                weight={SFSymbolWeight.SEMIBOLD}
                                decorative={true}
                                className="customer-icon--storage"
                              />
                              <span className="customer-name-text">{MY_STORAGE_DISPLAY_NAME}</span>
                            </span>
                          ) : (
                            // 일반 고객: 클릭 가능
                            <button
                              className="customer-name-button"
                              onClick={(e) => {
                                e.stopPropagation()
                                if (item.customer_relation?.customer_id) {
                                  handleCustomerNameClick(item.customer_relation.customer_id)
                                }
                              }}
                              onDoubleClick={(e) => {
                                e.stopPropagation()
                                if (item.customer_relation?.customer_id) {
                                  handleCustomerNameDoubleClick(item.customer_relation.customer_id)
                                }
                              }}
                              aria-label={`${item.customer_relation.customer_name} 상세 보기`}
                            >
                              <div className="customer-icon-wrapper">
                                {item.customer_relation.customer_type === '법인' ? (
                                  <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor" className="customer-icon--corporate">
                                    <circle cx="10" cy="10" r="10" opacity="0.2" />
                                    <path d="M6 5h2v2H6V5zm0 3h2v2H6V8zm0 3h2v2H6v-2zm3-6h2v2H9V5zm0 3h2v2H9V8zm0 3h2v2H9v-2zm3-6h2v2h-2V5zm0 3h2v2h-2V8zm0 3h2v2h-2v-2zM5 14h10v2H5v-2z" />
                                  </svg>
                                ) : (
                                  <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor" className="customer-icon--personal">
                                    <circle cx="10" cy="10" r="10" opacity="0.2" />
                                    <circle cx="10" cy="7" r="3" />
                                    <path d="M10 11c-3 0-5 2-5 4v2h10v-2c0-2-2-4-5-4z" />
                                  </svg>
                                )}
                              </div>
                              <span className="customer-name-text">{item.customer_relation.customer_name}</span>
                            </button>
                          )
                        ) : (
                          <span className="customer-none">-</span>
                        )}
                      </div>

                      {/* 상태 */}
                      <div className="row-status">
                        <Tooltip content={status.label}>
                          <div className={`status-icon status-${status.status}`}>
                            {status.icon}
                          </div>
                        </Tooltip>
                      </div>

                      {/* P3-1: 유사도 3단계 도트 시스템 (시맨틱 검색 시만 표시) */}
                      {searchMode === 'semantic' && (
                        <div className="row-similarity">
                          {score !== null && (
                            <Tooltip content={`유사도: ${getSimilarityLevel(score).percentage} - ${getSimilarityLevel(score).label}`}>
                              <div
                                className={`similarity-indicator similarity-${getSimilarityLevel(score).color}`}
                                aria-label={`유사도 ${getSimilarityLevel(score).percentage} ${getSimilarityLevel(score).label}`}
                              >
                                <span className="similarity-dot" />
                                <span className="similarity-text">{getSimilarityLevel(score).percentage}</span>
                              </div>
                            </Tooltip>
                          )}
                        </div>
                      )}

                      {/* 🍎 액션 버튼들 */}
                      <div className="row-actions">
                        {/* 🍎 상세 보기 버튼 (개발자 모드 전용) */}
                        {isDevMode && (
                        <Tooltip content="상세 보기">
                          <button
                            className="action-button action-button--detail"
                        onClick={(e) => {
                          e.stopPropagation()
                          handleDetailClick(item)
                        }}
                        aria-label="상세 보기"
                      >
                        <EyeIcon />
                      </button>
                    </Tooltip>
                        )}

                    {/* 🍎 요약 보기 버튼 */}
                    <Tooltip content={!(typeof (item as any).meta === 'object' && (item as any).meta?.summary) && !(typeof (item as any).ocr === 'object' && (item as any).ocr?.summary) ? '요약 없음' : '요약 보기'}>
                          <button
                            className="action-button action-button--summary"
                        disabled={!(typeof (item as any).meta === 'object' && (item as any).meta?.summary) && !(typeof (item as any).ocr === 'object' && (item as any).ocr?.summary)}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleSummaryClickInternal(item)
                        }}
                        aria-label="요약 보기"
                      >
                        <SummaryIcon />
                      </button>
                    </Tooltip>

                    {/* 🍎 전체 텍스트 보기 버튼 */}
                    <Tooltip content={(item as any).meta?.full_text || (item as any).ocr?.full_text ? '전체 텍스트 보기' : '전체 텍스트 없음'}>
                          <button
                            className="action-button action-button--full"
                        disabled={!(item as any).meta?.full_text && !(item as any).ocr?.full_text}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleFullTextClickInternal(item)
                        }}
                        aria-label="전체 텍스트 보기"
                      >
                        <DocumentIcon />
                      </button>
                    </Tooltip>

                    {/* 🍎 검색어 위치 버튼 (키워드 검색 시에만 표시) */}
                    {lastSearchMode === 'keyword' && (
                      <Tooltip content="검색어 위치 보기">
                        <button
                          type="button"
                          className="action-button action-button--keyword-location"
                          onClick={(e) => {
                            e.stopPropagation()
                            setSelectedDocumentForKeywordLocation(item)
                            setKeywordMatchIndex(0)  // 인덱스 초기화
                            setKeywordLocationModalVisible(true)
                          }}
                          aria-label="검색어 위치 보기"
                        >
                          <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
                            <path d="M11.742 10.344a6.5 6.5 0 1 0-1.397 1.398h-.001c.03.04.062.078.098.115l3.85 3.85a1 1 0 0 0 1.415-1.414l-3.85-3.85a1.007 1.007 0 0 0-.115-.1zM12 6.5a5.5 5.5 0 1 1-11 0 5.5 5.5 0 0 1 11 0z"/>
                            <path d="M6.5 3a.5.5 0 0 1 .5.5V6h2.5a.5.5 0 0 1 0 1H7v2.5a.5.5 0 0 1-1 0V7H3.5a.5.5 0 0 1 0-1H6V3.5a.5.5 0 0 1 .5-.5z"/>
                          </svg>
                        </button>
                      </Tooltip>
                    )}

                    {/* 🍎 고객에게 연결 버튼 (DEV 모드에서만 표시) */}
                    {isDevMode && (
                      <Tooltip content={linkTooltip}>
                        <button
                          type="button"
                          className="action-button action-button--link"
                          onClick={(e) => {
                            e.stopPropagation()
                            if (canLink) {
                              handleLinkClickInternal(item)
                            }
                          }}
                          aria-label={linkTooltip}
                          disabled={!canLink}
                          data-disabled={!canLink}
                          tabIndex={canLink ? 0 : -1}
                        >
                          <LinkIcon />
                        </button>
                      </Tooltip>
                    )}
                      </div>
                    </div>
                  )
                })}
              </div>

              {/* 🍎 페이지네이션 */}
              {totalSearchPages > 1 && (
                <div className="search-results-pagination">
                  <button
                    type="button"
                    className="search-results-pagination__btn"
                    onClick={() => handlePageChange(Math.max(1, searchPage - 1))}
                    disabled={searchPage <= 1 || isLoading}
                    aria-label="이전 페이지"
                  >
                    <SFSymbol name="chevron.left" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.SEMIBOLD} decorative />
                  </button>
                  <span className="search-results-pagination__info">
                    <span className="search-results-pagination__size">{SEARCH_PAGE_SIZE}건씩</span>
                    {searchPage} / {totalSearchPages}
                  </span>
                  <button
                    type="button"
                    className="search-results-pagination__btn"
                    onClick={() => handlePageChange(Math.min(totalSearchPages, searchPage + 1))}
                    disabled={searchPage >= totalSearchPages || isLoading}
                    aria-label="다음 페이지"
                  >
                    <SFSymbol name="chevron.right" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.SEMIBOLD} decorative />
                  </button>
                </div>
              )}
            </>
          ) : (
            !isLoading && (
              <div className="search-empty" role="status">
                {lastSearchMode ? (
                  <div className="search-no-results">
                    <div className="no-results-icon"><SFSymbol name="magnifyingglass" size={SFSymbolSize.TITLE_2} weight={SFSymbolWeight.MEDIUM} decorative /></div>
                    <div className="no-results-text">
                      <div className="no-results-title">검색 결과가 없습니다</div>
                      <div className="no-results-description">
                        다른 검색어를 입력하거나 검색 모드를 변경해보세요.
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="search-guide">
                    <div className="guide-header">
                      <div className="guide-icon">
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                          <path className="lightbulb-bulb" d="M12 3C8.68629 3 6 5.68629 6 9C6 11.4363 7.4152 13.5392 9.42857 14.3572V17C9.42857 17.5523 9.87629 18 10.4286 18H13.5714C14.1237 18 14.5714 17.5523 14.5714 17V14.3572C16.5848 13.5392 18 11.4363 18 9C18 5.68629 15.3137 3 12 3Z" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                          <path className="lightbulb-base" d="M9 18H15M10 21H14" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                        </svg>
                      </div>
                      <h3 className="guide-title">사용 방법</h3>
                    </div>

                    <div className="guide-content">
                      <div className="guide-section">
                        <div className="guide-step">
                          <span className="step-number">1</span>
                          <div className="step-content">
                            <h4 className="step-title">고객 선택</h4>
                            <p className="step-description">특정 고객을 선택하면 해당 고객 문서만 검색합니다</p>
                          </div>
                        </div>

                        <div className="guide-step">
                          <span className="step-number">2</span>
                          <div className="step-content">
                            <h4 className="step-title">검색어 입력</h4>
                            <p className="step-description">찾고 싶은 내용을 검색창에 입력하세요</p>
                          </div>
                        </div>

                        <div className="guide-step">
                          <span className="step-number">3</span>
                          <div className="step-content">
                            <h4 className="step-title">검색 모드 선택</h4>
                            <div className="mode-options">
                              <div className="mode-option">
                                <span className="mode-badge mode-keyword">키워드 검색</span>
                                <p className="mode-description">모두 포함: 입력한 키워드를 모두 포함</p>
                                <p className="mode-description">하나라도 포함: 키워드 중 하나라도 포함</p>
                              </div>
                              <div className="mode-option">
                                <span className="mode-badge mode-ai">AI 검색</span>
                                <p className="mode-description">자연어로 질문하여 답을 검색</p>
                                <p className="mode-description mode-description--credit">크레딧 사용</p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>

                      <div className="guide-tips">
                        <ul className="tips-list">
                          <li>고객을 먼저 선택하면 더 빠르고 정확합니다</li>
                          <li>AI 검색 예: "암 진단 시 보험금은?"</li>
                        </ul>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )
          )}
        </div>
      </div>

      {/* Full Text 모달 (기존 - 더 이상 사용하지 않음) */}
      {selectedDocument && (
        <FullTextModal
          visible={isFullTextModalVisible}
          onClose={handleCloseFullTextModal}
          documentName={selectedDocument.name}
          fullText={selectedDocument.fullText}
        />
      )}

      {/* 🍎 새로운 모달들 (DocumentLibrary와 동일) */}
      <DocumentDetailModal
        visible={isDetailModalVisible}
        onClose={handleDetailModalClose}
        document={selectedDocumentForDetail}
      />
      <DocumentSummaryModal
        visible={isSummaryModalVisible}
        onClose={handleSummaryModalClose}
        document={selectedDocumentForSummary}
      />
      <DocumentFullTextModal
        visible={isFullTextModalVisibleNew}
        onClose={handleFullTextModalCloseNew}
        document={selectedDocumentForFullTextNew}
      />
      <DocumentLinkModal
        visible={isLinkModalVisible}
        onClose={handleLinkModalClose}
        document={selectedDocumentForLink}
        onFetchCustomerDocuments={fetchCustomerDocuments}
        onLink={linkDocumentToCustomer}
      />
      {/* 메모 모달 */}
      {selectedNotes && (
        <DocumentNotesModal
          visible={notesModalVisible}
          documentName={selectedNotes.documentName}
          customerName={selectedNotes.customerName}
          customerId={selectedNotes.customerId}
          documentId={selectedNotes.documentId}
          notes={selectedNotes.notes}
          onClose={() => {
            setNotesModalVisible(false)
            setSelectedNotes(null)
          }}
          onSave={handleSaveNotes}
          onDelete={handleDeleteNotes}
        />
      )}

      {/* 🍎 고객 선택 모달 */}
      <CustomerSelectorModal
        visible={isCustomerSelectorOpen}
        onClose={() => setIsCustomerSelectorOpen(false)}
        onSelect={(customer) => {
          setSelectedCustomer(customer)
          handleCustomerIdChange(customer._id)
          // 최근 고객 목록에 추가 (전역 상태 자동 업데이트)
          addRecentCustomer(customer)
          console.log('선택된 고객:', customer)
        }}
      />

      {/* 🍎 검색어 위치 모달 (키워드 검색 전용) */}
      {selectedDocumentForKeywordLocation && (() => {
        const totalMatches = getAllKeywordMatches(selectedDocumentForKeywordLocation).length
        const { displayMatches, originalMatches, displayName, originalName } = getFilenameKeywordMatchesDetailed(selectedDocumentForKeywordLocation)
        const currentIndex = keywordMatchIndex
        const hasPrev = currentIndex > 0
        const hasNext = currentIndex < totalMatches - 1
        const filename = (filenameMode === 'display' && displayName) || originalName

        return (
          <DraggableModal
            visible={keywordLocationModalVisible}
            onClose={() => {
              setKeywordLocationModalVisible(false)
              setSelectedDocumentForKeywordLocation(null)
              setKeywordMatchIndex(0)
            }}
            title={
              <div className="keyword-location-modal-title">
                <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
                  <path d="M11.742 10.344a6.5 6.5 0 1 0-1.397 1.398h-.001c.03.04.062.078.098.115l3.85 3.85a1 1 0 0 0 1.415-1.414l-3.85-3.85a1.007 1.007 0 0 0-.115-.1zM12 6.5a5.5 5.5 0 1 1-11 0 5.5 5.5 0 0 1 11 0z"/>
                </svg>
                <span>검색어 위치</span>
              </div>
            }
            initialWidth={800}
            initialHeight={600}
            minWidth={400}
            minHeight={300}
            storageKey="keyword-location-modal"
          >
            <div className="keyword-location-modal-content">
              <div className="keyword-location-modal-header">
                <span className="keyword-location-filename">
                  {filename}
                </span>
                <span className="keyword-location-query">
                  검색어: <strong>{query}</strong>
                </span>
              </div>

              {/* 🍎 매칭 요약: 파일명(원본/별칭) + 본문 — 2줄 텍스트 */}
              <div className="keyword-location-summary-text">
                <div className="keyword-location-summary-row">
                  <span className="keyword-location-summary-label">파일명:</span>
                  <span className={`keyword-location-summary-value ${originalMatches.length > 0 ? 'keyword-location-summary-value--match' : ''}`}>
                    원본 {originalMatches.length > 0 ? `${originalMatches.length}건 일치` : '일치 없음'}
                  </span>
                  {displayName && (
                    <>
                      <span className="keyword-location-summary-separator">,</span>
                      <span className={`keyword-location-summary-value ${displayMatches.length > 0 ? 'keyword-location-summary-value--match' : ''}`}>
                        별칭 {displayMatches.length > 0 ? `${displayMatches.length}건 일치` : '일치 없음'}
                      </span>
                    </>
                  )}
                </div>
                <div className="keyword-location-summary-row">
                  <span className="keyword-location-summary-label">본문:</span>
                  <span className={`keyword-location-summary-value ${totalMatches > 0 ? 'keyword-location-summary-value--match' : ''}`}>
                    {totalMatches > 0 ? `${totalMatches}건 일치` : '일치 없음'}
                  </span>
                </div>
              </div>

              {/* 🍎 별칭 매칭 영역 */}
              {displayMatches.length > 0 && (
                <div className="keyword-location-section">
                  <div className="keyword-location-section-label">별칭에서 발견</div>
                  <div className="keyword-location-section-content">
                    {highlightKeywordsNormal(displayName, displayMatches)}
                  </div>
                </div>
              )}

              {/* 🍎 원본 제목 매칭 영역 */}
              {originalMatches.length > 0 && (
                <div className="keyword-location-section">
                  <div className="keyword-location-section-label">원본 제목에서 발견</div>
                  <div className="keyword-location-section-content">
                    {highlightKeywordsNormal(originalName, originalMatches)}
                  </div>
                </div>
              )}

              {/* 🍎 본문 매칭 영역 */}
              <div className="keyword-location-section keyword-location-section--body">
                <div className="keyword-location-section-label">
                  본문{totalMatches > 0 ? ` (${totalMatches}건)` : ''}
                </div>

                {totalMatches > 0 && (
                  <div className="keyword-location-nav">
                    <button
                      type="button"
                      className="keyword-location-nav-btn"
                      onClick={() => setKeywordMatchIndex(prev => Math.max(0, prev - 1))}
                      disabled={!hasPrev}
                      aria-label="이전 결과"
                    >
                      <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
                        <path fillRule="evenodd" d="M11.354 1.646a.5.5 0 0 1 0 .708L5.707 8l5.647 5.646a.5.5 0 0 1-.708.708l-6-6a.5.5 0 0 1 0-.708l6-6a.5.5 0 0 1 .708 0z"/>
                      </svg>
                    </button>

                    <span className="keyword-location-counter">
                      <strong>{currentIndex + 1}</strong>
                      <span className="keyword-location-separator">/</span>
                      <span>{totalMatches}</span>
                    </span>

                    <button
                      type="button"
                      className="keyword-location-nav-btn"
                      onClick={() => setKeywordMatchIndex(prev => Math.min(totalMatches - 1, prev + 1))}
                      disabled={!hasNext}
                      aria-label="다음 결과"
                    >
                      <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
                        <path fillRule="evenodd" d="M4.646 1.646a.5.5 0 0 1 .708 0l6 6a.5.5 0 0 1 0 .708l-6 6a.5.5 0 0 1-.708-.708L10.293 8 4.646 2.354a.5.5 0 0 1 0-.708z"/>
                      </svg>
                    </button>
                  </div>
                )}

                <div className="keyword-location-text">
                  {totalMatches > 0 ? (() => {
                    const { snippet, currentKeywordOffset, currentKeywordLength } = getTextSnippetAtIndex(selectedDocumentForKeywordLocation, currentIndex)
                    return highlightKeywordsWithCurrent(snippet, currentKeywordOffset, currentKeywordLength)
                  })() : (() => {
                    const bodyText = (selectedDocumentForKeywordLocation as any).ocr?.full_text ||
                                     (selectedDocumentForKeywordLocation as any).meta?.full_text ||
                                     (selectedDocumentForKeywordLocation as any).text?.full_text || ''
                    return bodyText
                      ? <span className="keyword-location-body-preview">{bodyText}</span>
                      : <span className="keyword-location-no-match">본문 텍스트 없음</span>
                  })()}
                </div>
              </div>
            </div>
          </DraggableModal>
        )
      })()}

      {/* 🍎 문서 컨텍스트 메뉴 */}
      <ContextMenu
        visible={documentContextMenu.isOpen}
        position={documentContextMenu.position}
        sections={documentContextMenuSections}
        onClose={documentContextMenu.close}
      />

      {/* 이름 변경 모달 */}
      <RenameModal
        visible={renamingDoc !== null}
        onClose={handleRenameCancel}
        onConfirm={handleRenameConfirm}
        editField={filenameMode === 'original' ? 'originalName' : 'displayName'}
        originalName={renamingDoc?.originalName || ''}
        displayName={renamingDoc?.displayName}
      />
    </CenterPaneView>
  )
}

export default DocumentSearchView

/**
 * DocumentSearchView - Lazy Enrichment 회귀 테스트
 * @since 2026-04-02
 *
 * AI 검색 결과 50건 제한 제거 + 페이지 단위 lazy enrichment 도입에 대한 회귀 테스트
 *
 * 테스트 범위:
 * - searchDocuments()가 enrichment 없이 raw 결과 반환
 * - enrichPageResults()가 페이지 단위 enrichment 수행
 * - enrichment 캐시: 이미 enrich된 건 재호출 안 함
 * - AbortController: 새 검색 시 진행 중인 enrichment 취소
 * - top_k 하드코딩 제거 확인
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { SearchService } from '@/services/searchService'
import type { SemanticSearchResultItem } from '@/entities/search'

// fetch mock
const mockFetch = vi.fn()
global.fetch = mockFetch

// errorReporter mock
vi.mock('@/shared/lib/errorReporter', () => ({
  errorReporter: {
    reportApiError: vi.fn()
  }
}))

// API 유틸 mock
vi.mock('@/shared/lib/api', () => ({
  API_CONFIG: { BASE_URL: 'http://localhost:3000' },
  getAuthHeaders: () => ({}),
  getAuthToken: () => 'mock-token',
  getCurrentUserId: () => 'test-user'
}))

describe('SearchService - Lazy Enrichment (이슈 #15)', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  describe('[회귀] searchDocuments()는 raw 결과만 반환', () => {
    it('시맨틱 검색 결과를 enrichment 없이 그대로 반환해야 함', async () => {
      const rawResults = [
        { id: 'q1', score: 0.9, payload: { doc_id: 'doc1', original_name: 'file1.pdf' } },
        { id: 'q2', score: 0.8, payload: { doc_id: 'doc2', original_name: 'file2.pdf' } },
      ]

      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({
          answer: 'AI 답변',
          search_results: rawResults,
        })
      })

      const result = await SearchService.searchDocuments({
        query: '보험 청구',
        search_mode: 'semantic',
      })

      // fetch는 검색 API 1회만 호출 (enrichment API 호출 없음)
      expect(mockFetch).toHaveBeenCalledTimes(1)
      expect(result.search_results).toEqual(rawResults)
      expect(result.answer).toBe('AI 답변')
    })

    it('키워드 검색 결과도 그대로 반환해야 함', async () => {
      const rawResults = [
        { _id: 'doc1', filename: 'file1.pdf', meta: { summary: '요약' } },
      ]

      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({
          answer: null,
          search_results: rawResults,
        })
      })

      const result = await SearchService.searchDocuments({
        query: '보험',
        search_mode: 'keyword',
      })

      expect(mockFetch).toHaveBeenCalledTimes(1)
      expect(result.search_results).toEqual(rawResults)
    })

    it('top_k가 요청에 포함되지 않아야 함 (하드코딩 제거 확인)', async () => {
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ search_results: [] })
      })

      await SearchService.searchDocuments({
        query: '테스트',
        search_mode: 'semantic',
      })

      const requestBody = JSON.parse(mockFetch.mock.calls[0][1].body)
      expect(requestBody.top_k).toBeUndefined()
    })
  })

  describe('[회귀] enrichPageResults()는 페이지 단위 enrichment 수행', () => {
    it('각 문서에 대해 /api/documents/{docId}/status 호출', async () => {
      const items: SemanticSearchResultItem[] = [
        { id: 'q1', score: 0.9, payload: { doc_id: 'doc1', original_name: 'file1.pdf' } },
        { id: 'q2', score: 0.8, payload: { doc_id: 'doc2', original_name: 'file2.pdf' } },
      ]

      // 문서 상태 API 응답 mock
      mockFetch
        .mockResolvedValueOnce({
          ok: true,
          json: () => Promise.resolve({
            success: true,
            data: {
              _id: 'doc1',
              raw: {
                meta: { originalName: 'file1.pdf', summary: '요약1' },
                ocr: { full_text: '텍스트1' },
                upload: { originalName: 'file1.pdf' },
                customer_relation: null,
                ownerId: 'user1',
                customerId: null,
                displayName: null,
              },
              computed: {
                uiStages: [],
                overallStatus: 'completed',
                progress: 100,
              }
            }
          })
        })
        .mockResolvedValueOnce({
          ok: true,
          json: () => Promise.resolve({
            success: true,
            data: {
              _id: 'doc2',
              raw: {
                meta: { originalName: 'file2.pdf', summary: '요약2' },
                ocr: { full_text: '텍스트2' },
                upload: { originalName: 'file2.pdf' },
                customer_relation: null,
                ownerId: 'user1',
                customerId: null,
                displayName: null,
              },
              computed: {
                uiStages: [],
                overallStatus: 'completed',
                progress: 100,
              }
            }
          })
        })

      const result = await SearchService.enrichPageResults(items)

      // 2건에 대해 각각 /api/documents/{docId}/status 호출
      expect(mockFetch).toHaveBeenCalledTimes(2)
      expect(result).toHaveLength(2)
      // enriched 결과에 meta, ocr 등이 병합되어야 함
      expect(result[0]).toHaveProperty('meta')
      expect(result[0]).toHaveProperty('ocr')
      expect(result[0]).toHaveProperty('_id', 'doc1')
      // 원본 score는 유지되어야 함
      expect((result[0] as any).score).toBe(0.9)
    })

    it('개별 문서 조회 실패 시 raw 결과 유지', async () => {
      const items: SemanticSearchResultItem[] = [
        { id: 'q1', score: 0.9, payload: { doc_id: 'doc1', original_name: 'file1.pdf' } },
      ]

      mockFetch.mockResolvedValueOnce({
        ok: false,
        status: 404,
      })

      const result = await SearchService.enrichPageResults(items)

      expect(result).toHaveLength(1)
      // enrichment 실패 → raw 결과 그대로
      expect(result[0]).toEqual(items[0])
    })

    it('doc_id가 없는 항목은 그대로 반환', async () => {
      const items: SemanticSearchResultItem[] = [
        { id: 'q1', score: 0.5, payload: {} },
      ]

      const result = await SearchService.enrichPageResults(items)

      expect(mockFetch).not.toHaveBeenCalled()
      expect(result).toHaveLength(1)
      expect(result[0]).toEqual(items[0])
    })

    it('빈 배열 입력 시 빈 배열 반환', async () => {
      const result = await SearchService.enrichPageResults([])

      expect(mockFetch).not.toHaveBeenCalled()
      expect(result).toEqual([])
    })
  })

  describe('[회귀] AbortController 지원', () => {
    it('abort 시 AbortError를 throw', async () => {
      const items: SemanticSearchResultItem[] = [
        { id: 'q1', score: 0.9, payload: { doc_id: 'doc1', original_name: 'file1.pdf' } },
      ]

      const controller = new AbortController()

      mockFetch.mockImplementation(() => {
        // fetch 호출 시 즉시 abort
        controller.abort()
        return Promise.reject(new DOMException('Aborted', 'AbortError'))
      })

      await expect(
        SearchService.enrichPageResults(items, controller.signal)
      ).rejects.toThrow()
    })
  })

  describe('[회귀] customer_name 보강', () => {
    it('유효한 customerId에 대해 고객 정보 조회', async () => {
      const validCustomerId = 'abcdef1234567890abcdef12'

      const items: SemanticSearchResultItem[] = [
        {
          id: 'q1',
          score: 0.9,
          payload: { doc_id: 'doc1', original_name: 'file1.pdf' },
        },
      ]

      // 문서 상태 API
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({
          success: true,
          data: {
            _id: 'doc1',
            raw: {
              meta: {},
              ocr: {},
              upload: {},
              customer_relation: { customer_id: validCustomerId },
              ownerId: 'user1',
              customerId: validCustomerId,
              displayName: null,
            },
            computed: { uiStages: [], overallStatus: 'completed', progress: 100 }
          }
        })
      })
      // 고객 API
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({
          success: true,
          data: {
            personal_info: { name: '홍길동' },
            insurance_info: { customer_type: '개인' }
          }
        })
      })

      const result = await SearchService.enrichPageResults(items)

      expect(result[0]).toHaveProperty('customer_relation')
      expect((result[0] as any).customer_relation.customer_name).toBe('홍길동')
      expect((result[0] as any).customer_relation.customer_type).toBe('개인')
    })

    it('플레이스홀더 customerId는 내 보관함으로 표시', async () => {
      const placeholderId = '000000000000000000000001'

      const items: SemanticSearchResultItem[] = [
        {
          id: 'q1',
          score: 0.9,
          payload: { doc_id: 'doc1', original_name: 'file1.pdf' },
        },
      ]

      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({
          success: true,
          data: {
            _id: 'doc1',
            raw: {
              meta: {},
              ocr: {},
              upload: {},
              customer_relation: { customer_id: placeholderId },
              ownerId: 'user1',
              customerId: placeholderId,
              displayName: null,
            },
            computed: { uiStages: [], overallStatus: 'completed', progress: 100 }
          }
        })
      })

      const result = await SearchService.enrichPageResults(items)

      // 플레이스홀더 → 고객 API 호출 없이 "내 보관함" 표시
      expect(mockFetch).toHaveBeenCalledTimes(1) // 문서 API만 호출
      expect((result[0] as any).customer_relation.customer_name).toBe('내 보관함')
    })
  })

  describe('[회귀] 정렬은 raw 결과 기준', () => {
    it('enrichment 전후로 score 값이 변경되지 않아야 함', async () => {
      const items: SemanticSearchResultItem[] = [
        { id: 'q1', score: 0.95, final_score: 0.88, payload: { doc_id: 'doc1', original_name: 'a.pdf' } },
        { id: 'q2', score: 0.70, final_score: 0.65, payload: { doc_id: 'doc2', original_name: 'b.pdf' } },
      ]

      // 두 건 모두 enrichment 성공
      mockFetch
        .mockResolvedValueOnce({
          ok: true,
          json: () => Promise.resolve({
            success: true,
            data: { _id: 'doc1', raw: { meta: {}, ocr: {}, upload: {}, customer_relation: null, ownerId: 'u', customerId: null, displayName: null }, computed: { uiStages: [], overallStatus: 'completed', progress: 100 } }
          })
        })
        .mockResolvedValueOnce({
          ok: true,
          json: () => Promise.resolve({
            success: true,
            data: { _id: 'doc2', raw: { meta: {}, ocr: {}, upload: {}, customer_relation: null, ownerId: 'u', customerId: null, displayName: null }, computed: { uiStages: [], overallStatus: 'completed', progress: 100 } }
          })
        })

      const result = await SearchService.enrichPageResults(items)

      // score, final_score가 원본 그대로 유지
      expect((result[0] as any).score).toBe(0.95)
      expect((result[0] as any).final_score).toBe(0.88)
      expect((result[1] as any).score).toBe(0.70)
      expect((result[1] as any).final_score).toBe(0.65)
    })
  })
})

/**
 * DocumentLinkModal Component
 * @version 3.0.0 - 🍎 공통 Modal 컴포넌트 적용
 * @updated 2025-11-04
 * @description 문서를 고객에게 연결하는 모달
 *
 * - 공통 Modal 컴포넌트 사용 (Portal, ESC, body overflow 자동 처리)
 * - iOS 스타일 디자인
 */

import React, { useEffect, useMemo, useState, useCallback } from 'react'
import type { Document, DocumentCustomerRelation } from '../../../../types/documentStatus'
import { DocumentStatusService } from '../../../../services/DocumentStatusService'
import type { Customer } from '@/entities/customer'
import type { CustomerDocumentsResult } from '../../../../services/DocumentService'
import { Button, Dropdown, type DropdownOption, Tooltip, Modal } from '../../../../shared/ui'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../../SFSymbol'
import CustomerSelectorModal from '../../../../shared/ui/CustomerSelectorModal/CustomerSelectorModal'
import { useRecentCustomersStore, type RecentCustomer } from '@/shared/store/useRecentCustomersStore'
import { SearchService } from '@/services/searchService'
import type { SearchResultItem } from '@/entities/search'
import { errorReporter } from '@/shared/lib/errorReporter'
import { invalidateQueries } from '@/app/queryClient'
import { getDocumentTypeLabelsMap } from '@/shared/constants/documentCategories'
import './DocumentLinkModal.css'

interface DocumentLinkModalProps {
  visible: boolean
  /** 단일 문서 (하위 호환성) 또는 여러 문서 배열 */
  document?: Document | null
  documents?: Document[]
  onClose: () => void
  /** 연결 성공 시 호출되는 콜백 (모달 닫기 전) */
  onLinkSuccess?: () => void
  onFetchCustomerDocuments: (customerId: string) => Promise<CustomerDocumentsResult>
  onLink: (params: {
    customerId: string
    documentId: string
    relationshipType: string
    notes?: string
  }) => Promise<DocumentCustomerRelation | undefined>
}

// 시스템 유형 제외 필터
const SYSTEM_TYPES = new Set(['annual_report', 'customer_review', 'unspecified'])

export const DocumentLinkModal: React.FC<DocumentLinkModalProps> = ({
  visible,
  document,
  documents,
  onClose,
  onLinkSuccess,
  onFetchCustomerDocuments,
  onLink
}) => {
  const [isCustomerSelectorOpen, setIsCustomerSelectorOpen] = useState(false)
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null)
  const [relationshipType, setRelationshipType] = useState<string>('general')
  const [notes, setNotes] = useState<string>('')
  const [duplicateWarning, setDuplicateWarning] = useState<string | null>(null)
  const [linkLoading, setLinkLoading] = useState(false)
  const [feedbackMessage, setFeedbackMessage] = useState<string | null>(null)
  // 최근 선택한 고객 목록 (전역 상태)
  const { recentCustomers, addRecentCustomer, getRecentCustomers } = useRecentCustomersStore()

  // DB 캐시 기반 문서유형 옵션 (시스템 유형 제외)
  const relationshipOptions = useMemo<DropdownOption[]>(() => {
    return Object.entries(getDocumentTypeLabelsMap())
      .filter(([value]) => !SYSTEM_TYPES.has(value))
      .map(([value, label]) => ({ value, label }))
  }, [])

  // 단일 문서 또는 여러 문서 배열 처리
  const targetDocuments = useMemo(() => {
    if (documents && documents.length > 0) {
      return documents
    }
    if (document) {
      return [document]
    }
    return []
  }, [document, documents])

  // documents prop이 있으면 bulk mode (문서가 1개여도)
  const isBulkMode = !!(documents && documents.length > 0)

  // 단일 문서 모드에서만 사용 (일괄 모드에서는 targetDocuments 사용)
  // SearchResultItem과 Document 모두 지원
  const documentName = useMemo(() => {
    if (!document) return ''

    // SearchResultItem인 경우 (payload, upload, meta 등의 구조)
    if ('payload' in document || 'upload' in document) {
      return SearchService.getOriginalName(document as SearchResultItem)
    }

    // Document 타입인 경우
    return DocumentStatusService.extractFilename(document)
  }, [document])

  /**
   * 모달이 열릴 때 상태 초기화
   */
  useEffect(() => {
    if (visible) {
      setSelectedCustomer(null)
      setRelationshipType('general')
      setNotes('')
      setDuplicateWarning(null)
      setFeedbackMessage(null)
      // 최근 선택한 고객 목록은 Zustand store에서 자동으로 관리됨
    }
  }, [visible])

  /**
   * 고객 선택 시 중복 연결 검사 (단일/일괄 모두 지원)
   */
  const handleSelectCustomer = async (customer: Customer) => {
    setSelectedCustomer(customer)
    setDuplicateWarning(null)
    setFeedbackMessage(null)
    setIsCustomerSelectorOpen(false)

    // 최근 선택 고객 목록에 추가 (전역 상태 자동 업데이트)
    addRecentCustomer(customer)

    if (targetDocuments.length === 0) {
      return
    }

    try {
      const customerDocs = await onFetchCustomerDocuments(customer._id)
      const customerDocIds = new Set(customerDocs.documents?.map(doc => String(doc._id)) || [])

      const duplicates = targetDocuments.filter(doc => {
        const docId = doc._id || (doc as Record<string, string | undefined>)?.['id'] || ''
        return customerDocIds.has(docId)
      })

      if (duplicates.length > 0) {
        if (isBulkMode) {
          setDuplicateWarning(`${duplicates.length}개의 문서가 이미 선택한 고객과 연결되어 있습니다.`)
        } else {
          setDuplicateWarning('이 문서는 이미 선택한 고객과 연결되어 있습니다.')
        }
      }
    } catch (error) {
      console.error('고객 문서 조회 오류:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentLinkModal.handleSelectCustomer', payload: { customerId: customer._id } })
      setDuplicateWarning(null)
    }
  }

  /**
   * 최근 선택 고객에서 빠른 선택 처리
   */
  const handleQuickSelectCustomer = async (recentCustomer: RecentCustomer) => {
    // Customer 객체 형태로 변환
    const customer: Customer = {
      _id: recentCustomer._id,
      personal_info: {
        name: recentCustomer.name,
        mobile_phone: recentCustomer.phone,
        address: recentCustomer.address ? {
          address1: recentCustomer.address
        } : undefined
      }
    } as Customer

    // 기존 고객 선택 핸들러 호출
    await handleSelectCustomer(customer)
  }

  /**
   * 🍎 최근 고객 드롭다운 옵션 생성 (DocumentSearchView와 동일)
   */
  const recentCustomerOptions = useMemo((): DropdownOption[] => {
    const options: DropdownOption[] = [
      { value: '', label: '고객 미선택' }
    ]

    // 전역 상태에서 최근 고객 목록 가져오기
    const recent = getRecentCustomers()
    recent.forEach(customer => {
      options.push({
        value: customer._id,
        label: customer.name
      })
    })

    return options
  }, [recentCustomers, getRecentCustomers])

  /**
   * 🍎 최근 고객 드롭다운에서 선택 핸들러 (DocumentSearchView와 동일)
   */
  const handleRecentCustomerSelect = useCallback(async (customerId: string) => {
    if (!customerId) {
      // "고객 미선택" 선택
      setSelectedCustomer(null)
      setDuplicateWarning(null)
      return
    }

    // 전역 상태에서 최근 고객 목록 가져와서 찾기
    const recent = getRecentCustomers()
    const recentCustomer = recent.find(c => c._id === customerId)
    if (recentCustomer) {
      // Customer 객체 재구성
      await handleQuickSelectCustomer(recentCustomer)
    }
  }, [getRecentCustomers, handleQuickSelectCustomer])

  /**
   * 연결 실행 (단일/일괄 모두 지원)
   */
  const handleLink = async () => {
    if (targetDocuments.length === 0 || !selectedCustomer) return

    setLinkLoading(true)
    setFeedbackMessage(null)

    try {
      const trimmedNotes = notes.trim()
      let successCount = 0
      let failureCount = 0

      // 모든 문서에 대해 순차적으로 연결 시도
      for (const doc of targetDocuments) {
        const docId = doc._id || (doc as Record<string, string | undefined>)?.['id'] || ''
        if (!docId) {
          failureCount++
          continue
        }

        try {
          const params: { customerId: string; documentId: string; relationshipType: string; notes?: string } = {
            customerId: selectedCustomer._id,
            documentId: docId,
            relationshipType
          }
          if (trimmedNotes) {
            params.notes = trimmedNotes
          }
          await onLink(params)

          // TanStack Query 캐시 무효화 + 레거시 이벤트 (고객 상세 페이지 자동 새로고침용)
          invalidateQueries.documentLinked({
            documentId: docId,
            customerId: selectedCustomer._id,
            timestamp: new Date().toISOString()
          })

          successCount++
        } catch (err) {
          console.error(`문서 ${docId} 연결 실패:`, err)
          errorReporter.reportApiError(err as Error, { component: 'DocumentLinkModal.handleLink.item', payload: { docId, customerId: selectedCustomer._id } })
          failureCount++
        }
      }

      if (isBulkMode) {
        if (failureCount === 0) {
          setFeedbackMessage(`${successCount}개의 문서가 고객에게 성공적으로 연결되었습니다.`)
        } else {
          setFeedbackMessage(
            `${successCount}개 성공, ${failureCount}개 실패했습니다.`
          )
        }
      } else {
        setFeedbackMessage('문서가 고객에게 성공적으로 연결되었습니다.')
      }

      if (import.meta.env.DEV) {
        console.log('[DocumentLinkModal] 일괄 연결 완료:', {
          total: targetDocuments.length,
          success: successCount,
          failure: failureCount,
          customerId: selectedCustomer._id
        })
      }

      // 성공한 문서가 하나라도 있으면 성공 콜백 호출 후 모달 닫기
      if (successCount > 0) {
        onLinkSuccess?.()
        onClose()
      }
    } catch (error) {
      console.error('문서 연결 오류:', error)
      errorReporter.reportApiError(error as Error, { component: 'DocumentLinkModal.handleLink' })
      const message =
        error instanceof Error
          ? error.message
          : '문서를 고객에게 연결하는 중 문제가 발생했습니다.'
      setFeedbackMessage(message)
    } finally {
      setLinkLoading(false)
    }
  }

  if (!visible || targetDocuments.length === 0) {
    return null
  }

  const isLinkDisabled = !selectedCustomer || Boolean(duplicateWarning) || linkLoading

  const footer = (
    <>
      <Tooltip content="모달을 닫습니다">
        <Button
          variant="ghost"
          size="md"
          onClick={onClose}
          className="document-link-modal__button document-link-modal__button--cancel"
        >
          취소
        </Button>
      </Tooltip>
      <Tooltip content={duplicateWarning ? duplicateWarning : '선택한 고객과 문서를 연결합니다'}>
        <Button
          variant="primary"
          size="md"
          onClick={handleLink}
          disabled={isLinkDisabled}
          loading={linkLoading}
          className="document-link-modal__button document-link-modal__button--confirm"
        >
          연결하기
        </Button>
      </Tooltip>
    </>
  )

  return (
    <>
    <Modal
      visible={visible}
      onClose={onClose}
      title={
        <div className="document-link-modal__title">
          <SFSymbol
            name="person.crop.circle.badge.plus"
            size={SFSymbolSize.TITLE_2}
            weight={SFSymbolWeight.MEDIUM}
            decorative={true}
          />
          <span>문서를 고객에게 연결</span>
        </div>
      }
      size={isBulkMode ? "xl" : "md"}
      footer={footer}
      ariaLabel="문서를 고객에게 연결"
      className="document-link-modal"
    >
      {/* Document Info - 단일 문서 또는 여러 문서 리스트 */}
      <section className="document-link-modal__section document-link-modal__section--document">
        {isBulkMode ? (
          <>
            <div className="document-link-modal__bulk-header">
              <span className="document-link-modal__bulk-count">
                📄 {targetDocuments.length}개의 문서 선택됨
              </span>
            </div>
            <div className="document-link-modal__document-list">
              {targetDocuments.map((doc, index) => {
                const docId = doc._id || (doc as Record<string, string | undefined>)?.['id'] || ''
                // SearchResultItem과 Document 모두 지원
                const docName = ('payload' in doc || 'upload' in doc)
                  ? SearchService.getOriginalName(doc as SearchResultItem)
                  : DocumentStatusService.extractFilename(doc)
                const docStatus = DocumentStatusService.extractStatus(doc)
                const statusLabel = DocumentStatusService.getStatusLabel(docStatus)
                return (
                  <div key={docId || index} className="document-list-item">
                    <span className="document-list-item__icon" aria-hidden="true">📄</span>
                    <span className="document-list-item__name" title={docName}>
                      {docName}
                    </span>
                    <span className="document-list-item__status">{statusLabel}</span>
                  </div>
                )
              })}
            </div>
          </>
        ) : (
          <div className="document-chip">
            <span className="document-chip__icon" aria-hidden="true">📄</span>
            <span className="document-chip__name">{documentName}</span>
            <span className="document-chip__status">
              {DocumentStatusService.getStatusLabel(DocumentStatusService.extractStatus(targetDocuments[0] || document!))}
            </span>
          </div>
        )}
      </section>

      {/* Customer Selection & Document Type */}
      <section className="document-link-modal__section">
        <div className="document-link-modal__main-row">
          {/* 🍎 고객 선택 (DocumentSearchView와 동일한 패턴) */}
          <div className="document-link-modal__customer-selection">
            <Button
              variant="secondary"
              size="md"
              onClick={() => setIsCustomerSelectorOpen(true)}
            >
              고객선택
            </Button>

            {/* 🍎 선택된 고객 표시 또는 최근 고객 드롭다운 */}
            <div className="document-link-modal__selected-customer">
              {selectedCustomer ? (
                <>
                  <span className="selected-customer-name">
                    {selectedCustomer.personal_info?.name || '이름 없음'}
                  </span>
                  <button
                    className="clear-customer-button"
                    onClick={() => {
                      setSelectedCustomer(null)
                      setDuplicateWarning(null)
                    }}
                    aria-label="고객 선택 해제"
                    title="고객 선택 해제"
                  >
                    ✕
                  </button>
                </>
              ) : (
                <Dropdown
                  value=""
                  options={recentCustomerOptions}
                  onChange={handleRecentCustomerSelect}
                  width="100%"
                  aria-label="최근 선택한 고객"
                />
              )}
            </div>
          </div>

          {/* 문서 유형 */}
          <div className="document-link-modal__field document-link-modal__field--inline">
            <label htmlFor="relationship-type">문서 유형</label>
            <Dropdown
              value={relationshipType}
              options={relationshipOptions}
              onChange={setRelationshipType}
              aria-label="문서 유형 선택"
              width="100%"
            />
          </div>
        </div>
      </section>

    {/* Memo */}
    <section className="document-link-modal__section">
      <div className="document-link-modal__field">
        <label htmlFor="link-notes">
          메모
          <span className="document-link-modal__optional">선택 사항</span>
        </label>
        <textarea
          id="link-notes"
          className="form-textarea document-link-modal__textarea"
          value={notes}
          onChange={(event) => setNotes(event.target.value)}
          placeholder="이 문서와 고객의 관계에 대한 참고 메모를 남겨주세요."
          rows={2}
        />
      </div>
    </section>

    {/* Feedback */}
    {feedbackMessage && (
      <section className="document-link-modal__section">
        <p className="document-link-modal__feedback">{feedbackMessage}</p>
      </section>
    )}
    </Modal>

    {/* 🍎 고객 선택 모달 */}
    <CustomerSelectorModal
      visible={isCustomerSelectorOpen}
      onClose={() => setIsCustomerSelectorOpen(false)}
      onSelect={handleSelectCustomer}
    />
    </>
  )
}

export default DocumentLinkModal

/**
 * DocumentStatusList Component
 * @version 3.0.0 - 🍎 DocumentLibrary 리스트 구조 완벽 복제
 *
 * 공간 효율적인 리스트 레이아웃
 */

import React, { useState, useCallback, useRef } from 'react'
import { useAppleConfirm } from '@/contexts/AppleConfirmProvider'
import { useDevModeStore } from '@/shared/store/useDevModeStore'
import { Tooltip, DocumentTypeCell, DocumentTypeBadge } from '@/shared/ui'
import { FilenameModeToggle } from '@/shared/ui/FilenameModeToggle'
import { SortIndicator } from '@/shared/ui/SortIndicator'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../../SFSymbol'
import { DocumentUtils } from '@/entities/document'
import { DocumentStatusService } from '../../../../services/DocumentStatusService'
import { DocumentService } from '../../../../services/DocumentService'
import { api } from '@/shared/lib/api'
import type { Document } from '../../../../types/documentStatus'
import {
  DocumentIcon,
  EyeIcon,
  LinkIcon,
  SummaryIcon
} from '../../components/DocumentActionIcons'
// InlineRenameInput 제거 — 부모 뷰에서 RenameModal로 대체
import { DocumentNotesModal } from './DocumentNotesModal'
import { useUserStore } from '../../../../stores/user'
import { errorReporter } from '@/shared/lib/errorReporter'
import { documentTypesService } from '../../../../services/documentTypesService'
import { highlightText } from '@/shared/lib/highlightText'
import { useColumnResize } from '@/shared/hooks'
import type { ColumnDef } from '@/shared/hooks'
import './DocumentStatusList.header.css';
import './DocumentStatusList.cells.css';
import './DocumentStatusList.responsive.css';
import './DocumentStatusList.badges.css';

// ─── 칼럼 리사이즈 정의 ───

/** 기본 칼럼 정의 (삭제 모드가 아닌 일반 상태) */
const COLUMN_DEFS: ColumnDef[] = [
  { defaultWidth: '45px',                defaultPx: 45,  minWidth: 30,  resizable: true  },  // 유형
  { defaultWidth: 'minmax(120px, 1fr)',   defaultPx: 300, minWidth: 120, resizable: true  },  // 파일명
  { defaultWidth: '90px',                defaultPx: 90,  minWidth: 60,  resizable: true  },  // 문서 유형
  { defaultWidth: '70px',                defaultPx: 70,  minWidth: 50,  resizable: true  },  // 크기
  { defaultWidth: '60px',                defaultPx: 60,  minWidth: 40,  resizable: true  },  // 타입
  { defaultWidth: '120px',               defaultPx: 120, minWidth: 80,  resizable: true  },  // 업로드 날짜
  { defaultWidth: '80px',                defaultPx: 80,  minWidth: 50,  resizable: true  },  // 상태
  { defaultWidth: 'minmax(130px, auto)',  defaultPx: 150, minWidth: 100, resizable: true  },  // 연결된 고객
  { defaultWidth: '52px',                defaultPx: 52,  minWidth: 40,  resizable: false },  // 액션 버튼
]

const COLUMN_RESIZE_STORAGE_KEY = 'aims-document-library-column-widths'

// ─── DocumentStatusRow: 개별 행 컴포넌트 (React.memo) ───

interface DocumentStatusRowProps {
  document: Document
  index: number
  // per-row boolean (부모에서 계산하여 전달 — memo 최적화)
  isSelected: boolean
  isPreview?: boolean
  isUpdating: boolean
  isRetryingPdf: boolean
  isRetryingOcr: boolean
  // 모드
  isDeleteMode: boolean
  isBulkLinkMode: boolean
  isAliasMode: boolean
  isDevMode: boolean
  // 사용자 ID (내 파일 판별)
  userId: string | null
  // 파일명 표시 모드
  filenameMode: 'display' | 'original'
  // 콜백
  onDocumentClick?: (documentId: string) => void
  onDocumentDoubleClick?: (document: Document) => void
  onSelectDocument?: (documentId: string, event: React.MouseEvent) => void
  onDetailClick?: (document: Document) => void
  onSummaryClick?: (document: Document) => void
  onFullTextClick?: (document: Document) => void
  onLinkClick?: (document: Document) => void
  onUnlinkedCustomerClick?: (documentId: string) => void
  onChangeCustomerClick?: (documentId: string, currentCustomerId: string) => void
  onCustomerClick?: (customerId: string) => void
  onCustomerDoubleClick?: (customerId: string) => void
  onRowContextMenu?: (document: Document, event: React.MouseEvent) => void
  onRetryPdfConversion: (documentId: string, e: React.MouseEvent) => void
  onRetryOcr: (documentId: string, e: React.MouseEvent) => void
  onDocTypeChange: (documentId: string, newType: string) => void
  // 호버 액션: 이름변경/삭제
  onRenameClick?: (document: Document) => void
  onDeleteClick?: (document: Document) => void
  renamingDocumentId?: string | null
  onRenameConfirm?: (documentId: string, newName: string) => void
  onRenameCancel?: () => void
  // 검색어 하이라이트
  searchTerm?: string
  // 칼럼 리사이즈 gridTemplateColumns
  gridTemplateColumns?: string | null
}

const DocumentStatusRow = React.memo<DocumentStatusRowProps>(({
  document,
  index,
  isSelected,
  isPreview,
  isUpdating,
  isRetryingPdf,
  isRetryingOcr,
  isDeleteMode,
  isBulkLinkMode,
  isAliasMode,
  isDevMode,
  userId,
  filenameMode,
  onDocumentClick,
  onDocumentDoubleClick,
  onSelectDocument,
  onDetailClick,
  onSummaryClick,
  onFullTextClick,
  onLinkClick,
  onUnlinkedCustomerClick,
  onChangeCustomerClick,
  onCustomerClick,
  onCustomerDoubleClick,
  onRowContextMenu,
  onRetryPdfConversion,
  onRetryOcr,
  onDocTypeChange,
  onRenameClick,
  onDeleteClick,
  renamingDocumentId: _renamingDocumentId,
  onRenameConfirm: _onRenameConfirm,
  onRenameCancel: _onRenameCancel,
  searchTerm,
  gridTemplateColumns,
}) => {
  // 각 Row 내부에서 싱글/더블클릭 타이머를 자체 관리
  const documentClickTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  const customerClickTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const status = DocumentStatusService.extractStatus(document)
  const progress = DocumentStatusService.extractProgress(document)
  // quota_exceeded 에러인 경우 "한도초과"로 표시
  const isQuotaExceeded = isQuotaExceededError(document)
  const statusLabel = isQuotaExceeded ? '한도초과' : DocumentStatusService.getStatusLabel(status)
  const statusIcon = DocumentStatusService.getStatusIcon(status)
  const isLinked = Boolean(document.customer_relation)
  const isAnnualReport = document.is_annual_report === true
  // 크레딧 부족 상태 확인
  const isCreditPending = status === 'credit_pending'
  // 내 파일 여부 확인 (ownerId === customerId)
  const isMyFile = document.ownerId && document.customerId && document.ownerId === document.customerId
  // AR 문서는 자동 연결되므로 처리 완료되어도 버튼 비활성화 유지
  const canLink = status === 'completed' && !isLinked && !isAnnualReport
  const linkTooltip = isLinked ? '이미 고객과 연결됨' : '고객에게 연결'

  const documentId = document._id ?? document.id ?? null
  const key = documentId ?? `${DocumentStatusService.extractFilename(document)}-${index}`

  return (
    <div
      key={key}
      className={`status-item ${isSelected ? 'status-item--selected' : ''} ${isPreview ? 'status-item--preview' : ''}`}
      data-context-menu="document"
      style={gridTemplateColumns ? {
        gridTemplateColumns: (isDeleteMode || isBulkLinkMode || isAliasMode)
          ? `24px ${gridTemplateColumns}`
          : gridTemplateColumns
      } : undefined}
      onClick={() => {
        if (isDeleteMode || isBulkLinkMode || isAliasMode) return
        if (!documentId) return
        if (documentClickTimer.current) {
          clearTimeout(documentClickTimer.current)
        }
        documentClickTimer.current = setTimeout(() => {
          if (onDocumentClick) {
            onDocumentClick(documentId)
          }
          documentClickTimer.current = null
        }, 250)
      }}
      onDoubleClick={() => {
        if (isDeleteMode || isBulkLinkMode || isAliasMode) return
        if (documentClickTimer.current) {
          clearTimeout(documentClickTimer.current)
          documentClickTimer.current = null
        }
        if (onDocumentDoubleClick) {
          onDocumentDoubleClick(document)
        }
      }}
      onContextMenu={(e) => {
        if (onRowContextMenu) {
          e.preventDefault()
          e.stopPropagation()
          onRowContextMenu(document, e)
        }
      }}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault()
          if (documentId && onDocumentClick && !isDeleteMode && !isBulkLinkMode && !isAliasMode) {
            onDocumentClick(documentId)
          }
        }
      }}
    >
      {/* 삭제 모드 또는 일괄 연결 모드: 개별 선택 체크박스 */}
      {(() => {
        // 일괄 연결 모드: 미연결 + 완료된 문서만 체크박스 표시
        if (isBulkLinkMode) {
          const hasCustomer = document.customer_relation?.customer_name
          if (hasCustomer || !canLink) {
            // 고객 연결됨 또는 처리 미완료 문서는 체크박스 없음 (공백으로 레이아웃 유지)
            return <div className="document-checkbox-wrapper"></div>
          }
        }

        // 별칭 모드: 이미 별칭이 있는 문서(displayName 존재 + failed 아닌)는 체크박스 대신 완료 표시
        if (isAliasMode) {
          const hasAlias = Boolean(document.displayName) && document.displayNameStatus !== 'failed'
          if (hasAlias) {
            return (
              <div className="document-checkbox-wrapper" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <span style={{ color: 'var(--color-text-tertiary)', fontSize: '12px' }}>✓</span>
              </div>
            )
          }
        }

        // 삭제 모드, 일괄 연결 모드, 또는 별칭 모드 (별칭 없는 문서)
        if (isDeleteMode || isBulkLinkMode || isAliasMode) {
          return (
            <div
              className="document-checkbox-wrapper"
              onClick={(e) => {
                if (documentId) {
                  onSelectDocument?.(documentId, e)
                }
              }}
            >
              <input
                type="checkbox"
                checked={isSelected}
                onChange={() => {}}
                aria-label={`${DocumentStatusService.extractFilename(document)} 선택`}
                className="document-checkbox"
              />
            </div>
          )
        }

        return null
      })()}

      {/* 유형 칼럼: 아이콘 + 모든 뱃지 (AR, TXT, OCR, BIN) */}
      <div className="document-icon-wrapper">
        <div className={`document-icon ${DocumentUtils.getFileTypeClass(document.mimeType, DocumentStatusService.extractFilename(document))}`}>
          <SFSymbol
            name={DocumentUtils.getFileIcon(document.mimeType, DocumentStatusService.extractFilename(document))}
            size={SFSymbolSize.CAPTION_1}
            weight={SFSymbolWeight.REGULAR}
            decorative={true}
          />
        </div>
        {/* AR BADGE: Annual Report 표시 (크레딧 부족 시 회색) */}
        {document.is_annual_report && (
          <Tooltip content={isCreditPending ? "연간보고서 (크레딧 부족)" : "연간보고서"}>
            <div className={`document-ar-badge ${isCreditPending ? 'badge--disabled' : ''}`}>
              AR
            </div>
          </Tooltip>
        )}
        {/* CR BADGE: Customer Review (변액 리포트) 표시 (크레딧 부족 시 회색) */}
        {document.is_customer_review && !document.is_annual_report && (
          <Tooltip content={isCreditPending ? "변액 리포트 (크레딧 부족)" : "변액 리포트"}>
            <div className={`document-cr-badge ${isCreditPending ? 'badge--disabled' : ''}`}>
              CR
            </div>
          </Tooltip>
        )}
        {/* TXT/OCR/BIN BADGE: 공유 컴포넌트 */}
        <DocumentTypeBadge document={document as any} isCreditPending={isCreditPending} />
      </div>

      {/* 파일명 + PDF 변환 상태 아이콘 + 호버 액션 */}
      <div className="status-filename" onDoubleClick={(e) => { e.stopPropagation(); onRenameClick?.(document) }}>
        {/* filenameMode에 따라 별칭/원본 전환 표시 */}
        {(() => {
          const hasDisplay = Boolean(document.displayName)
          const originalName = DocumentStatusService.extractOriginalFilename(document)
          const showName = filenameMode === 'display' && hasDisplay
            ? document.displayName!
            : originalName
          const altName = filenameMode === 'display' && hasDisplay
            ? `원본: ${originalName}`
            : (hasDisplay ? `별칭: ${document.displayName}` : '')

          return (
            <>
              {altName ? (
                <Tooltip content={altName}>
                  <span className={`status-filename-text${filenameMode === 'display' && hasDisplay ? ' document-name--alias' : ''}`}>{searchTerm ? highlightText(showName, searchTerm) : showName}</span>
                </Tooltip>
              ) : (
                <span className={`status-filename-text${filenameMode === 'display' && hasDisplay ? ' document-name--alias' : ''}`}>{searchTerm ? highlightText(showName, searchTerm) : showName}</span>
              )}
              {/* 별칭 생성 실패 표시 */}
              {filenameMode === 'display' && !hasDisplay && document.displayNameStatus === 'failed' && (
                <Tooltip content="별칭 자동 생성에 실패했습니다. 별칭AI 버튼으로 재생성할 수 있습니다.">
                  <span className="document-name__alias-failed">⚠</span>
                </Tooltip>
              )}
              {/* 호버 시 이름변경/삭제 아이콘 */}
              {onRenameClick && onDeleteClick && (
                <span className="status-filename-hover-actions" onClick={(e) => e.stopPropagation()}>
                  <Tooltip content="이름 변경">
                    <button
                      type="button"
                      className="hover-action-btn hover-action-btn--rename"
                      onClick={(e) => { e.stopPropagation(); onRenameClick(document) }}
                      aria-label="이름 변경"
                    >
                      <svg width="12" height="12" viewBox="0 0 16 16" fill="none">
                        <path d="M11.5 1.5l3 3L5 14H2v-3L11.5 1.5z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                      </svg>
                    </button>
                  </Tooltip>
                  <Tooltip content="삭제">
                    <button
                      type="button"
                      className="hover-action-btn hover-action-btn--delete"
                      onClick={(e) => { e.stopPropagation(); onDeleteClick(document) }}
                      aria-label="삭제"
                    >
                      <svg width="12" height="12" viewBox="0 0 16 16" fill="none">
                        <path d="M2 4h12M5.33 4V2.67a1.33 1.33 0 011.34-1.34h2.66a1.33 1.33 0 011.34 1.34V4m2 0v9.33a1.33 1.33 0 01-1.34 1.34H4.67a1.33 1.33 0 01-1.34-1.34V4h9.34z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
                      </svg>
                    </button>
                  </Tooltip>
                </span>
              )}
            </>
          )
        })()}
        {/* PDF 변환 상태 배지 (변환 대상 파일에만 표시) */}
        {(() => {
          const uploadData = typeof document.upload === 'object' ? document.upload : null

          // 파일명에서 확장자 추출하여 변환 대상 여부 판단
          const filename = DocumentStatusService.extractFilename(document) || ''
          const extMatch = filename.match(/\.([^.]+)$/i)
          const ext = extMatch ? extMatch[1].toLowerCase() : ''
          const convertibleExts = ['pptx', 'ppt', 'xlsx', 'xls', 'docx', 'doc', 'hwp', 'txt']
          const isConvertible = document.isConvertible ?? convertibleExts.includes(ext)

          // 변환 대상이 아니면 배지 안 보임
          if (!isConvertible) return null

          // 변환 상태: API 값 우선, 없으면 변환 대상 파일은 "pending" 기본값
          const rawStatus = document.conversionStatus || uploadData?.conversion_status
          if (rawStatus === 'not_required') return null
          const conversionStatus = rawStatus || 'pending'

          const docId = document._id || document.id

          // 상태별 툴팁
          const tooltips: Record<string, string> = {
            completed: 'PDF 변환 완료',
            processing: 'PDF 변환 중...',
            pending: 'PDF 변환 대기 중 - 오래 걸리면 클릭하여 재시도',
            failed: 'PDF 변환 실패 - 클릭하여 재시도'
          }

          const tooltip = isRetryingPdf ? 'PDF 재변환 중...' : tooltips[conversionStatus] || ''

          // 상태별 아이콘 (굵고 선명한 SVG)
          const statusIcons: Record<string, React.ReactNode> = {
            completed: (
              <svg className="pdf-badge-icon" viewBox="0 0 12 12">
                <circle cx="6" cy="6" r="5.5" fill="#34c759"/>
                <path d="M3.5 6l2 2 3-4" fill="none" stroke="#fff" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            ),
            processing: (
              <svg className="pdf-badge-icon pdf-badge-icon--spin" viewBox="0 0 12 12">
                <circle cx="6" cy="6" r="5" fill="none" stroke="#fff" strokeWidth="2" strokeDasharray="16 8" opacity="0.9"/>
              </svg>
            ),
            pending: (
              <svg className="pdf-badge-icon" viewBox="0 0 12 12">
                <circle cx="3" cy="6" r="1.5" fill="#fff"/>
                <circle cx="6" cy="6" r="1.5" fill="#fff"/>
                <circle cx="9" cy="6" r="1.5" fill="#fff"/>
              </svg>
            ),
            failed: (
              <svg className="pdf-badge-icon" viewBox="0 0 12 12">
                <circle cx="6" cy="6" r="5.5" fill="#fff"/>
                <path d="M4 4l4 4M8 4l-4 4" stroke="#ff3b30" strokeWidth="2" strokeLinecap="round"/>
              </svg>
            )
          }

          const icon = statusIcons[conversionStatus] || statusIcons['pending']

          // failed/pending 상태: 클릭 가능한 버튼 (재시도)
          if (conversionStatus === 'failed' || conversionStatus === 'pending') {
            return (
              <Tooltip content={tooltip}>
                <button
                  type="button"
                  className={`pdf-conversion-badge pdf-conversion-badge--${conversionStatus} ${isRetryingPdf ? 'pdf-conversion-badge--retrying' : ''}`}
                  onClick={(e) => docId && onRetryPdfConversion(docId, e)}
                  disabled={isRetryingPdf || !docId}
                  aria-label="PDF 변환 재시도"
                >
                  {isRetryingPdf ? statusIcons['processing'] : icon}
                  <span className="pdf-badge-text">pdf</span>
                </button>
              </Tooltip>
            )
          }

          // 그 외 상태 (completed, processing): 일반 span
          return (
            <Tooltip content={tooltip}>
              <span className={`pdf-conversion-badge pdf-conversion-badge--${conversionStatus}`}>
                {icon}
                <span className="pdf-badge-text">pdf</span>
              </span>
            </Tooltip>
          )
        })()}
        {/* 바이러스 감염 배지 */}
        {(() => {
          const virusScan = (document as any).virusScan
          if (!virusScan) return null

          // 감염 또는 삭제된 파일만 배지 표시
          if (virusScan.status === 'infected' || virusScan.status === 'deleted') {
            const tooltipMsg = virusScan.status === 'deleted'
              ? `바이러스 감염으로 삭제됨: ${virusScan.threatName || '알 수 없는 위협'}`
              : `바이러스 감염: ${virusScan.threatName || '알 수 없는 위협'}`

            return (
              <Tooltip content={tooltipMsg}>
                <span className="virus-badge">
                  <svg className="virus-badge-icon" viewBox="0 0 12 12" width="8" height="8">
                    {/* Virus icon - center circle with spikes */}
                    <circle cx="6" cy="6" r="2.5" fill="#fff"/>
                    <circle cx="6" cy="1.2" r="1" fill="#fff"/>
                    <circle cx="6" cy="10.8" r="1" fill="#fff"/>
                    <circle cx="1.2" cy="6" r="1" fill="#fff"/>
                    <circle cx="10.8" cy="6" r="1" fill="#fff"/>
                    <circle cx="2.6" cy="2.6" r="0.8" fill="#fff"/>
                    <circle cx="9.4" cy="2.6" r="0.8" fill="#fff"/>
                    <circle cx="2.6" cy="9.4" r="0.8" fill="#fff"/>
                    <circle cx="9.4" cy="9.4" r="0.8" fill="#fff"/>
                  </svg>
                  <span className="virus-badge-text">virus</span>
                </span>
              </Tooltip>
            )
          }
          return null
        })()}
      </div>

      {/* 문서 유형 - 공통 컴포넌트 사용 (Single Source of Truth) */}
      <div className="document-doctype" onClick={(e) => e.stopPropagation()}>
        <DocumentTypeCell
          documentType={document.docType || document.document_type}
          isAnnualReport={document.is_annual_report}
          isCustomerReview={document.is_customer_review}
          onChange={(newType) => {
            const docId = document._id || document.id
            if (docId) {
              onDocTypeChange(docId, newType)
            }
          }}
          isUpdating={isUpdating}
        />
      </div>

      {/* 크기 */}
      <span className="document-size">
        {DocumentUtils.formatFileSize(DocumentStatusService.extractFileSize(document))}
      </span>

      {/* 타입 */}
      <span className="document-type">
        {document.mimeType ? DocumentUtils.getFileExtension(document.mimeType) : '-'}
      </span>

      {/* 업로드 날짜 */}
      <div className="status-date">
        {DocumentStatusService.formatUploadDate(
          DocumentStatusService.extractUploadedDate(document)
        )}
      </div>

      {/* 상태 (아이콘 + 텍스트) */}
      <div className="status-cell">
        {status === 'error' ? (
          // 에러 상태: 클릭하여 재시도 (quota_exceeded는 재시도 불가)
          (() => {
            const docId = document._id || document.id
            const errorMsg = getErrorMessage(document) || statusLabel
            const tooltipContent = isRetryingOcr
              ? 'OCR 재시도 중...'
              : isQuotaExceeded
                ? `${errorMsg}\n\nOCR 한도 해제 후 재시도 가능`
                : `${errorMsg}\n\n클릭하여 재시도`

            // quota_exceeded: 버튼 비활성화 (클릭 불가)
            const isDisabled = isRetryingOcr || !docId || isQuotaExceeded

            return (
              <Tooltip content={tooltipContent}>
                <button
                  type="button"
                  className={`status-cell-inner ${!isQuotaExceeded ? 'status-cell-inner--clickable' : 'status-cell-inner--disabled'} ${isRetryingOcr ? 'status-cell-inner--retrying' : ''}`}
                  onClick={(e) => !isQuotaExceeded && docId && onRetryOcr(docId, e)}
                  disabled={isDisabled}
                  aria-label={isQuotaExceeded ? 'OCR 한도 초과' : 'OCR 재시도'}
                >
                  <div className={"status-icon status-" + status}>
                    {isRetryingOcr ? (
                      <svg className="retry-spinner" viewBox="0 0 16 16" width="12" height="12">
                        <circle cx="8" cy="8" r="6" fill="none" stroke="currentColor" strokeWidth="2" strokeDasharray="20 10" />
                      </svg>
                    ) : statusIcon}
                  </div>
                  <div className="status-text">
                    <span className="status-label">{isRetryingOcr ? '재시도 중' : statusLabel}</span>
                  </div>
                </button>
              </Tooltip>
            )
          })()
        ) : (
          // 일반 상태: 아이콘만 툴팁
          <>
            <Tooltip content={statusLabel}>
              <div className={"status-icon status-" + status}>
                {statusIcon}
              </div>
            </Tooltip>
            <div className="status-text">
              {(['processing', 'uploading', 'converting', 'extracting', 'ocr_processing', 'classifying', 'embedding'].includes(status)) && progress ? (
                <span className="progress-text">{progress}%</span>
              ) : (
                <span className="status-label">{statusLabel}</span>
              )}
            </div>
          </>
        )}
      </div>

      {/* 연결된 고객 */}
      <div className="status-customer">
        {document.customer_relation?.customer_name ? (
          <>
            <button
              className="customer-name customer-name-button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => {
                e.stopPropagation()
                e.preventDefault()
                const customerId = document.customer_relation?.customer_id
                if (!customerId) return

                // 더블클릭 대기 (250ms)
                if (customerClickTimer.current) {
                  clearTimeout(customerClickTimer.current)
                }
                customerClickTimer.current = setTimeout(() => {
                  // 싱글클릭: RightPane에 고객 정보 표시
                  if (onCustomerClick) {
                    onCustomerClick(customerId)
                  }
                  customerClickTimer.current = null
                }, 250)
              }}
              onDoubleClick={(e) => {
                e.stopPropagation()
                e.preventDefault()
                const customerId = document.customer_relation?.customer_id
                if (!customerId) return

                // 싱글클릭 타이머 취소
                if (customerClickTimer.current) {
                  clearTimeout(customerClickTimer.current)
                  customerClickTimer.current = null
                }
                // 더블클릭: 고객 전체보기 페이지로 이동
                if (onCustomerDoubleClick) {
                  onCustomerDoubleClick(customerId)
                }
              }}
              aria-label={`${document.customer_relation.customer_name} 상세 보기`}
            >
              <div className="customer-icon-wrapper">
                {document.customer_relation.customer_type === '법인' ? (
                  <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor" className="customer-icon--corporate">
                    <circle cx="10" cy="10" r="10" opacity="0.2" />
                    <path d="M6 5h2v2H6V5zm0 3h2v2H6V8zm0 3h2v2H6v-2zm3-6h2v2H9V5zm0 3h2v2H9V8zm0 3h2v2H9v-2zm3-6h2v2h-2V5zm0 3h2v2h-2V8zm0 3h2v2h-2v-2zM5 14h10v2H5v-2z" />
                  </svg>
                ) : (
                  <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor" className="customer-icon--personal">
                    <circle cx="10" cy="10" r="10" opacity="0.2" />
                    <circle cx="10" cy="7" r="3" />
                    <path d="M10 11c-3 0-5 2-5 4v2h10v-2c0-2-2-4-5-4z" />
                  </svg>
                )}
              </div>
              <span className="customer-name-text">{document.customer_relation.customer_name}</span>
            </button>
            {/* 고객 변경 아이콘 — 행 호버 시에만 표시 */}
            {onChangeCustomerClick && status === 'completed' && (
              <button
                className="customer-change-icon"
                onMouseDown={(e) => e.stopPropagation()}
                onClick={(e) => {
                  e.stopPropagation()
                  e.preventDefault()
                  const docId = document._id ?? document.id
                  const customerId = document.customer_relation?.customer_id
                  if (docId && customerId) {
                    onChangeCustomerClick(docId, customerId)
                  }
                }}
                aria-label="연결 고객 변경"
                title="다른 고객으로 변경"
              >
                <SFSymbol name="link" size={SFSymbolSize.CAPTION_2} />
              </button>
            )}
          </>
        ) : (userId && document.customerId && userId === document.customerId) ? (
          <span className="customer-id-text">{userId}</span>
        ) : (onUnlinkedCustomerClick && canLink) ? (
          <button
            className="customer-none customer-none--linkable"
            onMouseDown={(e) => e.stopPropagation()}
            onClick={(e) => {
              e.stopPropagation()
              e.preventDefault()
              const docId = document._id ?? document.id
              if (docId) onUnlinkedCustomerClick(docId)
            }}
            aria-label="고객 연결"
          >
            <div className="customer-icon-wrapper">
              <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor" className="customer-icon--unlinked">
                <circle cx="10" cy="10" r="9" fill="none" stroke="currentColor" strokeWidth="1.2" strokeDasharray="3 2" />
                <circle cx="10" cy="7.5" r="2.5" opacity="0.5" />
                <path d="M10 11c-2.5 0-4.5 1.5-4.5 3.5v1h9v-1c0-2-2-3.5-4.5-3.5z" opacity="0.5" />
              </svg>
            </div>
            <span className="customer-none-text">미연결</span>
          </button>
        ) : (
          <span className="customer-none">-</span>
        )}
      </div>

      {/* 액션 버튼 */}
      <div className="status-actions">
        {/* 상세 보기는 DEV 모드에서만 표시 */}
        {isDevMode && (
          <Tooltip content="상세 보기">
            <button
              className="action-btn action-btn--detail"
              onClick={(e) => {
                e.stopPropagation()
                onDetailClick?.(document)
              }}
              aria-label="상세 보기"
            >
              <EyeIcon />
            </button>
          </Tooltip>
        )}
        <Tooltip content={isCreditPending ? "크레딧 부족 - 요약 없음" : (!(typeof document.meta === 'object' && document.meta?.summary) && !(typeof document.ocr === 'object' && (document.ocr as any)?.summary)) ? '요약 없음' : "요약 보기"}>
          <button
            className={`action-btn action-btn--summary ${isCreditPending || (!(typeof document.meta === 'object' && document.meta?.summary) && !(typeof document.ocr === 'object' && (document.ocr as any)?.summary)) ? 'action-btn--disabled' : ''}`}
            onClick={(e) => {
              e.stopPropagation()
              if (!isCreditPending) {
                onSummaryClick?.(document)
              }
            }}
            aria-label="요약 보기"
            disabled={isCreditPending || (!(typeof document.meta === 'object' && document.meta?.summary) && !(typeof document.ocr === 'object' && (document.ocr as any)?.summary))}
          >
            <SummaryIcon />
          </button>
        </Tooltip>
        <Tooltip content={isCreditPending ? "크레딧 부족 - 텍스트 없음" : (!document._hasMetaText && !document._hasOcrText) ? '전체 텍스트 없음' : "전체 텍스트 보기"}>
          <button
            className={`action-btn action-btn--full ${isCreditPending || (!document._hasMetaText && !document._hasOcrText) ? 'action-btn--disabled' : ''}`}
            onClick={(e) => {
              e.stopPropagation()
              if (!isCreditPending) {
                onFullTextClick?.(document)
              }
            }}
            aria-label="전체 텍스트 보기"
            disabled={isCreditPending || (!document._hasMetaText && !document._hasOcrText)}
          >
            <DocumentIcon />
          </button>
        </Tooltip>
        {/* 내 파일(ownerId === customerId)이 아니고, DEV 모드일 때만 "고객에게 연결" 버튼 표시 */}
        {isDevMode && !isMyFile && (
          <Tooltip content={linkTooltip}>
            <button
              type="button"
              className="action-btn action-btn--link"
              onClick={(e) => {
                e.stopPropagation()
                if (canLink) {
                  onLinkClick?.(document)
                }
              }}
              aria-label={linkTooltip}
              aria-disabled={!canLink ? 'true' : 'false'}
              data-disabled={!canLink}
              tabIndex={canLink ? 0 : -1}
            >
              <LinkIcon />
            </button>
          </Tooltip>
        )}
      </div>
    </div>
  )
})

DocumentStatusRow.displayName = 'DocumentStatusRow'

// ─── DocumentStatusList: 메인 리스트 컴포넌트 ───

export interface DocumentStatusListProps {
  documents: Document[]
  isLoading: boolean
  isEmpty: boolean
  error: string | null
  onDocumentClick?: (documentId: string) => void
  onDocumentDoubleClick?: (document: Document) => void
  onDetailClick?: (document: Document) => void
  onSummaryClick?: (document: Document) => void
  onFullTextClick?: (document: Document) => void
  onLinkClick?: (document: Document) => void
  // 🍎 미연결 고객 클릭 (단건 고객 연결)
  onUnlinkedCustomerClick?: (documentId: string) => void
  // 🍎 연결된 고객 변경 클릭
  onChangeCustomerClick?: (documentId: string, currentCustomerId: string) => void
  // 🍎 Sort props
  sortField?: 'filename' | 'status' | 'uploadDate' | 'fileSize' | 'mimeType' | 'customer' | 'badgeType' | 'docType' | null
  sortDirection?: 'asc' | 'desc'
  onColumnSort?: (field: 'filename' | 'status' | 'uploadDate' | 'fileSize' | 'mimeType' | 'customer' | 'badgeType' | 'docType') => void
  // 🍎 Delete mode props
  isDeleteMode?: boolean
  selectedDocumentIds?: Set<string>
  onSelectAll?: (checked: boolean) => void | Promise<void>
  onSelectDocument?: (documentId: string, event: React.MouseEvent) => void
  // 🍎 Bulk link mode props
  isBulkLinkMode?: boolean
  // 🍎 Alias mode props
  isAliasMode?: boolean
  // 🍎 Customer click handler
  onCustomerClick?: (customerId: string) => void
  // 🍎 Customer double click handler (전체보기 페이지로 이동)
  onCustomerDoubleClick?: (customerId: string) => void
  // 🍎 Refresh handler
  onRefresh?: () => Promise<void>
  // 🍎 Navigation handler
  onNavigate?: (viewKey: string) => void
  // 🍎 Context menu handler
  onRowContextMenu?: (document: Document, event: React.MouseEvent) => void
  // 🍎 파일명 표시 모드
  filenameMode?: 'display' | 'original'
  onFilenameModeChange?: (mode: 'display' | 'original') => void
  // 호버 액션: 이름변경/삭제
  onRenameClick?: (document: Document) => void
  onDeleteClick?: (document: Document) => void
  renamingDocumentId?: string | null
  onRenameConfirm?: (documentId: string, newName: string) => void
  onRenameCancel?: () => void
  // 검색어 하이라이트
  searchTerm?: string
  // RP에서 보고 있는 문서 ID (프리뷰 하이라이트용)
  previewDocumentId?: string | null
}

/**
 * 에러 코드를 한글 메시지로 변환
 */
export const ERROR_CODE_LABELS: Record<string, string> = {
  'OPENAI_QUOTA_EXCEEDED': 'OpenAI 크레딧 소진\n크레딧을 충전해주세요',
  'UNKNOWN': '알 수 없는 오류',
  'TIMEOUT': '처리 시간 초과',
  'CONNECTION_ERROR': '서버 연결 오류',
  'RATE_LIMIT': 'API 요청 한도 초과'
}

/**
 * 에러 메시지 정리 (URL 제거, 핵심만 추출)
 */
export const formatErrorMessage = (message: string): string => {
  // URL 제거
  let formatted = message.replace(/https?:\/\/[^\s]+/g, '').trim()

  // 특정 패턴 처리
  // "6 validation errors for..." → "Qdrant 저장 오류 (6개 필드)"
  const validationMatch = formatted.match(/(\d+)\s*validation\s*errors?\s*for/i)
  if (validationMatch) {
    return `Qdrant 저장 오류\n(${validationMatch[1]}개 유효성 검사 실패)`
  }

  // "insufficient_quota" 패턴
  if (formatted.includes('insufficient_quota') || formatted.includes('exceeded your current quota')) {
    return 'OpenAI 크레딧 소진\n크레딧을 충전해주세요'
  }

  // 너무 긴 경우 첫 문장만
  if (formatted.length > 60) {
    const firstSentence = formatted.match(/^[^.!]+[.!]?/)
    if (firstSentence) {
      formatted = firstSentence[0].trim()
    }
    if (formatted.length > 60) {
      formatted = formatted.slice(0, 57) + '...'
    }
  }

  return formatted || '처리 오류'
}

/**
 * quota_exceeded 에러인지 확인
 * OCR 한도 초과 에러는 수동 재시도 불가
 */
export const isQuotaExceededError = (document: Document): boolean => {
  // 1. ocr.status 확인 (타입에 없는 값도 체크 가능하도록 as string 사용)
  if (document.ocr && typeof document.ocr !== 'string') {
    const ocrStatus = document.ocr.status as string | undefined
    if (ocrStatus === 'quota_exceeded') {
      return true
    }
  }

  // 2. stages.ocr.message 확인
  if (document.stages?.ocr && typeof document.stages.ocr !== 'string') {
    const message = document.stages.ocr.message
    if (message && typeof message === 'string' && message.includes('한도 초과')) {
      return true
    }
  }

  return false
}

/**
 * Document에서 에러 메시지 추출
 */
export const getErrorMessage = (document: Document): string | null => {
  // 1. docembed 에러
  if (document.docembed && typeof document.docembed !== 'string') {
    const docembed = document.docembed as Record<string, unknown>
    // error_code가 있으면 해당 라벨 사용
    if (docembed['error_code'] && typeof docembed['error_code'] === 'string') {
      const label = ERROR_CODE_LABELS[docembed['error_code']]
      if (label) return label
    }
    // error_message 사용
    if (docembed['error_message'] && typeof docembed['error_message'] === 'string') {
      return formatErrorMessage(docembed['error_message'])
    }
    // error_code만 있는 경우 (라벨 없음)
    if (docembed['error_code'] && typeof docembed['error_code'] === 'string') {
      return docembed['error_code']
    }
  }

  // 2. stages.docembed 에러
  if (document.stages?.docembed && typeof document.stages.docembed !== 'string') {
    const stageDocembed = document.stages.docembed as Record<string, unknown>
    if (stageDocembed['error_code'] && typeof stageDocembed['error_code'] === 'string') {
      const label = ERROR_CODE_LABELS[stageDocembed['error_code']]
      if (label) return label
    }
    if (stageDocembed['error_message'] && typeof stageDocembed['error_message'] === 'string') {
      return formatErrorMessage(stageDocembed['error_message'])
    }
    if (stageDocembed['error_code'] && typeof stageDocembed['error_code'] === 'string') {
      return stageDocembed['error_code']
    }
  }

  // 3. OCR 에러 (quota_exceeded 포함)
  if (document.ocr && typeof document.ocr !== 'string') {
    const ocr = document.ocr as Record<string, unknown>
    // quota_exceeded인 경우 quota_message 사용
    if (ocr['status'] === 'quota_exceeded') {
      if (ocr['quota_message'] && typeof ocr['quota_message'] === 'string') {
        return 'OCR 한도 초과'
      }
      return 'OCR 한도 초과'
    }
    if (ocr['status'] === 'error' && ocr['message'] && typeof ocr['message'] === 'string') {
      return formatErrorMessage(ocr['message'])
    }
  }

  // 4. stages.ocr 에러
  if (document.stages?.ocr && typeof document.stages.ocr !== 'string') {
    const stageOcr = document.stages.ocr as Record<string, unknown>
    if (stageOcr['status'] === 'error' && stageOcr['message'] && typeof stageOcr['message'] === 'string') {
      return formatErrorMessage(stageOcr['message'])
    }
  }

  // 5. meta 에러
  if (document.meta && typeof document.meta !== 'string') {
    const meta = document.meta as Record<string, unknown>
    if (meta['meta_status'] === 'error' && meta['message'] && typeof meta['message'] === 'string') {
      return formatErrorMessage(meta['message'])
    }
  }

  return null
}

export const DocumentStatusList: React.FC<DocumentStatusListProps> = ({
