      })
      throw error
    }
  }, [selectedNotes, onRefresh, showAlert])

  /**
   * 🍎 문서 유형 변경 핸들러
   */
  const handleDocTypeChange = useCallback(async (documentId: string, newType: string) => {
    if (updatingDocTypeId) return // 이미 업데이트 중이면 무시

