          <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
            <rect x="2" y="3" width="12" height="11" rx="1.5" stroke="currentColor" strokeWidth="1.2" fill="none"/>
            <path d="M2 6h12M5 1v3M11 1v3" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/>
          </svg>
          <span>업로드 날짜</span>
          {onColumnSort && <SortIndicator field="uploadDate" currentSortField={sortField} sortDirection={sortDirection} />}
          <div
            className="column-resize-handle"
            onMouseDown={(e) => handleResizeStart(5, e)}
            onDoubleClick={(e) => { e.preventDefault(); e.stopPropagation(); handleResizeReset(5); }}
          />
        </div>
        <div
          className={`header-status header-cell--resizable ${onColumnSort ? 'header-sortable' : ''}`}
          onClick={() => onColumnSort?.('status')}
          role={onColumnSort ? 'button' : undefined}
          tabIndex={onColumnSort ? 0 : undefined}
          aria-label={onColumnSort ? '상태로 정렬' : undefined}
        >
          <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
            <rect x="2" y="3" width="12" height="10" rx="1.5" stroke="currentColor" strokeWidth="1.2" fill="none"/>
            <path d="M5 7l2 2 4-4" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
          <span>상태</span>
          {onColumnSort && <SortIndicator field="status" currentSortField={sortField} sortDirection={sortDirection} />}
          <div
            className="column-resize-handle"
            onMouseDown={(e) => handleResizeStart(6, e)}
            onDoubleClick={(e) => { e.preventDefault(); e.stopPropagation(); handleResizeReset(6); }}
          />
        </div>
        <div
          className={`header-customer header-cell--resizable ${onColumnSort ? 'header-sortable' : ''}`}
          onClick={() => onColumnSort?.('customer')}
          role={onColumnSort ? 'button' : undefined}
          tabIndex={onColumnSort ? 0 : undefined}
          aria-label={onColumnSort ? '연결된 고객으로 정렬' : undefined}
        >
          <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
            <circle cx="8" cy="5" r="3" stroke="currentColor" strokeWidth="1.2" fill="none"/>
            <path d="M2 14c0-3.3 2.7-6 6-6s6 2.7 6 6" stroke="currentColor" strokeWidth="1.2" fill="none"/>
          </svg>
          <span>연결된 고객</span>
          {onColumnSort && <SortIndicator field="customer" currentSortField={sortField} sortDirection={sortDirection} />}
          <div
            className="column-resize-handle"
            onMouseDown={(e) => handleResizeStart(7, e)}
            onDoubleClick={(e) => { e.preventDefault(); e.stopPropagation(); handleResizeReset(7); }}
          />
        </div>
        <div className="header-actions">
          <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
            <circle cx="5" cy="8" r="1.5" fill="currentColor"/>
            <circle cx="11" cy="8" r="1.5" fill="currentColor"/>
          </svg>
          <span>액션</span>
        </div>
      </div>

      {documents.map((document, index) => {
        const documentId = document._id ?? document.id ?? null
        const key = documentId ?? `${DocumentStatusService.extractFilename(document)}-${index}`

        return (
          <DocumentStatusRow
            key={key}
            document={document}
            index={index}
            isSelected={documentId ? selectedDocumentIds.has(documentId) : false}
            isPreview={Boolean(documentId) && documentId === previewDocumentId}
            isUpdating={updatingDocTypeId === documentId}
            isRetryingPdf={retryingDocumentId === documentId}
            isRetryingOcr={retryingOcrDocumentId === documentId}
            isDeleteMode={isDeleteMode}
            isBulkLinkMode={isBulkLinkMode}
            isAliasMode={isAliasMode}
            isDevMode={isDevMode}
            userId={userId}
            filenameMode={filenameMode}
            onDocumentClick={onDocumentClick}
            onDocumentDoubleClick={onDocumentDoubleClick}
            onSelectDocument={onSelectDocument}
            onDetailClick={onDetailClick}
            onSummaryClick={onSummaryClick}
            onFullTextClick={onFullTextClick}
            onLinkClick={onLinkClick}
            onUnlinkedCustomerClick={onUnlinkedCustomerClick}
            onChangeCustomerClick={onChangeCustomerClick}
            onCustomerClick={onCustomerClick}
            onCustomerDoubleClick={onCustomerDoubleClick}
            onRowContextMenu={onRowContextMenu}
            onRetryPdfConversion={handleRetryPdfConversion}
            onRetryOcr={handleRetryOcr}
            onDocTypeChange={handleDocTypeChange}
            onRenameClick={onRenameClick}
            onDeleteClick={onDeleteClick}
            renamingDocumentId={renamingDocumentId}
            onRenameConfirm={onRenameConfirm}
            onRenameCancel={onRenameCancel}
            searchTerm={searchTerm}
            gridTemplateColumns={resizedGridTemplate}
          />
        )
      })}

      {/* 메모 모달 */}
      {selectedNotes && (
        <DocumentNotesModal
          visible={notesModalVisible}
          documentName={selectedNotes.documentName}
          customerName={selectedNotes.customerName}
          customerId={selectedNotes.customerId}
          documentId={selectedNotes.documentId}
          notes={selectedNotes.notes}
          onClose={() => {
            setNotesModalVisible(false)
            setSelectedNotes(null)
          }}
          onSave={handleSaveNotes}
          onDelete={handleDeleteNotes}
        />
      )}
    </div>
  )
}

export default DocumentStatusList

/**
 * DocumentStatusList - badgeType Sorting Regression Tests
 * @since 2025-11-15
 * @commit a2cc9c92, 9a319088
 *
 * badgeType 정렬 기능 및 뱃지 표시 회귀 방지 테스트
 *
 * 테스트 범위:
 * - badgeType 칼럼 렌더링 (9a319088)
 * - badgeType 정렬 기능 (BIN → OCR → TXT)
 * - DocumentUtils.getDocumentType() 기반 뱃지 판정 (SSoT)
 * - 뱃지 색상 및 스타일 검증
 * - OCR 신뢰도별 5단계 색상
 */

import { describe, it, expect, vi } from 'vitest'
import { render } from '@testing-library/react'
import { DocumentStatusList } from '../DocumentStatusList'
import type { Document } from '../../../../../types/documentStatus'

describe('DocumentStatusList - badgeType Sorting (커밋 a2cc9c92, 9a319088)', () => {
  const createMockDocument = (overrides: Partial<Document> = {}): Document => ({
    _id: `doc-${Math.random()}`,
    id: `doc-${Math.random()}`,
    filename: 'test.pdf',
    mimeType: 'application/pdf',
    uploaded_at: new Date().toISOString(),
    fileSize: 1024,
    meta: {},
    stages: {},
    ...overrides
  })

  describe('[회귀 방지] badgeType 칼럼 렌더링', () => {
    it('badgeType 칼럼 헤더가 표시되어야 함', () => {
      const mockDocuments: Document[] = [
        createMockDocument({ filename: 'test1.pdf' })
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const header = container.querySelector('.header-badge-type')
      expect(header).toBeInTheDocument()
      expect(header).toHaveTextContent('유형')
    })

    it('badgeType 칼럼이 정렬 가능해야 함 (onColumnSort 제공 시)', () => {
      const mockDocuments: Document[] = [
        createMockDocument({ filename: 'test1.pdf' })
      ]
      const mockOnColumnSort = vi.fn()

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
          onColumnSort={mockOnColumnSort}
        />
      )

      const header = container.querySelector('.header-badge-type')
      expect(header).toHaveClass('header-sortable')
      expect(header).toHaveAttribute('role', 'button')
      expect(header).toHaveAttribute('aria-label', '유형으로 정렬')
    })

    it('badgeType 비활성 시 정렬 인디케이터가 표시되지 않아야 함', () => {
      const mockDocuments: Document[] = [
        createMockDocument({ filename: 'test1.pdf' })
      ]
      const mockOnColumnSort = vi.fn()

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
          onColumnSort={mockOnColumnSort}
          sortField={null}
          sortDirection="asc"
        />
      )

      const header = container.querySelector('.header-badge-type')
      const indicator = header?.querySelector('.sort-indicator')

      // 통일 규칙: 비활성 칼럼에는 인디케이터 없음
      expect(indicator).toBeNull()
    })

    it('badgeType 정렬 활성화 시 올바른 인디케이터 표시', () => {
      const mockDocuments: Document[] = [
        createMockDocument({ filename: 'test1.pdf' })
      ]
      const mockOnColumnSort = vi.fn()

      const { container, rerender } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
          onColumnSort={mockOnColumnSort}
          sortField="badgeType"
          sortDirection="asc"
        />
      )

      let header = container.querySelector('.header-badge-type')
      let indicator = header?.querySelector('.sort-indicator')
      expect(indicator).toHaveTextContent('▲')

      rerender(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
          onColumnSort={mockOnColumnSort}
          sortField="badgeType"
          sortDirection="desc"
        />
      )

      header = container.querySelector('.header-badge-type')
      indicator = header?.querySelector('.sort-indicator')
      expect(indicator).toHaveTextContent('▼')
    })
  })

  describe('[회귀 방지] badgeType 정렬 기능', () => {
    it('badgeType 칼럼 클릭 시 onColumnSort 호출', () => {
      const mockDocuments: Document[] = [
        createMockDocument({ filename: 'test1.pdf' })
      ]
      const mockOnColumnSort = vi.fn()

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
          onColumnSort={mockOnColumnSort}
        />
      )

      const header = container.querySelector('.header-badge-type')
      header?.dispatchEvent(new MouseEvent('click', { bubbles: true }))

      expect(mockOnColumnSort).toHaveBeenCalledWith('badgeType')
    })
  })

  describe('[회귀 방지] DocumentUtils.getDocumentType() 기반 뱃지 판정', () => {
    it('meta.full_text가 있으면 TXT 뱃지를 표시해야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          meta: { full_text: '텍스트 내용' }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const txtBadge = container.querySelector('.document-txt-badge')
      expect(txtBadge).toBeInTheDocument()
      expect(txtBadge).toHaveTextContent('TXT')
    })

    it('ocr.status=done이면 OCR 뱃지 표시', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { status: 'done', confidence: '0.95' }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = container.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
      expect(ocrBadge).toHaveTextContent('OCR')
    })

    it('meta/ocr 필드 없으면 BIN 뱃지 표시', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          // meta, ocr, docembed 없음 → BIN
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const binBadge = container.querySelector('.document-bin-badge')
      expect(binBadge).toBeInTheDocument()
      expect(binBadge).toHaveTextContent('BIN')
    })

    it('ocr.confidence만 있으면 OCR 뱃지 표시 (하위 호환성)', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { confidence: '0.85' } // confidence만 있음 (status 없음)
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = container.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
    })
  })

  describe('[회귀 방지] 뱃지 색상 및 스타일', () => {
    it('TXT 뱃지는 파란색 클래스를 가져야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          meta: { full_text: '텍스트 내용' }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const txtBadge = container.querySelector('.document-txt-badge')
      expect(txtBadge).toBeInTheDocument()
      expect(txtBadge).toHaveClass('document-txt-badge')
    })

    it('BIN 뱃지는 회색 클래스를 가져야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          // meta, ocr, docembed 없음 → BIN
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const binBadge = container.querySelector('.document-bin-badge')
      expect(binBadge).toBeInTheDocument()
      expect(binBadge).toHaveClass('document-bin-badge')
    })

    it('OCR 뱃지는 신뢰도별 색상 클래스를 가져야 함', () => {
      const testCases = [
        { confidence: 0.98, expectedClass: 'ocr-excellent', label: '매우 높음' },
        { confidence: 0.90, expectedClass: 'ocr-high', label: '높음' },
        { confidence: 0.75, expectedClass: 'ocr-medium', label: '보통' },
        { confidence: 0.60, expectedClass: 'ocr-low', label: '낮음' },
        { confidence: 0.40, expectedClass: 'ocr-very-low', label: '매우 낮음' }
      ]

      testCases.forEach(({ confidence, expectedClass }) => {
        const mockDocuments: Document[] = [
          {
            ...createMockDocument({ filename: 'test1.pdf' }),
            ocr: { status: 'done', confidence: String(confidence) }
          } as any
        ]

        const { container } = render(
          <DocumentStatusList
            documents={mockDocuments}
            isLoading={false}
            isEmpty={false}
            error={null}
          />
        )

        const ocrBadge = container.querySelector('.document-ocr-badge')
        expect(ocrBadge).toHaveClass(expectedClass)
      })
    })
  })

  describe('[회귀 방지] OCR 신뢰도 추출', () => {
    it('document.ocr.confidence에서 신뢰도 추출', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { status: 'done', confidence: '0.9817' }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = container.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
      expect(ocrBadge).toHaveClass('ocr-excellent') // 0.9817 >= 0.95
    })

    it('stages.ocr.message에서 신뢰도 파싱', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { status: 'done' },
          stages: {
            ocr: {
              status: 'completed',
              message: 'OCR 완료 (신뢰도: 0.8765)'
            }
          }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = container.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
      expect(ocrBadge).toHaveClass('ocr-high') // 0.8765 >= 0.85
    })

    it('신뢰도 없으면 기본 OCR 뱃지 표시 (medium 색상)', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { status: 'done' }
          // confidence 없음
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = container.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
      expect(ocrBadge).toHaveClass('ocr-medium') // 기본값
    })
  })

  describe('[회귀 방지] 뱃지 툴팁', () => {
    it('TXT 뱃지에 툴팁이 있어야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          meta: { full_text: '텍스트 내용' }
        } as any
      ]

      render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      // Tooltip 컴포넌트가 content prop을 받음
      // 실제 툴팁 렌더링은 hover 시 발생하므로 컴포넌트 존재 여부만 확인
      const txtBadge = document.querySelector('.document-txt-badge')
      expect(txtBadge).toBeInTheDocument()
    })

    it('OCR 뱃지에 신뢰도 정보가 포함된 툴팁이 있어야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          ocr: { status: 'done', confidence: '0.9234' }
        } as any
      ]

      render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const ocrBadge = document.querySelector('.document-ocr-badge')
      expect(ocrBadge).toBeInTheDocument()
      // 툴팁 내용: "OCR 신뢰도: 92.3% (매우 높음)"
    })

    it('BIN 뱃지에 툴팁이 있어야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'test1.pdf' }),
          // meta, ocr 없음 → BIN
        } as any
      ]

      render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      const binBadge = document.querySelector('.document-bin-badge')
      expect(binBadge).toBeInTheDocument()
      // 툴팁 내용: "바이너리 파일 (텍스트 추출 불가)"
    })
  })

  describe('[회귀 방지] 정렬 순서', () => {
    it('정렬 없을 때 문서가 표시되어야 함', () => {
      const mockDocuments: Document[] = [
        {
          ...createMockDocument({ filename: 'bin-file.zip' }),
          // meta, ocr 없음 → BIN
        } as any,
        {
          ...createMockDocument({ filename: 'ocr-file.pdf' }),
          ocr: { status: 'done', confidence: '0.90' }
        } as any,
        {
          ...createMockDocument({ filename: 'txt-file.docx' }),
          meta: { full_text: '텍스트 내용' }
        } as any
      ]

      const { container } = render(
        <DocumentStatusList
          documents={mockDocuments}
          isLoading={false}
          isEmpty={false}
          error={null}
        />
      )

      expect(container.querySelectorAll('.status-item')).toHaveLength(3)
    })
  })
})

