    console.log('✅ 삭제 확인됨, API 호출 시작...')

    try {
      // 문서 라이브러리 파일과 폴더 시스템 항목을 구분하여 삭제
      if (itemToDelete.isLibraryDocument) {
        // 문서 라이브러리 파일 삭제 (files 컬렉션)
        console.log('📄 문서 라이브러리 파일 삭제:', itemToDelete._id)
