  // 폴더/파일 이동 실행
  const handleMove = useCallback(async (targetFolderId: string | null) => {
    if (!selectedItem) return

    console.log('🚚 [Move] 시작:', {
      item: selectedItem.name,
      itemId: selectedItem._id,
      from: currentFolderId,
