      } else {
        // 폴더 시스템 항목 이동
        await personalFilesService.moveItem(selectedItem._id, targetFolderId)
        console.log('✅ [Move] 폴더 시스템 항목 이동 완료')
      }

      // 🍎 캐시 무효화 (이동 관련 모든 폴더)
      folderItemCache.current.delete(selectedItem._id) // 이동한 항목 자체
      if (currentFolderId) {
        folderItemCache.current.delete(currentFolderId) // 원본 폴더 (항목이 사라짐)
      }
      if (targetFolderId) {
        folderItemCache.current.delete(targetFolderId) // 목적지 폴더 (항목이 추가됨)
      }
      console.log('✅ [Move] 캐시 무효화 완료')

      // 즉시 UI 업데이트 (Optimistic Update)
      // 1. 우측 목록(currentFolderItems)에서 제거
      setCurrentFolderItems(prev => prev.filter(item => item._id !== selectedItem._id))

      // 2. 좌측 트리 전체 다시 로드 + 목적지 폴더 자동 확장
      if (selectedItem.type === 'folder') {
        // 🍎 핵심: 전체 폴더 구조를 재귀적으로 로드하여 좌측 트리 즉시 업데이트
        const allFolders = await loadAllFolders() // 모든 폴더 재귀 로드
        setItems(allFolders) // 좌측 트리에 즉시 반영

        // 목적지 폴더를 자동으로 확장 (이동한 폴더를 즉시 볼 수 있도록)
        if (targetFolderId) {
          setExpandedFolderIds(prev => new Set([...prev, targetFolderId]))
          console.log('✅ [Move] 목적지 폴더 자동 확장:', targetFolderId)
        }

        console.log('✅ [Move] 좌측 트리 전체 새로고침 완료')
      }

      // 3. 백엔드와 동기화 (정확한 상태 보장)
      await loadFolderContents(currentFolderId)
      console.log('✅ [Move] 원본 폴더 새로고침 완료')

      // 4. 목적지 폴더의 내용도 새로고침 (확장 여부와 무관하게 항상)
      if (targetFolderId) {
        await loadFolderContents(targetFolderId)
        console.log('✅ [Move] 목적지 폴더 새로고침 완료')
      }

      setShowMoveModal(false)
      setSelectedItem(null)
      console.log('🏁 [Move] 완료')
    } catch (err) {
      console.error('❌ [Move] 오류:', err)
      errorReporter.reportApiError(err as Error, { component: 'PersonalFilesView.handleMove' })
      setError(err instanceof Error ? err.message : '이동에 실패했습니다')
    }
  }, [selectedItem, currentFolderId, loadFolderContents, expandedFolderIds, loadAllFolders])


  // 컨텍스트 메뉴에서 새 폴더 생성
  const handleNewFolderFromContext = useCallback(() => {
    if (!selectedItem || selectedItem.type !== 'folder') return
    setCurrentFolderId(selectedItem._id)
    loadFolderContents(selectedItem._id)
    handleCloseContextMenu()
    setTimeout(() => setShowNewFolderModal(true), 100)
  }, [selectedItem, loadFolderContents, handleCloseContextMenu])

  // 🍎 삭제 모드 토글 핸들러
  const handleToggleDeleteMode = useCallback(() => {
    if (isDeleteMode) {
      setSelectedDocumentIds(new Set())
    }
    setIsDeleteMode(!isDeleteMode)
  }, [isDeleteMode])

  // 🍎 개별 선택/해제 핸들러
  const handleSelectDocument = useCallback((documentId: string, event: React.MouseEvent) => {
    event.stopPropagation()
    setSelectedDocumentIds(prev => {
      const newSet = new Set(prev)
      if (newSet.has(documentId)) {
        newSet.delete(documentId)
      } else {
        newSet.add(documentId)
      }
      return newSet
    })
  }, [])

  // 🍎 전체 선택/해제 핸들러
  const handleSelectAll = useCallback((checked: boolean) => {
    if (checked) {
      const allItemIds = currentFolderItems
        .filter(item => {
          // 폴더는 모두 선택 가능
          if (item.type === 'folder') return true
          // 문서 라이브러리 파일인 경우: 처리중이 아닌 것만
          if (item.isLibraryDocument && item.document) {
            const status = DocumentStatusService.extractStatus(item.document as any)
            return status !== 'processing'
          }
          // 일반 파일은 모두 선택 가능
          return true
        })
        .map(item => item._id)
        .filter(id => id !== '')
      setSelectedDocumentIds(new Set(allItemIds))
    } else {
      setSelectedDocumentIds(new Set())
    }
  }, [currentFolderItems])

  // 🍎 선택된 파일/폴더 삭제 핸들러
  const handleDeleteSelected = useCallback(async () => {
    if (selectedDocumentIds.size === 0) {
      await confirmModal.actions.openModal({
        title: '선택 항목 없음',
        message: '삭제할 항목을 선택해주세요.',
        confirmText: '확인',
        showCancel: false,
      })
      return
    }

    // 선택된 항목들의 타입 구분
    const itemsToDelete = currentFolderItems.filter(item =>
      selectedDocumentIds.has(item._id)
    )
    const fileCount = itemsToDelete.filter(item => item.type === 'file').length
    const folderCount = itemsToDelete.filter(item => item.type === 'folder').length

    // 확인 메시지 생성
    let deleteMessage = '선택한 '
    if (fileCount > 0 && folderCount > 0) {
      deleteMessage += `${fileCount}개의 파일과 ${folderCount}개의 폴더를 삭제하시겠습니까?`
    } else if (fileCount > 0) {
      deleteMessage += `${fileCount}개의 파일을 삭제하시겠습니까?`
    } else {
      deleteMessage += `${folderCount}개의 폴더를 삭제하시겠습니까?`
    }

    if (folderCount > 0) {
      deleteMessage += '\n\n⚠️ 폴더 내의 모든 하위 파일과 폴더도 함께 삭제됩니다.'
    }

    // 확인 모달 표시
    const confirmed = await confirmModal.actions.openModal({
      title: '항목 삭제',
      message: deleteMessage,
      confirmText: '삭제',
      cancelText: '취소',
      showCancel: true,
      confirmStyle: 'destructive',
    })

    if (!confirmed) return

    try {
      setIsDeleting(true)

      // 선택된 항목들의 정보 가져오기
      const itemsToDelete = currentFolderItems.filter(item =>
        selectedDocumentIds.has(item._id)
      )

      // 각 항목 삭제 (라이브러리 문서는 API 삭제, 일반 파일/폴더는 폴더 시스템 삭제)
      const deletePromises = itemsToDelete.map(async (item) => {
        try {
          if (item.isLibraryDocument) {
            // 문서 라이브러리 파일 삭제
            await api.delete(`/api/documents/${item._id}`)
          } else {
            // 폴더 시스템 파일/폴더 삭제 (폴더 삭제 시 하위 항목도 재귀적으로 삭제됨)
            await personalFilesService.deleteItem(item._id)
          }
          return { success: true, itemId: item._id }
        } catch (error) {
          console.error(`Error deleting item ${item._id}:`, error)
          errorReporter.reportApiError(error as Error, { component: 'PersonalFilesView.handleDeleteSelected.item', payload: { itemId: item._id } })
          return { success: false, itemId: item._id, error }
        }
      })

      const results = await Promise.all(deletePromises)
      const failedDeletes = results.filter((r) => !r.success)
      const successfulIds = results
        .filter((r) => r.success)
        .map((r) => r.itemId)

      // 🍎 캐시에서 삭제된 항목 제거
      successfulIds.forEach(id => {
        docToFileItemCache.current.delete(id)
        folderItemCache.current.delete(id)
      })

      // 선택 초기화 및 삭제 모드 종료
      setSelectedDocumentIds(new Set())
      setIsDeleteMode(false)
      setIsDeleting(false)

      // 🔄 현재 폴더 새로고침
      await loadFolderContents(currentFolderId, { silentRefresh: false })

      // 실패한 경우만 오류 모달 표시
      if (failedDeletes.length > 0) {
        await confirmModal.actions.openModal({
          title: '삭제 실패',
          message: `${failedDeletes.length}개의 항목 삭제에 실패했습니다.`,
          confirmText: '확인',
          showCancel: false,
        })
      }
    } catch (error) {
      console.error('Error in handleDeleteSelected:', error)
      errorReporter.reportApiError(error as Error, { component: 'PersonalFilesView.handleDeleteSelected' })
      setIsDeleting(false)
      await confirmModal.actions.openModal({
        title: '삭제 실패',
        message: '항목 삭제 중 오류가 발생했습니다.',
        confirmText: '확인',
        showCancel: false,
      })
    }
  }, [selectedDocumentIds, currentFolderItems, confirmModal, currentFolderId, loadFolderContents])

  // 컨텍스트 메뉴 외부 클릭 감지
  useEffect(() => {
    if (!showContextMenu) return

    const handleClickOutside = () => {
      setShowContextMenu(false)
      setSelectedItem(null)
    }

    document.addEventListener('click', handleClickOutside)
    return () => document.removeEventListener('click', handleClickOutside)
  }, [showContextMenu])

  // 드래그 시작
  const handleDragStart = useCallback((e: React.DragEvent, item: PersonalFileItem) => {
    e.stopPropagation()
    setDraggingItemId(item._id)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', item._id)
  }, [])

  // 드래그 오버 (드롭 허용)
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    e.dataTransfer.dropEffect = 'move'
  }, [])

  // 폴더에 드래그 진입
  const handleDragEnter = useCallback((e: React.DragEvent, folderId: string | null) => {
    e.preventDefault()
    e.stopPropagation()
    setDragOverFolderId(folderId)
  }, [])

  // 폴더에서 드래그 벗어남
  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    // relatedTarget이 자식 요소가 아닐 때만 제거 (이벤트 버블링 방지)
    if (!e.currentTarget.contains(e.relatedTarget as Node)) {
      setDragOverFolderId(null)
    }
  }, [])

  // 드롭
  const handleDrop = useCallback(async (e: React.DragEvent, targetFolderId: string | null) => {
    e.preventDefault()
    e.stopPropagation()

    const itemId = e.dataTransfer.getData('text/plain')
    if (!itemId || itemId === targetFolderId) {
      setDraggingItemId(null)
      setDragOverFolderId(null)
      return
    }

    try {
      // 드래그된 항목 찾기 (좌측 트리 + 우측 목록에서 검색)
      const draggedItem = items.find(item => item._id === itemId)
                        || currentFolderItems.find(item => item._id === itemId)

      if (!draggedItem) {
        throw new Error('이동할 항목을 찾을 수 없습니다')
      }

      // 폴더를 자신의 하위 폴더로 이동하는 것 방지 (순환 참조)
      if (draggedItem.type === 'folder' && targetFolderId) {
        let currentParent: string | null = targetFolderId
        while (currentParent) {
          if (currentParent === draggedItem._id) {
            throw new Error('폴더를 자신의 하위 폴더로 이동할 수 없습니다')
          }
          const parentFolder = items.find(item => item._id === currentParent)
          currentParent = parentFolder?.parentId || null
        }
      }

      // 문서 라이브러리 파일인지 폴더 시스템 항목인지 확인
      if (draggedItem.isLibraryDocument) {
        // 문서 라이브러리 파일 이동 (files 컬렉션)
        console.log(`📄 문서 이동: ${itemId} → 폴더 ${targetFolderId}`)
        await personalFilesService.moveDocument(itemId, targetFolderId)
      } else {
        // 폴더 시스템 항목 이동 (personal_files 컬렉션)
        console.log(`📁 폴더/파일 이동: ${itemId} → 폴더 ${targetFolderId}`)
        await personalFilesService.moveItem(itemId, targetFolderId)
      }

      // 폴더 이동이면 전체 트리 업데이트, 파일 이동이면 현재 폴더만 새로고침
      if (draggedItem.type === 'folder') {
        // 🍎 핵심: 전체 폴더 구조를 재귀적으로 로드하여 좌측 트리 즉시 업데이트
        const allFolders = await loadAllFolders()
        setItems(allFolders)

        // 목적지 폴더를 자동으로 확장 (이동한 폴더를 즉시 볼 수 있도록)
        if (targetFolderId) {
          setExpandedFolderIds(prev => new Set(prev).add(targetFolderId))
        }
      }

      // 현재 폴더 새로고침
      await loadFolderContents(currentFolderId)
    } catch (err) {
      console.error('항목 이동 오류:', err)
      errorReporter.reportApiError(err as Error, { component: 'PersonalFilesView.handleDrop' })
      setError(err instanceof Error ? err.message : '항목 이동에 실패했습니다')
    } finally {
      setDraggingItemId(null)
      setDragOverFolderId(null)
    }
  }, [currentFolderId, loadFolderContents, items, currentFolderItems, loadAllFolders])

  // 드래그 종료
  const handleDragEnd = useCallback(() => {
    setDraggingItemId(null)
    setDragOverFolderId(null)
  }, [])

  // 액션 버튼 핸들러
  const handleDetailClick = useCallback((document: Document, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(document)
    setIsDetailModalVisible(true)
  }, [])

  const handleSummaryClick = useCallback((document: Document, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(document)
    setIsSummaryModalVisible(true)
  }, [])

  const handleFullTextClick = useCallback((document: Document, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(document)
    setIsFullTextModalVisible(true)
  }, [])

  const handleLinkClick = useCallback((document: Document, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(document)
    setIsLinkModalVisible(true)
  }, [])

  // 모달 닫기 핸들러
  const handleCloseDetailModal = useCallback(() => {
    setIsDetailModalVisible(false)
    setSelectedDocument(null)
  }, [])

  const handleCloseSummaryModal = useCallback(() => {
    setIsSummaryModalVisible(false)
    setSelectedDocument(null)
  }, [])

  const handleCloseFullTextModal = useCallback(() => {
    setIsFullTextModalVisible(false)
    setSelectedDocument(null)
  }, [])

  const handleCloseLinkModal = useCallback(() => {
    setIsLinkModalVisible(false)
    setSelectedDocument(null)
  }, [])

  // 리사이저 핸들러
  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartXRef.current = e.clientX
    resizeStartWidthRef.current = sidebarWidth
  }, [sidebarWidth])

  const handleResizeMove = useCallback((e: MouseEvent) => {
    if (!isResizing) return

    const deltaX = e.clientX - resizeStartXRef.current
    const newWidth = resizeStartWidthRef.current + deltaX

    // 브라우저 너비 기준 비율 제한 (15% ~ 40%)
    const viewportWidth = window.innerWidth
    const minWidth = Math.max(180, viewportWidth * 0.15)  // 최소 15% (절대 최소값 180px)
    const maxWidth = Math.min(600, viewportWidth * 0.4)   // 최대 40% (절대 최대값 600px)

    const clampedWidth = Math.max(minWidth, Math.min(maxWidth, newWidth))
    setSidebarWidth(clampedWidth)
  }, [isResizing])

  const handleResizeEnd = useCallback(() => {
    setIsResizing(false)
  }, [])

  // 리사이저 이벤트 리스너
  useEffect(() => {
    if (!isResizing) return

    document.addEventListener('mousemove', handleResizeMove)
    document.addEventListener('mouseup', handleResizeEnd)
    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'

    return () => {
      document.removeEventListener('mousemove', handleResizeMove)
      document.removeEventListener('mouseup', handleResizeEnd)
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }
  }, [isResizing, handleResizeMove, handleResizeEnd])

  // 🍎 깜빡임 방지: useMemo는 의존성이 변하지 않으면 이전 결과를 재사용
  // currentFolderItems 참조가 유지되면 sort도 재실행되지 않음
  const filteredAndSortedItems = useMemo(() => {
    let result = currentFolderItems

    // 1. 타입 필터링 (필터 없으면 원본 유지)
    if (typeFilter === 'file') {
      result = currentFolderItems.filter(item => item.type === 'file')
    } else if (typeFilter === 'folder') {
      result = currentFolderItems.filter(item => item.type === 'folder')
    }

    // 2. 정렬 (useMemo가 캐싱하므로 의존성 불변시 재실행 안 됨)
    const sorted = result.slice().sort((a, b) => {
      // 🍎 업계 표준: 폴더 먼저, 파일 나중 (Windows, macOS, Google Drive)
      if (a.type === 'folder' && b.type === 'file') return -1
      if (a.type === 'file' && b.type === 'folder') return 1

      // 같은 타입끼리는 sortBy 기준으로 정렬
      let comparison = 0

      if (sortBy === 'name') {
        comparison = a.name.localeCompare(b.name, 'ko-KR')
      } else if (sortBy === 'createdAt') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
      } else if (sortBy === 'size') {
        const aSize = a.size || 0
        const bSize = b.size || 0
        comparison = aSize - bSize
      } else if (sortBy === 'status') {
        // 둘 다 파일인 경우 상태 비교
        if (a.type === 'file' && b.type === 'file') {
          const aStatus = a.document?.status || a.document?.overallStatus || ''
          const bStatus = b.document?.status || b.document?.overallStatus || ''
          comparison = aStatus.localeCompare(bStatus, 'ko-KR')
        }
      }

      return sortDirection === 'asc' ? comparison : -comparison
    })

    return sorted
  }, [currentFolderItems, typeFilter, sortBy, sortDirection])

  // 폴더 트리 렌더링 (재귀)
  const renderFolderTree = (parentId: string | null, level: number = 0) => {
    const folders = items
      .filter(item => item.type === 'folder' && item.parentId === parentId)
      .sort((a, b) => a.name.localeCompare(b.name)) // 이름순 오름차순 고정

    return folders.map(folder => {
      const isExpanded = expandedFolderIds.has(folder._id)
      const isActive = currentFolderId === folder._id
      const isDragOver = dragOverFolderId === folder._id

      return (
        <div key={folder._id} className="folder-tree-item">
          <div
            className={`folder-tree-row ${isActive ? 'active' : ''} ${isDragOver ? 'drag-over' : ''}`}
            style={{ paddingLeft: `${level * 16 + 8}px` }}
            draggable
            onDragStart={(e) => handleDragStart(e, folder)}
            onDragEnd={handleDragEnd}
            onDragOver={handleDragOver}
            onDragEnter={(e) => handleDragEnter(e, folder._id)}
            onDragLeave={handleDragLeave}
            onDrop={(e) => handleDrop(e, folder._id)}
            onContextMenu={(e) => handleContextMenu(e, folder)}
          >
            <button
              className="folder-expand-button"
              draggable={false}
              onClick={(e) => {
                e.stopPropagation()
                console.log(`▶️ chevron 클릭: ${folder.name} (expanded=${isExpanded})`)
                toggleFolder(folder._id)
              }}
              aria-label={isExpanded ? '폴더 닫기' : '폴더 열기'}
            >
              {isExpanded ? (
                <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                  <path d="M4 6l4 4 4-4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              ) : (
                <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                  <path d="M6 4l4 4-4 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              )}
            </button>
            <button
              className="folder-name-button"
              draggable={false}
              onClick={(e) => {
                e.stopPropagation()
                console.log(`📁 폴더 클릭: ${folder.name}`)
                handleFolderClick(folder._id)
              }}
            >
              <span className="folder-icon">
                {isActive ? '📂' : '📁'}
              </span>
              <span className="folder-name">{folder.name}</span>
            </button>
          </div>
          {isExpanded && (
            <div className="folder-tree-children">
              {renderFolderTree(folder._id, level + 1)}
            </div>
          )}
        </div>
      )
    })
  }

  return (
    <>
    <CenterPaneView
      visible={visible}
      onClose={onClose}
      title="내 보관함"
      titleIcon={<span className="menu-icon-yellow"><SFSymbol name="folder" size={SFSymbolSize.CALLOUT} weight={SFSymbolWeight.MEDIUM} /></span>}
      marginTop={0}
      marginBottom={0}
      marginLeft={0}
      marginRight={0}
      className="personal-files-view-wrapper"
    >
      <div className="personal-files-view" style={{ '--sidebar-width': `${sidebarWidth}px` } as React.CSSProperties}>
        {/* 좌측: 폴더 트리 */}
        <div className="files-sidebar" onContextMenu={(e) => e.preventDefault()}>
          <div className="sidebar-section">
            <div className="sidebar-title">빠른 액세스</div>

            {/* 즐겨찾기 */}
            <button className="sidebar-item">
              <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                <path d="M8 1.5l1.854 3.757 4.146.603-3 2.924.708 4.128L8 11.019l-3.708 1.893.708-4.128-3-2.924 4.146-.603L8 1.5z" fill="currentColor"/>
              </svg>
              <span>즐겨찾기</span>
            </button>
          </div>

          {/* 폴더 트리 - Google Drive 스타일 */}
          <div className="sidebar-section">
            <div className="folder-tree">
              {/* 내 보관함 (루트) */}
              <div className="folder-tree-item">
                <div
                  className={`folder-tree-row ${currentFolderId === null ? 'active' : ''} ${dragOverFolderId === null && draggingItemId ? 'drag-over' : ''}`}
                  style={{ paddingLeft: '8px' }}
                  onDragOver={handleDragOver}
                  onDragEnter={(e) => handleDragEnter(e, null)}
                  onDragLeave={handleDragLeave}
                  onDrop={(e) => handleDrop(e, null)}
                  onContextMenu={(e) => handleContextMenu(e)}
                >
                  <button
                    className="folder-expand-button"
                    onClick={(e) => {
                      e.stopPropagation()
                      setMyDriveExpanded(!myDriveExpanded)
                    }}
                    aria-label={myDriveExpanded ? '내 보관함 닫기' : '내 보관함 열기'}
                  >
                    {myDriveExpanded ? (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <path d="M4 6l4 4 4-4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                      </svg>
                    ) : (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <path d="M6 4l4 4-4 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                      </svg>
                    )}
                  </button>
                  <button
                    className="folder-name-button"
                    onClick={(e) => {
                      e.stopPropagation()
                      handleFolderClick(null)
                    }}
                  >
                    <span className="folder-icon">
                      {currentFolderId === null ? '📂' : '📁'}
                    </span>
                    <span className="folder-name">내 보관함</span>
                  </button>
                </div>

                {/* 하위 폴더들 */}
                {myDriveExpanded && renderFolderTree(null, 1)}
              </div>
            </div>
          </div>
        </div>

        {/* 리사이저 핸들 */}
        <div
          className={`files-resizer ${isResizing ? 'resizing' : ''}`}
          onMouseDown={handleResizeStart}
          role="separator"
          aria-orientation="vertical"
          aria-label="사이드바 크기 조절"
        >
          <div className="files-resizer-line" />
        </div>

        {/* 우측: 파일 목록 */}
        <div className="files-main" onContextMenu={(e) => e.preventDefault()}>
          {/* 툴바 */}
          <div className="files-toolbar">
            {/* 상위 폴더 버튼 */}
            <Tooltip content="상위 폴더">
              <button
                className="up-folder-button"
                onClick={handleGoUpFolder}
                disabled={!currentFolderId}
                aria-label="상위 폴더"
              >
                <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                  <path
                    d="M8 12V4M8 4L4 8M8 4L12 8"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
              </button>
            </Tooltip>

            {/* 브레드크럼 */}
            <div className="breadcrumb" ref={breadcrumbRef}>
              {(() => {
                // 빈 배열이면 아무것도 표시하지 않음
                if (breadcrumbs.length === 0) {
                  return null
                }

                const lastCrumb = breadcrumbs[breadcrumbs.length - 1]
                if (!lastCrumb) return null

                // 🍎 핵심: 주어진 공간과 예상 문자열 길이를 미리 비교!

                // 1. 공간 극소 (100px 미만): 마지막만
                if (breadcrumbWidth > 0 && breadcrumbWidth < 100) {
                  return (
                    <button
                      className="breadcrumb-item"
                      onClick={() => handleFolderClick(lastCrumb._id)}
                    >
                      {lastCrumb.name}
                    </button>
                  )
                }

                // 2. 단일 항목: 그대로 표시
                if (breadcrumbs.length === 1) {
                  const singleCrumb = breadcrumbs[0]
                  if (!singleCrumb) return null
                  return (
                    <button
                      className="breadcrumb-item"
                      onClick={() => handleFolderClick(singleCrumb._id)}
                    >
                      {singleCrumb.name}
                    </button>
                  )
                }

                // 3. 여유 공간 계산 (버튼 패딩, 간격 등 고려)
                const availableWidth = breadcrumbWidth - 40
                const separatorWidth = measureTextWidth(' > ')
                const ellipsisWidth = measureTextWidth('..')

                // 4. 전체 경로 문자열 길이 계산
                const fullPathWidth = breadcrumbs.reduce((total, crumb, index) => {
                  const nameWidth = measureTextWidth(crumb.name)
                  const sepWidth = index > 0 ? separatorWidth : 0
                  return total + nameWidth + sepWidth
                }, 0)

                // 5. 전체 경로가 공간에 맞으면 → 전체 표시
                if (availableWidth > 0 && fullPathWidth <= availableWidth) {
                  return breadcrumbs.map((crumb, index) => (
                    <React.Fragment key={crumb._id || 'root'}>
                      {index > 0 && <span className="breadcrumb-separator"> &gt; </span>}
                      <button
                        className="breadcrumb-item"
                        onClick={() => handleFolderClick(crumb._id)}
                      >
                        {crumb.name}
                      </button>
                    </React.Fragment>
                  ))
                }

                // 6. 점진적 축약 (Progressive Truncation)
                // 경로가 3개 이상일 때만 시도
                if (breadcrumbs.length >= 3) {
                  const firstCrumb = breadcrumbs[0]
                  if (!firstCrumb) return null

                  // 마지막 N개를 점점 줄여가며 시도 (N: length-2부터 1까지)
                  for (let lastCount = breadcrumbs.length - 2; lastCount >= 1; lastCount--) {
                    const lastCrumbs = breadcrumbs.slice(-lastCount)

                    // 패턴: "첫 > .. > 마지막 N개" 너비 계산
                    const firstWidth = measureTextWidth(firstCrumb.name)
                    const lastWidth = lastCrumbs.reduce((total, crumb) => {
                      const nameWidth = measureTextWidth(crumb.name)
                      const sepWidth = separatorWidth // 각 마지막 항목 앞에 구분자
                      return total + nameWidth + sepWidth
                    }, 0)

                    const patternWidth = firstWidth + separatorWidth + ellipsisWidth + lastWidth

                    // 공간에 맞으면 이 패턴 사용
                    if (patternWidth <= availableWidth) {
                      return (
                        <>
                          {/* 첫 번째 */}
                          <button
                            className="breadcrumb-item"
                            onClick={() => handleFolderClick(firstCrumb._id)}
                          >
                            {firstCrumb.name}
                          </button>
                          <span className="breadcrumb-separator"> &gt; </span>

                          {/* 생략 표시 */}
                          <span className="breadcrumb-ellipsis">..</span>

                          {/* 마지막 N개 */}
                          {lastCrumbs.map((crumb) => (
                            <React.Fragment key={crumb._id}>
                              <span className="breadcrumb-separator"> &gt; </span>
                              <button
                                className="breadcrumb-item"
                                onClick={() => handleFolderClick(crumb._id)}
                              >
                                {crumb.name}
                              </button>
                            </React.Fragment>
                          ))}
                        </>
                      )
                    }
                  }
                }

                // 7. 최종 fallback: ".. > 마지막" (가장 축약된 형태)
                return (
                  <>
                    <span className="breadcrumb-ellipsis">..</span>
                    <span className="breadcrumb-separator"> &gt; </span>
                    <button
                      className="breadcrumb-item"
                      onClick={() => handleFolderClick(lastCrumb._id)}
                    >
                      {lastCrumb.name}
                    </button>
                  </>
                )
              })()}
            </div>

            {/* 검색 및 뷰 모드 */}
            <div className="toolbar-actions">
              {/* 🍎 도움말 버튼 */}
              <Tooltip content="도움말" placement="bottom">
                <button
                  type="button"
                  className="help-icon-button"
                  onClick={() => setHelpModalVisible(true)}
                  aria-label="도움말"
                >
                  <SFSymbol
                    name="questionmark.circle"
                    size={SFSymbolSize.CAPTION_1}
                    weight={SFSymbolWeight.MEDIUM}
                    decorative={true}
                  />
                </button>
              </Tooltip>

              {/* 파일 업로드 */}
              <input
                ref={fileInputRef}
                type="file"
                multiple
                onChange={handleFileSelect}
                style={{ display: 'none' }}
                aria-label="파일 선택"
              />
              <Tooltip content="파일 업로드">
                <button
                  className="upload-button upload-file-button"
                  onClick={handleUploadClick}
                  disabled={uploading}
                  aria-label="파일 업로드"
                  style={{ color: 'var(--color-primary-400)' }}
                >
                  <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                    <path d="M3 14h10c.55 0 1-.45 1-1V6h-3c-.55 0-1-.45-1-1V2H3c-.55 0-1 .45-1 1v10c0 .55.45 1 1 1z" fill="currentColor"/>
                    <path d="M11 2l3 3h-3V2z" fill="currentColor"/>
                    <path d="M8 11V6M8 6L6 8M8 6l2 2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
              </Tooltip>

              {/* 새 폴더 */}
              <Tooltip content="새 폴더">
                <button
                  className="upload-button new-folder-button"
                  onClick={handleNewFolderClick}
                  aria-label="새 폴더"
                  style={{ color: 'var(--color-success)' }}
                >
                  <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                    <path d="M2 4c0-.55.45-1 1-1h3.586c.265 0 .52.105.707.293L8.414 4.414c.187.188.442.293.707.293H13c.55 0 1 .45 1 1v6c0 .55-.45 1-1 1H3c-.55 0-1-.45-1-1V4z" fill="currentColor"/>
                    <path d="M11 8h-2m0 0H7m2 0V6m0 2v2" stroke="var(--color-bg-primary)" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                </button>
              </Tooltip>

              {/* 삭제 버튼 (개발자 모드에서만 표시) */}
              {isDevMode && (
                <Tooltip key={`delete-mode-${isDeleteMode}`} content={isDeleteMode ? '삭제 완료' : '삭제'}>
                  <button
                    type="button"
                    className={`edit-mode-icon-button ${isDeleteMode ? 'edit-mode-icon-button--active' : ''}`}
                    onClick={handleToggleDeleteMode}
                    aria-label={isDeleteMode ? '삭제 완료' : '삭제'}
                  >
                    {isDeleteMode ? (
                      <svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M13.5 4.5L6 12L2.5 8.5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                      </svg>
                    ) : (
                      <SFSymbol
                        name="trash"
                        size={SFSymbolSize.CAPTION_1}
                        weight={SFSymbolWeight.MEDIUM}
                        decorative={true}
                      />
                    )}
                  </button>
                </Tooltip>
              )}

              {/* 삭제 모드일 때: 선택된 개수 + 삭제 버튼 (개발자 모드에서만) */}
              {isDevMode && isDeleteMode && (
                <>
                  <span className="selected-count-inline">
                    {selectedDocumentIds.size}개 선택됨
                  </span>
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={handleDeleteSelected}
                    disabled={isDeleting || selectedDocumentIds.size === 0}
                  >
                    {isDeleting ? '삭제 중...' : '삭제'}
                  </Button>
                </>
              )}

              <div className="toolbar-divider" />

              {/* 타입 필터 */}
              <div className="type-filter-group">
                <Tooltip content="전체">
                  <button
                    className={`type-filter-button ${typeFilter === 'all' ? 'active' : ''}`}
                    onClick={() => setTypeFilter('all')}
                    aria-label="전체"
                  >
                    전체
                  </button>
                </Tooltip>
                <Tooltip content="파일만">
                  <button
                    className={`type-filter-button ${typeFilter === 'file' ? 'active' : ''}`}
                    onClick={() => setTypeFilter('file')}
                    aria-label="파일만"
                  >
                    파일
                  </button>
                </Tooltip>
                <Tooltip content="폴더만">
                  <button
                    className={`type-filter-button ${typeFilter === 'folder' ? 'active' : ''}`}
                    onClick={() => setTypeFilter('folder')}
                    aria-label="폴더만"
                  >
                    폴더
                  </button>
                </Tooltip>
              </div>

              {/* 검색 */}
              <div className="search-box">
                <SFSymbol
                  name="magnifyingglass"
                  size={SFSymbolSize.CAPTION_1}
                  weight={SFSymbolWeight.MEDIUM}
                  className="search-icon"
                  decorative={true}
                />
                <input
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="파일명으로 검색"
                  className="search-input"
                />
                {/* 검색어 초기화 X 버튼 */}
                {searchTerm && (
                  <button
                    type="button"
                    className="pf-search-clear"
                    onClick={() => {
                      setSearchTerm('')
                    }}
                    aria-label="검색어 지우기"
                  >
                    <SFSymbol
                      name="xmark.circle.fill"
                      size={SFSymbolSize.CAPTION_1}
                      weight={SFSymbolWeight.REGULAR}
                    />
                  </button>
                )}
              </div>

              {/* 뷰 모드 전환 */}
              <div className="view-mode-toggle">
                <Tooltip content="리스트 뷰">
                  <button
                    className={`view-mode-button ${viewMode === 'list' ? 'active' : ''}`}
                    onClick={() => setViewMode('list')}
                    aria-label="리스트 뷰"
                  >
                    {viewMode === 'list' ? (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <rect x="2" y="3" width="2.5" height="2.5" rx="0.5" fill="currentColor"/>
                        <rect x="6" y="3" width="8" height="2.5" rx="0.5" fill="currentColor"/>
                        <rect x="2" y="7" width="2.5" height="2.5" rx="0.5" fill="currentColor"/>
                        <rect x="6" y="7" width="8" height="2.5" rx="0.5" fill="currentColor"/>
                        <rect x="2" y="11" width="2.5" height="2.5" rx="0.5" fill="currentColor"/>
                        <rect x="6" y="11" width="8" height="2.5" rx="0.5" fill="currentColor"/>
                      </svg>
                    ) : (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <rect x="2" y="3" width="2.5" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="6" y="3" width="8" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="2" y="7" width="2.5" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="6" y="7" width="8" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="2" y="11" width="2.5" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="6" y="11" width="8" height="2.5" rx="0.5" stroke="currentColor" strokeWidth="1.2"/>
                      </svg>
                    )}
                  </button>
                </Tooltip>
                <Tooltip content="그리드 뷰">
                  <button
                    className={`view-mode-button ${viewMode === 'grid' ? 'active' : ''}`}
                    onClick={() => setViewMode('grid')}
                    aria-label="그리드 뷰"
                  >
                    {viewMode === 'grid' ? (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <rect x="2" y="2" width="5" height="5" rx="1" fill="currentColor"/>
                        <rect x="9" y="2" width="5" height="5" rx="1" fill="currentColor"/>
                        <rect x="2" y="9" width="5" height="5" rx="1" fill="currentColor"/>
                        <rect x="9" y="9" width="5" height="5" rx="1" fill="currentColor"/>
                      </svg>
                    ) : (
                      <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                        <rect x="2" y="2" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="9" y="2" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="2" y="9" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.2"/>
                        <rect x="9" y="9" width="5" height="5" rx="1" stroke="currentColor" strokeWidth="1.2"/>
                      </svg>
                    )}
                  </button>
                </Tooltip>
              </div>

              {/* SSE 실시간 업데이트로 자동 갱신되므로 수동 컨트롤 불필요 */}
            </div>
          </div>

          {/* 업로드 진행률 표시 */}
          {uploading && (
            <div className="upload-progress">
              <div className="progress-bar">
                <div className="progress-fill" style={{ width: `${uploadProgress}%` }} />
              </div>
              <span className="progress-text">업로드 중... {uploadProgress}%</span>
            </div>
          )}

          {/* 파일 목록 */}
          <div
            className={`files-content ${viewMode === 'grid' ? 'grid-view' : 'list-view'}`}
            onContextMenu={(e) => handleContextMenu(e)}
          >
            {loading ? (
              <div className="empty-state">
                <p>로딩 중...</p>
              </div>
            ) : error ? (
              <div className="empty-state">
                <p style={{ color: 'var(--color-destructive)' }}>{error}</p>
              </div>
            ) : filteredAndSortedItems.length === 0 ? (
              <div className="empty-state">
                <p>{searchTerm.trim()
                  ? `'${searchTerm.trim()}'에 대한 검색 결과가 없습니다`
                  : '파일이 없습니다'
                }</p>
              </div>
            ) : viewMode === 'list' ? (
              // 리스트 뷰
              <div className={`files-list ${isDeleteMode ? 'files-list--delete-mode' : ''}`} onContextMenu={(e) => handleContextMenu(e)}>
                <div className="files-list-header" onContextMenu={(e) => { e.preventDefault(); e.stopPropagation(); }}>
                  {/* 🍎 삭제 모드: 전체 선택 체크박스 (폴더 포함) */}
                  {isDeleteMode && (
                    <div className="header-checkbox">
                      <input
                        type="checkbox"
                        checked={filteredAndSortedItems.length > 0 && filteredAndSortedItems.every(item => {
                          // 폴더는 모두 선택 가능
                          if (item.type === 'folder') {
                            return selectedDocumentIds.has(item._id)
                          }
                          // 문서 라이브러리 파일인 경우 처리중이면 제외
                          if (item.isLibraryDocument && item.document) {
                            const status = DocumentStatusService.extractStatus(item.document as any)
                            if (status === 'processing') {
                              return true // 비활성화된 항목은 체크 상태 계산에서 제외
                            }
                          }
                          return selectedDocumentIds.has(item._id)
                        })}
                        onChange={(e) => handleSelectAll(e.target.checked)}
                        aria-label="전체 선택"
                        className="document-select-all-checkbox"
                      />
                    </div>
                  )}
                  <div
                    className={`header-name sortable ${sortBy === 'name' ? 'sorted' : ''}`}
                    onClick={() => handleSort('name')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('name')
                      }
                    }}
                    aria-label={`이름으로 정렬 ${sortBy === 'name' ? (sortDirection === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <path d="M4 1h5l3 3v9a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1z" fill="currentColor"/>
                      <path className="pdf-icon-fold" d="M9 1v3h3" strokeWidth="0.8" fill="none"/>
                    </svg>
                    <span>이름</span>
                    <SortIndicator field="name" currentSortField={sortBy} sortDirection={sortDirection} />
                  </div>
                  <div
                    className={`header-size sortable ${sortBy === 'size' ? 'sorted' : ''}`}
                    onClick={() => handleSort('size')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('size')
                      }
                    }}
                    aria-label={`크기로 정렬 ${sortBy === 'size' ? (sortDirection === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <rect x="2" y="3" width="6" height="6" rx="1" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                      <rect x="6" y="7" width="8" height="8" rx="1" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                    </svg>
                    <span>크기</span>
                    <SortIndicator field="size" currentSortField={sortBy} sortDirection={sortDirection} />
                  </div>
                  <div
                    className={`header-modified sortable ${sortBy === 'createdAt' ? 'sorted' : ''}`}
                    onClick={() => handleSort('createdAt')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('createdAt')
                      }
                    }}
                    aria-label={`수정한 날짜로 정렬 ${sortBy === 'createdAt' ? (sortDirection === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <rect x="2" y="3" width="12" height="11" rx="1.5" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                      <path d="M2 6h12" stroke="currentColor" strokeWidth="1.2"/>
                      <path d="M5 1.5v3M11 1.5v3" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/>
                    </svg>
                    <span>수정한 날짜</span>
                    <SortIndicator field="createdAt" currentSortField={sortBy} sortDirection={sortDirection} />
                  </div>
                  <div
                    className={`header-status sortable ${sortBy === 'status' ? 'sorted' : ''}`}
                    onClick={() => handleSort('status')}
                    role="button"
                    tabIndex={0}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault()
                        handleSort('status')
                      }
                    }}
                    aria-label={`상태로 정렬 ${sortBy === 'status' ? (sortDirection === 'asc' ? '(오름차순)' : '(내림차순)') : ''}`}
                  >
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <rect x="2" y="3" width="12" height="10" rx="1.5" stroke="currentColor" strokeWidth="1.2" fill="none"/>
                      <path d="M5 7l2 2 4-4" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                    <span>상태</span>
                    <SortIndicator field="status" currentSortField={sortBy} sortDirection={sortDirection} />
                  </div>
                  <div className="header-actions">
                    <svg className="header-icon-svg" width="13" height="13" viewBox="0 0 16 16">
                      <circle cx="5" cy="8" r="1.5" fill="currentColor"/>
                      <circle cx="11" cy="8" r="1.5" fill="currentColor"/>
                    </svg>
                    <span>작업</span>
                  </div>
                </div>
                {filteredAndSortedItems.map(item => {
                  const isSelected = selectedDocumentIds.has(item._id)
                  const isProcessing = item.isLibraryDocument && item.document
                    ? DocumentStatusService.extractStatus(item.document as any) === 'processing'
                    : false
                  const isCheckboxDisabled = isDeleteMode && isProcessing

                  return (
                    <div
                      key={item._id}
                      className={`file-list-row ${draggingItemId === item._id ? 'dragging' : ''} ${item.type === 'folder' && dragOverFolderId === item._id ? 'drag-over' : ''} ${isSelected ? 'status-item--selected' : ''}`}
                      onClick={() => {
                        if (item.type === 'folder') {
                          handleFolderClick(item._id)
                        } else if (item.type === 'file' && item.document?._id && onDocumentClick) {
                          onDocumentClick(item.document._id!)
                        }
                      }}
                      onContextMenu={(e) => handleContextMenu(e, item)}
                      draggable
                      onDragStart={(e) => handleDragStart(e, item)}
                      onDragEnd={handleDragEnd}
                      onDragOver={item.type === 'folder' ? handleDragOver : undefined}
                      onDragEnter={item.type === 'folder' ? (e) => handleDragEnter(e, item._id) : undefined}
                      onDragLeave={item.type === 'folder' ? handleDragLeave : undefined}
                      onDrop={item.type === 'folder' ? (e) => handleDrop(e, item._id) : undefined}
                    >
                      {/* 🍎 삭제 모드: 개별 선택 체크박스 (폴더와 파일 모두 표시) */}
                      {isDeleteMode && (
                        <div
                          className={`document-checkbox-wrapper ${isCheckboxDisabled ? 'document-checkbox-wrapper--disabled' : ''}`}
                          onClick={(e) => {
                            if (!isCheckboxDisabled) {
                              handleSelectDocument(item._id, e)
                            }
                          }}
                        >
                          <input
                            type="checkbox"
                            checked={isSelected}
                            onChange={() => {}}
                            disabled={isCheckboxDisabled}
                            aria-label={`${item.name} 선택`}
                            className="document-checkbox"
                          />
                        </div>
                      )}
                      <div className="row-name">
                      {item.type === 'folder' ? (
                        <>
                          <span className="folder-icon">📁</span>
                          <span>{highlightText(item.name, searchTerm)}</span>
                        </>
                      ) : (
                        <>
                          <div className="document-icon-wrapper">
                            <div className={`document-icon ${DocumentUtils.getFileTypeClass(item.mimeType, item.name)}`}>
                              <SFSymbol
                                name={DocumentUtils.getFileIcon(item.mimeType, item.name)}
                                size={SFSymbolSize.CAPTION_1}
                                weight={SFSymbolWeight.REGULAR}
                                decorative={true}
                              />
                            </div>
                            {/* 🍎 AR BADGE */}
                            {item.document?.is_annual_report && (
                              <Tooltip content="연간보고서">
                                <div className="document-ar-badge">
                                  AR
                                </div>
                              </Tooltip>
                            )}
                            {/* 🍎 CR BADGE */}
                            {(item.document as any)?.is_customer_review && !item.document?.is_annual_report && (
                              <Tooltip content="변액 리뷰">
                                <div className="document-cr-badge">
                                  CR
                                </div>
                              </Tooltip>
                            )}
                            {/* 🍎 TXT/OCR/BIN BADGE — 공유 컴포넌트 (SSoT) */}
                            {item.document && (
                              <DocumentTypeBadge document={item.document as any} />
                            )}
                          </div>
                          <span>{highlightText(item.name, searchTerm)}</span>
                        </>
                      )}
                    </div>
                    <div className="row-size">
                      {item.type === 'file' && item.size ? formatFileSize(item.size) : null}
                    </div>
                    <div className="row-modified">
                      {formatDate(item.updatedAt)}
                    </div>
                    <div className="row-status">
                      {item.type === 'file' && item.document ? (() => {
                        const status = DocumentStatusService.extractStatus(item.document as any)
                        const progress = DocumentStatusService.extractProgress(item.document as any)
                        const statusLabel = DocumentStatusService.getStatusLabel(status)
                        const statusIcon = DocumentStatusService.getStatusIcon(status)

                        return (
                          <>
                            <Tooltip content={statusLabel}>
                              <div className={`status-icon status-${status}`}>
                                {statusIcon}
                              </div>
                            </Tooltip>
                            <div className="status-text">
                              {status === 'processing' && progress ? (
                                <span className="progress-text">{progress}%</span>
                              ) : (
                                <span className="status-label">{statusLabel}</span>
                              )}
                            </div>
                          </>
                        )
                      })() : null}
                    </div>
                    <div className="row-actions">
                      {item.type === 'file' && item.document && (
                        <>
                          <Tooltip content="상세 보기">
                            <button
                              type="button"
                              className="action-btn action-btn--detail"
                              onClick={(e) => handleDetailClick(item.document as any, e)}
                              aria-label="상세 보기"
                            >
                              <EyeIcon />
                            </button>
                          </Tooltip>
                          <Tooltip content={!(typeof (item.document as any)?.meta === 'object' && (item.document as any)?.meta?.summary) && !(typeof (item.document as any)?.ocr === 'object' && (item.document as any)?.ocr?.summary) ? '요약 없음' : '요약 보기'}>
                            <button
                              type="button"
                              className="action-btn action-btn--summary"
                              disabled={!(typeof (item.document as any)?.meta === 'object' && (item.document as any)?.meta?.summary) && !(typeof (item.document as any)?.ocr === 'object' && (item.document as any)?.ocr?.summary)}
                              onClick={(e) => handleSummaryClick(item.document as any, e)}
                              aria-label="요약 보기"
                            >
                              <SummaryIcon />
                            </button>
                          </Tooltip>
                          <Tooltip content={(item.document as any)?._hasMetaText || (item.document as any)?._hasOcrText ? '전체 텍스트 보기' : '전체 텍스트 없음'}>
                            <button
                              type="button"
                              className="action-btn action-btn--full"
                              disabled={!(item.document as any)?._hasMetaText && !(item.document as any)?._hasOcrText}
                              onClick={(e) => handleFullTextClick(item.document as any, e)}
                              aria-label="전체 텍스트 보기"
                            >
                              <DocumentIcon />
                            </button>
                          </Tooltip>
                          {/* 내 보관함(ownerId === customerId)이 아닐 때만 "고객에게 연결" 버튼 표시 (개발자 모드에서만) */}
                          {isDevMode && !(item.document.ownerId && item.document.customerId && item.document.ownerId === item.document.customerId) && (
                            <Tooltip content="고객에게 연결">
                              <button
                                type="button"
                                className="action-btn action-btn--link"
                                onClick={(e) => handleLinkClick(item.document as any, e)}
                                aria-label="고객에게 연결"
                              >
                                <LinkIcon />
                              </button>
                            </Tooltip>
                          )}
                        </>
                      )}
                    </div>
                  </div>
                  )
                })}
              </div>
            ) : (
              // 그리드 뷰
              <div className="files-grid" onContextMenu={(e) => handleContextMenu(e)}>
                {filteredAndSortedItems.map(item => (
                  <div
                    key={item._id}
                    className={`file-grid-item ${draggingItemId === item._id ? 'dragging' : ''} ${item.type === 'folder' && dragOverFolderId === item._id ? 'drag-over' : ''}`}
                    onClick={() => {
                      if (item.type === 'folder') {
                        handleFolderClick(item._id)
                      } else if (item.type === 'file' && item.document && onDocumentClick) {
                        onDocumentClick(item.document._id!)
                      }
                    }}
                    onContextMenu={(e) => handleContextMenu(e, item)}
                    draggable
                    onDragStart={(e) => handleDragStart(e, item)}
                    onDragEnd={handleDragEnd}
                    onDragOver={item.type === 'folder' ? handleDragOver : undefined}
                    onDragEnter={item.type === 'folder' ? (e) => handleDragEnter(e, item._id) : undefined}
                    onDragLeave={item.type === 'folder' ? handleDragLeave : undefined}
                    onDrop={item.type === 'folder' ? (e) => handleDrop(e, item._id) : undefined}
                  >
                    <div className="grid-item-icon">
                      {item.type === 'folder' ? (
                        <span className="folder-icon folder-icon-large">📁</span>
                      ) : (
                        <div className={`document-icon ${DocumentUtils.getFileTypeClass(item.mimeType, item.name)}`}>
                          <SFSymbol
                            name={DocumentUtils.getFileIcon(item.mimeType, item.name)}
                            size={SFSymbolSize.CALLOUT}
                            weight={SFSymbolWeight.REGULAR}
                            decorative={true}
                          />
                        </div>
                      )}
                    </div>
                    <div className="grid-item-name">
                      {highlightText(item.name, searchTerm)}
                    </div>
                    <div className="grid-item-info">
                      {item.type === 'file' && item.size ? formatFileSize(item.size) : ''}
                    </div>
                    {item.type === 'file' && (
                      <Tooltip content="다운로드">
                        <button
                          className="grid-download-button"
                          onClick={(e) => handleFileDownload(item._id, item.name, e)}
                          aria-label="다운로드"
                        >
                          <SFSymbol
                            name="arrow.down.circle"
                            size={SFSymbolSize.FOOTNOTE}
                            weight={SFSymbolWeight.REGULAR}
                            decorative={true}
                          />
                        </button>
                      </Tooltip>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* 폴더 생성 모달 */}
      <Modal
        visible={showNewFolderModal}
        onClose={handleCloseFolderModal}
        title="새 폴더"
        size="sm"
        footer={
          <div style={{ display: 'flex', gap: 'var(--spacing-2)', justifyContent: 'flex-end' }}>
            <Button variant="secondary" onClick={handleCloseFolderModal}>
              취소
            </Button>
            <Button
              variant="primary"
              onClick={handleCreateFolder}
              loading={creatingFolder}
              disabled={!newFolderName.trim()}
            >
              만들기
            </Button>
          </div>
        }
      >
        <div style={{ padding: 'var(--spacing-3)' }}>
          <div style={{ marginBottom: 'var(--spacing-2)' }}>
            <label
              htmlFor="folder-name-input"
              style={{
                display: 'block',
                fontSize: 'var(--font-size-footnote)',
                fontWeight: 'var(--font-weight-medium)',
                color: 'var(--color-text-primary)',
                marginBottom: 'var(--spacing-1)'
              }}
            >
              폴더 이름
            </label>
            <input
              id="folder-name-input"
              type="text"
              value={newFolderName}
              onChange={(e) => setNewFolderName(e.target.value)}
              onKeyPress={(e) => {
                if (e.key === 'Enter' && newFolderName.trim()) {
                  handleCreateFolder()
                }
              }}
              placeholder="폴더 이름을 입력하세요"
              autoFocus
              style={{
                width: '100%',
                padding: 'var(--spacing-2)',
                fontSize: 'var(--font-size-body)',
                border: '1px solid var(--color-border)',
                borderRadius: 'var(--radius-md)',
                outline: 'none',
                backgroundColor: 'var(--color-bg-primary)',
                color: 'var(--color-text-primary)',
                transition: 'border-color var(--duration-fast) var(--easing-ease-out)'
              }}
            />
          </div>
        </div>
      </Modal>

      {/* 컨텍스트 메뉴 - Portal로 body에 렌더링하여 부모 transform 영향 회피 */}
      {showContextMenu && createPortal(
        <div
          className="context-menu"
          data-theme={document.documentElement.getAttribute('data-theme') || 'light'}
          style={{
            position: 'fixed',
            left: `${contextMenuPosition.x}px`,
            top: `${contextMenuPosition.y}px`,
            zIndex: 1000
          }}
          onClick={(e) => e.stopPropagation()}
        >
          {selectedItem ? (
            // 항목이 선택된 경우: 기존 메뉴들
            <>
              <button className="context-menu-item" onClick={handleRenameClick}>
                <span className="context-menu-icon context-menu-icon--rename">
                  <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                    <path d="M11.5 1.5l3 3-8 8H3.5v-3l8-8z" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"/>
                    <path d="M9.5 3.5l3 3" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/>
                  </svg>
                </span>
                <span>이름 변경</span>
              </button>
              <button className="context-menu-item" onClick={handleMoveClick}>
                <span className="context-menu-icon context-menu-icon--move">
                  <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                    <path d="M2 4h4l1.5-1.5h6.5a1 1 0 0 1 1 1v9a1 1 0 0 1-1 1H2a1 1 0 0 1-1-1V5a1 1 0 0 1 1-1z" stroke="currentColor" strokeWidth="1.2"/>
                  </svg>
                </span>
                <span>이동...</span>
              </button>

              {selectedItem.type === 'folder' && (
                <button className="context-menu-item" onClick={handleNewFolderFromContext}>
                  <span className="context-menu-icon context-menu-icon--new">
                    <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                      <path d="M2 4h4l1.5-1.5h6.5a1 1 0 0 1 1 1v9a1 1 0 0 1-1 1H2a1 1 0 0 1-1-1V5a1 1 0 0 1 1-1z" stroke="currentColor" strokeWidth="1.2"/>
                      <path d="M8 7v4M6 9h4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                    </svg>
                  </span>
                  <span>새 폴더</span>
                </button>
              )}

              <button className="context-menu-item context-menu-item--danger" onClick={handleDeleteClick}>
                <SFSymbol
                  name="trash"
                  size={SFSymbolSize.CAPTION_1}
                  weight={SFSymbolWeight.MEDIUM}
                  decorative={true}
                />
                <span>삭제</span>
              </button>
            </>
          ) : (
            // 빈 공간 우클릭: "새 폴더"만 표시
            <button className="context-menu-item" onClick={handleNewFolderClick}>
              <span className="context-menu-icon context-menu-icon--new">
                <svg width="13" height="13" viewBox="0 0 16 16" fill="none">
                  <path d="M2 4h4l1.5-1.5h6.5a1 1 0 0 1 1 1v9a1 1 0 0 1-1 1H2a1 1 0 0 1-1-1V5a1 1 0 0 1 1-1z" stroke="currentColor" strokeWidth="1.2"/>
                  <path d="M8 7v4M6 9h4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              </span>
              <span>새 폴더</span>
            </button>
          )}
        </div>,
        document.body
      )}

      {/* 이름 변경 모달 */}
      <Modal
        visible={showRenameModal}
        onClose={handleCloseRenameModal}
        title="이름 변경"
        size="sm"
        footer={
          <div style={{ display: 'flex', gap: 'var(--spacing-2)', justifyContent: 'flex-end' }}>
            <Button variant="secondary" onClick={handleCloseRenameModal}>
              취소
            </Button>
            <Button
              variant="primary"
              onClick={handleRenameItem}
              loading={renamingItem}
              disabled={!renameValue.trim()}
            >
              변경
            </Button>
          </div>
        }
      >
        <div style={{ padding: 'var(--spacing-3)' }}>
          <div style={{ marginBottom: 'var(--spacing-2)' }}>
            <label
              htmlFor="rename-input"
              style={{
                display: 'block',
                fontSize: 'var(--font-size-footnote)',
                fontWeight: 'var(--font-weight-medium)',
                color: 'var(--color-text-primary)',
                marginBottom: 'var(--spacing-1)'
              }}
            >
              {itemToRename?.type === 'folder' ? '폴더 이름' : '파일 이름'}
            </label>
            <input
              id="rename-input"
              type="text"
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onKeyPress={(e) => {
                if (e.key === 'Enter' && renameValue.trim()) {
                  handleRenameItem()
                }
              }}
              placeholder="새 이름을 입력하세요"
              autoFocus
              style={{
                width: '100%',
                padding: 'var(--spacing-2)',
                fontSize: 'var(--font-size-body)',
                border: '1px solid var(--color-border)',
                borderRadius: 'var(--radius-md)',
                outline: 'none',
                backgroundColor: 'var(--color-bg-primary)',
                color: 'var(--color-text-primary)',
                transition: 'border-color var(--duration-fast) var(--easing-ease-out)'
              }}
            />
          </div>
        </div>
      </Modal>

      {/* 액션 모달들 */}
      <DocumentDetailModal
        visible={isDetailModalVisible}
        onClose={handleCloseDetailModal}
        document={selectedDocument}
      />
      <DocumentSummaryModal
        visible={isSummaryModalVisible}
        onClose={handleCloseSummaryModal}
        document={selectedDocument}
      />
      <DocumentFullTextModal
        visible={isFullTextModalVisible}
        onClose={handleCloseFullTextModal}
        document={selectedDocument}
      />
      <DocumentLinkModal
        visible={isLinkModalVisible}
        onClose={handleCloseLinkModal}
        document={selectedDocument}
        onFetchCustomerDocuments={async (customerId: string) => ({
          customer_id: customerId,
          documents: [],
          total: 0
        })}
        onLink={async () => undefined}
      />

      {/* 🍎 도움말 모달 */}
      <Modal
        visible={helpModalVisible}
        onClose={() => setHelpModalVisible(false)}
        title="📁 내 보관함"
        size="sm"
      >
        <div className="help-modal-content">
          <p><strong>이 화면에서 할 수 있는 일</strong></p>
          <ul>
            <li>개인 폴더를 만들어 문서를 정리</li>
            <li>파일을 직접 업로드하여 보관</li>
            <li>문서 라이브러리 파일을 폴더로 이동</li>
          </ul>
          <div className="help-modal-section">
            <p><strong>폴더 관리</strong></p>
            <ul>
              <li><strong>새 폴더</strong>: 상단 도구 모음에서 생성</li>
              <li><strong>폴더 이동</strong>: 우클릭 → "이동" 메뉴</li>
              <li><strong>이름 변경</strong>: 우클릭 → "이름 변경"</li>
            </ul>
          </div>
          <div className="help-modal-section">
            <p><strong>파일 관리</strong></p>
            <ul>
              <li><strong>업로드</strong>: 상단 "업로드" 버튼 또는 드래그 앤 드롭</li>
              <li><strong>다운로드</strong>: 파일 우클릭 → "다운로드"</li>
              <li><strong>미리보기</strong>: 파일 클릭 또는 우클릭 → "미리보기"</li>
            </ul>
          </div>
          <div className="help-modal-section">
            <p><strong>팁</strong></p>
            <ul>
              <li>문서 라이브러리에서 가져온 파일은 원본과 동기화됩니다</li>
              <li>폴더 구조로 계약서, 청구서 등을 체계적으로 분류하세요</li>
            </ul>
          </div>
        </div>
      </Modal>
    </CenterPaneView>

    {/* Apple Confirm Modal */}
    <AppleConfirmModal
      state={confirmModal.state}
      actions={confirmModal.actions}
    />

    {/* Move Folder Modal */}
    <MoveFolderModal
      visible={showMoveModal}
      onClose={() => { setShowMoveModal(false); setSelectedItem(null); }}
      onMove={handleMove}
      currentItem={selectedItem}
      allItems={allFoldersForMove}
    />
    </>
  )
}

export default PersonalFilesView

/**
 * PersonalFilesView 컴포넌트 테스트
 * @since 2025-12-07
 *
 * 복잡한 UI 컴포넌트의 통합 테스트
 * - 모킹 최소화, 실제 렌더링 검증
 */

import { describe, test, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { PersonalFilesView } from '../PersonalFilesView'
import type { PersonalFileItem, FolderContents } from '@/services/personalFilesService'

// vi.hoisted를 사용하여 mock 함수들이 vi.mock과 함께 호이스팅되도록 함
const {
  mockGetFolderContents,
  mockCreateFolder,
  mockUploadFile,
  mockRenameItem,
  mockDeleteItem,
  mockMoveItem,
  mockGetDownloadUrl,
  mockDownloadFile,
  mockSearchFiles,
  mockMoveDocument,
} = vi.hoisted(() => ({
  mockGetFolderContents: vi.fn(),
  mockCreateFolder: vi.fn(),
  mockUploadFile: vi.fn(),
  mockRenameItem: vi.fn(),
  mockDeleteItem: vi.fn(),
  mockMoveItem: vi.fn(),
  mockGetDownloadUrl: vi.fn(),
  mockDownloadFile: vi.fn(),
  mockSearchFiles: vi.fn(),
  mockMoveDocument: vi.fn(),
}))

// personalFilesService 모킹
vi.mock('@/services/personalFilesService', () => ({
  default: {
    getFolderContents: mockGetFolderContents,
    createFolder: mockCreateFolder,
    uploadFile: mockUploadFile,
    renameItem: mockRenameItem,
    deleteItem: mockDeleteItem,
    moveItem: mockMoveItem,
    getDownloadUrl: mockGetDownloadUrl,
    downloadFile: mockDownloadFile,
    searchFiles: mockSearchFiles,
    moveDocument: mockMoveDocument,
  },
  personalFilesService: {
    getFolderContents: mockGetFolderContents,
    createFolder: mockCreateFolder,
    uploadFile: mockUploadFile,
    renameItem: mockRenameItem,
    deleteItem: mockDeleteItem,
    moveItem: mockMoveItem,
    getDownloadUrl: mockGetDownloadUrl,
    downloadFile: mockDownloadFile,
    searchFiles: mockSearchFiles,
    moveDocument: mockMoveDocument,
  },
}))

// DocumentStatusService 모킹
vi.mock('@/services/DocumentStatusService', () => ({
  DocumentStatusService: {
    getRecentDocuments: vi.fn().mockResolvedValue({
      documents: [],
      total: 0,
    }),
  },
}))

// uploadService 모킹
vi.mock('../DocumentRegistrationView/services/uploadService', () => ({
  uploadService: {
    uploadFile: vi.fn(),
    addStatusCallback: vi.fn(),
    removeStatusCallback: vi.fn(),
    addProgressCallback: vi.fn(),
    removeProgressCallback: vi.fn(),
  },
}))

// Mock DocumentLinkModal (uses useQuery which requires QueryClientProvider)
vi.mock('../../DocumentStatusView/components/DocumentLinkModal', () => ({
  default: () => null,
}))

/**
 * 모킹된 폴더 아이템 생성
 */
function createMockFolder(overrides: Partial<PersonalFileItem> = {}): PersonalFileItem {
  return {
    _id: 'folder-1',
    name: '테스트 폴더',
    type: 'folder',
    parentId: null,
    createdAt: '2025-01-01T00:00:00Z',
    updatedAt: '2025-01-01T00:00:00Z',
    isDeleted: false,
    ...overrides,
  }
}

/**
 * 모킹된 파일 아이템 생성
 */
function createMockFile(overrides: Partial<PersonalFileItem> = {}): PersonalFileItem {
  return {
    _id: 'file-1',
    name: '테스트.pdf',
    type: 'file',
    mimeType: 'application/pdf',
    size: 1024 * 1024,
    parentId: null,
    createdAt: '2025-01-01T00:00:00Z',
    updatedAt: '2025-01-01T00:00:00Z',
    isDeleted: false,
    ...overrides,
  }
}

/**
 * 모킹된 폴더 컨텐츠 생성
 */
function createMockFolderContents(overrides: Partial<FolderContents> = {}): FolderContents {
  return {
    currentFolder: null,
    items: [],
    breadcrumbs: [{ _id: null, name: '내 드라이브' }],
    ...overrides,
  }
}

describe('PersonalFilesView', () => {
  beforeEach(() => {
    vi.clearAllMocks()

    // 기본 모킹 설정
    mockGetFolderContents.mockResolvedValue(createMockFolderContents())

    // localStorage 모킹
    const localStorageMock = {
      getItem: vi.fn().mockReturnValue('tester'),
      setItem: vi.fn(),
      removeItem: vi.fn(),
      clear: vi.fn(),
    }
    Object.defineProperty(window, 'localStorage', { value: localStorageMock })
  })

  afterEach(() => {
    vi.clearAllMocks()
  })

  describe('기본 렌더링', () => {
    test('visible=false일 때 컴포넌트가 숨겨짐', () => {
      render(
        <PersonalFilesView
          visible={false}
          onClose={vi.fn()}
        />
      )

      // visible=false일 때 주요 컨텐츠가 보이지 않음
      expect(screen.queryByText('내 드라이브')).not.toBeInTheDocument()
    })

    test('visible=true일 때 컴포넌트가 표시됨', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 내 드라이브 텍스트가 표시됨
        expect(screen.getByText('내 드라이브')).toBeInTheDocument()
      })
    })

    test('폴더 API가 호출됨', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        expect(mockGetFolderContents).toHaveBeenCalled()
      })
    })
  })

  describe('폴더 내용 표시', () => {
    test('폴더 트리가 표시됨', async () => {
      const mockItems = [
        createMockFolder({ _id: 'f1', name: '문서 폴더' }),
      ]

      mockGetFolderContents.mockResolvedValue(
        createMockFolderContents({ items: mockItems })
      )

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 폴더 트리 영역이 있음
        const folderTree = document.querySelector('.folder-tree')
        expect(folderTree).toBeInTheDocument()
      })
    })

    test('파일 아이템이 표시됨', async () => {
      const mockItems = [
        createMockFile({ _id: 'f1', name: '계약서.pdf', size: 2048 }),
      ]

      mockGetFolderContents.mockResolvedValue(
        createMockFolderContents({ items: mockItems })
      )

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        expect(screen.getByText('계약서.pdf')).toBeInTheDocument()
      })
    })

    test('빈 폴더일 때 안내 메시지가 표시됨', async () => {
      mockGetFolderContents.mockResolvedValue(
        createMockFolderContents({ items: [] })
      )

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        expect(screen.getByText('파일이 없습니다')).toBeInTheDocument()
      })
    })
  })

  describe('UI 컨트롤', () => {
    test('입력 필드가 있음', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 검색 또는 기타 입력 필드가 있음
        const inputs = document.querySelectorAll('input')
        expect(inputs.length).toBeGreaterThanOrEqual(0)
      })
    })

    test('툴바에 버튼들이 있음', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 툴바 영역에 버튼들이 있는지 확인
        const allButtons = document.querySelectorAll('button')
        expect(allButtons.length).toBeGreaterThan(3)
      })
    })

    test('액션 버튼들이 있음', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 툴바 영역에 버튼들이 있음
        const buttons = document.querySelectorAll('button')
        expect(buttons.length).toBeGreaterThan(2)
      })
    })
  })

  describe('폴더 기능', () => {
    test('폴더 관련 버튼이 있음', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 폴더 관련 버튼 또는 영역이 있음
        const folderButtons = document.querySelectorAll('[aria-label*="폴더"], .folder-expand-button')
        expect(folderButtons.length).toBeGreaterThan(0)
      })
    })
  })

  describe('컨텍스트 메뉴', () => {
    test('파일에서 우클릭이 동작함', async () => {
      const mockItems = [
        createMockFile({ _id: 'file1', name: '테스트.pdf' }),
      ]

      mockGetFolderContents.mockResolvedValue(
        createMockFolderContents({ items: mockItems })
      )

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        expect(screen.getByText('테스트.pdf')).toBeInTheDocument()
      })

      const fileItem = screen.getByText('테스트.pdf')

      // 우클릭 이벤트가 에러 없이 동작함
      fireEvent.contextMenu(fileItem)
      expect(true).toBe(true)
    })
  })

  describe('드래그 앤 드롭', () => {
    test('드래그 가능한 요소가 있음', async () => {
      const mockItems = [
        createMockFile({ _id: 'file1', name: '드래그파일.pdf' }),
      ]

      mockGetFolderContents.mockResolvedValue(
        createMockFolderContents({ items: mockItems })
      )

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // draggable 속성이 있는 요소가 있음
        const draggableElements = document.querySelectorAll('[draggable="true"]')
        expect(draggableElements.length).toBeGreaterThanOrEqual(0)
      })
    })
  })

  describe('에러 처리', () => {
    test('API 에러 시 에러 메시지가 표시됨', async () => {
      mockGetFolderContents.mockRejectedValue(new Error('서버 오류'))

      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 에러 메시지가 표시됨
        expect(screen.getByText('서버 오류')).toBeInTheDocument()
      })
    })
  })

  describe('사이드바', () => {
    test('사이드바에 내 드라이브가 표시됨', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        expect(screen.getByText('내 드라이브')).toBeInTheDocument()
      })
    })
  })

  // 새로고침/폴링 토글 버튼 테스트 제거됨 (SSE 자동 갱신으로 대체, 수동 컨트롤 불필요)

  describe('툴바 컨트롤', () => {
    test('툴바 영역이 있음', async () => {
      render(
        <PersonalFilesView
          visible={true}
          onClose={vi.fn()}
        />
      )

      await waitFor(() => {
        // 툴바 영역이 있음
        const toolbar = document.querySelector('.toolbar, .files-toolbar')
        const buttons = document.querySelectorAll('button')
        expect(toolbar || buttons.length >= 3).toBeTruthy()
      })
    })
  })
})

/**
 * 사용 가이드 뷰
 * CenterPaneView 패턴 적용
 * 검색 기능 및 동적 카테고리 지원
 * @since 2025-12-18
 * @updated 2025-12-19 - 검색 기능, 추가 카테고리 아이콘
 */

import { useState, ReactNode, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { CenterPaneView } from '../../CenterPaneView/CenterPaneView';
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../SFSymbol';
import { helpApi } from '@/features/help';
import './UsageGuideView.css';
import './UsageGuideView.mobile.css';

// 책 아이콘 (타이틀용) — LP와 동일 (SFSymbol: book, menu-icon-green)
const BookIcon = () => (
  <span className="menu-icon-green">
    <SFSymbol name="book" size={SFSymbolSize.CALLOUT} weight={SFSymbolWeight.MEDIUM} />
  </span>
);

// 카테고리 아이콘들
