describe('NaverMap.tsx - TypeScript 타입 안정성', () => {
  describe('커밋 a0a39d3: Optional chaining 적용', () => {
    it('group[0]?.customer?._id 접근이 안전해야 함', () => {
      const group: Array<{ customer: Customer; result: any }> = []

      // Optional chaining으로 안전하게 접근
