    })

    it('그룹 마커 (이중 원) 컨테이너는 24x24px이어야 함', () => {
      const containerSize = { width: 24, height: 24 }

      expect(containerSize.width).toBe(24)
      expect(containerSize.height).toBe(24)
    })

    it('모든 마커 타입이 동일한 컨테이너 크기를 가져 클릭 영역이 일관되어야 함', () => {
      const singleMarkerContainer = { width: 24, height: 24 }
      const groupMarkerNumberContainer = { width: 24, height: 24 }
      const groupMarkerCircleContainer = { width: 24, height: 24 }

      expect(singleMarkerContainer).toEqual(groupMarkerNumberContainer)
      expect(groupMarkerNumberContainer).toEqual(groupMarkerCircleContainer)
    })
  })

  describe('마커 로딩 진행률 표시', () => {
    it('퍼센티지 계산이 정확해야 함', () => {
      const testCases = [
        { current: 0, total: 100, expected: 0 },
        { current: 10, total: 100, expected: 10 },
        { current: 50, total: 100, expected: 50 },
        { current: 99, total: 100, expected: 99 },
        { current: 100, total: 100, expected: 100 },
        { current: 33, total: 100, expected: 33 },
        { current: 1, total: 3, expected: 33 }, // 33.33... → 33
        { current: 2, total: 3, expected: 67 }, // 66.66... → 67
        { current: 25, total: 50, expected: 50 }
      ]

      for (const { current, total, expected } of testCases) {
        const percentage = Math.round((current / total) * 100)
        expect(percentage).toBe(expected)
      }
    })

    it('로딩 진행률 텍스트가 올바른 형식이어야 함', () => {
      const current = 25
      const total = 100
      const percentage = Math.round((current / total) * 100)
      const progressText = `마커 로딩 중... ${percentage}% (${current}/${total})`

      expect(progressText).toBe('마커 로딩 중... 25% (25/100)')
    })

    it('0으로 나누기를 방지해야 함', () => {
      const current = 0
      const total = 0
      // total이 0일 때 NaN을 방지하기 위한 안전장치 필요
      const percentage = total === 0 ? 0 : Math.round((current / total) * 100)

      expect(percentage).toBe(0)
      expect(Number.isNaN(percentage)).toBe(false)
    })

    it('진행률이 100%를 초과하지 않아야 함', () => {
      const current = 100
      const total = 100
      const percentage = Math.round((current / total) * 100)

      expect(percentage).toBeLessThanOrEqual(100)
    })

    it('소수점 반올림이 정확해야 함', () => {
      // 10 / 3 = 3.333... → 3%
      expect(Math.round((10 / 30) * 100)).toBe(33)

      // 20 / 3 = 6.666... → 7%
      expect(Math.round((20 / 30) * 100)).toBe(67)

      // 15 / 23 = 0.652... → 65%
      expect(Math.round((15 / 23) * 100)).toBe(65)
    })
  })
})

/**
 * PDFViewer Component
 * @since 1.0.0
 * @refactored 2025-11-03 - 공통 Hook 및 컴포넌트 적용 (DRY 원칙)
 *
 * PDF 문서 프리뷰 컴포넌트
 * react-pdf를 사용하여 PDF 렌더링
 * Apple 디자인 철학 준수 - 깔끔하고 직관적인 컨트롤
 */

import React, { useState, useCallback, useEffect } from 'react'
import { Document, Page, pdfjs } from 'react-pdf'
import { ViewerControls } from '../ViewerControls'
import { useViewerControls } from '../../hooks/useViewerControls'
import '../../styles/viewer-common.css'
import 'react-pdf/dist/Page/AnnotationLayer.css'
import 'react-pdf/dist/Page/TextLayer.css'
import './PDFViewer.css'

// PDF.js 워커 설정
// 프로덕션: CDN 사용 (더 안정적), 개발: 로컬 파일
if (import.meta.env.PROD) {
  pdfjs.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`
} else {
  pdfjs.GlobalWorkerOptions.workerSrc = `/pdf.worker.min.mjs`
}

interface PDFViewerProps {
  /** PDF 파일 URL */
  file: string
  /** 다운로드 핸들러 */
  onDownload?: () => void
  /** 다운로드 비활성화 여부 (바이러스 감염 등) */
  downloadDisabled?: boolean
  /** 다운로드 비활성화 사유 - 툴팁에 표시 */
  downloadDisabledReason?: string
  /** 초기 scale (fit to page) */
  initialScale?: number
}

/**
 * PDFViewer React 컴포넌트
 *
 * PDF 문서를 렌더링하고 페이지 네비게이션, 확대/축소 기능 제공
 * @example
 * ```tsx
 * <PDFViewer
 *   file="https://example.com/document.pdf"
 *   onDownload={handleDownload}
 * />
 * ```
 */
export const PDFViewer: React.FC<PDFViewerProps> = ({
  file,
  onDownload,
  downloadDisabled,
  downloadDisabledReason,
  initialScale
}) => {
  // 🎯 공통 Hook 사용 (확대/축소/드래그)
  const controls = useViewerControls(initialScale)

  // PDF 전용 state
  const [numPages, setNumPages] = useState<number | null>(null)
  const [pageNumber, setPageNumber] = useState(1)
  const [containerWidth, setContainerWidth] = useState(600)
  const [error, setError] = useState<string | null>(null)

  const onDocumentLoadSuccess = useCallback(({ numPages }: { numPages: number }) => {
    setNumPages(numPages)
    setPageNumber(1)
    setError(null)
  }, [])

  const onDocumentLoadError = useCallback((error: Error) => {
    setError(error.message || 'PDF 파일을 불러오는 데 실패했습니다.')
  }, [])

  const handleRetry = useCallback(() => {
    setError(null)
  }, [])

  const changePage = useCallback((offset: number) => {
    setPageNumber(prevPageNumber => prevPageNumber + offset)
  }, [])

  const previousPage = () => changePage(-1)
  const nextPage = () => changePage(1)

  // 페이지 변경 시 위치만 초기화 (scale은 유지)
  useEffect(() => {
    controls.resetPosition()
  }, [pageNumber])

  // 컨테이너 크기에 따른 PDF 너비 동적 조정
  useEffect(() => {
    const updateContainerWidth = () => {
      const rightPane = document.querySelector('.layout-rightpane-content')
      if (rightPane) {
        const paneWidth = rightPane.clientWidth
        const optimalWidth = paneWidth * 0.85
        setContainerWidth(optimalWidth)
      }
    }

    updateContainerWidth()

    const rightPane = document.querySelector('.layout-rightpane-content')
    if (rightPane) {
      const resizeObserver = new ResizeObserver(updateContainerWidth)
      resizeObserver.observe(rightPane)

      return () => {
        resizeObserver.disconnect()
      }
    }

    return undefined
  }, [])

  return (
    <div className="viewer-container"> {/* 공통 CSS */}
      {/* PDF Document */}
      <div
        className={`viewer-content pdf-viewer-content ${controls.scale > 1.0 ? (controls.isDragging ? 'viewer-content--dragging' : 'viewer-content--draggable') : ''}`}
        onMouseDown={controls.handleMouseDown}
        onMouseMove={controls.handleMouseMove}
        onMouseUp={controls.handleMouseUp}
        onMouseLeave={controls.handleMouseUp}
      >
        <Document
          file={file}
          onLoadSuccess={onDocumentLoadSuccess}
          onLoadError={onDocumentLoadError}
          loading={
            <div className="viewer-loading">
              <div className="viewer-loading__spinner" aria-label="로딩 중" />
              <span>문서를 불러오는 중...</span>
            </div>
          }
          error={
            <div className="viewer-error">
              <span className="viewer-error__icon" aria-hidden="true">⚠️</span>
              <p className="viewer-error__message">{error || 'PDF 파일을 불러오는 데 실패했습니다.'}</p>
              <button type="button" className="retry-button" onClick={handleRetry}>
                다시 시도
              </button>
            </div>
          }
        >
          <div
            className="pdf-page-container"
            style={{
              // ⚠️ 예외: 런타임 동적 계산 (CSS로 불가능)
              transform: `translate(${controls.position.x}px, ${controls.position.y}px)`
            }}
          >
            <Page
              pageNumber={pageNumber}
              renderTextLayer={false}
              renderAnnotationLayer={false}
              scale={controls.scale}
              width={containerWidth}
            />
          </div>
        </Document>
      </div>

      {/* 🎯 공통 컴포넌트 사용 (Controls) */}
      <ViewerControls
        scale={controls.scale}
        isModified={controls.isModified}
        onZoomIn={controls.zoomIn}
        onZoomOut={controls.zoomOut}
        onReset={controls.resetView}
        {...(onDownload ? { onDownload } : {})}
        downloadDisabled={downloadDisabled}
        downloadDisabledReason={downloadDisabledReason}
        pageNav={{
          currentPage: pageNumber,
          totalPages: numPages,
          onPrevPage: previousPage,
          onNextPage: nextPage
        }}
      />
    </div>
  )
}

export default PDFViewer

/**
 * QuickSearch Component
 * @since 1.0.0
 *
 * 헤더에 배치되는 빠른 검색 컴포넌트
 * 고객명/문서명을 빠르게 검색하여 즉시 이동할 수 있는 기능 제공
 * 애플 디자인 시스템 준수
 */

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react'
import { useQuery } from '@tanstack/react-query'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../SFSymbol'
import { CustomerService } from '@/services/customerService'
import { CustomerUtils, type Customer } from '@/entities/customer/model'
import { highlightText } from '@/shared/lib/highlightText'
import './QuickSearch.css'

interface QuickSearchProps {
  /** 검색 결과 클릭 시 네비게이션 핸들러 */
  onNavigate?: (type: 'customer' | 'document', id: string) => void
  /** 고객 클릭 핸들러 */
  onCustomerClick?: (customerId: string, customer: Customer) => void
  /** 플레이스홀더 텍스트 */
  placeholder?: string
  /** 추가 CSS 클래스 */
  className?: string
}

interface SearchResult {
  id: string
  type: 'customer' | 'document'
  title: string
  subtitle?: string
  customerType?: '개인' | '법인'
}

/**
 * QuickSearch 컴포넌트
 *
 * 빠른 고객/문서 검색을 위한 검색바
 * - 실시간 검색 결과 표시
 * - 키보드 네비게이션 지원
 * - 애플 스타일 UI
 */
export const QuickSearch: React.FC<QuickSearchProps> = ({
  onNavigate,
  onCustomerClick,
  placeholder = '고객 검색...',
  className = ''
}) => {
  const [query, setQuery] = useState('')
  const [isOpen, setIsOpen] = useState(false)
  const [selectedIndex, setSelectedIndex] = useState(-1)
  const inputRef = useRef<HTMLInputElement>(null)
  const containerRef = useRef<HTMLDivElement>(null)
  const resultsRef = useRef<HTMLDivElement>(null)

  // 디바운스된 검색어
  const [debouncedQuery, setDebouncedQuery] = useState('')

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedQuery(query)
    }, 200)
    return () => clearTimeout(timer)
  }, [query])

  // 고객 검색 쿼리
  const { data: customersData, isLoading: isCustomersLoading } = useQuery({
    queryKey: ['quickSearch', 'customers', debouncedQuery],
    queryFn: () => CustomerService.getCustomers({
      search: debouncedQuery,
      limit: 5
    }),
    enabled: debouncedQuery.length >= 1,
    staleTime: 30000,
  })

  // 검색 결과 통합
  const searchResults = useMemo<SearchResult[]>(() => {
    const results: SearchResult[] = []

    // 고객 결과
    if (customersData?.customers) {
      customersData.customers.slice(0, 5).forEach(customer => {
        const customerType = CustomerUtils.getCustomerTypeText(customer)
        results.push({
          id: customer._id,
          type: 'customer',
          title: customer.personal_info?.name || '이름 없음',
          subtitle: customerType,
          customerType: customerType as '개인' | '법인'
        })
      })
    }

    return results
  }, [customersData])

  const isLoading = isCustomersLoading

  // 고객 타입별 아이콘 렌더링 (AllCustomersView와 동일한 아이콘 사용)
  const renderCustomerIcon = (customerType?: '개인' | '법인') => {
    if (customerType === '법인') {
      // 법인: 건물 아이콘 (orange)
      return (
        <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor" className="quick-search__customer-icon quick-search__customer-icon--corporate">
          <circle cx="10" cy="10" r="10" opacity="0.2" />
          <path d="M6 5h2v2H6V5zm0 3h2v2H6V8zm0 3h2v2H6v-2zm3-6h2v2H9V5zm0 3h2v2H9V8zm0 3h2v2H9v-2zm3-6h2v2h-2V5zm0 3h2v2h-2V8zm0 3h2v2h-2v-2zM5 14h10v2H5v-2z" />
        </svg>
      )
    }
    // 개인: 사람 아이콘 (blue)
    return (
      <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor" className="quick-search__customer-icon quick-search__customer-icon--personal">
        <circle cx="10" cy="10" r="10" opacity="0.2" />
        <circle cx="10" cy="7" r="3" />
        <path d="M10 11c-3 0-5 2-5 4v2h10v-2c0-2-2-4-5-4z" />
      </svg>
    )
  }

  // 외부 클릭 감지
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false)
        setSelectedIndex(-1)
      }
    }

    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [])

  // 키보드 네비게이션
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (!isOpen || searchResults.length === 0) {
      if (e.key === 'ArrowDown' && query.length >= 1) {
        setIsOpen(true)
      }
      return
    }

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault()
        setSelectedIndex(prev =>
          prev < searchResults.length - 1 ? prev + 1 : 0
        )
        break
      case 'ArrowUp':
        e.preventDefault()
        setSelectedIndex(prev =>
          prev > 0 ? prev - 1 : searchResults.length - 1
        )
        break
      case 'Enter':
        e.preventDefault()
        if (selectedIndex >= 0 && searchResults[selectedIndex]) {
          handleResultClick(searchResults[selectedIndex])
        }
        break
      case 'Escape':
        setIsOpen(false)
        setSelectedIndex(-1)
        inputRef.current?.blur()
        break
    }
  }, [isOpen, searchResults, selectedIndex, query])

  // 결과 클릭 핸들러
  const handleResultClick = useCallback((result: SearchResult) => {
    if (result.type === 'customer') {
      const customer = customersData?.customers.find(c => c._id === result.id)
      if (customer && onCustomerClick) {
        onCustomerClick(result.id, customer)
      } else if (onNavigate) {
        onNavigate('customer', result.id)
      }
    } else if (onNavigate) {
      onNavigate('document', result.id)
    }

    // 검색 초기화
    setQuery('')
    setIsOpen(false)
    setSelectedIndex(-1)
    inputRef.current?.blur()
  }, [customersData, onCustomerClick, onNavigate])

  // 입력 변경 핸들러
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value
    setQuery(value)
    setSelectedIndex(-1)
    if (value.length >= 1) {
      setIsOpen(true)
    } else {
      setIsOpen(false)
    }
  }

  // 입력 포커스 핸들러
  const handleFocus = () => {
    if (query.length >= 1 && searchResults.length > 0) {
      setIsOpen(true)
    }
  }

  // 검색 초기화
  const handleClear = () => {
    setQuery('')
    setIsOpen(false)
    setSelectedIndex(-1)
    inputRef.current?.focus()
  }

  return (
    <div
      ref={containerRef}
      className={`quick-search ${className}`}
      role="combobox"
      aria-expanded={isOpen}
      aria-haspopup="listbox"
      aria-owns="quick-search-results"
    >
      {/* 검색 입력 */}
      <div className="quick-search__input-wrapper">
        <span className="quick-search__icon">
          <SFSymbol
            name="magnifyingglass"
            size={SFSymbolSize.FOOTNOTE}
            weight={SFSymbolWeight.MEDIUM}
          />
        </span>
        <input
          ref={inputRef}
          type="text"
          className="quick-search__input"
          placeholder={placeholder}
          value={query}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          aria-label="빠른 검색"
          aria-autocomplete="list"
          aria-controls="quick-search-results"
          aria-activedescendant={selectedIndex >= 0 ? `quick-search-result-${selectedIndex}` : undefined}
        />
        {query && (
          <button
            className="quick-search__clear"
            onClick={handleClear}
            aria-label="검색어 지우기"
            type="button"
          >
            <SFSymbol
              name="xmark-circle-fill"
              size={SFSymbolSize.CAPTION_1}
              weight={SFSymbolWeight.MEDIUM}
            />
          </button>
        )}
      </div>

      {/* 검색 결과 드롭다운 */}
      {isOpen && (
        <div
          ref={resultsRef}
          id="quick-search-results"
          className="quick-search__results"
          role="listbox"
          aria-label="검색 결과"
        >
          {isLoading && (
            <div className="quick-search__loading">
              <span className="quick-search__loading-text">검색 중...</span>
            </div>
          )}

          {!isLoading && searchResults.length === 0 && debouncedQuery.length >= 1 && (
            <div className="quick-search__empty">
              <SFSymbol
                name="magnifyingglass"
                size={SFSymbolSize.CALLOUT}
                weight={SFSymbolWeight.ULTRALIGHT}
              />
              <span>"{debouncedQuery}"에 대한 결과가 없습니다</span>
            </div>
          )}

          {!isLoading && searchResults.length > 0 && (
            <>
              {/* 고객 섹션 */}
              {searchResults.some(r => r.type === 'customer') && (
                <div className="quick-search__section">
                  <div className="quick-search__section-header">
                    <SFSymbol
                      name="person"
                      size={SFSymbolSize.CAPTION_1}
                      weight={SFSymbolWeight.MEDIUM}
                    />
                    <span>고객</span>
                  </div>
                  {searchResults
                    .filter(r => r.type === 'customer')
                    .map((result, _index) => {
                      const globalIndex = searchResults.findIndex(r => r.id === result.id)
                      return (
                        <div
                          key={result.id}
                          id={`quick-search-result-${globalIndex}`}
                          className={`quick-search__result ${globalIndex === selectedIndex ? 'quick-search__result--selected' : ''}`}
                          role="option"
                          aria-selected={globalIndex === selectedIndex}
                          onClick={() => handleResultClick(result)}
                          onMouseEnter={() => setSelectedIndex(globalIndex)}
                        >
                          <span className="quick-search__result-icon">
                            {renderCustomerIcon(result.customerType)}
                          </span>
                          <div className="quick-search__result-content">
                            <span className="quick-search__result-title">{highlightText(result.title, debouncedQuery)}</span>
                            {result.subtitle && (
                              <span className="quick-search__result-subtitle">{result.subtitle}</span>
                            )}
                          </div>
                          <span className="quick-search__result-arrow">
                            <SFSymbol
                              name="chevron-right"
                              size={SFSymbolSize.CAPTION_2}
                              weight={SFSymbolWeight.MEDIUM}
                            />
                          </span>
                        </div>
                      )
                    })}
                </div>
              )}

              {/* 고급 검색 링크 */}
              <div className="quick-search__footer">
                <button
                  className="quick-search__advanced-link"
                  onClick={() => {
                    if (onNavigate) {
                      onNavigate('document', 'search')
                    }
                    setIsOpen(false)
                  }}
                  type="button"
                >
                  <SFSymbol
                    name="magnifyingglass"
                    size={SFSymbolSize.CAPTION_1}
                    weight={SFSymbolWeight.MEDIUM}
                  />
                  <span>고급 검색</span>
                </button>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  )
}

/**
 * AppleConfirmProvider - 전역 확인 모달 Context
 * @since 2025-11-27
 * @version 1.0.0
 *
 * 브라우저 alert() 대신 AppleConfirmModal을 전역에서 사용하기 위한 Provider
 * 기존 useAppleConfirmController + AppleConfirmModal을 재사용합니다.
 */

import React, { createContext, useContext } from 'react'
import { useAppleConfirmController, type AppleConfirmParams } from '../controllers/useAppleConfirmController'
import { AppleConfirmModal } from '../components/DocumentViews/DocumentRegistrationView/AppleConfirmModal/AppleConfirmModal'

/** Context 타입 */
interface AppleConfirmContextType {
  /**
   * alert() 대신 사용하는 함수
   *
   * @example
   * ```tsx
   * const { showAlert } = useAppleConfirm()
   *
   * // 간단한 알림
   * await showAlert({ message: '저장되었습니다.' })
   *
   * // 성공 알림
   * await showAlert({
   *   title: '완료',
   *   message: '153건이 삭제되었습니다.',
   *   iconType: 'success'
   * })
   *
   * // 에러 알림
   * await showAlert({
   *   title: '오류',
   *   message: '삭제 중 오류가 발생했습니다.',
   *   iconType: 'error'
   * })
   * ```
   */
  showAlert: (params: AppleConfirmParams) => Promise<boolean>

  /**
   * 확인/취소 선택이 필요한 경우
   *
   * @example
   * ```tsx
   * const confirmed = await showConfirm({
   *   title: '삭제 확인',
   *   message: '정말 삭제하시겠습니까?',
   *   confirmText: '삭제',
   *   confirmStyle: 'destructive',
   *   showCancel: true
   * })
   * if (confirmed) { ... }
   * ```
   */
  showConfirm: (params: AppleConfirmParams) => Promise<boolean>
}

const AppleConfirmContext = createContext<AppleConfirmContextType | null>(null)

/**
 * AppleConfirmProvider
 *
 * App 최상위에 배치하여 전역에서 showAlert/showConfirm 사용 가능
 */
export const AppleConfirmProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const confirmController = useAppleConfirmController()

  /**
   * alert() 대체 - 확인 버튼만 있는 알림
   */
  const showAlert = async (params: AppleConfirmParams): Promise<boolean> => {
    return confirmController.actions.openModal({
      title: '알림',
      confirmText: '확인',
      showCancel: false,
      iconType: 'info',
      ...params
    })
  }

  /**
   * confirm() 대체 - 확인/취소 버튼이 있는 확인
   */
  const showConfirm = async (params: AppleConfirmParams): Promise<boolean> => {
    return confirmController.actions.openModal({
      title: '확인',
      confirmText: '확인',
      cancelText: '취소',
      showCancel: true,
      iconType: 'warning',
      ...params
    })
  }

  return (
    <AppleConfirmContext.Provider value={{ showAlert, showConfirm }}>
      {children}
      <AppleConfirmModal
        state={confirmController.state}
        actions={confirmController.actions}
      />
    </AppleConfirmContext.Provider>
  )
}

/**
 * useAppleConfirm Hook
 *
 * @returns { showAlert, showConfirm }
 *
 * @example
 * ```tsx
 * const { showAlert } = useAppleConfirm()
 *
 * // alert() 대신
 * await showAlert({ message: '저장되었습니다.', iconType: 'success' })
 *
 * // 에러 알림
 * await showAlert({ message: '오류가 발생했습니다.', iconType: 'error' })
 * ```
 */
export const useAppleConfirm = (): AppleConfirmContextType => {
  const context = useContext(AppleConfirmContext)
  if (!context) {
    throw new Error('useAppleConfirm must be used within AppleConfirmProvider')
  }
  return context
}

import React, { useCallback, useRef, useState } from 'react'
import type { ReactNode } from 'react'
import type { KeywordMode, SearchMode } from '@/entities/search'
import { SearchService } from '@/services/searchService'
import { usePersistedState } from '@/hooks/usePersistedState'
import { errorReporter } from '@/shared/lib/errorReporter'
import {
  DocumentSearchContext,
  type DocumentSearchContextValue
} from './DocumentSearchContext.types'

interface DocumentSearchProviderProps {
  children: ReactNode
}

export const DocumentSearchProvider: React.FC<DocumentSearchProviderProps> = ({ children }) => {
  // F5 이후에도 유지되는 검색 상태들
  const [query, setQuery] = usePersistedState<string>('document-search-query', '')
  const [searchMode, setSearchMode] = usePersistedState<SearchMode>('document-search-mode', 'keyword')
  const [keywordMode, setKeywordMode] = usePersistedState<KeywordMode>('document-search-keyword-mode', 'AND')
  const [customerId, setCustomerId] = useState<string | null>(null)
  // 검색 결과는 대량 데이터(2000+건)이므로 sessionStorage 저장 불가 (5MB 한도 초과)
  const [results, setResults] = useState<DocumentSearchContextValue['results']>([])
  const [answer, setAnswer] = useState<string | null>(null)
  // 현재 세션에서 검색 실행 여부 (새로고침 시 초기화 → 가이드 표시)
  const [lastSearchMode, setLastSearchMode] = useState<SearchMode | null>(null)
  // 키워드 검색 백엔드 페이지네이션: 전체 결과 수
  const [totalCount, setTotalCount] = useState<number | null>(null)

  // 임시 상태들 (새로고침 시 초기화되어도 됨)
  const [isLoading, setIsLoading] = useState<boolean>(false)
  const [error, setError] = useState<string | null>(null)

  // 검색 취소용 AbortController
  const abortControllerRef = useRef<AbortController | null>(null)

  const handleSearch = useCallback(async () => {
    if (!query.trim()) {
      setError('검색어를 입력해 주세요.')
      return
    }

    // 이전 진행 중인 요청 중단
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
    }
    const controller = new AbortController()
    abortControllerRef.current = controller

    setIsLoading(true)
    setError(null)
    setResults([])
    setAnswer(null)
    setTotalCount(null)

    try {
      const searchQuery = {
        query: query.trim(),
        search_mode: searchMode,
        ...(searchMode === 'keyword' && { mode: keywordMode }),
        ...(customerId && { customer_id: customerId })
      }

      const response = await SearchService.searchDocuments(searchQuery, controller.signal)

      setResults(response.search_results)
      setAnswer(response.answer || null)
      setLastSearchMode(searchMode)
      setTotalCount(response.total_count ?? null)
    } catch (err) {
      // 사용자 취소 시 에러 표시하지 않음
      if (err instanceof DOMException && err.name === 'AbortError') {
        return
      }
      console.error('[DocumentSearchContext] 검색 오류:', err)
      errorReporter.reportApiError(err as Error, { component: 'DocumentSearchProvider.handleSearch' })
      setError('검색 중 오류가 발생했습니다. 다시 시도해 주세요.')
    } finally {
      // 취소된 요청이 아닌 경우에만 로딩 해제
      if (!controller.signal.aborted) {
        setIsLoading(false)
      }
      if (abortControllerRef.current === controller) {
        abortControllerRef.current = null
      }
    }
  }, [keywordMode, query, searchMode, customerId])

  const handleKeywordPageSearch = useCallback(async (page: number) => {
    if (!query.trim()) return

    // 이전 진행 중인 요청 중단
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
    }
    const controller = new AbortController()
    abortControllerRef.current = controller

    setIsLoading(true)
    setError(null)

    try {
      const pageSize = 20
      const offset = (page - 1) * pageSize

      const searchQuery = {
        query: query.trim(),
        search_mode: 'keyword' as const,
        mode: keywordMode,
        top_k: pageSize,
        offset,
        ...(customerId && { customer_id: customerId }),
      }

      const response = await SearchService.searchDocuments(searchQuery, controller.signal)

      setResults(response.search_results)
      setTotalCount(response.total_count ?? null)
    } catch (err) {
      if (err instanceof DOMException && err.name === 'AbortError') return
      console.error('[DocumentSearchProvider] 페이지 검색 오류:', err)
      errorReporter.reportApiError(err as Error, { component: 'DocumentSearchProvider.handleKeywordPageSearch' })
      setError('검색 중 오류가 발생했습니다. 다시 시도해 주세요.')
    } finally {
      if (!controller.signal.aborted) {
        setIsLoading(false)
      }
      if (abortControllerRef.current === controller) {
        abortControllerRef.current = null
      }
    }
  }, [keywordMode, query, customerId])

  const handleCancel = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
      abortControllerRef.current = null
    }
    setIsLoading(false)
    setError(null)
  }, [])

  const handleQueryChange = useCallback((value: string) => {
    setQuery(value)
    setError(null)
  }, [])

  const handleSearchModeChange = useCallback((mode: SearchMode) => {
    setSearchMode(mode)
    setError(null)
  }, [])

  const handleKeywordModeChange = useCallback((mode: KeywordMode) => {
    setKeywordMode(mode)
  }, [])

  const handleCustomerIdChange = useCallback((id: string | null) => {
    setCustomerId(id)
  }, [])

  const handleReset = useCallback(() => {
    setQuery('')
    setResults([])
    setAnswer(null)
    setError(null)
    setLastSearchMode(null)
    setCustomerId(null)
    setTotalCount(null)
  }, [])

  const value: DocumentSearchContextValue = {
    query,
    searchMode,
    keywordMode,
    customerId,
    results,
    answer,
    isLoading,
    error,
    lastSearchMode,
    totalCount,
    handleSearch,
    handleKeywordPageSearch,
    handleQueryChange,
    handleSearchModeChange,
    handleKeywordModeChange,
    handleCustomerIdChange,
    handleReset,
    handleCancel
  }

  return (
    <DocumentSearchContext.Provider value={value}>
      {children}
    </DocumentSearchContext.Provider>
  )
}

/**
 * useDocumentSearch 훅 테스트
 * @since 1.0.0
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook, waitFor, act } from '@testing-library/react'
import React from 'react'
import { DocumentSearchProvider } from '../DocumentSearchProvider'
import { useDocumentSearch } from '../useDocumentSearch'
import { SearchService } from '@/services/searchService'
import type { SearchResultItem, SemanticSearchResultItem } from '@/entities/search'

// Mock SearchService
vi.mock('@/services/searchService', () => ({
  SearchService: {
    searchDocuments: vi.fn()
  }
}))

describe('useDocumentSearch', () => {
  const wrapper = ({ children }: { children: React.ReactNode }) => (
    <DocumentSearchProvider>{children}</DocumentSearchProvider>
  )

  beforeEach(() => {
    vi.clearAllMocks()
    // persistent state 초기화 (usePersistedState는 sessionStorage 사용)
    sessionStorage.clear()
  })

  afterEach(() => {
    vi.restoreAllMocks()
    // persistent state 정리
    sessionStorage.clear()
  })

  describe('초기 상태', () => {
    it('초기값이 올바르게 설정되어야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      expect(result.current.query).toBe('')
      expect(result.current.searchMode).toBe('keyword')
      expect(result.current.keywordMode).toBe('AND')
      expect(result.current.results).toEqual([])
      expect(result.current.answer).toBeNull()
      expect(result.current.isLoading).toBe(false)
      expect(result.current.error).toBeNull()
      expect(result.current.lastSearchMode).toBeNull()
    })

    it('액션 핸들러가 제공되어야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      expect(typeof result.current.handleSearch).toBe('function')
      expect(typeof result.current.handleQueryChange).toBe('function')
      expect(typeof result.current.handleSearchModeChange).toBe('function')
      expect(typeof result.current.handleKeywordModeChange).toBe('function')
      expect(typeof result.current.handleReset).toBe('function')
    })
  })

  describe('Provider 없이 사용 시 에러', () => {
    it('Provider 없이 사용하면 에러를 던져야 함', () => {
      // Suppress console.error for this test
      const consoleError = vi.spyOn(console, 'error').mockImplementation(() => {})

      expect(() => {
        renderHook(() => useDocumentSearch())
      }).toThrow('useDocumentSearch must be used within DocumentSearchProvider')

      consoleError.mockRestore()
    })
  })

  describe('handleQueryChange', () => {
    it('검색어를 업데이트해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      act(() => {
        result.current.handleQueryChange('테스트 검색어')
      })

      expect(result.current.query).toBe('테스트 검색어')
    })

    it('검색어 변경시 에러를 초기화해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      // 먼저 에러 상태 만들기 (빈 검색어로 검색 시도)
      act(() => {
        result.current.handleSearch()
      })

      expect(result.current.error).not.toBeNull()

      // 검색어 변경
      act(() => {
        result.current.handleQueryChange('새 검색어')
      })

      expect(result.current.error).toBeNull()
    })
  })

  describe('handleSearchModeChange', () => {
    it('검색 모드를 변경해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      act(() => {
        result.current.handleSearchModeChange('semantic')
      })

      expect(result.current.searchMode).toBe('semantic')
    })

    it('검색 모드 변경시 에러를 초기화해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      // 에러 상태 만들기
      act(() => {
        result.current.handleSearch()
      })

      expect(result.current.error).not.toBeNull()

      // 검색 모드 변경
      act(() => {
        result.current.handleSearchModeChange('semantic')
      })

      expect(result.current.error).toBeNull()
    })
  })

  describe('handleKeywordModeChange', () => {
    it('키워드 모드를 변경해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      act(() => {
        result.current.handleKeywordModeChange('OR')
      })

      expect(result.current.keywordMode).toBe('OR')
    })
  })

  describe('handleReset', () => {
    it('모든 상태를 초기화해야 함', () => {
      const { result } = renderHook(() => useDocumentSearch(), { wrapper })

      // 상태 설정
      act(() => {
        result.current.handleQueryChange('검색어')
        result.current.handleSearchModeChange('semantic')
        result.current.handleKeywordModeChange('OR')
      })

      // 리셋
      act(() => {
        result.current.handleReset()
      })

      expect(result.current.query).toBe('')
      expect(result.current.results).toEqual([])
      expect(result.current.answer).toBeNull()
      expect(result.current.error).toBeNull()
      expect(result.current.lastSearchMode).toBeNull()
      // searchMode와 keywordMode는 리셋되지 않음 (의도된 동작)
    })
  })

  describe('handleSearch - 성공 케이스', () => {
    it('키워드 검색을 성공적으로 수행해야 함', async () => {
      const mockResults: SearchResultItem[] = [
        {
