      act(() => {
        result.current.handleQueryChange('첫 검색')
      })

      await act(async () => {
        await result.current.handleSearch()
      })

      await waitFor(() => {
        expect(result.current.results).toHaveLength(1)
      })

      // 두 번째 검색 - 이전 결과가 초기화되어야 함
