      await act(async () => {
        await result.current.handleSearch()
      })

      expect(result.current.error).toBe('검색어를 입력해 주세요.')
      expect(SearchService.searchDocuments).not.toHaveBeenCalled()
    })

    it('API 호출 실패 시 에러를 처리해야 함', async () => {
