/**
 * MappingPreview Component
 * @since 2025-12-05
 * @version 3.0.0
 *
 * 폴더-고객 매핑 미리보기 (윈도우 탐색기 스타일 트리)
 */

import { useState, useMemo, useCallback, useEffect } from 'react'
import { SFSymbol, SFSymbolSize, SFSymbolWeight } from '../../../components/SFSymbol'
import Button from '@/shared/ui/Button'
import { formatFileSize } from '../utils/fileValidation'
import type { FolderMapping } from '../types'
import './MappingPreview.css'

interface MappingPreviewProps {
  mappings: FolderMapping[]
  onBack: () => void
  onStartUpload: (selectedMappings: FolderMapping[]) => void  // 선택된 매핑만 업로드
  expandedPaths?: Set<string>  // 외부에서 제어하는 펼침 상태
  onExpandedPathsChange?: (paths: Set<string>) => void  // 펼침 상태 변경 콜백
}

// 트리 노드 타입
interface TreeNode {
  name: string
  type: 'folder' | 'file'
  size?: number
  children?: TreeNode[]
  path: string
}

// 파일 목록을 트리 구조로 변환
function buildTree(files: File[], rootFolder: string): TreeNode[] {
  const root: TreeNode[] = []

  for (const file of files) {
    const relativePath = (file as File & { webkitRelativePath?: string }).webkitRelativePath || file.name
    const pathParts = relativePath.split('/')
    const startIndex = pathParts.indexOf(rootFolder) + 1
    const parts = pathParts.slice(startIndex)

    let current = root
    let currentPath = rootFolder

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i]
      const isLast = i === parts.length - 1
      currentPath = `${currentPath}/${part}`

      if (isLast) {
        current.push({
          name: part,
          type: 'file',
          size: file.size,
          path: currentPath
        })
      } else {
        let folder = current.find(n => n.type === 'folder' && n.name === part)
        if (!folder) {
          folder = { name: part, type: 'folder', children: [], path: currentPath }
          current.push(folder)
        }
        current = folder.children!
      }
    }
  }

  // 정렬: 폴더 먼저, 그 다음 파일 (알파벳순)
  const sortNodes = (nodes: TreeNode[]): TreeNode[] => {
    return nodes.sort((a, b) => {
      if (a.type !== b.type) return a.type === 'folder' ? -1 : 1
      return a.name.localeCompare(b.name, 'ko')
    }).map(node => {
      if (node.children) {
        node.children = sortNodes(node.children)
      }
      return node
    })
  }

  return sortNodes(root)
}

// 폴더 내 파일 수 계산
function countFiles(nodes: TreeNode[]): number {
  return nodes.reduce((count, node) => {
    if (node.type === 'file') return count + 1
    if (node.children) return count + countFiles(node.children)
    return count
  }, 0)
}

// 폴더 크기 계산
function calculateSize(nodes: TreeNode[]): number {
  return nodes.reduce((sum, node) => {
    if (node.type === 'file') return sum + (node.size || 0)
    if (node.children) return sum + calculateSize(node.children)
    return sum
  }, 0)
}

export default function MappingPreview({
  mappings,
  onBack,
  onStartUpload,
  expandedPaths: controlledExpandedPaths,
  onExpandedPathsChange
}: MappingPreviewProps) {
  // 내부 상태 (controlled prop이 없을 때 사용)
  const [internalExpandedPaths, setInternalExpandedPaths] = useState<Set<string>>(() => {
    // 기본적으로 루트 폴더들만 펼침
    return new Set(mappings.map(m => m.folderName))
  })

  // controlled 또는 uncontrolled 모드 지원
  const expandedPaths = controlledExpandedPaths ?? internalExpandedPaths
  const setExpandedPaths = (onExpandedPathsChange ?? setInternalExpandedPaths) as React.Dispatch<React.SetStateAction<Set<string>>>

  // 선택된 폴더 상태 (기본값: 모든 매칭된 폴더 선택)
  const [selectedFolders, setSelectedFolders] = useState<Set<string>>(() => {
    return new Set(mappings.filter(m => m.matched).map(m => m.folderName))
  })

  // mappings가 변경될 때 선택 상태 동기화 (모든 매칭된 폴더 자동 선택)
  useEffect(() => {
    setSelectedFolders(new Set(mappings.filter(m => m.matched).map(m => m.folderName)))
  }, [mappings])

  const stats = useMemo(() => {
    const matched = mappings.filter(m => m.matched).length
    const unmatched = mappings.length - matched
    const hasPlaceholder = mappings.some(m => m.isPlaceholder)

    // 선택된 폴더만의 파일 수와 크기 (실시간 업데이트)
    const selectedMappings = mappings.filter(m => m.matched && selectedFolders.has(m.folderName))
    const selectedFiles = selectedMappings.reduce((sum, m) => sum + m.fileCount, 0)
    const selectedSize = selectedMappings.reduce((sum, m) => sum + m.totalSize, 0)

    return { matched, unmatched, selectedFiles, selectedSize, hasPlaceholder }
  }, [mappings, selectedFolders])

  // 선택된 매칭 폴더 수
  const selectedCount = useMemo(() => {
    return mappings.filter(m => m.matched && selectedFolders.has(m.folderName)).length
  }, [mappings, selectedFolders])

  // 선택된 폴더가 있고, placeholder가 아니어야 업로드 가능
  const canUpload = selectedCount > 0 && !stats.hasPlaceholder

  // 폴더 선택 토글
  const toggleSelection = useCallback((folderName: string, e: React.MouseEvent) => {
    e.stopPropagation() // 트리 펼침/접힘 방지
    setSelectedFolders(prev => {
      const next = new Set(prev)
      if (next.has(folderName)) {
        next.delete(folderName)
      } else {
        next.add(folderName)
      }
      return next
    })
  }, [])

  // 전체 선택/해제
  const toggleAllSelection = useCallback(() => {
    const matchedFolders = mappings.filter(m => m.matched).map(m => m.folderName)
    if (selectedCount === stats.matched) {
      // 모두 선택됨 -> 모두 해제
      setSelectedFolders(new Set())
    } else {
      // 일부 또는 없음 -> 모두 선택
      setSelectedFolders(new Set(matchedFolders))
    }
  }, [mappings, selectedCount, stats.matched])

  // 업로드 시작 핸들러
  const handleStartUpload = useCallback(() => {
    const selectedMappings = mappings.filter(m => m.matched && selectedFolders.has(m.folderName))
    onStartUpload(selectedMappings)
  }, [mappings, selectedFolders, onStartUpload])

  // 모든 폴더 경로 수집
  const allFolderPaths = useMemo(() => {
    const paths: string[] = []

    const collectPaths = (nodes: TreeNode[]) => {
      for (const node of nodes) {
        if (node.type === 'folder') {
          paths.push(node.path)
          if (node.children) collectPaths(node.children)
        }
      }
    }

    for (const mapping of mappings) {
      paths.push(mapping.folderName)
      const tree = buildTree(mapping.files, mapping.folderName)
      collectPaths(tree)
    }

    return paths
  }, [mappings])

  const allExpanded = expandedPaths.size === allFolderPaths.length

  const togglePath = useCallback((path: string) => {
    setExpandedPaths((prev: Set<string>) => {
      const next = new Set(prev)
      if (next.has(path)) {
        next.delete(path)
      } else {
        next.add(path)
      }
      return next
    })
  }, [])

  const toggleAll = useCallback(() => {
    if (allExpanded) {
      setExpandedPaths(new Set())
    } else {
      setExpandedPaths(new Set(allFolderPaths))
    }
  }, [allExpanded, allFolderPaths])

  // 트리 노드 렌더링 (FolderDropZone과 동일한 CSS 라인 구조)
  const renderNode = (node: TreeNode, isLast: boolean): React.ReactNode => {
    const isFolder = node.type === 'folder'
    const isExpanded = expandedPaths.has(node.path)
    const hasChildren = isFolder && node.children && node.children.length > 0

    return (
      <div key={node.path} className={`guide-node ${isLast ? 'last' : ''}`}>
        <div
          className={`guide-node-content ${isFolder ? 'clickable' : ''}`}
          onClick={isFolder ? () => togglePath(node.path) : undefined}
        >
          {isFolder && (
            <span className="guide-toggle">
              {hasChildren ? (isExpanded ? '▼' : '▶') : ''}
            </span>
          )}
          <span className={`guide-icon ${isFolder ? 'folder' : 'file'}`}>
            {isFolder ? '📁' : '📄'}
          </span>
          <span className={`guide-name ${isFolder ? 'subfolder' : 'file'}`}>{node.name}</span>
          {isFolder && hasChildren && (
            <span className="guide-info">{countFiles(node.children!)}개 · {formatFileSize(calculateSize(node.children || []))}</span>
          )}
          {!isFolder && (
            <span className="guide-info">{formatFileSize(node.size || 0)}</span>
          )}
        </div>
        {isFolder && isExpanded && hasChildren &&
          node.children!.map((child, idx) =>
            renderNode(child, idx === node.children!.length - 1)
          )
        }
      </div>
    )
  }

  return (
    <div className="mapping-preview">
      {/* 요약 통계 */}
      <div className="preview-stats">
        <div className="stat-item">
          <span className="stat-value matched">{selectedCount}/{stats.matched}</span>
          <span className="stat-label">선택됨</span>
        </div>
        <div className="stat-divider" />
        <div className="stat-item">
          <span className="stat-value unmatched">{stats.unmatched}</span>
          <span className="stat-label">미매칭</span>
        </div>
        <div className="stat-divider" />
        <div className="stat-item">
          <span className="stat-value">{stats.selectedFiles}</span>
          <span className="stat-label">파일</span>
        </div>
        <div className="stat-divider" />
        <div className="stat-item">
          <span className="stat-value">{formatFileSize(stats.selectedSize)}</span>
          <span className="stat-label">총 크기</span>
        </div>
      </div>

      {/* 매칭 설명 */}
      <div className="preview-legend">
        <span className="legend-item matched">매칭: 고객명과 일치</span>
        <span className="legend-divider">|</span>
        <span className="legend-item unmatched">미매칭: 일치하는 고객명 없음</span>
      </div>

      {/* 트리 헤더 */}
      <div className="tree-header">
        <div className="tree-header-left">
          <span>폴더 구조</span>
          {stats.matched > 0 && (
            <button type="button" className="select-all-btn" onClick={toggleAllSelection}>
              {selectedCount === stats.matched ? '전체 해제' : '전체 선택'}
            </button>
          )}
        </div>
        <button type="button" className="toggle-all-btn" onClick={toggleAll}>
          {allExpanded ? '▲ 모두 접기' : '▼ 모두 펼치기'}
        </button>
      </div>

      {/* 트리 뷰 - FolderDropZone과 동일한 CSS 라인 구조 */}
      <div className="tree-container">
        <div className="guide-node root">
          {mappings.map((mapping, idx) => {
            const isExpanded = expandedPaths.has(mapping.folderName)
            const tree = buildTree(mapping.files, mapping.folderName)
            const isLast = idx === mappings.length - 1
            const isSelected = selectedFolders.has(mapping.folderName)

            return (
              <div key={mapping.folderName} className={`guide-node ${isLast ? 'last' : ''} has-children`}>
                <div
                  className={`guide-node-content customer-root ${mapping.matched ? 'matched' : 'unmatched'} ${isSelected ? 'selected' : ''}`}
                  onClick={() => togglePath(mapping.folderName)}
                >
                  {/* 매칭된 폴더에만 체크박스 표시 */}
                  {mapping.matched && (
                    <span
                      className={`guide-checkbox ${isSelected ? 'checked' : ''}`}
                      onClick={(e) => toggleSelection(mapping.folderName, e)}
                    >
                      {isSelected ? '☑' : '☐'}
                    </span>
                  )}
                  <span className="guide-toggle">
                    {isExpanded ? '▼' : '▶'}
                  </span>
                  {mapping.matched ? (
                    <span className="guide-icon customer-icon">
                      <SFSymbol name="person" size={SFSymbolSize.FOOTNOTE} weight={SFSymbolWeight.MEDIUM} />
                    </span>
                  ) : (
                    <span className="guide-icon folder">📁</span>
                  )}
                  <span className={`guide-name customer ${mapping.matched ? '' : 'unmatched'}`}>{mapping.folderName}</span>
                  {!mapping.matched && (
                    <span className="guide-note">미매칭</span>
                  )}
                  <span className="guide-info">{mapping.fileCount}개 · {formatFileSize(mapping.totalSize)}</span>
                </div>
                {isExpanded && tree.length > 0 &&
                  tree.map((node, nodeIdx) =>
                    renderNode(node, nodeIdx === tree.length - 1)
                  )
                }
              </div>
            )
          })}
        </div>
      </div>

      {/* 경고 - placeholder 상태 */}
      {stats.hasPlaceholder && (
        <div className="preview-warning placeholder">
          <SFSymbol name="arrow-counterclockwise" size={SFSymbolSize.FOOTNOTE} weight={SFSymbolWeight.MEDIUM} />
          <span>새로고침으로 파일 내용이 사라졌습니다. 뒤로 가서 폴더를 다시 선택해주세요.</span>
        </div>
      )}

      {/* 경고 - 미매칭 */}
      {stats.unmatched > 0 && !stats.hasPlaceholder && (
        <div className="preview-warning">
          <SFSymbol name="exclamationmark-triangle-fill" size={SFSymbolSize.FOOTNOTE} weight={SFSymbolWeight.MEDIUM} />
          <span>미매칭된 {stats.unmatched}개 폴더는 업로드되지 않습니다.</span>
        </div>
      )}

      {/* 버튼 */}
      <div className="preview-actions">
        <Button variant="secondary" onClick={onBack}>뒤로</Button>
        <Button variant="primary" onClick={handleStartUpload} disabled={!canUpload}>
          {stats.hasPlaceholder
            ? '폴더 다시 선택 필요'
            : canUpload
              ? `${selectedCount}개 폴더 업로드 시작`
              : '업로드할 폴더를 선택하세요'}
        </Button>
      </div>
    </div>
  )
}

/**
 * useBatchUpload Hook - Advanced Scenario Tests
 * @since 2025-12-07
 * @version 1.0.0
 *
 * 고급 시나리오 테스트:
 * - 동시 업로드 관리 (MAX_CONCURRENT_UPLOADS = 3)
 * - 재시도 로직 (MAX_RETRY_COUNT = 3)
 * - 복합 중복 처리 시나리오
 * - 메모리/리소스 정리
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import { useBatchUpload } from '../useBatchUpload'
import { BatchUploadApi } from '../../api/batchUploadApi'
import * as duplicateChecker from '@/shared/lib/fileValidation'
import type { FolderMapping } from '../../types'

// Mock modules
vi.mock('../../api/batchUploadApi', () => ({
  BatchUploadApi: {
    uploadFile: vi.fn(),
    getCustomersForMatching: vi.fn(),
  },
}))

vi.mock('@/shared/lib/fileValidation', async (importOriginal) => {
  const actual = await importOriginal<typeof import('@/shared/lib/fileValidation')>()
  return {
    ...actual,
    getCustomerFileHashes: vi.fn(),
    checkDuplicateFile: vi.fn(),
    getUniqueFileName: vi.fn(),
  }
})

const mockUploadFile = vi.mocked(BatchUploadApi.uploadFile)
const mockGetCustomerFileHashes = vi.mocked(duplicateChecker.getCustomerFileHashes)
const mockCheckDuplicateFile = vi.mocked(duplicateChecker.checkDuplicateFile)
const mockGetUniqueFileName = vi.mocked(duplicateChecker.getUniqueFileName)

describe('useBatchUpload - Advanced Scenarios', () => {
  beforeEach(() => {
    vi.clearAllMocks()

    // Default mocks
    mockGetCustomerFileHashes.mockResolvedValue([])
    mockCheckDuplicateFile.mockResolvedValue({
      isDuplicate: false,
      newFileHash: 'mock-hash',
    })
    mockUploadFile.mockResolvedValue({
      success: true,
      fileName: 'test.pdf',
      customerId: 'customer-1',
    })
    mockGetUniqueFileName.mockImplementation((name) => name)
  })

  afterEach(() => {
    vi.resetAllMocks()
  })

  // ==================== 헬퍼 함수 ====================

  const createMockFile = (name: string, size: number = 1024): File => {
    const content = 'x'.repeat(size)
    return new File([content], name, { type: 'application/pdf' })
  }

  const createMockMapping = (overrides: Partial<FolderMapping> = {}): FolderMapping => ({
    folderName: '홍길동',
    customerId: 'customer-1',
    customerName: '홍길동',
    matched: true,
    files: [createMockFile('test.pdf')],
    fileCount: 1,
    totalSize: 1000,
    ...overrides,
  })

  const createMultipleFiles = (count: number): File[] => {
    return Array.from({ length: count }, (_, i) => createMockFile(`file${i + 1}.pdf`))
  }

  // ==================== 동시 업로드 관리 ====================

  describe('동시 업로드 관리', () => {
    it('여러 파일이 동시에 업로드됨', async () => {
      const files = createMultipleFiles(5)
      const mapping = createMockMapping({
        files,
        fileCount: 5,
      })

      // 업로드 완료 순서 추적
      const uploadOrder: string[] = []
      mockUploadFile.mockImplementation(async (file) => {
        uploadOrder.push(file.name)
        await new Promise((resolve) => setTimeout(resolve, 10))
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      // 모든 파일이 업로드됨
      expect(result.current.progress.completedFiles).toBe(5)
      expect(mockUploadFile).toHaveBeenCalledTimes(5)
    })

    it('매핑되지 않은 폴더는 무시됨', async () => {
      const mappings: FolderMapping[] = [
        createMockMapping({
          folderName: '홍길동',
          matched: true,
          files: [createMockFile('matched.pdf')],
        }),
        createMockMapping({
          folderName: '미매칭',
          matched: false,
          customerId: undefined,
          files: [createMockFile('unmatched.pdf')],
        }),
      ]

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload(mappings)
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      // matched된 파일만 업로드됨
      expect(mockUploadFile).toHaveBeenCalledTimes(1)
      expect(result.current.progress.completedFiles).toBe(1)
    })

    it('여러 고객 폴더가 동시에 처리됨', async () => {
      const mappings: FolderMapping[] = [
        createMockMapping({
          folderName: '홍길동',
          customerId: 'customer-1',
          files: createMultipleFiles(2),
          fileCount: 2,
        }),
        createMockMapping({
          folderName: '김영희',
          customerId: 'customer-2',
          files: createMultipleFiles(2),
          fileCount: 2,
        }),
      ]

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload(mappings)
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      expect(result.current.progress.completedFiles).toBe(4)
      expect(result.current.progress.totalFolders).toBe(2)
    })
  })

  // ==================== 재시도 로직 ====================

  describe('재시도 로직', () => {
    it('업로드 실패 시 자동 재시도됨', async () => {
      const mapping = createMockMapping()

      // 첫 2번 실패, 3번째 성공
      mockUploadFile
        .mockResolvedValueOnce({
          success: false,
          fileName: 'test.pdf',
          customerId: 'customer-1',
          error: '일시적 오류',
        })
        .mockResolvedValueOnce({
          success: false,
          fileName: 'test.pdf',
          customerId: 'customer-1',
          error: '일시적 오류',
        })
        .mockResolvedValueOnce({
          success: true,
          fileName: 'test.pdf',
          customerId: 'customer-1',
        })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(
        () => {
          expect(result.current.progress.state).toBe('completed')
        },
        { timeout: 10000 }
      )

      // 3번 호출됨 (2번 실패 + 1번 성공)
      expect(mockUploadFile).toHaveBeenCalledTimes(3)
      expect(result.current.progress.completedFiles).toBe(1)
      expect(result.current.progress.failedFiles).toBe(0)
    })

    it('최대 재시도 횟수 초과 시 실패 처리됨', async () => {
      const mapping = createMockMapping()

      // 모든 시도 실패
      mockUploadFile.mockResolvedValue({
        success: false,
        fileName: 'test.pdf',
        customerId: 'customer-1',
        error: '영구 오류',
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(
        () => {
          expect(result.current.progress.state).toBe('completed')
        },
        { timeout: 15000 }
      )

      // MAX_RETRY_COUNT (3) 만큼 호출됨
      expect(mockUploadFile).toHaveBeenCalledTimes(3)
      expect(result.current.progress.failedFiles).toBe(1)
      expect(result.current.progress.completedFiles).toBe(0)
    })

    it('일부 파일만 실패하는 경우', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(3),
        fileCount: 3,
      })

      // file1, file3는 성공, file2는 실패
      mockUploadFile.mockImplementation(async (file) => {
        if (file.name === 'file2.pdf') {
          return {
            success: false,
            fileName: file.name,
            customerId: 'customer-1',
            error: '업로드 실패',
          }
        }
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(
        () => {
          expect(result.current.progress.state).toBe('completed')
        },
        { timeout: 15000 }
      )

      // file2는 3번 재시도 후 실패
      expect(result.current.progress.completedFiles).toBe(2)
      expect(result.current.progress.failedFiles).toBe(1)
    })
  })

  // ==================== 폴더 상태 관리 ====================

  describe('폴더 상태 관리', () => {
    it('모든 파일 완료 시 폴더 상태가 completed로 변경됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(3),
        fileCount: 3,
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      const folder = result.current.progress.folders.find((f) => f.folderName === '홍길동')
      expect(folder?.status).toBe('completed')
      expect(folder?.completedFiles).toBe(3)
    })

    it('일부 파일 실패 시 폴더 상태가 partial로 변경됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(3),
        fileCount: 3,
      })

      // 2번 파일만 실패
      mockUploadFile.mockImplementation(async (file) => {
        if (file.name === 'file2.pdf') {
          return {
            success: false,
            fileName: file.name,
            customerId: 'customer-1',
            error: '실패',
          }
        }
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(
        () => {
          expect(result.current.progress.state).toBe('completed')
        },
        { timeout: 15000 }
      )

      const folder = result.current.progress.folders.find((f) => f.folderName === '홍길동')
      expect(folder?.status).toBe('partial')
      expect(folder?.completedFiles).toBe(2)
      expect(folder?.failedFiles).toBe(1)
    })

    it('모든 파일 실패 시 폴더 상태가 failed로 변경됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(2),
        fileCount: 2,
      })

      mockUploadFile.mockResolvedValue({
        success: false,
        fileName: 'test.pdf',
        customerId: 'customer-1',
        error: '실패',
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(
        () => {
          expect(result.current.progress.state).toBe('completed')
        },
        { timeout: 15000 }
      )

      const folder = result.current.progress.folders.find((f) => f.folderName === '홍길동')
      expect(folder?.status).toBe('failed')
    })
  })

  // ==================== 진행률 계산 ====================

  describe('진행률 계산', () => {
    it('전체 진행률이 올바르게 계산됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(4),
        fileCount: 4,
      })

      let uploadCount = 0
      mockUploadFile.mockImplementation(async (file) => {
        uploadCount++
        await new Promise((resolve) => setTimeout(resolve, 10))
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      // 완료 시 100%
      expect(result.current.progress.overallProgress).toBe(100)
    })

    it('빈 파일 목록의 진행률은 0', () => {
      const { result } = renderHook(() => useBatchUpload())

      expect(result.current.progress.overallProgress).toBe(0)
    })
  })

  // ==================== 취소 처리 ====================

  describe('취소 처리', () => {
    it('업로드 중 취소 시 pending 파일이 cancelled로 변경됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(5),
        fileCount: 5,
      })

      // 업로드를 느리게 만들어 취소할 시간 확보
      mockUploadFile.mockImplementation(async (file) => {
        await new Promise((resolve) => setTimeout(resolve, 100))
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      // 업로드 시작 (비동기) — startUpload 내부 50ms cleanup 대기 후 실제 업로드
      act(() => {
        result.current.startUpload([mapping])
      })

      // cleanup 대기(50ms) 이후 취소해야 실제 취소됨
      await act(async () => {
        await new Promise((resolve) => setTimeout(resolve, 60))
      })

      act(() => {
        result.current.cancelUpload()
      })

      // 취소 상태 확인
      expect(result.current.progress.state).toBe('cancelled')
    })

    it('취소 후 상태가 cancelled로 유지됨', async () => {
      const mapping = createMockMapping()

      const { result } = renderHook(() => useBatchUpload())

      act(() => {
        result.current.startUpload([mapping])
      })

      // cleanup 대기(50ms) 이후 취소해야 실제 취소됨
      await act(async () => {
        await new Promise((resolve) => setTimeout(resolve, 60))
      })

      act(() => {
        result.current.cancelUpload()
      })

      // 상태 확인
      expect(result.current.progress.state).toBe('cancelled')

      // 잠시 대기 후에도 상태 유지
      await new Promise((resolve) => setTimeout(resolve, 100))
      expect(result.current.progress.state).toBe('cancelled')
    })
  })

  // ==================== 일시정지/재개 ====================

  describe('일시정지/재개', () => {
    it('일시정지 상태에서 업로드가 중단됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(5),
        fileCount: 5,
      })

      let uploadCount = 0
      mockUploadFile.mockImplementation(async (file) => {
        uploadCount++
        await new Promise((resolve) => setTimeout(resolve, 50))
        return {
          success: true,
          fileName: file.name,
          customerId: 'customer-1',
        }
      })

      const { result } = renderHook(() => useBatchUpload())

      // 업로드 시작
      act(() => {
        result.current.startUpload([mapping])
      })

      // 즉시 일시정지
      act(() => {
        result.current.pauseUpload()
      })

      expect(result.current.progress.state).toBe('paused')
    })

    it('재개 시 업로드가 계속됨', async () => {
      const { result } = renderHook(() => useBatchUpload())

      // 일시정지 후 재개
      act(() => {
        result.current.pauseUpload()
      })

      expect(result.current.progress.state).toBe('paused')

      act(() => {
        result.current.resumeUpload()
      })

      expect(result.current.progress.state).toBe('uploading')
    })
  })

  // ==================== 리소스 정리 ====================

  describe('리소스 정리', () => {
    it('reset 호출 시 모든 상태가 초기화됨', async () => {
      const mapping = createMockMapping({
        files: createMultipleFiles(3),
        fileCount: 3,
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      // reset 실행
      act(() => {
        result.current.reset()
      })

      // 초기 상태 확인
      expect(result.current.progress.state).toBe('idle')
      expect(result.current.progress.totalFiles).toBe(0)
      expect(result.current.progress.completedFiles).toBe(0)
      expect(result.current.progress.files).toHaveLength(0)
      expect(result.current.progress.folders).toHaveLength(0)
    })

    it('취소 후 reset이 가능함', async () => {
      const mapping = createMockMapping()

      const { result } = renderHook(() => useBatchUpload())

      act(() => {
        result.current.startUpload([mapping])
      })

      act(() => {
        result.current.cancelUpload()
      })

      act(() => {
        result.current.reset()
      })

      expect(result.current.progress.state).toBe('idle')
    })
  })

  // ==================== 에지 케이스 ====================

  describe('에지 케이스', () => {
    it('빈 매핑 배열로 시작해도 에러가 발생하지 않음', async () => {
      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([])
      })

      expect(result.current.progress.state).toBe('completed')
      expect(result.current.progress.totalFiles).toBe(0)
    })

    it('파일이 없는 폴더는 건너뜀', async () => {
      const mapping = createMockMapping({
        files: [],
        fileCount: 0,
      })

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload([mapping])
      })

      expect(result.current.progress.state).toBe('completed')
      expect(result.current.progress.totalFiles).toBe(0)
    })

    it('동일한 고객에게 여러 폴더가 매핑되어도 정상 처리됨', async () => {
      const mappings: FolderMapping[] = [
        createMockMapping({
          folderName: '홍길동_문서1',
          customerId: 'customer-1',
          files: [createMockFile('doc1.pdf')],
        }),
        createMockMapping({
          folderName: '홍길동_문서2',
          customerId: 'customer-1',
          files: [createMockFile('doc2.pdf')],
        }),
      ]

      const { result } = renderHook(() => useBatchUpload())

      await act(async () => {
        await result.current.startUpload(mappings)
      })

      await waitFor(() => {
        expect(result.current.progress.state).toBe('completed')
      })

      // 같은 고객에 대한 해시 캐시는 한 번만 로드됨
      expect(mockGetCustomerFileHashes).toHaveBeenCalledTimes(1)
      expect(result.current.progress.completedFiles).toBe(2)
    })
  })
})

