  describe('초기 상태', () => {
    it('duplicateState가 올바르게 초기화됨', () => {
      const { result } = renderHook(() => useBatchUpload())

      expect(result.current.progress.duplicateState).toEqual({
        isChecking: false,
        currentDuplicate: null,
        pendingDuplicates: [],
        resolvedCount: 0,
        totalDuplicates: 0,
