      mockCheckDuplicateFile.mockResolvedValueOnce({
        isDuplicate: true,
        existingDoc: {
          documentId: 'existing-doc-1',
          fileName: 'test.pdf',
          fileHash: 'existing-hash',
          fileSize: 1000,
          uploadedAt: '2025-12-01',
