/**
 * useAddressArchiveController 훅 테스트
 *
 * 주소 보관소 컨트롤러 검증
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act, waitFor } from '@testing-library/react';
import { useAddressArchiveController } from '../useAddressArchiveController';
import { AddressService } from '@/services/addressService';
import type { AddressHistoryItem } from '@/entities/customer/model';

vi.mock('@/services/addressService');

describe('useAddressArchiveController', () => {
  const mockCustomerId = 'customer-123';
  const mockAddressHistory: AddressHistoryItem[] = [
    {
      address: {
        postal_code: '12345',
        address1: '서울시 강남구',
        address2: '101호'
      },
      changed_at: '2025-01-01T00:00:00Z'
    },
    {
      address: {
        postal_code: '54321',
        address1: '부산시 해운대구',
        address2: '202호'
      },
      changed_at: '2025-01-01T00:00:00Z'
    }
  ];

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('초기화', () => {
    it('초기 isOpen은 false여야 함', () => {
      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      expect(result.current.isOpen).toBe(false);
    });

    it('초기 addressHistory는 빈 배열이어야 함', () => {
      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      expect(result.current.addressHistory).toEqual([]);
    });

    it('초기 isLoading은 false여야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      // useEffect로 자동 로딩이 완료될 때까지 대기
      await waitFor(() => {
        expect(result.current.isLoading).toBe(false);
      });
    });

    it('초기 error는 null이어야 함', () => {
      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      expect(result.current.error).toBeNull();
    });
  });

  describe('open', () => {
    it('모달을 열어야 함', () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      act(() => {
        result.current.open();
      });

      expect(result.current.isOpen).toBe(true);
    });

    it('모달을 열 때 주소 이력을 로드해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      act(() => {
        result.current.open();
      });

      await waitFor(() => {
        expect(AddressService.getAddressHistory).toHaveBeenCalledWith(mockCustomerId);
      });
    });
  });

  describe('close', () => {
    it('모달을 닫아야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      act(() => {
        result.current.open();
      });

      expect(result.current.isOpen).toBe(true);

      act(() => {
        result.current.close();
      });

      expect(result.current.isOpen).toBe(false);
    });

    it('모달을 닫을 때 에러를 초기화해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockRejectedValue(
        new Error('로드 실패')
      );

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      act(() => {
        result.current.open();
      });

      await waitFor(() => {
        expect(result.current.error).toBeTruthy();
      });

      act(() => {
        result.current.close();
      });

      expect(result.current.error).toBeNull();
    });
  });

  describe('loadAddressHistory', () => {
    it('주소 이력을 성공적으로 로드해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      await act(async () => {
        await result.current.loadAddressHistory(mockCustomerId);
      });

      expect(result.current.addressHistory).toEqual(mockAddressHistory);
      expect(result.current.error).toBeNull();
      expect(result.current.isLoading).toBe(false);
    });

    it('로딩 중에는 isLoading이 true여야 함', async () => {
      let resolveLoad: ((value: any) => void) | null = null;

      vi.mocked(AddressService.getAddressHistory).mockImplementation(
        () => new Promise(resolve => {
          resolveLoad = resolve;
        })
      );

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      act(() => {
        result.current.loadAddressHistory(mockCustomerId);
      });

      await waitFor(() => {
        expect(result.current.isLoading).toBe(true);
      });

      act(() => {
        resolveLoad?.(mockAddressHistory);
      });

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false);
      });
    });

    it('로드 실패 시 에러를 설정해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockRejectedValue(
        new Error('API 에러')
      );

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      await act(async () => {
        await result.current.loadAddressHistory(mockCustomerId);
      });

      expect(result.current.error).toBe('API 에러');
      expect(result.current.addressHistory).toEqual([]);
      expect(result.current.isLoading).toBe(false);
    });

    it('customerId가 없으면 에러를 설정해야 함', async () => {
      // customerId가 빈 문자열일 때 useEffect에서 자동 로딩되지 않음
      const { result } = renderHook(() =>
        useAddressArchiveController('')
      );

      // useEffect가 실행되지 않았으므로 초기 상태 확인
      expect(result.current.error).toBeNull();
      expect(AddressService.getAddressHistory).not.toHaveBeenCalled();

      // 직접 빈 문자열로 loadAddressHistory 호출
      await act(async () => {
        await result.current.loadAddressHistory('');
      });

      expect(result.current.error).toBe('고객 ID가 필요합니다');
      expect(AddressService.getAddressHistory).not.toHaveBeenCalled();
    });

    it('로드 시작 시 이전 에러를 초기화해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory)
        .mockRejectedValueOnce(new Error('첫 번째 에러')) // useEffect에서 소비
        .mockResolvedValueOnce(mockAddressHistory);       // 수동 호출에서 성공

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      // useEffect에서 자동 로드가 실패할 때까지 대기
      await waitFor(() => {
        expect(result.current.error).toBe('첫 번째 에러');
        expect(result.current.isLoading).toBe(false);
      });

      // 두 번째 로드 성공 (수동 호출)
      await act(async () => {
        await result.current.loadAddressHistory(mockCustomerId);
      });

      expect(result.current.error).toBeNull();
      expect(result.current.addressHistory).toEqual(mockAddressHistory);
    });

    it('Error 객체가 아닌 에러도 처리해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockRejectedValue('문자열 에러');

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      await act(async () => {
        await result.current.loadAddressHistory(mockCustomerId);
      });

      expect(result.current.error).toBe('주소 이력을 불러오는데 실패했습니다.');
    });
  });

  describe('통합 시나리오', () => {
    it('open → 로드 성공 → close 플로우가 정상 작동해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory).mockResolvedValue(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      // 1. 모달 열기
      act(() => {
        result.current.open();
      });

      expect(result.current.isOpen).toBe(true);

      // 2. 로드 완료 대기
      await waitFor(() => {
        expect(result.current.addressHistory).toEqual(mockAddressHistory);
      });

      expect(result.current.error).toBeNull();

      // 3. 모달 닫기
      act(() => {
        result.current.close();
      });

      expect(result.current.isOpen).toBe(false);
    });

    it('open → 로드 실패 → 재시도 → 성공 플로우가 정상 작동해야 함', async () => {
      vi.mocked(AddressService.getAddressHistory)
        .mockRejectedValueOnce(new Error('첫 번째 실패'))   // useEffect auto-load
        .mockRejectedValueOnce(new Error('첫 번째 실패'))   // open() calls load
        .mockResolvedValueOnce(mockAddressHistory);

      const { result } = renderHook(() =>
        useAddressArchiveController(mockCustomerId)
      );

      // 1. 모달 열기 (첫 번째 로드 실패)
      act(() => {
        result.current.open();
      });

      await waitFor(() => {
        expect(result.current.error).toBe('첫 번째 실패');
      });

      // 2. 재시도 (두 번째 로드 성공)
      await act(async () => {
        await result.current.loadAddressHistory(mockCustomerId);
      });

      expect(result.current.error).toBeNull();
      expect(result.current.addressHistory).toEqual(mockAddressHistory);
    });

    it('customerId 변경 시 새로운 고객의 주소 이력을 로드해야 함', async () => {
      const anotherCustomerId = 'customer-456';
      const anotherHistory: AddressHistoryItem[] = [
        {
          address: {
            postal_code: '99999',
            address1: '대구시',
            address2: '303호'
          },
          changed_at: '2025-01-01T00:00:00Z'
        }
      ];

      vi.mocked(AddressService.getAddressHistory).mockImplementation((id) => {
        if (id === anotherCustomerId) return Promise.resolve(anotherHistory);
        return Promise.resolve(mockAddressHistory);
      });

      const { result, rerender } = renderHook(
        ({ customerId }) => useAddressArchiveController(customerId),
        { initialProps: { customerId: mockCustomerId } }
      );

      // 첫 번째 고객의 주소 로드
      act(() => {
        result.current.open();
      });

      await waitFor(() => {
        expect(result.current.addressHistory).toEqual(mockAddressHistory);
      });

      act(() => {
        result.current.close();
      });

      // customerId 변경
      rerender({ customerId: anotherCustomerId });

      // 두 번째 고객의 주소 로드
      act(() => {
        result.current.open();
      });

      await waitFor(() => {
        expect(AddressService.getAddressHistory).toHaveBeenCalledWith(anotherCustomerId);
      });
    });
  });
});

/**
 * useCustomerDocumentsController 훅 테스트
 *
 * 고객 상세 문서 탭 전용 컨트롤러 검증
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act, waitFor } from '@testing-library/react';
import { useCustomerDocumentsController } from '../useCustomerDocumentsController';
import { DocumentService } from '@/services/DocumentService';
import { DocumentStatusService } from '@/services/DocumentStatusService';

vi.mock('@/services/DocumentService');
vi.mock('@/services/DocumentStatusService');

describe('useCustomerDocumentsController', () => {
  const mockCustomerId = 'customer-123';
  const mockDocuments = [
    {
      _id: 'doc-1',
      originalName: 'document1.pdf',
      mimeType: 'application/pdf',
      fileSize: 1024,
      uploadedAt: '2025-01-01T00:00:00Z',
      linkedAt: '2025-01-02T00:00:00Z',
      status: 'completed'
    },
    {
      _id: 'doc-2',
      originalName: 'document2.pdf',
      mimeType: 'application/pdf',
      fileSize: 2048,
      uploadedAt: '2025-01-03T00:00:00Z',
      linkedAt: '2025-01-04T00:00:00Z',
      status: 'processing'
    }
  ];

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('초기화 및 자동 로드', () => {
    it('customerId가 제공되면 자동으로 문서를 로드해야 함', async () => {
      vi.mocked(DocumentService.getCustomerDocuments).mockResolvedValue({
        customer_id: mockCustomerId,
        documents: mockDocuments,
        total: mockDocuments.length
      });

      const { result } = renderHook(() =>
        useCustomerDocumentsController(mockCustomerId)
      );

      expect(result.current.isLoading).toBe(true);

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false);
      });

      expect(DocumentService.getCustomerDocuments).toHaveBeenCalledWith(mockCustomerId);
      expect(result.current.documents).toEqual(mockDocuments);
      expect(result.current.documentCount).toBe(2);
      expect(result.current.isEmpty).toBe(false);
    });

    it('customerId가 null이면 문서를 로드하지 않아야 함', () => {
      const { result } = renderHook(() =>
        useCustomerDocumentsController(null)
      );

      expect(DocumentService.getCustomerDocuments).not.toHaveBeenCalled();
      expect(result.current.documents).toEqual([]);
      expect(result.current.isEmpty).toBe(true);
    });

    it('customerId가 undefined이면 문서를 로드하지 않아야 함', () => {
      const { result } = renderHook(() =>
        useCustomerDocumentsController(undefined)
      );

      expect(DocumentService.getCustomerDocuments).not.toHaveBeenCalled();
      expect(result.current.documents).toEqual([]);
    });

    it('enabled가 false이면 문서를 로드하지 않아야 함', () => {
      const { result } = renderHook(() =>
        useCustomerDocumentsController(mockCustomerId, { enabled: false })
      );

      expect(DocumentService.getCustomerDocuments).not.toHaveBeenCalled();
      expect(result.current.documents).toEqual([]);
    });

    it('autoLoad가 false이면 자동 로드하지 않아야 함', () => {
      const { result } = renderHook(() =>
        useCustomerDocumentsController(mockCustomerId, { autoLoad: false })
      );

      expect(DocumentService.getCustomerDocuments).not.toHaveBeenCalled();
      expect(result.current.documents).toEqual([]);
    });
  });

  describe('loadDocuments / refresh', () => {
    it('문서 로드 성공 시 상태를 업데이트해야 함', async () => {
      vi.mocked(DocumentService.getCustomerDocuments).mockResolvedValue({
        customer_id: mockCustomerId,
        documents: mockDocuments,
        total: mockDocuments.length
      });

      const { result } = renderHook(() =>
        useCustomerDocumentsController(mockCustomerId)
      );

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false);
      });

      expect(result.current.documents).toEqual(mockDocuments);
      expect(result.current.error).toBeNull();
      expect(result.current.lastUpdated).toBeGreaterThan(0);
    });

    it('문서 로드 실패 시 에러를 설정해야 함', async () => {
      vi.mocked(DocumentService.getCustomerDocuments).mockRejectedValue(
        new Error('Load failed')
      );

      const { result } = renderHook(() =>
        useCustomerDocumentsController(mockCustomerId)
      );

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false);
