      expect(result.current.previewState.isOpen).toBe(false);
    });
  });

  describe('closePreview', () => {
    it('프리뷰를 닫고 상태를 초기화해야 함', async () => {
      vi.mocked(DocumentStatusService.getDocumentDetailViaWebhook).mockResolvedValue({
