      const { result } = renderHook(() => useCustomerEditController(mockCustomer));

      expect(result.current.activeTab).toBe('info');
    });

    it('초기 errors는 빈 객체여야 함', () => {
      const { result } = renderHook(() => useCustomerEditController(mockCustomer));

      expect(result.current.errors).toEqual({});
