import { describe, it, expect, vi, beforeEach } from 'vitest'
import { checkAnnualReportFromPDF, checkCustomerReviewFromPDF } from '../pdfParser'

// pdfjs-dist 모킹
vi.mock('pdfjs-dist', () => {
