      const result = await checkAnnualReportFromPDF(file)

      expect(result.is_annual_report).toBe(false)
    })

    it('텍스트가 없는 스캔 PDF는 false를 반환해야 함', async () => {
      const mockText = {
        items: [
          { str: '' },
