// 🍎 페이지당 항목 수 옵션 (자동 옵션 포함)
const ITEMS_PER_PAGE_OPTIONS_BASE = [
  { value: 'auto', label: '자동' },
  { value: '10', label: '10개씩' },
  { value: '25', label: '25개씩' },
  { value: '50', label: '50개씩' },
  { value: '100', label: '100개씩' },
];

// 🍎 행 높이 상수 (CSS와 동일하게 유지)
const ROW_HEIGHT = 32;   // CSS height: 32px
const ROW_GAP = 2;       // CSS gap: 2px (행 사이 간격)
// 🍎 기본 높이값 (실제 DOM 측정이 안될 때 fallback)
const DEFAULT_TABLE_HEADER_HEIGHT = 32;
const DEFAULT_PAGINATION_HEIGHT = 26;

// 🍎 컬럼 리사이즈 설정
const ANNUAL_REPORT_COLUMNS: ColumnConfig[] = [
  { id: 'owner', minWidth: 50, maxWidth: 150 },
  { id: 'issueDate', minWidth: 70, maxWidth: 120 },
  { id: 'parsedAt', minWidth: 100, maxWidth: 180 },
  { id: 'premium', minWidth: 80, maxWidth: 180 },
  { id: 'count', minWidth: 50, maxWidth: 100 },
  { id: 'status', minWidth: 40, maxWidth: 80 }
];

// 🍎 기본 컬럼 폭 (고정값)
const DEFAULT_ISSUE_DATE_WIDTH = 80;
const DEFAULT_COUNT_WIDTH = 70;
const DEFAULT_STATUS_WIDTH = 40;

export const AnnualReportTab: React.FC<AnnualReportTabProps> = ({
  customer,
  onAnnualReportCountChange,
  refreshTrigger,
  searchTerm: externalSearchTerm,
  onSearchChange: _onSearchChange
}) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [reports, setReports] = useState<AnnualReport[]>([]);
  const [selectedReport, setSelectedReport] = useState<AnnualReport | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // 🍎 검색어 상태 (외부/내부)
  const [internalSearchTerm] = useState('');
  const searchTerm = externalSearchTerm ?? internalSearchTerm;
  // 🍎 페이지네이션 상태 ('auto' 또는 숫자)
  const [itemsPerPageMode, setItemsPerPageMode] = useState<'auto' | number>(() => {
    const saved = localStorage.getItem('aims-customer-ar-items-per-page');
    if (!saved || saved === 'auto') return 'auto';
    const num = parseInt(saved, 10);
    return isNaN(num) ? 'auto' : num;
  });
  const [currentPage, setCurrentPage] = useState(1);
  const [containerHeight, setContainerHeight] = useState(0);
  const sectionContainerRef = useRef<HTMLDivElement>(null);

  // itemsPerPageMode 변경 시 localStorage에 자동 저장
  useEffect(() => {
    localStorage.setItem('aims-customer-ar-items-per-page', String(itemsPerPageMode));
  }, [itemsPerPageMode]);

  // 삭제 기능 상태
  const [selectedIndices, setSelectedIndices] = useState<Set<number>>(new Set());
  const [isDeleting, setIsDeleting] = useState(false);
  // AR 파싱 대기/진행 중인 문서 상태
  const [pendingCount, setPendingCount] = useState(0);
  const [pendingDocs, setPendingDocs] = useState<PendingDocument[]>([]);

  // 🍎 정렬 상태
  const [sortField, setSortField] = useState<SortField>('issue_date');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // 개발자 모드 - 전역 상태 사용
  const { isDevMode } = useDevModeStore();

  // Apple Confirm Modal 컨트롤러
  const confirmModal = useAppleConfirmController();

  // 🍎 Toast 알림
  const toast = useToastContext();

  // 🍎 AR 컨텍스트 메뉴 훅
  const reportContextMenu = useContextMenu<AnnualReport>();

  // SSE 새로고침 콜백 (pending + reports 모두 갱신)
  const handleSSERefresh = useCallback(() => {
    loadPendingDocuments();
    loadAnnualReports();
  }, []);

  // SSE 실시간 업데이트 - 통합 SSE 사용
  // HTTP/1.1 연결 제한 문제 해결을 위해 개별 SSE 대신 통합 SSE 사용
  const { isConnected: sseConnected } = useCustomerSSE(customer._id, {
    onRefreshAR: handleSSERefresh,
  }, {
    enabled: Boolean(customer._id),
  });

  // 🍎 팝업 → 메인 창 복귀 리스너 (브라우저 내로 이동)
  useEffect(() => {
    const handlePopupMessage = (event: MessageEvent) => {
      // 같은 origin에서 온 메시지만 처리
      if (event.origin !== window.location.origin) return;

      if (event.data?.type === 'AIMS_AR_OPEN_IN_MAIN') {
        console.log('[AnnualReportTab] 팝업에서 브라우저 내로 이동 요청');
        try {
          const reportData = JSON.parse(event.data.report);
          setSelectedReport(reportData);
          setIsModalOpen(true);
        } catch (err) {
          console.error('[AnnualReportTab] AR 데이터 파싱 실패:', err);
        }
      }
    };

    window.addEventListener('message', handlePopupMessage);
    return () => window.removeEventListener('message', handlePopupMessage);
  }, []);

  // 🔄 폴링 fallback: 분석 중인 문서가 있을 때 10초마다 상태 확인
  // SSE가 끊겨도 안정적으로 업데이트
  useEffect(() => {
    if (!customer._id || pendingCount === 0) return;

    console.log(`[AnnualReportTab] 폴링 시작 - pendingCount: ${pendingCount}, SSE 연결: ${sseConnected}`);

    const pollInterval = setInterval(() => {
      console.log('[AnnualReportTab] 폴링 실행 (10초 간격)');
      loadPendingDocuments();
      loadAnnualReports();
    }, 10000); // 10초마다

    return () => {
      console.log('[AnnualReportTab] 폴링 중지');
      clearInterval(pollInterval);
    };
  }, [customer._id, pendingCount, sseConnected]);

  // 개발자 모드 OFF시 선택 초기화
  useEffect(() => {
    if (!isDevMode) {
      setSelectedIndices(new Set());
    }
  }, [isDevMode]);

  // 🍎 검색어 변경 시 첫 페이지로 이동
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm]);

  // 🍎 자동 모드일 때 컨테이너 높이 기반 항목 수 계산 (ContractsTab/DocumentsTab과 동일한 DOM 측정 방식)
  // ⚠️ CustomerFullDetailView에서는 일부 요소가 display:none으로 숨겨지므로 실제 DOM 요소 높이를 측정해야 함.
  const autoCalculatedItems = useMemo(() => {
    // 📱 모바일(≤768px): 페이지네이션 숨김 → 전체 표시 (스크롤 처리)
    if (typeof window !== 'undefined' && window.matchMedia('(max-width: 768px)').matches) {
      return 9999;
    }
    if (containerHeight <= 0) return 10; // 기본값

    const container = sectionContainerRef.current;
    if (!container) return 10;

    // 요약 헤더 높이 측정 (CustomerFullDetailView에서는 display:none → 0)
    const summaryHeader = container.querySelector('.annual-report-tab__header') as HTMLElement | null;
    const summaryHeight = summaryHeader ? summaryHeader.getBoundingClientRect().height : 0;

    // 테이블 헤더 높이 측정 (⚠️ 0이면 기본값 사용 - 렌더링 전 상태 대응)
    const tableHeader = container.querySelector('.annual-report-table-header') as HTMLElement | null;
    const measuredTableHeaderHeight = tableHeader ? tableHeader.getBoundingClientRect().height : 0;
    const tableHeaderHeight = measuredTableHeaderHeight > 0 ? measuredTableHeaderHeight : DEFAULT_TABLE_HEADER_HEIGHT;

    // 페이지네이션 높이 측정 (⚠️ 0이면 기본값 사용 - 렌더링 전 상태 대응)
    const pagination = container.querySelector('.annual-report-pagination') as HTMLElement | null;
    const measuredPaginationHeight = pagination ? pagination.getBoundingClientRect().height : 0;
    const paginationHeight = measuredPaginationHeight > 0 ? measuredPaginationHeight : DEFAULT_PAGINATION_HEIGHT;

    // 컨테이너 gap 측정 (요약 헤더가 보일 때만 적용)
    const containerStyle = getComputedStyle(container);
    const gap = parseFloat(containerStyle.gap) || 0;

    // fixedHeight 계산: 실제 보이는 요소들의 높이 합
    const fixedHeight = summaryHeight + (summaryHeight > 0 ? gap : 0) + tableHeaderHeight + paginationHeight;
    const availableHeight = containerHeight - fixedHeight;

    // N개 행의 총 높이 = N * ROW_HEIGHT + (N-1) * ROW_GAP
    // 이를 풀면: N <= (availableHeight + ROW_GAP) / (ROW_HEIGHT + ROW_GAP)
    const maxItems = Math.max(1, Math.floor((availableHeight + ROW_GAP) / (ROW_HEIGHT + ROW_GAP)));

    // 디버그 로그 (개발 모드에서만)
    if (import.meta.env.DEV) {
      console.log('[AnnualReportTab] 자동 페이지네이션 계산:', {
        containerHeight,
        summaryHeight,
        tableHeaderHeight: `${measuredTableHeaderHeight} → ${tableHeaderHeight}`,
        paginationHeight: `${measuredPaginationHeight} → ${paginationHeight}`,
        gap,
        fixedHeight,
        availableHeight,
        maxItems
      });
    }

    return maxItems;
  }, [containerHeight]);

  // 🍎 실제 적용되는 페이지당 항목 수
  const itemsPerPage = itemsPerPageMode === 'auto' ? autoCalculatedItems : itemsPerPageMode;

  // 🍎 섹션 컨테이너 높이 측정 (ResizeObserver)
  useEffect(() => {
    const container = sectionContainerRef.current;
    if (!container) return;

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerHeight(entry.contentRect.height);
      }
    });

    resizeObserver.observe(container);
    return () => resizeObserver.disconnect();
  }, []);

  // 🍎 드롭다운 옵션 (자동 모드일 때 계산된 값 표시)
  const itemsPerPageOptions = useMemo(() => {
    return ITEMS_PER_PAGE_OPTIONS_BASE.map(opt => {
      if (opt.value === 'auto') {
        return {
          value: 'auto',
          label: itemsPerPageMode === 'auto' ? (autoCalculatedItems >= 9999 ? '자동(전체)' : `자동(${autoCalculatedItems})`) : '자동'
        };
      }
      return opt;
    });
  }, [itemsPerPageMode, autoCalculatedItems]);

  // 🍎 동적 칼럼 폭 계산: 소유주(customer_name) 기준
  const ownerColumnWidth = useMemo(() => {
    if (reports.length === 0) return 80; // 기본값
    const maxLength = Math.max(...reports.map(r => (r.customer_name || '').length));
    // 글자당 약 10px (한글), 최소 60px, 최대 150px
    const calculatedWidth = Math.max(60, Math.min(150, maxLength * 10 + 16));
    return calculatedWidth;
  }, [reports]);

  // 🍎 동적 칼럼 폭 계산: 총 월보험료 기준
  const premiumColumnWidth = useMemo(() => {
    if (reports.length === 0) return 120; // 기본값
    const maxLength = Math.max(
      ...reports.map(r => AnnualReportApi.formatCurrency(r.total_monthly_premium).length)
    );
    // 글자당 약 8px, 최소 80px, 최대 180px
    const calculatedWidth = Math.max(80, Math.min(180, maxLength * 8 + 16));
    return calculatedWidth;
  }, [reports]);

  // 🍎 동적 칼럼 폭 계산: 파싱일시 기준
  const parsedAtColumnWidth = useMemo(() => {
    if (reports.length === 0) return 130; // 기본값
    const maxLength = Math.max(
      ...reports.map(r => AnnualReportApi.formatDateTime(r.parsed_at).length)
    );
    // 글자당 약 7px, 최소 100px, 최대 180px
    const calculatedWidth = Math.max(100, Math.min(180, maxLength * 7 + 16));
    return calculatedWidth;
  }, [reports]);

  // 🍎 컬럼 리사이즈: 기본 폭 계산
  const defaultColumnWidths = useMemo(() => ({
    owner: ownerColumnWidth,
    issueDate: DEFAULT_ISSUE_DATE_WIDTH,
    parsedAt: parsedAtColumnWidth,
    premium: premiumColumnWidth,
    count: DEFAULT_COUNT_WIDTH,
    status: DEFAULT_STATUS_WIDTH,
  }), [ownerColumnWidth, parsedAtColumnWidth, premiumColumnWidth])

  // 🍎 컬럼 리사이즈 훅
  const {
    columnWidths,
    isResizing,
    getResizeHandleProps,
    wasJustResizing
  } = useColumnResize({
    storageKey: 'annual-report-tab',
    columns: ANNUAL_REPORT_COLUMNS,
    defaultWidths: defaultColumnWidths
  })

  // Annual Report 목록 로드
  useEffect(() => {
    loadAnnualReports();
    loadPendingDocuments();
  }, [customer._id, refreshTrigger]);

  // 🍎 Annual Report 개수 변경 시 부모에게 알림
  useEffect(() => {
    onAnnualReportCountChange?.(reports.length);
  }, [reports.length, onAnnualReportCountChange]);

  const loadPendingDocuments = async () => {
    try {
      // ⭐ 공유 api 클라이언트 사용 (JWT 토큰 자동 포함)
      const data = await api.get<{ success: boolean; data: { pending_count: number; documents: PendingDocument[] } }>(
        `/api/customers/${customer._id}/annual-reports/pending`
      );

      if (data.success) {
        setPendingCount(data.data.pending_count);
        setPendingDocs(data.data.documents);
      }
    } catch (err) {
      console.error('Failed to load pending AR documents:', err);
      errorReporter.reportApiError(err as Error, { component: 'AnnualReportTab.loadPendingDocuments', payload: { customerId: customer._id } });
    }
  };

  const loadAnnualReports = async () => {
    console.log('[AnnualReportTab] 🔴 loadAnnualReports 시작');
    setIsLoading(true);
    setError(null);

    try {
      const userId = UserContextService.getContext().identifierValue;
      console.log('[AnnualReportTab] 🔴 API 호출 시작:', customer._id);

      const response = await AnnualReportApi.getAnnualReports(customer._id, userId, 20);
      console.log('[AnnualReportTab] 🔴 API 응답:', response);

      if (response.success && response.data) {
        // API 응답의 data 배열을 직접 AnnualReport 타입으로 변환
        const transformedReports: AnnualReport[] = response.data.reports.map((rawData: RawAnnualReportData) => {
          const mapContract = (contract: Record<string, unknown>) => ({
            insurance_company: '메트라이프',
            contract_number: (contract['증권번호'] || '') as string,
            product_name: (contract['보험상품'] || '') as string,
            contractor_name: (contract['계약자'] || '') as string,
            insured_name: (contract['피보험자'] || '') as string,
            monthly_premium: (contract['보험료(원)'] || 0) as number,
            coverage_amount: ((contract['가입금액(만원)'] || 0) as number) * 10000,
            contract_date: (contract['계약일'] || '') as string,
            maturity_date: '',
            premium_payment_period: (contract['납입기간'] || '') as string,
            insurance_period: (contract['보험기간'] || '') as string,
            status: (contract['계약상태'] || '') as string
          });

          const transformedContracts = (rawData.contracts || []).map(mapContract);
          const transformedLapsedContracts = (rawData.lapsed_contracts || []).map(mapContract);

          // 🔥 status 필드 처리: error/processing 상태는 null 값 유지
          const status = rawData.status || 'completed';
          const isFailedOrProcessing = status === 'error' || status === 'processing';

          return {
            report_id: rawData.file_id || rawData.source_file_id || `report_${rawData.parsed_at}`,
            issue_date: rawData.issue_date || '',
            // ⚠️ customer_name이 없으면 고객명으로 fallback하지 않음
            // AR 문서의 소유주는 고객과 다를 수 있음 (예: 가족의 AR 문서)
            customer_name: rawData.customer_name || '',
            // 실패/진행중 문서는 null 유지, 완료된 문서는 0으로 fallback
            total_monthly_premium: isFailedOrProcessing ? rawData.total_monthly_premium : (rawData.total_monthly_premium || 0),
            total_coverage: rawData.total_coverage || 0,
            contract_count: isFailedOrProcessing ? (rawData.total_contracts ?? rawData.contract_count) : (rawData.total_contracts || rawData.contract_count || 0),
            contracts: transformedContracts,
            lapsed_contracts: transformedLapsedContracts,
            source_file_id: rawData.source_file_id || rawData.file_id || '',
            created_at: rawData.uploaded_at || '',
            parsed_at: isFailedOrProcessing ? rawData.parsed_at : (rawData.parsed_at || ''),
            status: status,
            error_message: rawData.error_message,
            retry_count: rawData.retry_count,  // 재시도 횟수
            fsr_name: rawData.fsr_name,
            registered_at: rawData.registered_at,
          };
        });

        setReports(transformedReports);
      } else {
        setError(response.error || 'Annual Report 조회에 실패했습니다.');
      }
    } catch (err) {
      console.error('[AnnualReportTab] Annual Report 조회 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'AnnualReportTab.loadAnnualReports', payload: { customerId: customer._id } });
      setError(err instanceof Error ? err.message : 'Annual Report 조회 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleViewReport = (report: AnnualReport) => {
    // 실패/진행중 문서는 모달 열지 않음
    if (report.status === 'error' || report.status === 'processing') {
      return;
    }
    setSelectedReport(report);
    setIsModalOpen(true);
  };

  // 🔄 AR 파싱 재시도 핸들러
  const handleRetryParsing = async (report: AnnualReport, event: React.MouseEvent) => {
    event.stopPropagation();  // 행 클릭 이벤트 방지

    const fileId = report.source_file_id;
    if (!fileId) {
      console.error('[AnnualReportTab] 재시도 불가: file_id 없음');
      errorReporter.reportApiError(new Error('AR 재시도 불가: file_id 없음'), { component: 'AnnualReportTab.handleRetryParsing.validation', payload: { reportId: report.report_id } });
      await confirmModal.actions.openModal({
        title: '재시도 불가',
        message: '파일 정보를 찾을 수 없습니다.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'error'
      });
      return;
    }

    try {
      const result = await AnnualReportApi.retryParsing(fileId);

      if (result.success) {
        await confirmModal.actions.openModal({
          title: '재시도 시작',
          message: 'AR 파싱 재시도가 시작되었습니다.\n잠시 후 목록이 업데이트됩니다.',
          confirmText: '확인',
          showCancel: false,
          iconType: 'success'
        });
        // 목록 새로고침
        loadAnnualReports();
        loadPendingDocuments();
      } else {
        await confirmModal.actions.openModal({
          title: '재시도 실패',
          message: result.message,
          confirmText: '확인',
          showCancel: false,
          iconType: 'error'
        });
      }
    } catch (err) {
      console.error('[AnnualReportTab] 재시도 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'AnnualReportTab.handleRetry', payload: { fileId } });
      await confirmModal.actions.openModal({
        title: '오류',
        message: '재시도 중 오류가 발생했습니다.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'error'
      });
    }
  };

  // 🍎 정렬 핸들러
  const handleSort = useCallback((field: SortField) => {
    // 리사이즈 직후 클릭은 무시 (정렬 방지)
    if (wasJustResizing()) return;

    if (sortField === field) {
      // 같은 필드 클릭 시 방향 토글
      setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
    } else {
      // 다른 필드 클릭 시 해당 필드로 변경, 기본 내림차순
      setSortField(field);
      setSortDirection('desc');
    }
  }, [sortField, wasJustResizing]);

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedReport(null);
  };

  // 🍎 AR 우클릭 컨텍스트 메뉴 열기
  const handleReportContextMenu = useCallback((e: React.MouseEvent, report: AnnualReport) => {
    reportContextMenu.open(e, report);
  }, [reportContextMenu]);

  // 🍎 보험계약 등록 핸들러
  const handleRegisterContracts = useCallback(async (report: AnnualReport) => {
    const confirmed = await confirmModal.actions.openModal({
      title: '보험계약 등록',
      message: `"${report.customer_name}" 님의 AR (발행일: ${formatDate(report.issue_date)})에서\n${report.contract_count}건의 계약 정보를 보험계약 탭에 등록합니다.`,
      confirmText: '등록',
      cancelText: '취소',
      showCancel: true,
      iconType: 'info'
    });

    if (!confirmed) return;

    try {
      const result = await AnnualReportApi.registerARContracts(
        customer._id,
        report.issue_date || '',
        report.customer_name
      );

      if (result.success) {
        if (result.duplicate) {
          // 이미 등록된 경우 - 토스트 알림 (3초)
          toast.info('이미 등록된 Annual Report입니다', 3000);
        } else {
          // 등록 성공
          toast.success('보험계약이 등록되었습니다', 3000);
        }
      } else {
        toast.error(result.message || '보험계약 등록에 실패했습니다');
      }
    } catch (err) {
      console.error('[AnnualReportTab] 보험계약 등록 오류:', err);
      toast.error('보험계약 등록 중 오류가 발생했습니다');
    }
  }, [confirmModal.actions, customer._id, toast]);

  // 🍎 단일 AR 삭제 핸들러
  const handleDeleteReport = useCallback(async (report: AnnualReport) => {
    // 보험계약 탭에 등록된 AR인 경우 추가 경고
    const contractWarning = report.registered_at
      ? '\n\n⚠️ 이 AR은 보험계약 탭에 등록되어 있습니다.\n함께 삭제됩니다.'
      : '';

    const confirmed = await confirmModal.actions.openModal({
      title: 'Annual Report 삭제',
      message: `"${report.customer_name}" 님의 AR (발행일: ${formatDate(report.issue_date)})을 삭제하시겠습니까?\n삭제된 데이터는 복구할 수 없습니다.${contractWarning}`,
      confirmText: '삭제',
      cancelText: '취소',
      confirmStyle: 'destructive',
      showCancel: true,
      iconType: 'warning'
    });

    if (!confirmed) return;

    // 고유 식별자 기반 삭제 (인덱스 불일치 버그 방지)
    const identifier: { source_file_id?: string; issue_date?: string; customer_name?: string } = {};
    if (report.source_file_id) {
      identifier.source_file_id = report.source_file_id;
    } else {
      identifier.issue_date = report.issue_date;
      identifier.customer_name = report.customer_name;
    }

    setIsDeleting(true);
    try {
      const userId = UserContextService.getContext().identifierValue;
      const result = await AnnualReportApi.deleteAnnualReports(
        customer._id,
        userId,
        [identifier]
      );

      setIsDeleting(false);

      if (result.success) {
        // 목록 새로고침
        await Promise.all([
          loadAnnualReports(),
          loadPendingDocuments()
        ]);

        await confirmModal.actions.openModal({
          title: '완료',
          message: 'Annual Report가 삭제되었습니다.',
          confirmText: '확인',
          showCancel: false,
          iconType: 'success'
        });
      } else {
        await confirmModal.actions.openModal({
          title: '실패',
          message: result.message,
          confirmText: '확인',
          showCancel: false,
          iconType: 'error'
        });
      }
    } catch (err) {
      setIsDeleting(false);
      console.error('[AnnualReportTab] 삭제 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'AnnualReportTab.handleDeleteReport', payload: { customerId: customer._id } });
      await confirmModal.actions.openModal({
        title: '오류',
        message: '삭제 중 오류가 발생했습니다.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'error'
      });
    }
  }, [reports, customer._id, confirmModal.actions]);

  // 체크박스 전체 선택/해제
  const handleSelectAll = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.checked) {
      const allIndices = new Set(visibleReports.map((_, idx) => (currentPage - 1) * itemsPerPage + idx));
      setSelectedIndices(allIndices);
    } else {
      setSelectedIndices(new Set());
    }
  };

  // 개별 체크박스 선택/해제
  const handleSelectReport = (globalIndex: number, event: React.MouseEvent) => {
    event.stopPropagation(); // 행 클릭 이벤트 방지
    setSelectedIndices((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(globalIndex)) {
        newSet.delete(globalIndex);
      } else {
        newSet.add(globalIndex);
      }
      return newSet;
    });
  };

  // Annual Reports 삭제
  const handleDeleteSelected = async () => {
    if (selectedIndices.size === 0) {
      await confirmModal.actions.openModal({
        title: '선택 항목 없음',
        message: '삭제할 항목을 선택해주세요.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'warning'
      });
      return;
    }
    // 보험계약 탭에 등록된 AR이 포함되어 있는지 확인
    const hasRegisteredAR = Array.from(selectedIndices).some(idx => reports[idx]?.registered_at);
    const contractWarning = hasRegisteredAR
      ? '\n\n⚠️ 보험계약 탭에 등록된 AR이 포함되어 있습니다.\n함께 삭제됩니다.'
      : '';


    const confirmed = await confirmModal.actions.openModal({
      title: 'Annual Report 삭제',
      message: `${selectedIndices.size}개 항목을 삭제하시겠습니까?\n삭제된 데이터는 복구할 수 없습니다.${contractWarning}`,
      confirmText: '삭제',
      cancelText: '취소',
      confirmStyle: 'destructive',
      showCancel: true,
      iconType: 'warning'
    });

    if (!confirmed) {
      return;
    }

    setIsDeleting(true);
    try {
      const userId = UserContextService.getContext().identifierValue;
      // 선택된 인덱스 → 고유 식별자 변환 (인덱스 불일치 버그 방지)
      const identifiers = Array.from(selectedIndices).map(idx => {
        const report = reports[idx];
        if (report?.source_file_id) {
          return { source_file_id: report.source_file_id };
        }
        return { issue_date: report?.issue_date, customer_name: report?.customer_name };
      });
      const result = await AnnualReportApi.deleteAnnualReports(
        customer._id,
        userId,
        identifiers
      );

      // 삭제 작업 완료 후 즉시 isDeleting을 false로 설정
      setIsDeleting(false);

      if (result.success) {
        setSelectedIndices(new Set());
        // 목록 새로고침 (pending + reports 모두)
        await Promise.all([
          loadAnnualReports(),
          loadPendingDocuments()
        ]);

        // 성공 모달은 마지막에 표시
        await confirmModal.actions.openModal({
          title: '완료',
          message: `${result.deleted_count}건 삭제되었습니다.`,
          confirmText: '확인',
          showCancel: false,
          iconType: 'success'
        });
      } else {
        await confirmModal.actions.openModal({
          title: '실패',
          message: result.message,
          confirmText: '확인',
          showCancel: false,
          iconType: 'error'
        });
      }
    } catch (err) {
      setIsDeleting(false);
      console.error('[AnnualReportTab] 삭제 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'AnnualReportTab.handleDeleteSelected', payload: { customerId: customer._id, count: selectedIndices.size } });
      await confirmModal.actions.openModal({
        title: '오류',
        message: '삭제 중 오류가 발생했습니다.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'error'
      });
    }
  };

  // 🍎 검색어로 필터링된 리포트 목록
  const filteredReports = useMemo(() => {
    if (!searchTerm.trim()) return reports;

    const term = searchTerm.toLowerCase().trim();
    return reports.filter(report => {
      // 소유주(customer_name), 발행일(issue_date), 파싱일시(parsed_at)로 검색
      const customerName = (report.customer_name || '').toLowerCase();
      const issueDate = formatDate(report.issue_date).toLowerCase();
      const parsedAt = AnnualReportApi.formatDateTime(report.parsed_at).toLowerCase();

      return customerName.includes(term) ||
             issueDate.includes(term) ||
             parsedAt.includes(term);
    });
  }, [reports, searchTerm]);

  // 🍎 정렬된 리포트 목록 (hooks는 조건부 반환 이전에 호출해야 함)
  const sortedReports = useMemo(() => {
    return [...filteredReports].sort((a, b) => {
      let comparison = 0;
      const aIndex = reports.indexOf(a);
      const bIndex = reports.indexOf(b);

      switch (sortField) {
        case 'customer_name':
          comparison = (a.customer_name || '').localeCompare(b.customer_name || '', 'ko');
          break;
        case 'issue_date':
          comparison = new Date(a.issue_date || 0).getTime() - new Date(b.issue_date || 0).getTime();
          break;
        case 'parsed_at':
          comparison = new Date(a.parsed_at || 0).getTime() - new Date(b.parsed_at || 0).getTime();
          break;
        case 'total_monthly_premium':
          comparison = (a.total_monthly_premium || 0) - (b.total_monthly_premium || 0);
          break;
        case 'contract_count':
          comparison = (a.contract_count || 0) - (b.contract_count || 0);
          break;
        case 'status':
          // status는 최신(index 0)인지 여부로 정렬
          comparison = aIndex - bIndex;
          break;
      }

      return sortDirection === 'asc' ? comparison : -comparison;
    });
  }, [filteredReports, reports, sortField, sortDirection]);

  // 🍎 AR 컨텍스트 메뉴 섹션 정의
  const reportContextMenuSections: ContextMenuSection[] = useMemo(() => {
    const report = reportContextMenu.targetData;
    if (!report) return [];

    const sections: ContextMenuSection[] = [];
    const actionItems: ContextMenuSection['items'] = [];

    // 완료 상태: 상세 보기, 보험계약 등록
    if (report.status === 'completed') {
      actionItems.push({
        id: 'view',
        label: '상세 보기',
        onClick: () => handleViewReport(report),
      });
      actionItems.push({
        id: 'register-contracts',
        label: '보험계약 등록',
        onClick: () => handleRegisterContracts(report),
      });
    }

    // 에러 상태: 재시도
    if (report.status === 'error') {
      actionItems.push({
        id: 'retry',
        label: '재시도',
        onClick: (e?: React.MouseEvent) => {
          if (e) handleRetryParsing(report, e);
        },
      });
    }

    if (actionItems.length > 0) {
      sections.push({ id: 'actions', items: actionItems });
    }

    // 삭제 섹션 (항상)
    sections.push({
      id: 'danger',
      items: [{
        id: 'delete',
        label: '삭제',
        danger: true,
        onClick: () => handleDeleteReport(report),
      }]
    });

    return sections;
  }, [reportContextMenu.targetData, handleViewReport, handleRegisterContracts, handleDeleteReport]);

  // 🍎 페이지네이션 계산 (hooks 이후에 배치)
  const itemsPerPageNumber = itemsPerPage;
  const totalPages = Math.max(1, Math.ceil(sortedReports.length / itemsPerPageNumber));
  const safeCurrentPage = Math.min(currentPage, totalPages);

  // 현재 페이지에 표시할 리포트들
  const visibleReports = sortedReports.slice(
    (safeCurrentPage - 1) * itemsPerPageNumber,
    safeCurrentPage * itemsPerPageNumber
  );

  // 전체 선택 여부 (현재 페이지 기준)
  const isAllSelected = visibleReports.length > 0 && visibleReports.every((_, idx) => {
    const globalIndex = (safeCurrentPage - 1) * itemsPerPageNumber + idx;
    return selectedIndices.has(globalIndex);
  });

  // 로딩 상태
  if (isLoading) {
    return (
      <div ref={sectionContainerRef} className="annual-report-tab">
        <div className="annual-report-tab__loading">
          <div className="annual-report-tab__loading-spinner"></div>
          <p>Annual Report를 불러오는 중...</p>
        </div>
      </div>
    );
  }

  // 에러 상태
  if (error) {
    return (
      <div ref={sectionContainerRef} className="annual-report-tab">
        <div className="annual-report-tab__error">
          <div className="annual-report-tab__error-icon">⚠️</div>
          <p>{error}</p>
          <Button variant="secondary" size="sm" onClick={loadAnnualReports}>
            다시 시도
          </Button>
        </div>
      </div>
    );
  }

  // Annual Report 없음
  if (reports.length === 0) {
    return (
      <div ref={sectionContainerRef} className="annual-report-tab">
        {/* AR 파싱 진행 중 알림 (빈 상태에서도 표시) */}
        {pendingCount > 0 && (
          <div className="annual-report-parsing-notice">
            <div className="parsing-notice-icon">
              <div className="parsing-spinner"></div>
            </div>
            <div className="parsing-notice-content">
              <div className="parsing-notice-title">
                Annual Report 분석 중
              </div>
              <div className="parsing-notice-description">
                {pendingCount}개의 문서를 백그라운드에서 분석하고 있습니다. 완료되면 자동으로 목록에 추가됩니다.
              </div>
              {pendingDocs.length > 0 && (
                <div className="parsing-notice-files">
                  {pendingDocs.map(doc => (
                    <div key={doc.file_id} className="parsing-file-item">
                      <span className="parsing-file-name">{doc.filename}</span>
                      <span className="parsing-file-status">
                        {doc.status === 'processing' ? '분석 중...' : '대기 중...'}
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        <div className="annual-report-tab__empty">
          <h3 className="annual-report-tab__empty-title">
            {pendingCount > 0 ? '분석이 완료되면 여기에 표시됩니다' : 'Annual Report가 없습니다'}
          </h3>
          <p className="annual-report-tab__empty-description">
            {pendingCount > 0
              ? '백그라운드에서 문서를 분석하고 있습니다. 잠시만 기다려주세요.'
              : 'Annual Report를 업로드하면 자동 분석하여 여기에 표시됩니다.'}
          </p>
          {pendingCount === 0 && (
            <div className="annual-report-tab__empty-hint">
              <p className="annual-report-tab__empty-hint-text">
                💡 Annual Report는 보험 계약 현황을 요약한 문서입니다.
              </p>
            </div>
          )}
        </div>

        {/* Annual Report Modal */}
        <AnnualReportModal
          isOpen={isModalOpen}
          onClose={handleCloseModal}
          report={null}
          isLoading={false}
          error={null}
          customerName={customer.personal_info?.name || '고객'}
        />
      </div>
    );
  }

  // 페이지 변경은 Pagination 컴포넌트에서 직접 호출
  const handlePageChange = (page: number) => {
    setCurrentPage(page);
  };

  // 🍎 페이지당 항목 수 변경 ('auto' 또는 숫자)
  const handleItemsPerPageChange = (value: string) => {
    if (import.meta.env.DEV) {
      console.log('[AnnualReportTab] handleItemsPerPageChange 호출:', { value, currentMode: itemsPerPageMode })
    }
    if (value === 'auto') {
      setItemsPerPageMode('auto');
    } else {
      setItemsPerPageMode(Number(value));
    }
    setCurrentPage(1);
  };

  // Annual Report 목록 있음
  return (
    <div ref={sectionContainerRef} className="annual-report-tab">
      {/* AR 파싱 진행 중 알림 */}
      {pendingCount > 0 && (
        <div className="annual-report-parsing-notice">
          <div className="parsing-notice-icon">
            <div className="parsing-spinner"></div>
          </div>
          <div className="parsing-notice-content">
            <div className="parsing-notice-title">
              Annual Report 분석 중
            </div>
            <div className="parsing-notice-description">
              {pendingCount}개의 문서를 백그라운드에서 분석하고 있습니다. 완료되면 자동으로 목록에 추가됩니다.
            </div>
            {pendingDocs.length > 0 && (
              <div className="parsing-notice-files">
                {pendingDocs.map(doc => (
                  <div key={doc.file_id} className="parsing-file-item">
                    <span className="parsing-file-name">{doc.filename}</span>
                    <span className="parsing-file-status">
                      {doc.status === 'processing' ? '분석 중...' : '대기 중...'}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* 삭제 버튼 (개발자 모드 전용) */}
      {isDevMode && selectedIndices.size > 0 && (
        <div className="annual-report-actions">
          <Button
            variant="destructive"
            size="sm"
            onClick={handleDeleteSelected}
            disabled={isDeleting}
            title="개발자 전용 기능 (Ctrl+Shift+D)"
          >
            {isDeleting ? '삭제 중...' : `🗑️ 선택 항목 삭제 (${selectedIndices.size})`}
          </Button>
        </div>
      )}

      {/* 테이블 컨테이너 */}
      <div
        ref={(el) => {
          if (el) {
            el.style.setProperty('--owner-column-width', `${columnWidths['owner'] || ownerColumnWidth}px`);
            el.style.setProperty('--issue-date-column-width', `${columnWidths['issueDate'] || DEFAULT_ISSUE_DATE_WIDTH}px`);
            el.style.setProperty('--parsed-at-column-width', `${columnWidths['parsedAt'] || parsedAtColumnWidth}px`);
            el.style.setProperty('--premium-column-width', `${columnWidths['premium'] || premiumColumnWidth}px`);
            el.style.setProperty('--count-column-width', `${columnWidths['count'] || DEFAULT_COUNT_WIDTH}px`);
            el.style.setProperty('--status-column-width', `${columnWidths['status'] || DEFAULT_STATUS_WIDTH}px`);
          }
        }}
        className={`tab-table__scroll annual-report-table-container${isResizing ? ' is-resizing' : ''}`}
      >
        {/* 테이블 헤더 */}
        <div className="tab-table__header annual-report-table-header">
          {isDevMode && (
            <div className="header-checkbox">
              <input
                type="checkbox"
                checked={isAllSelected}
                onChange={handleSelectAll}
                aria-label="전체 선택"
              />
            </div>
          )}
          <div
            className="header-owner annual-report-table__sortable resizable-header"
            onClick={() => handleSort('customer_name')}
          >
            <span className="annual-report-table__header-content">
              소유주
              <SortIndicator field="customer_name" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('owner')} />
          </div>
          <div
            className="header-issue-date annual-report-table__sortable resizable-header"
            onClick={() => handleSort('issue_date')}
          >
            <span className="annual-report-table__header-content">
              발행일
              <SortIndicator field="issue_date" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('issueDate')} />
          </div>
          <div
            className="header-parsed-at annual-report-table__sortable resizable-header"
            onClick={() => handleSort('parsed_at')}
          >
            <span className="annual-report-table__header-content">
              파싱일시
              <SortIndicator field="parsed_at" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('parsedAt')} />
          </div>
          <div
            className="header-premium annual-report-table__sortable resizable-header"
            onClick={() => handleSort('total_monthly_premium')}
          >
            <span className="annual-report-table__header-content">
              총 월보험료
              <SortIndicator field="total_monthly_premium" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('premium')} />
          </div>
          <div
            className="header-count annual-report-table__sortable resizable-header"
            onClick={() => handleSort('contract_count')}
          >
            <span className="annual-report-table__header-content">
              계약 수
              <SortIndicator field="contract_count" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('count')} />
          </div>
          <div
            className="header-status annual-report-table__sortable resizable-header"
            onClick={() => handleSort('status')}
          >
            <span className="annual-report-table__header-content">
              상태
              <SortIndicator field="status" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('status')} />
          </div>
        </div>

        {/* 테이블 바디 */}
        <div className="tab-table__body annual-report-table-body">
          {visibleReports.map((report) => {
            const globalIndex = reports.indexOf(report);
            const formattedDate = formatDate(report.issue_date);
            const isSelected = selectedIndices.has(globalIndex);
            const isError = report.status === 'error';
            const isProcessing = report.status === 'processing';
            const isPending = report.status === 'pending';

            return (
              <div
                key={report.report_id}
                className={`tab-table__row annual-report-row ${isSelected ? 'annual-report-row--selected' : ''} ${isError ? 'annual-report-row--error' : ''} ${isProcessing ? 'annual-report-row--processing' : ''} ${isPending ? 'annual-report-row--pending' : ''}`}
                onClick={() => handleViewReport(report)}
                onContextMenu={(e) => handleReportContextMenu(e, report)}
              >
                {isDevMode && (
                  <div className="row-checkbox" onClick={(e) => handleSelectReport(globalIndex, e)}>
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={() => {}}
                      aria-label={`${formattedDate} 리포트 선택`}
                    />
                  </div>
                )}
                <div className="row-owner">{report.customer_name || '-'}</div>
                <div className="row-issue-date">{formattedDate || '-'}</div>
                <div className="row-parsed-at">
                  {report.parsed_at ? AnnualReportApi.formatDateTime(report.parsed_at) : '-'}
                </div>
                <div className="row-premium">
                  {report.total_monthly_premium != null ? AnnualReportApi.formatCurrency(report.total_monthly_premium) : '-'}
                </div>
                <div className="row-count">
                  {report.contract_count != null ? `${report.contract_count}건` : '-'}
                </div>
                <div className="row-status">
                  {/* 에러 상태: 실패 배지 + 재시도 버튼 */}
                  {isError && (
                    <>
                      <span
                        className="status-badge status-badge--error"
                        title={report.error_message || '파싱 실패'}
                      >
                        실패{report.retry_count ? ` (${report.retry_count}/3)` : ''}
                      </span>
                      <button
                        type="button"
                        className="retry-button"
                        onClick={(e) => handleRetryParsing(report, e)}
                        title={`AR 파싱 재시도\n${report.error_message || ''}`}
                      >
                        재시도
                      </button>
                    </>
                  )}
                  {/* 처리중 상태: 스피너 + 처리중 배지 + [1/3] */}
                  {isProcessing && (
                    <>
                      <span className="status-badge status-badge--processing">
                        <span className="status-spinner"></span>
                        처리중
                      </span>
                      <span className="retry-indicator">[{report.retry_count || 1}/3]</span>
                    </>
                  )}
                  {/* 대기중 상태: 대기중 배지 + [1/3] */}
                  {isPending && (
                    <>
                      <span className="status-badge status-badge--pending">
                        대기중
                      </span>
                      <span className="retry-indicator">[{report.retry_count || 1}/3]</span>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* 페이지네이션 - 항상 표시 (전체보기와 동일) */}
      <div className="tab-table__pagination annual-report-pagination">
        {/* 페이지당 항목 수 선택 */}
        <div className="pagination-limit">
          <Dropdown
            value={itemsPerPageMode === 'auto' ? 'auto' : String(itemsPerPageMode)}
            options={itemsPerPageOptions}
            onChange={handleItemsPerPageChange}
            aria-label="페이지당 항목 수"
            width={100}
          />
        </div>

        {/* 페이지 네비게이션 */}
        <Pagination
          currentPage={safeCurrentPage}
          totalPages={totalPages}
          onPageChange={handlePageChange}
          variant="compact"
        />
      </div>

      {/* 🍎 AR 컨텍스트 메뉴 */}
      <ContextMenu
        visible={reportContextMenu.isOpen}
        position={reportContextMenu.position}
        sections={reportContextMenuSections}
        onClose={reportContextMenu.close}
      />

      {/* Annual Report Modal */}
      <AnnualReportModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        report={selectedReport}
        isLoading={false}
        error={null}
        customerName={customer.personal_info?.name || '고객'}
      />

      {/* Apple Confirm Modal */}
      <AppleConfirmModal
        state={confirmModal.state}
        actions={confirmModal.actions}
      />
    </div>
  );
};

/**
 * AIMS UIX-3 Customer Detail - Corporate Contracts Tab
 * @since 2026-02-14
 *
 * 🍎 법인 관계 구성원 전체 보험 계약 통합 조회
 * - 개인고객: 관계된 법인의 모든 구성원 계약 표시
 * - 법인고객: 관계된 모든 개인/법인의 계약 표시
 * - 증권번호 기준 중복 제거 (우선순위: AR > CRS > 수동)
 * - 관계 뱃지, 정렬, 검색 지원 (페이지네이션 없이 전체 스크롤)
 */

import React, { useCallback, useState, useMemo, useEffect } from 'react'
import type { Customer } from '@/entities/customer/model'
import type { Contract } from '@/entities/contract/model'
import { ContractService } from '@/services/contractService'
import { CustomerService } from '@/services/customerService'
import {
  AnnualReportApi,
  type AnnualReport,
  groupContractsByPolicyNumber,
} from '@/features/customer/api/annualReportApi'
import {
  CustomerReviewApi,
  type CustomerReview,
} from '@/features/customer/api/customerReviewApi'
import { RelationshipService, type Relationship } from '@/services/relationshipService'
import { UserContextService } from '../../../../../components/DocumentViews/DocumentRegistrationView/services/userContextService'
import { SFSymbol,
  SFSymbolAnimation,
  SFSymbolSize,
  SFSymbolWeight
} from '../../../../../components/SFSymbol'
import { errorReporter } from '@/shared/lib/errorReporter'
import { useColumnResize, type ColumnConfig } from '@/hooks/useColumnResize'
import { formatDate } from '@/shared/lib/timeUtils'
import { SortIndicator } from '@/shared/ui/SortIndicator';
import './CorporateContractsTab.css';

// ==================== 타입 정의 ====================

interface CorporateContractsTabProps {
  customer: Customer
  /** 외부에서 전달받는 검색어 */
  searchTerm?: string
  /** 검색어 변경 핸들러 */
  onSearchChange?: (term: string) => void
  /** 법인 계약 수 변경 콜백 */
  onCorporateContractCountChange?: (count: number) => void
  /** 탭 클릭 시 데이터 새로고침 트리거 */
  refreshTrigger?: number
}

/** 통합 법인 계약 타입 */
interface CorporateContract {
  policyNumber: string       // 증권번호 (유일 키)
  productName: string        // 보험상품
  holderName: string         // 계약자
  insuredName: string        // 피보험자
  contractDate: string       // 계약일
  status: string             // 계약상태
  premium: number            // 보험료
  coverageAmount: number     // 가입금액 (만원)
  memberName: string         // 데이터 출처 구성원명
  memberRelationship: string // 관계 (대표이사/직원/임원 등)
  source: 'ar' | 'crs' | 'manual'
}

// ==================== 상수 ====================

// 🍎 컬럼 리사이즈 설정 (9칼럼)
const CORPORATE_CONTRACTS_COLUMNS: ColumnConfig[] = [
  { id: 'relation', minWidth: 50, maxWidth: 80 },
  { id: 'policy', minWidth: 83, maxWidth: 130 },
  { id: 'product', minWidth: 110, maxWidth: 440 },
  { id: 'holder', minWidth: 44, maxWidth: 77 },
  { id: 'insured', minWidth: 44, maxWidth: 77 },
  { id: 'date', minWidth: 72, maxWidth: 88 },
  { id: 'status', minWidth: 42, maxWidth: 61 },
  { id: 'amount', minWidth: 55, maxWidth: 83 },
  { id: 'premium', minWidth: 66, maxWidth: 105 },
]

// 정렬 필드 타입
type SortField = 'memberRelationship' | 'policyNumber' | 'productName' | 'holderName' | 'insuredName' | 'contractDate' | 'status' | 'coverageAmount' | 'premium'
type SortDirection = 'asc' | 'desc'

// 관계 뱃지 CSS 클래스 매핑
const RELATION_BADGE_CLASS: Record<string, string> = {
  '본인': 'cc-relation-badge--본인',
  '대표이사': 'cc-relation-badge--대표이사',
  '임원': 'cc-relation-badge--임원',
  '직원': 'cc-relation-badge--직원',
  '주주': 'cc-relation-badge--주주',
  '이사': 'cc-relation-badge--이사',
  '회사': 'cc-relation-badge--회사',
  '고용주': 'cc-relation-badge--고용주',
}

// 관계 타입 → 한글 라벨 매핑
const CORP_RELATION_TYPE_LABELS: Record<string, string> = {
  'ceo': '대표이사',
  'executive': '임원',
  'employee': '직원',
  'shareholder': '주주',
  'director': '이사',
  'company': '회사',
  'employer': '고용주',
}

// ==================== 컴포넌트 ====================

export const CorporateContractsTab: React.FC<CorporateContractsTabProps> = ({
  customer,
  searchTerm: externalSearchTerm,
  onSearchChange: _onSearchChange,
  onCorporateContractCountChange,
  refreshTrigger
}) => {
  // 🍎 상태
  const [corporateContracts, setCorporateContracts] = useState<CorporateContract[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [memberCount, setMemberCount] = useState(0)
  const [corporateMemberNames, setCorporateMemberNames] = useState<Set<string>>(new Set())

  // 🍎 검색어 (외부/내부)
  const [internalSearchTerm] = useState('')
  const searchTerm = externalSearchTerm ?? internalSearchTerm
  // 🍎 정렬
  const [sortField, setSortField] = useState<SortField>('policyNumber')
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc')

  // 🍎 칼럼 기본 폭
  const ccDefaultWidths = useMemo(() => ({
    relation: 60,
    policy: 94,
    product: 198,
    holder: 50,
    insured: 50,
    date: 75,
    status: 46,
    amount: 61,
    premium: 83,
  }), [])

  // 🍎 칼럼 리사이즈
  const {
    columnWidths: ccColumnWidths,
    getResizeHandleProps: getCcResizeHandleProps,
    isResizing: isCcResizing,
  } = useColumnResize({
    columns: CORPORATE_CONTRACTS_COLUMNS,
    storageKey: 'corporate-contracts-tab',
    defaultWidths: ccDefaultWidths,
  })

  // ==================== 데이터 로드 ====================

  const loadCorporateContracts = useCallback(async () => {
    if (!customer?._id) return

    setIsLoading(true)
    setError(null)

    try {
      // Step 1: 관계 데이터 로드 → 가족 이름 수집 + 명시적 법인 관계 수집
      const relationships = await RelationshipService.getCustomerRelationships(customer._id)

      // 🍎 가족 구성원 이름 Set (본인 포함) — 법인계약 판별 시 제외 대상
      const familyNames = new Set<string>()
      const selfName = customer.personal_info?.name
      if (selfName) familyNames.add(selfName)

      const familyRelations = relationships.filter(
        (rel: Relationship) => rel.relationship_info.relationship_category === 'family'
      )
      for (const rel of familyRelations) {
        const relatedCustomer = rel.related_customer as Customer
        const fromCustomer = rel.from_customer as Customer
        if (typeof relatedCustomer === 'object' && relatedCustomer.personal_info?.name) {
          familyNames.add(relatedCustomer.personal_info.name)
        }
        if (typeof fromCustomer === 'object' && fromCustomer.personal_info?.name) {
          familyNames.add(fromCustomer.personal_info.name)
        }
      }

      // 🍎 명시적 법인 관계: corpName → relationship label (있으면 관계 라벨 사용)
      const corporateRelations = relationships.filter(
        (rel: Relationship) => rel.relationship_info.relationship_category === 'corporate'
      )
      const explicitCorpMap = new Map<string, string>()
      for (const rel of corporateRelations) {
        const relatedCustomer = rel.related_customer as Customer
        const fromCustomer = rel.from_customer as Customer
        const relLabel = rel.display_relationship_label
          || CORP_RELATION_TYPE_LABELS[rel.relationship_info.relationship_type]
          || rel.relationship_info.relationship_type
          || '법인관계'

        if (typeof relatedCustomer === 'object' && relatedCustomer._id && relatedCustomer._id !== customer._id) {
          const name = relatedCustomer.personal_info?.name
          if (name && !explicitCorpMap.has(name)) explicitCorpMap.set(name, relLabel)
        }
        if (typeof fromCustomer === 'object' && fromCustomer._id && fromCustomer._id !== customer._id) {
          const name = fromCustomer.personal_info?.name
          if (name && !explicitCorpMap.has(name)) explicitCorpMap.set(name, relLabel)
        }
      }

      // ===== 법인/개인 분기 =====
      const isCorpCustomer = customer.insurance_info?.customer_type === '법인'
      const userId = UserContextService.getContext().identifierValue

      if (isCorpCustomer && selfName) {
        // =====================================================
        // 🏢 법인 고객 경로: 관련 개인들의 계약에서 이 법인이 계약자/피보험자인 것
        // =====================================================

        // (A) 명시적 법인 관계에서 관련 개인 수집
        const uniqueRelated = new Map<string, { name: string; relLabel: string }>()
        for (const rel of corporateRelations) {
          const relatedCustomer = rel.related_customer as Customer
          const fromCustomer = rel.from_customer as Customer
          const relLabel = rel.display_relationship_label
            || CORP_RELATION_TYPE_LABELS[rel.relationship_info.relationship_type]
            || rel.relationship_info.relationship_type
            || '법인관계'

          if (typeof relatedCustomer === 'object' && relatedCustomer._id && relatedCustomer._id !== customer._id) {
            if (!uniqueRelated.has(relatedCustomer._id)) {
              uniqueRelated.set(relatedCustomer._id, { name: relatedCustomer.personal_info?.name || '', relLabel })
            }
          }
          if (typeof fromCustomer === 'object' && fromCustomer._id && fromCustomer._id !== customer._id) {
            if (!uniqueRelated.has(fromCustomer._id)) {
              uniqueRelated.set(fromCustomer._id, { name: fromCustomer.personal_info?.name || '', relLabel })
            }
          }
        }

        // (B) 암시적 감지: AR/CRS/수동계약에서 이 법인명이 계약자/피보험자인 고객 검색
        const implicitCustomers = await CustomerService.findCustomersByContractParty(selfName)
        for (const c of implicitCustomers) {
          if (c._id !== customer._id && !uniqueRelated.has(c._id)) {
            uniqueRelated.set(c._id, { name: c.name, relLabel: '법인' })
          }
        }

        // (C) name→relLabel 조회 테이블 (본인 데이터에서 상대방 관계 파악용)
        const nameToRelLabel = new Map<string, string>()
        for (const [, info] of uniqueRelated) {
          if (info.name) nameToRelLabel.set(info.name, info.relLabel)
        }

        // 본인 데이터에서 상대방의 관계 라벨 결정
        const resolveRelLabel = (baseLabel: string, isSelfData: boolean, holder: string, insured: string): string => {
          if (!isSelfData) return baseLabel
          const otherParty = holder !== selfName ? holder : (insured !== selfName ? insured : '')
          if (otherParty && nameToRelLabel.has(otherParty)) return nameToRelLabel.get(otherParty)!
          if (otherParty) return '법인'
          return baseLabel
        }

        // 자기 자신 + 관련 고객들의 계약 병렬 로드
        const allCustomerIds = [customer._id, ...uniqueRelated.keys()]
        const loadResults = await Promise.all(
          allCustomerIds.map(async (custId) => {
            const [ar, crs, manual] = await Promise.allSettled([
              AnnualReportApi.getAnnualReports(custId, userId, 50),
              CustomerReviewApi.getCustomerReviews(custId, 100),
              ContractService.getContractsByCustomer(custId),
            ])
            return { custId, ar, crs, manual }
          })
        )

        const seenPolicies = new Map<string, CorporateContract>()
        const discoveredMembers = new Set<string>()

        // selfName(법인명)이 계약자 or 피보험자인지 체크
        const isSelfInvolved = (holder: string, insured: string): boolean =>
          holder === selfName || insured === selfName

        for (const { custId, ar, crs, manual } of loadResults) {
          const isSelf = custId === customer._id
          const relInfo = uniqueRelated.get(custId)
          const relLabel = isSelf ? '본인' : (relInfo?.relLabel || '법인관계')
          const memberName = isSelf ? selfName : (relInfo?.name || '')

          // --- AR (최우선) ---
          if (ar.status === 'rejected') {
            console.error(`[CorporateContracts] AR 조회 실패 (${custId}):`, ar.reason)
          }
          if (ar.status === 'fulfilled') {
            const arResponse = ar.value as { success?: boolean; data?: { reports: AnnualReport[] } }
            if (arResponse.success && arResponse.data) {
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              const completedReports = (arResponse.data.reports as any[])
                .filter(r => r.status === 'completed')
                .map(r => ({ report_id: r.report_id || r.file_id || '', issue_date: r.issue_date || '', customer_name: r.customer_name || '', contracts: r.contracts || [], status: r.status || 'completed' })) as AnnualReport[]

              for (const h of groupContractsByPolicyNumber(completedReports)) {
                if (!isSelfInvolved(h.holder || '', h.insured || '') || seenPolicies.has(h.policyNumber)) continue
                discoveredMembers.add(memberName)
                seenPolicies.set(h.policyNumber, {
                  policyNumber: h.policyNumber, productName: h.productName || '-',
                  holderName: h.holder || '-', insuredName: h.insured || '-',
                  contractDate: h.contractDate || '-', status: h.latestSnapshot.status || '-',
                  premium: h.latestSnapshot.premium || 0, coverageAmount: h.latestSnapshot.coverageAmount || 0,
                  memberName, memberRelationship: resolveRelLabel(relLabel, isSelf, h.holder || '', h.insured || ''), source: 'ar',
                })
              }
            }
          }

          // --- CRS ---
          if (crs.status === 'rejected') {
            console.error(`[CorporateContracts] CRS 조회 실패 (${custId}):`, crs.reason)
          }
          if (crs.status === 'fulfilled') {
            const crsResponse = crs.value as { success?: boolean; data?: { reviews: CustomerReview[] } }
            if (crsResponse.success && crsResponse.data) {
              for (const review of crsResponse.data.reviews) {
                const pn = review.contract_info?.policy_number
                if (!pn || seenPolicies.has(pn)) continue
                if (!isSelfInvolved(review.contractor_name || '', review.insured_name || '')) continue
                discoveredMembers.add(memberName)
                seenPolicies.set(pn, {
                  policyNumber: pn, productName: review.product_name || '-',
                  holderName: review.contractor_name || '-', insuredName: review.insured_name || '-',
                  contractDate: review.contract_info?.contract_date || '-', status: '-',
                  premium: 0, coverageAmount: review.contract_info?.insured_amount ? Math.round(review.contract_info.insured_amount / 10000) : 0,
                  memberName, memberRelationship: resolveRelLabel(relLabel, isSelf, review.contractor_name || '', review.insured_name || ''), source: 'crs',
                })
              }
            }
          }

          // --- 수동 계약 ---
          if (manual.status === 'rejected') {
            console.error(`[CorporateContracts] 수동계약 조회 실패 (${custId}):`, manual.reason)
          }
          if (manual.status === 'fulfilled') {
            const contracts = manual.value as Contract[]
            if (Array.isArray(contracts)) {
              for (const c of contracts) {
                if (!c.policy_number || seenPolicies.has(c.policy_number)) continue
                if (!isSelfInvolved(c.customer_name || '', c.insured_person || '')) continue
                discoveredMembers.add(memberName)
                seenPolicies.set(c.policy_number, {
                  policyNumber: c.policy_number, productName: c.product_name || '-',
                  holderName: c.customer_name || '-', insuredName: c.insured_person || '-',
                  contractDate: c.contract_date || '-', status: c.payment_status || '-',
                  premium: c.premium || 0, coverageAmount: 0,
                  memberName, memberRelationship: resolveRelLabel(relLabel, isSelf, c.customer_name || '', c.insured_person || ''), source: 'manual',
                })
              }
            }
          }
        }

        setMemberCount(discoveredMembers.size)
        setCorporateMemberNames(new Set([selfName]))

        const merged = Array.from(seenPolicies.values())
        setCorporateContracts(merged)
        onCorporateContractCountChange?.(merged.length)
        return
      }

      // =====================================================
      // 👤 개인 고객 경로: 현재 고객의 계약에서 법인명 매칭
      // =====================================================

      // Step 2: 현재 고객의 AR / CRS / 수동 계약을 병렬 로드
      const [arResult, crsResult, manualResult] = await Promise.allSettled([
        AnnualReportApi.getAnnualReports(customer._id, userId, 50),
        CustomerReviewApi.getCustomerReviews(customer._id, 100),
        ContractService.getContractsByCustomer(customer._id),
      ])

      // Step 3: 계약에서 본인/가족이 아닌 계약자/피보험자 이름 후보 수집
      const candidateNames = new Set<string>()

      const collectCandidates = (holderName: string, insuredName: string) => {
        if (holderName && holderName !== '-' && !familyNames.has(holderName)) {
          candidateNames.add(holderName)
        }
        if (insuredName && insuredName !== '-' && !familyNames.has(insuredName)) {
          candidateNames.add(insuredName)
        }
      }

      // AR에서 후보 수집
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let arHistories: any[] = []
      if (arResult.status === 'fulfilled') {
        const arResponse = arResult.value as { success?: boolean; data?: { reports: AnnualReport[] } }
        if (arResponse.success && arResponse.data) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const completedReports = (arResponse.data.reports as any[])
            .filter(r => r.status === 'completed')
            .map(r => ({
              report_id: r.report_id || r.file_id || '',
              issue_date: r.issue_date || '',
              customer_name: r.customer_name || '',
              contracts: r.contracts || [],
              status: r.status || 'completed',
            })) as AnnualReport[]

          arHistories = groupContractsByPolicyNumber(completedReports)
          for (const h of arHistories) collectCandidates(h.holder || '', h.insured || '')
        }
      }

      // CRS에서 후보 수집
      let crsReviews: CustomerReview[] = []
      if (crsResult.status === 'fulfilled') {
        const crsResponse = crsResult.value as { success?: boolean; data?: { reviews: CustomerReview[] } }
        if (crsResponse.success && crsResponse.data) {
          crsReviews = crsResponse.data.reviews
          for (const r of crsReviews) collectCandidates(r.contractor_name || '', r.insured_name || '')
        }
      }

      // 수동 계약에서 후보 수집
      let manualContracts: Contract[] = []
      if (manualResult.status === 'fulfilled') {
        const contracts = manualResult.value as Contract[]
        if (Array.isArray(contracts)) {
          manualContracts = contracts
          for (const c of manualContracts) collectCandidates(c.customer_name || '', c.insured_person || '')
        }
      }

      // Step 4: 후보 이름을 DB에서 검증 → 실제 법인 고객만 확인
      const confirmedCorpMap = new Map<string, string>(explicitCorpMap)
      const namesToVerify = Array.from(candidateNames).filter(n => !confirmedCorpMap.has(n))

      if (namesToVerify.length > 0) {
        const verifyResults = await Promise.allSettled(
          namesToVerify.map(name => CustomerService.checkDuplicateName(name))
        )
        for (let i = 0; i < namesToVerify.length; i++) {
          const result = verifyResults[i]
          if (result.status === 'fulfilled' && result.value.exists && result.value.customer?.customer_type === '법인') {
            confirmedCorpMap.set(namesToVerify[i], '법인')
          }
        }
      }

      // 법인으로 확정된 이름이 없으면 빈 결과
      if (confirmedCorpMap.size === 0) {
        setCorporateContracts([])
        setMemberCount(0)
        setCorporateMemberNames(new Set())
        onCorporateContractCountChange?.(0)
        return
      }

      const confirmedCorpNames = new Set(confirmedCorpMap.keys())

      const findConfirmedCorp = (holderName: string, insuredName: string): { corpName: string; relationship: string } | null => {
        if (holderName && confirmedCorpNames.has(holderName)) {
          return { corpName: holderName, relationship: confirmedCorpMap.get(holderName)! }
        }
        if (insuredName && confirmedCorpNames.has(insuredName)) {
          return { corpName: insuredName, relationship: confirmedCorpMap.get(insuredName)! }
        }
        return null
      }

      // Step 5: 확정된 법인명으로 계약 필터링 & 중복 제거
      const seenPolicies = new Map<string, CorporateContract>()
      const discoveredCorpNames = new Set<string>()

      for (const history of arHistories) {
        const match = findConfirmedCorp(history.holder || '', history.insured || '')
        if (!match || seenPolicies.has(history.policyNumber)) continue
        discoveredCorpNames.add(match.corpName)
        seenPolicies.set(history.policyNumber, {
          policyNumber: history.policyNumber, productName: history.productName || '-',
          holderName: history.holder || '-', insuredName: history.insured || '-',
          contractDate: history.contractDate || '-', status: history.latestSnapshot.status || '-',
          premium: history.latestSnapshot.premium || 0, coverageAmount: history.latestSnapshot.coverageAmount || 0,
          memberName: match.corpName, memberRelationship: match.relationship, source: 'ar',
        })
      }

      for (const review of crsReviews) {
        const pn = review.contract_info?.policy_number
        if (!pn || seenPolicies.has(pn)) continue
        const match = findConfirmedCorp(review.contractor_name || '', review.insured_name || '')
        if (!match) continue
        discoveredCorpNames.add(match.corpName)
        seenPolicies.set(pn, {
          policyNumber: pn, productName: review.product_name || '-',
          holderName: review.contractor_name || '-', insuredName: review.insured_name || '-',
          contractDate: review.contract_info?.contract_date || '-', status: '-',
          premium: 0, coverageAmount: review.contract_info?.insured_amount ? Math.round(review.contract_info.insured_amount / 10000) : 0,
          memberName: match.corpName, memberRelationship: match.relationship, source: 'crs',
        })
      }

      for (const contract of manualContracts) {
        if (!contract.policy_number || seenPolicies.has(contract.policy_number)) continue
        const match = findConfirmedCorp(contract.customer_name || '', contract.insured_person || '')
        if (!match) continue
        discoveredCorpNames.add(match.corpName)
        seenPolicies.set(contract.policy_number, {
          policyNumber: contract.policy_number, productName: contract.product_name || '-',
          holderName: contract.customer_name || '-', insuredName: contract.insured_person || '-',
          contractDate: contract.contract_date || '-', status: contract.payment_status || '-',
          premium: contract.premium || 0, coverageAmount: 0,
          memberName: match.corpName, memberRelationship: match.relationship, source: 'manual',
        })
      }

      setMemberCount(discoveredCorpNames.size)
      setCorporateMemberNames(discoveredCorpNames)

      const merged = Array.from(seenPolicies.values())
      setCorporateContracts(merged)
      onCorporateContractCountChange?.(merged.length)
    } catch (err) {
      console.error('[CorporateContractsTab] 법인 계약 로드 실패:', err)
      errorReporter.reportApiError(err as Error, {
        component: 'CorporateContractsTab.loadCorporateContracts',
        payload: { customerId: customer._id }
      })
      setError(err instanceof Error ? err.message : '법인 계약 정보를 불러올 수 없습니다.')
      onCorporateContractCountChange?.(0)
    } finally {
      setIsLoading(false)
    }
  }, [customer?._id, onCorporateContractCountChange])

  // 🍎 마운트 시 로드
  useEffect(() => {
    loadCorporateContracts()
  }, [loadCorporateContracts])

  // 🍎 탭 클릭 시 데이터 새로고침
  useEffect(() => {
    if (refreshTrigger !== undefined && refreshTrigger > 0) {
      void loadCorporateContracts()
    }
  }, [refreshTrigger, loadCorporateContracts])

  // ==================== 검색 & 정렬 ====================

  // 검색 필터링
  const filteredContracts = useMemo(() => {
    if (!searchTerm) return corporateContracts
    const term = searchTerm.toLowerCase()
    return corporateContracts.filter(c =>
      c.productName.toLowerCase().includes(term) ||
      c.policyNumber.toLowerCase().includes(term) ||
      c.holderName.toLowerCase().includes(term) ||
      c.insuredName.toLowerCase().includes(term) ||
      c.memberName.toLowerCase().includes(term)
    )
  }, [corporateContracts, searchTerm])

  // 정렬
  const sortedContracts = useMemo(() => {
    const sorted = [...filteredContracts]
    sorted.sort((a, b) => {
      let valA: string | number = ''
      let valB: string | number = ''

      switch (sortField) {
        case 'memberRelationship':
          valA = a.memberRelationship
          valB = b.memberRelationship
          break
        case 'policyNumber':
          valA = a.policyNumber
          valB = b.policyNumber
          break
        case 'productName':
          valA = a.productName
          valB = b.productName
          break
        case 'holderName':
          valA = a.holderName
          valB = b.holderName
          break
        case 'insuredName':
          valA = a.insuredName
          valB = b.insuredName
          break
        case 'contractDate':
          valA = a.contractDate
          valB = b.contractDate
          break
        case 'status':
          valA = a.status
          valB = b.status
          break
        case 'coverageAmount':
          valA = a.coverageAmount
          valB = b.coverageAmount
          break
        case 'premium':
          valA = a.premium
          valB = b.premium
          break
      }

      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortDirection === 'asc' ? valA - valB : valB - valA
      }
      const cmp = String(valA).localeCompare(String(valB))
      return sortDirection === 'asc' ? cmp : -cmp
    })
    return sorted
  }, [filteredContracts, sortField, sortDirection])

  // 정렬 토글 핸들러
  const handleSort = useCallback((field: SortField) => {
    if (sortField === field) {
      setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc')
    } else {
      setSortField(field)
      setSortDirection('asc')
    }
  }, [sortField])

  // 정렬 인디케이터 (공유 컴포넌트)
  const renderSortIndicatorEl = useCallback((field: SortField) => {
    return <SortIndicator field={field} currentSortField={sortField} sortDirection={sortDirection} />
  }, [sortField, sortDirection])

  // 금액 포맷
  const formatAmount = (amount: number): string => {
    if (!amount) return '-'
    return amount.toLocaleString()
  }

  const formatPremium = (premium: number): string => {
    if (!premium) return '-'
    return premium.toLocaleString()
  }

  // 관계 뱃지 렌더링
  const renderRelationBadge = (relationship: string) => {
    const badgeClass = RELATION_BADGE_CLASS[relationship] || 'cc-relation-badge--default'
    return <span className={`cc-relation-badge ${badgeClass}`}>{relationship}</span>
  }

  // ==================== 렌더링 ====================

  // 로딩 상태
  if (isLoading) {
    return (
      <div className="corporate-contracts">
        <div className="corporate-contracts__state">
          <SFSymbol
            name="arrow.trianglehead.2.clockwise"
            size={SFSymbolSize.TITLE_3}
            weight={SFSymbolWeight.MEDIUM}
            animation={SFSymbolAnimation.ROTATE}
          />
          <span className="corporate-contracts__loading-text">
            법인 관계 구성원의 계약을 조회하는 중...
          </span>
        </div>
      </div>
    )
  }

  // 에러 상태
  if (error) {
    return (
      <div className="corporate-contracts">
        <div className="corporate-contracts__state corporate-contracts__state--error">
          <SFSymbol
            name="exclamationmark.triangle"
            size={SFSymbolSize.TITLE_3}
            weight={SFSymbolWeight.MEDIUM}
          />
          <span>{error}</span>
        </div>
      </div>
    )
  }

  // 빈 상태: 법인 계약 없음
  if (corporateContracts.length === 0) {
    return (
      <div className="corporate-contracts">
        <div className="corporate-contracts__state">
          <SFSymbol
            name="doc.text.magnifyingglass"
            size={SFSymbolSize.TITLE_3}
            weight={SFSymbolWeight.MEDIUM}
          />
          <span>법인(제3자) 계약이 없습니다.</span>
        </div>
      </div>
    )
  }

  return (
    <div className="corporate-contracts">
      {/* 🍎 요약 헤더 */}
      <div className="corporate-contracts__summary">
        <span>
          법인 <strong>{memberCount}</strong>곳 · 계약 <strong>{filteredContracts.length}</strong>건
        </span>
      </div>

      {/* 🍎 테이블 */}
      <div
        className={`tab-table__scroll corporate-contracts__table-section${isCcResizing ? ' is-resizing' : ''}`}
        style={{
          '--cc-relation-width': `${ccColumnWidths['relation'] || ccDefaultWidths.relation}px`,
          '--cc-policy-width': `${ccColumnWidths['policy'] || ccDefaultWidths.policy}px`,
          '--cc-product-width': `${ccColumnWidths['product'] || ccDefaultWidths.product}px`,
          '--cc-holder-width': `${ccColumnWidths['holder'] || ccDefaultWidths.holder}px`,
          '--cc-insured-width': `${ccColumnWidths['insured'] || ccDefaultWidths.insured}px`,
          '--cc-date-width': `${ccColumnWidths['date'] || ccDefaultWidths.date}px`,
          '--cc-status-width': `${ccColumnWidths['status'] || ccDefaultWidths.status}px`,
          '--cc-amount-width': `${ccColumnWidths['amount'] || ccDefaultWidths.amount}px`,
          '--cc-premium-width': `${ccColumnWidths['premium'] || ccDefaultWidths.premium}px`,
        } as React.CSSProperties}
      >
        {/* 헤더 */}
        <div className="tab-table__header corporate-contracts-header">
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('memberRelationship')}
            role="button"
            tabIndex={0}
          >
            <span>관계</span>
            {renderSortIndicatorEl('memberRelationship')}
            <div {...getCcResizeHandleProps('relation')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('policyNumber')}
            role="button"
            tabIndex={0}
          >
            <span>증권번호</span>
            {renderSortIndicatorEl('policyNumber')}
            <div {...getCcResizeHandleProps('policy')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('productName')}
            role="button"
            tabIndex={0}
          >
            <span>보험상품</span>
            {renderSortIndicatorEl('productName')}
            <div {...getCcResizeHandleProps('product')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('holderName')}
            role="button"
            tabIndex={0}
          >
            <span>계약자</span>
            {renderSortIndicatorEl('holderName')}
            <div {...getCcResizeHandleProps('holder')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('insuredName')}
            role="button"
            tabIndex={0}
          >
            <span>피보험자</span>
            {renderSortIndicatorEl('insuredName')}
            <div {...getCcResizeHandleProps('insured')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('contractDate')}
            role="button"
            tabIndex={0}
          >
            <span>계약일</span>
            {renderSortIndicatorEl('contractDate')}
            <div {...getCcResizeHandleProps('date')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('status')}
            role="button"
            tabIndex={0}
          >
            <span>상태</span>
            {renderSortIndicatorEl('status')}
            <div {...getCcResizeHandleProps('status')} />
          </div>
          <div
            className="resizable-header header-sortable"
            onClick={() => handleSort('coverageAmount')}
            role="button"
            tabIndex={0}
          >
            <span>가입금액</span>
            {renderSortIndicatorEl('coverageAmount')}
            <div {...getCcResizeHandleProps('amount')} />
          </div>
          <div
            className="header-sortable"
            onClick={() => handleSort('premium')}
            role="button"
            tabIndex={0}
          >
            <span>보험료</span>
            {renderSortIndicatorEl('premium')}
          </div>
        </div>

        {/* 리스트 */}
        <div className="tab-table__body corporate-contracts-list">
          {sortedContracts.map((contract) => (
            <div key={contract.policyNumber} className="tab-table__row corporate-contracts-row">
              <span className="cc-relation">
                {renderRelationBadge(contract.memberRelationship)}
              </span>
              <span className="cc-policy">{contract.policyNumber}</span>
              <span className="cc-product" title={contract.productName}>{contract.productName}</span>
              <span className={`cc-holder${corporateMemberNames.has(contract.holderName) ? ' cc-holder--corp' : ''}`}>
                {contract.holderName}
              </span>
              <span className={`cc-insured${corporateMemberNames.has(contract.insuredName) ? ' cc-insured--corp' : ''}`}>
                {contract.insuredName}
              </span>
              <span className="cc-date">{formatDate(contract.contractDate)}</span>
              <span className={`cc-status cc-status--${contract.status}`}>{contract.status}</span>
              <span className="cc-amount">{formatAmount(contract.coverageAmount)}</span>
              <span className="cc-premium">{formatPremium(contract.premium)}</span>
            </div>
          ))}
        </div>
      </div>

    </div>
  )
}

/**
 * AIMS UIX-3 Customer Review Tab
 * @since 2026-01-02
 * @version 1.0.0
 *
 * Customer Review Service 탭 컴포넌트
 * - Customer Review 조회 및 표시
 * - AnnualReportTab과 동일한 Document-Controller-View 패턴 준수
 */

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { Button } from '@/shared/ui/Button';
import { Dropdown } from '@/shared/ui';
import { Pagination } from '@/shared/ui/Pagination';
import { SortIndicator } from '@/shared/ui/SortIndicator';
import { CustomerReviewModal } from '@/features/customer/components/CustomerReviewModal';
import { CustomerReviewApi, type CustomerReview } from '@/features/customer/api/customerReviewApi';
import { AppleConfirmModal } from '../../../../../components/DocumentViews/DocumentRegistrationView/AppleConfirmModal/AppleConfirmModal';
import { useAppleConfirmController } from '../../../../../controllers/useAppleConfirmController';
import { useDevModeStore } from '@/shared/store/useDevModeStore';
import { useCustomerSSE } from '@/shared/hooks/useCustomerSSE';
import type { Customer } from '@/entities/customer/model';
import { errorReporter } from '@/shared/lib/errorReporter';
import { useColumnResize, type ColumnConfig } from '@/hooks/useColumnResize';
import './CustomerReviewTab.css';

// 정렬 필드 타입 (AnnualReportTab 스타일: 계약자, 발행일, 파싱일시, 상품명, 펀드 수, 상태)
type SortField = 'contractor_name' | 'insured_name' | 'issue_date' | 'parsed_at' | 'product_name' | 'fund_count' | 'status';
type SortDirection = 'asc' | 'desc';

interface CustomerReviewTabProps {
  customer: Customer;
  onCustomerReviewCountChange?: (count: number) => void;
  refreshTrigger?: number;
  /** 외부에서 제공하는 검색어 */
  searchTerm?: string;
  /** 외부 검색어 변경 핸들러 */
  onSearchChange?: (term: string) => void;
}

// 페이지당 항목 수 옵션
const ITEMS_PER_PAGE_OPTIONS_BASE = [
  { value: 'auto', label: '자동' },
  { value: '10', label: '10개씩' },
  { value: '25', label: '25개씩' },
  { value: '50', label: '50개씩' },
];

// 행 높이 상수 (CSS와 동일)
const ROW_HEIGHT = 32;
const ROW_GAP = 2;
const DEFAULT_TABLE_HEADER_HEIGHT = 32;
const DEFAULT_PAGINATION_HEIGHT = 26;

// 🍎 컬럼 리사이즈 설정 (계약자, 피보험자, 발행일, 파싱일시, 상품명, 펀드 수, 상태)
const CUSTOMER_REVIEW_COLUMNS: ColumnConfig[] = [
  { id: 'contractor', minWidth: 50, maxWidth: 150 },
  { id: 'insured', minWidth: 50, maxWidth: 150 },
  { id: 'issueDate', minWidth: 70, maxWidth: 120 },
  { id: 'parsedAt', minWidth: 100, maxWidth: 180 },
  { id: 'product', minWidth: 80, maxWidth: 300 },
  { id: 'fundCount', minWidth: 50, maxWidth: 100 },
  { id: 'status', minWidth: 40, maxWidth: 80 }
];

// 🍎 기본 컬럼 폭
const DEFAULT_CONTRACTOR_WIDTH = 60;
const DEFAULT_INSURED_WIDTH = 70;
const DEFAULT_ISSUE_DATE_WIDTH = 80;
const DEFAULT_PARSED_AT_WIDTH = 130;
const DEFAULT_PRODUCT_WIDTH = 120;
const DEFAULT_FUND_COUNT_WIDTH = 70;
const DEFAULT_STATUS_WIDTH = 40;

export const CustomerReviewTab: React.FC<CustomerReviewTabProps> = ({
  customer,
  onCustomerReviewCountChange,
  refreshTrigger,
  searchTerm: externalSearchTerm,
  onSearchChange: _onSearchChange
}) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [reviews, setReviews] = useState<CustomerReview[]>([]);
  const [selectedReview, setSelectedReview] = useState<CustomerReview | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // 검색어 상태
  const [internalSearchTerm] = useState('');
  const searchTerm = externalSearchTerm ?? internalSearchTerm;
  // 페이지네이션 상태
  const [itemsPerPageMode, setItemsPerPageMode] = useState<'auto' | number>(() => {
    const saved = localStorage.getItem('aims-customer-cr-items-per-page');
    if (!saved || saved === 'auto') return 'auto';
    const num = parseInt(saved, 10);
    return isNaN(num) ? 'auto' : num;
  });
  const [currentPage, setCurrentPage] = useState(1);
  const [containerHeight, setContainerHeight] = useState(0);
  const sectionContainerRef = useRef<HTMLDivElement>(null);

  // itemsPerPageMode 변경 시 localStorage에 자동 저장
  useEffect(() => {
    localStorage.setItem('aims-customer-cr-items-per-page', String(itemsPerPageMode));
  }, [itemsPerPageMode]);

  // 삭제 기능 상태
  const [selectedIndices, setSelectedIndices] = useState<Set<number>>(new Set());
  const [isDeleting, setIsDeleting] = useState(false);

  // 정렬 상태
  const [sortField, setSortField] = useState<SortField>('issue_date');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // 개발자 모드
  const { isDevMode } = useDevModeStore();

  // Apple Confirm Modal 컨트롤러
  const confirmModal = useAppleConfirmController();

  // SSE 새로고침 콜백
  const handleSSERefresh = useCallback(() => {
    loadCustomerReviews();
  }, []);

  // SSE 실시간 업데이트 - 통합 SSE 사용
  useCustomerSSE(customer._id, {
    onRefreshCR: handleSSERefresh,
  }, {
    enabled: Boolean(customer._id),
  });

  // 🔴 폴링/재시도용 refs (loadCustomerReviews 정의 후 값 설정)
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const loadRef = useRef<() => void>(() => {});
  const emptyRetryCountRef = useRef(0);

  // 개발자 모드 OFF시 선택 초기화
  useEffect(() => {
    if (!isDevMode) {
      setSelectedIndices(new Set());
    }
  }, [isDevMode]);

  // 검색어 변경 시 첫 페이지로 이동
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm]);

  // 자동 모드일 때 컨테이너 높이 기반 항목 수 계산
  const autoCalculatedItems = useMemo(() => {
    // 📱 모바일(≤768px): 페이지네이션 숨김 → 전체 표시 (스크롤 처리)
    if (typeof window !== 'undefined' && window.matchMedia('(max-width: 768px)').matches) {
      return 9999;
    }
    if (containerHeight <= 0) return 10;

    const container = sectionContainerRef.current;
    if (!container) return 10;

    const tableHeader = container.querySelector('.customer-review-table-header') as HTMLElement | null;
    const measuredTableHeaderHeight = tableHeader ? tableHeader.getBoundingClientRect().height : 0;
    const tableHeaderHeight = measuredTableHeaderHeight > 0 ? measuredTableHeaderHeight : DEFAULT_TABLE_HEADER_HEIGHT;

    const pagination = container.querySelector('.customer-review-pagination') as HTMLElement | null;
    const measuredPaginationHeight = pagination ? pagination.getBoundingClientRect().height : 0;
    const paginationHeight = measuredPaginationHeight > 0 ? measuredPaginationHeight : DEFAULT_PAGINATION_HEIGHT;

    const fixedHeight = tableHeaderHeight + paginationHeight;
    const availableHeight = containerHeight - fixedHeight;

    const maxItems = Math.max(1, Math.floor((availableHeight + ROW_GAP) / (ROW_HEIGHT + ROW_GAP)));
    return maxItems;
  }, [containerHeight]);

  // 실제 적용되는 페이지당 항목 수
  const itemsPerPage = itemsPerPageMode === 'auto' ? autoCalculatedItems : itemsPerPageMode;

  // 섹션 컨테이너 높이 측정
  useEffect(() => {
    const container = sectionContainerRef.current;
    if (!container) return;

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerHeight(entry.contentRect.height);
      }
    });

    resizeObserver.observe(container);
    return () => resizeObserver.disconnect();
  }, []);

  // 드롭다운 옵션
  const itemsPerPageOptions = useMemo(() => {
    return ITEMS_PER_PAGE_OPTIONS_BASE.map(opt => {
      if (opt.value === 'auto') {
        return {
          value: 'auto',
          label: itemsPerPageMode === 'auto' ? (autoCalculatedItems >= 9999 ? '자동(전체)' : `자동(${autoCalculatedItems})`) : '자동'
        };
      }
      return opt;
    });
  }, [itemsPerPageMode, autoCalculatedItems]);

  // 🍎 컬럼 리사이즈: 기본 폭 계산 (AnnualReportTab 동일 패턴)
  const defaultColumnWidths = useMemo(() => ({
    contractor: DEFAULT_CONTRACTOR_WIDTH,
    issueDate: DEFAULT_ISSUE_DATE_WIDTH,
    parsedAt: DEFAULT_PARSED_AT_WIDTH,
    product: DEFAULT_PRODUCT_WIDTH,
    fundCount: DEFAULT_FUND_COUNT_WIDTH,
    status: DEFAULT_STATUS_WIDTH,
  }), [])

  // 🍎 컬럼 리사이즈 훅
  const {
    columnWidths,
    isResizing,
    getResizeHandleProps,
    wasJustResizing
  } = useColumnResize({
    storageKey: 'customer-review-tab-v2',
    columns: CUSTOMER_REVIEW_COLUMNS,
    defaultWidths: defaultColumnWidths
  })

  // Customer Review 목록 로드
  useEffect(() => {
    loadCustomerReviews();
  }, [customer._id, refreshTrigger]);

  // Customer Review 개수 변경 시 부모에게 알림
  useEffect(() => {
    onCustomerReviewCountChange?.(reviews.length);
  }, [reviews.length, onCustomerReviewCountChange]);

  const loadCustomerReviews = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await CustomerReviewApi.getCustomerReviews(customer._id, 50);

      if (response.success && response.data) {
        setReviews(response.data.reviews);
      } else {
        setError(response.error || 'Customer Review 조회에 실패했습니다.');
      }
    } catch (err) {
      console.error('[CustomerReviewTab] Customer Review 조회 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'CustomerReviewTab.loadCustomerReviews', payload: { customerId: customer._id } });
      setError(err instanceof Error ? err.message : 'Customer Review 조회 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  };

  // 🔴 폴링/재시도 refs에 최신 함수 바인딩
  loadRef.current = loadCustomerReviews;

  // 🔴 폴링 기반 자동 갱신 (SSE 백업 - 신뢰성 강화)
  // pending/processing 상태 CRS가 있으면 5초마다 폴링하여 완료 감지
  useEffect(() => {
    const hasPending = reviews.some(r => r.status === 'pending' || r.status === 'processing');

    if (hasPending && !pollingRef.current) {
      pollingRef.current = setInterval(() => loadRef.current(), 5000);
    }

    if (!hasPending && pollingRef.current) {
      clearInterval(pollingRef.current);
      pollingRef.current = null;
    }

    return () => {
      if (pollingRef.current) {
        clearInterval(pollingRef.current);
        pollingRef.current = null;
      }
    };
  }, [reviews]);

  // 🔴 초기 로드 빈 결과 시 점진적 재시도 (레이스 컨디션 방지)
  // 업로드 직후 DB에 파일 미생성 상태일 수 있으므로 최대 5회(15초) 재시도
  useEffect(() => {
    const MAX_EMPTY_RETRIES = 5;
    if (!isLoading && reviews.length === 0 && emptyRetryCountRef.current < MAX_EMPTY_RETRIES) {
      const retryNum = emptyRetryCountRef.current + 1;
      emptyRetryCountRef.current = retryNum;
      const timer = setTimeout(() => loadRef.current(), 3000);
      return () => { clearTimeout(timer); };
    }
    if (reviews.length > 0) {
      emptyRetryCountRef.current = 0;
    }
    return undefined;
  }, [isLoading, reviews.length]);

  const handleViewReview = (review: CustomerReview) => {
    // 실패/진행중 문서는 모달 열지 않음
    if (review.status === 'error' || review.status === 'processing') {
      return;
    }
    setSelectedReview(review);
    setIsModalOpen(true);
  };

  // 정렬 핸들러
  const handleSort = useCallback((field: SortField) => {
    // 리사이즈 직후 클릭은 무시 (정렬 방지)
    if (wasJustResizing()) return;

    if (sortField === field) {
      setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  }, [sortField, wasJustResizing]);

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedReview(null);
  };

  // 체크박스 전체 선택/해제
  const handleSelectAll = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.checked) {
      const allIndices = new Set(visibleReviews.map((_, idx) => (currentPage - 1) * itemsPerPage + idx));
      setSelectedIndices(allIndices);
    } else {
      setSelectedIndices(new Set());
    }
  };

  // 개별 체크박스 선택/해제
  const handleSelectReview = (globalIndex: number, event: React.MouseEvent) => {
    event.stopPropagation();
    setSelectedIndices((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(globalIndex)) {
        newSet.delete(globalIndex);
      } else {
        newSet.add(globalIndex);
      }
      return newSet;
    });
  };

  // Customer Reviews 삭제
  const handleDeleteSelected = async () => {
    if (selectedIndices.size === 0) {
      await confirmModal.actions.openModal({
        title: '선택 항목 없음',
        message: '삭제할 항목을 선택해주세요.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'warning'
      });
      return;
    }

    const confirmed = await confirmModal.actions.openModal({
      title: 'Customer Review 삭제',
      message: `${selectedIndices.size}개 항목을 삭제하시겠습니까?\n삭제된 데이터는 복구할 수 없습니다.`,
      confirmText: '삭제',
      cancelText: '취소',
      confirmStyle: 'destructive',
      showCancel: true,
      iconType: 'warning'
    });

    if (!confirmed) {
      return;
    }

    setIsDeleting(true);
    try {
      const result = await CustomerReviewApi.deleteCustomerReviews(
        customer._id,
        Array.from(selectedIndices)
      );

      setIsDeleting(false);

      if (result.success) {
        setSelectedIndices(new Set());
        await loadCustomerReviews();

        await confirmModal.actions.openModal({
          title: '완료',
          message: `${result.deleted_count}건 삭제되었습니다.`,
          confirmText: '확인',
          showCancel: false,
          iconType: 'success'
        });
      } else {
        await confirmModal.actions.openModal({
          title: '실패',
          message: result.message,
          confirmText: '확인',
          showCancel: false,
          iconType: 'error'
        });
      }
    } catch (err) {
      setIsDeleting(false);
      console.error('[CustomerReviewTab] 삭제 오류:', err);
      errorReporter.reportApiError(err as Error, { component: 'CustomerReviewTab.handleDeleteSelected', payload: { customerId: customer._id, count: selectedIndices.size } });
      await confirmModal.actions.openModal({
        title: '오류',
        message: '삭제 중 오류가 발생했습니다.',
        confirmText: '확인',
        showCancel: false,
        iconType: 'error'
      });
    }
  };

  // 검색어로 필터링된 리뷰 목록
  const filteredReviews = useMemo(() => {
    if (!searchTerm.trim()) return reviews;

    const term = searchTerm.toLowerCase().trim();
    return reviews.filter(review => {
      const contractorName = (review.contractor_name || '').toLowerCase();
      const insuredName = (review.insured_name || '').toLowerCase();
      const productName = (review.product_name || '').toLowerCase();
      const issueDate = CustomerReviewApi.formatDate(review.issue_date).toLowerCase();
      const parsedAt = CustomerReviewApi.formatDateTime(review.parsed_at).toLowerCase();

      return contractorName.includes(term) ||
             insuredName.includes(term) ||
             productName.includes(term) ||
             issueDate.includes(term) ||
             parsedAt.includes(term);
    });
  }, [reviews, searchTerm]);

  // 정렬된 리뷰 목록
  const sortedReviews = useMemo(() => {
    return [...filteredReviews].sort((a, b) => {
      let comparison = 0;

      switch (sortField) {
        case 'contractor_name':
          comparison = (a.contractor_name || '').localeCompare(b.contractor_name || '', 'ko');
          break;
        case 'insured_name':
          comparison = (a.insured_name || '').localeCompare(b.insured_name || '', 'ko');
          break;
        case 'issue_date':
          comparison = new Date(a.issue_date || 0).getTime() - new Date(b.issue_date || 0).getTime();
          break;
        case 'parsed_at':
          comparison = new Date(a.parsed_at || 0).getTime() - new Date(b.parsed_at || 0).getTime();
          break;
        case 'product_name':
          comparison = (a.product_name || '').localeCompare(b.product_name || '', 'ko');
          break;
        case 'fund_count':
          comparison = (a.fund_count || 0) - (b.fund_count || 0);
          break;
        case 'status':
          const statusOrder = { 'completed': 0, 'processing': 1, 'pending': 2, 'error': 3 };
          comparison = (statusOrder[a.status || 'completed'] || 0) - (statusOrder[b.status || 'completed'] || 0);
          break;
      }

      return sortDirection === 'asc' ? comparison : -comparison;
    });
  }, [filteredReviews, sortField, sortDirection]);

  // 페이지네이션 계산
  const itemsPerPageNumber = itemsPerPage;
  const totalPages = Math.max(1, Math.ceil(sortedReviews.length / itemsPerPageNumber));
  const safeCurrentPage = Math.min(currentPage, totalPages);

  // 현재 페이지에 표시할 리뷰들
  const visibleReviews = sortedReviews.slice(
    (safeCurrentPage - 1) * itemsPerPageNumber,
    safeCurrentPage * itemsPerPageNumber
  );

  // 전체 선택 여부
  const isAllSelected = visibleReviews.length > 0 && visibleReviews.every((_, idx) => {
    const globalIndex = (safeCurrentPage - 1) * itemsPerPageNumber + idx;
    return selectedIndices.has(globalIndex);
  });

  // 로딩 상태
  if (isLoading) {
    return (
      <div ref={sectionContainerRef} className="customer-review-tab">
        <div className="customer-review-tab__loading">
          <div className="customer-review-tab__loading-spinner"></div>
          <p>Customer Review를 불러오는 중...</p>
        </div>
      </div>
    );
  }

  // 에러 상태
  if (error) {
    return (
      <div ref={sectionContainerRef} className="customer-review-tab">
        <div className="customer-review-tab__error">
          <div className="customer-review-tab__error-icon">!</div>
          <p>{error}</p>
          <Button variant="secondary" size="sm" onClick={loadCustomerReviews}>
            다시 시도
          </Button>
        </div>
      </div>
    );
  }

  // Customer Review 없음
  if (reviews.length === 0) {
    return (
      <div ref={sectionContainerRef} className="customer-review-tab">
        <div className="customer-review-tab__empty">
          <h3 className="customer-review-tab__empty-title">Customer Review가 없습니다</h3>
          <p className="customer-review-tab__empty-description">
            Customer Review Service 문서를 업로드하면 자동 분석하여 여기에 표시됩니다.
          </p>
        </div>
      </div>
    );
  }

  // 페이지 변경은 Pagination 컴포넌트에서 직접 호출
  const handlePageChange = (page: number) => {
    setCurrentPage(page);
  };

  const handleItemsPerPageChange = (value: string) => {
    if (value === 'auto') {
      setItemsPerPageMode('auto');
    } else {
      setItemsPerPageMode(Number(value));
    }
    setCurrentPage(1);
  };

  // Customer Review 목록 있음
  return (
    <div ref={sectionContainerRef} className="customer-review-tab">
      {/* 삭제 버튼 (개발자 모드 전용) */}
      {isDevMode && selectedIndices.size > 0 && (
        <div className="customer-review-actions">
          <Button
            variant="destructive"
            size="sm"
            onClick={handleDeleteSelected}
            disabled={isDeleting}
            title="개발자 전용 기능"
          >
            {isDeleting ? '삭제 중...' : `선택 항목 삭제 (${selectedIndices.size})`}
          </Button>
        </div>
      )}

      {/* 테이블 컨테이너 */}
      <div
        className={`tab-table__scroll customer-review-table-container${isResizing ? ' is-resizing' : ''}`}
        style={{
          '--contractor-column-width': `${columnWidths['contractor'] || DEFAULT_CONTRACTOR_WIDTH}px`,
          '--insured-column-width': `${columnWidths['insured'] || DEFAULT_INSURED_WIDTH}px`,
          '--issue-date-column-width': `${columnWidths['issueDate'] || DEFAULT_ISSUE_DATE_WIDTH}px`,
          '--parsed-at-column-width': `${columnWidths['parsedAt'] || DEFAULT_PARSED_AT_WIDTH}px`,
          '--product-column-width': `${columnWidths['product'] || DEFAULT_PRODUCT_WIDTH}px`,
          '--fund-count-column-width': `${columnWidths['fundCount'] || DEFAULT_FUND_COUNT_WIDTH}px`,
          '--status-column-width': `${columnWidths['status'] || DEFAULT_STATUS_WIDTH}px`,
        } as React.CSSProperties}
      >
        {/* 테이블 헤더 (AnnualReportTab 동일 패턴) */}
        <div className="tab-table__header customer-review-table-header">
          {isDevMode && (
            <div className="header-checkbox">
              <input
                type="checkbox"
                checked={isAllSelected}
                onChange={handleSelectAll}
                aria-label="전체 선택"
              />
            </div>
          )}
          <div
            className="header-contractor customer-review-table__sortable resizable-header"
            onClick={() => handleSort('contractor_name')}
          >
            <span className="customer-review-table__header-content">
              계약자
              <SortIndicator field="contractor_name" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('contractor')} />
          </div>
          <div
            className="header-insured customer-review-table__sortable resizable-header"
            onClick={() => handleSort('insured_name')}
          >
            <span className="customer-review-table__header-content">
              피보험자
              <SortIndicator field="insured_name" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('insured')} />
          </div>
          <div
            className="header-issue-date customer-review-table__sortable resizable-header"
            onClick={() => handleSort('issue_date')}
          >
            <span className="customer-review-table__header-content">
              발행일
              <SortIndicator field="issue_date" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('issueDate')} />
          </div>
          <div
            className="header-parsed-at customer-review-table__sortable resizable-header"
            onClick={() => handleSort('parsed_at')}
          >
            <span className="customer-review-table__header-content">
              파싱일시
              <SortIndicator field="parsed_at" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('parsedAt')} />
          </div>
          <div
            className="header-product customer-review-table__sortable resizable-header"
            onClick={() => handleSort('product_name')}
          >
            <span className="customer-review-table__header-content">
              상품명
              <SortIndicator field="product_name" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('product')} />
          </div>
          <div
            className="header-fund-count customer-review-table__sortable resizable-header"
            onClick={() => handleSort('fund_count')}
          >
            <span className="customer-review-table__header-content">
              펀드 수
              <SortIndicator field="fund_count" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('fundCount')} />
          </div>
          <div
            className="header-status customer-review-table__sortable resizable-header"
            onClick={() => handleSort('status')}
          >
            <span className="customer-review-table__header-content">
              상태
              <SortIndicator field="status" currentSortField={sortField} sortDirection={sortDirection} />
            </span>
            <div {...getResizeHandleProps('status')} />
          </div>
        </div>

        {/* 테이블 바디 */}
        <div className="tab-table__body customer-review-table-body">
          {visibleReviews.map((review, idx) => {
            const globalIndex = reviews.indexOf(review);
            const isSelected = selectedIndices.has(globalIndex);
            const isError = review.status === 'error';
            const isProcessing = review.status === 'processing';
            const isPending = review.status === 'pending';

            return (
              <div
                key={review.source_file_id || `review_${idx}`}
                className={`tab-table__row customer-review-row ${isSelected ? 'customer-review-row--selected' : ''} ${isError ? 'customer-review-row--error' : ''} ${isProcessing ? 'customer-review-row--processing' : ''} ${isPending ? 'customer-review-row--pending' : ''}`}
                onClick={() => handleViewReview(review)}
              >
                {isDevMode && (
                  <div className="row-checkbox" onClick={(e) => handleSelectReview(globalIndex, e)}>
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={() => {}}
                      aria-label={`리뷰 선택`}
                    />
                  </div>
                )}
                <div className="row-contractor">{review.contractor_name || '-'}</div>
                <div className="row-insured">{review.insured_name || '-'}</div>
                <div className="row-issue-date">
                  {CustomerReviewApi.formatDate(review.issue_date)}
                </div>
                <div className="row-parsed-at">
                  {review.parsed_at ? CustomerReviewApi.formatDateTime(review.parsed_at) : '-'}
                </div>
                <div className="row-product" title={review.product_name || ''}>
                  {review.product_name || '-'}
                </div>
                <div className="row-fund-count">
                  {review.fund_count != null ? `${review.fund_count}개` : '-'}
                </div>
                <div className="row-status">
                  {isError && (
                    <span
                      className="status-badge status-badge--error"
                      title={review.error_message || '파싱 실패'}
                    >
                      실패{review.retry_count ? ` (${review.retry_count}/3)` : ''}
                    </span>
                  )}
                  {isProcessing && (
                    <>
                      <span className="status-badge status-badge--processing">
                        <span className="status-spinner"></span>
                        처리중
                      </span>
                      <span className="retry-indicator">[{review.retry_count || 1}/3]</span>
                    </>
                  )}
                  {isPending && (
                    <>
                      <span className="status-badge status-badge--pending">
                        대기중
                      </span>
                      <span className="retry-indicator">[{review.retry_count || 1}/3]</span>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* 페이지네이션 */}
      <div className="tab-table__pagination customer-review-pagination">
        <div className="pagination-limit">
          <Dropdown
            value={itemsPerPageMode === 'auto' ? 'auto' : String(itemsPerPageMode)}
            options={itemsPerPageOptions}
            onChange={handleItemsPerPageChange}
            aria-label="페이지당 항목 수"
            width={70}
          />
        </div>

        <Pagination
          currentPage={safeCurrentPage}
          totalPages={totalPages}
          onPageChange={handlePageChange}
          variant="compact"
        />
      </div>

      {/* Customer Review Modal */}
      <CustomerReviewModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        review={selectedReview}
      />

      {/* Apple Confirm Modal */}
      <AppleConfirmModal
        state={confirmModal.state}
        actions={confirmModal.actions}
      />
    </div>
  );
};

/**
 * AIMS UIX-3 Customer Detail - Documents Tab
 * @since 2025-10-25
 *
 * 🍎 CenterPane DocumentLibraryView 디자인 100% 복제
 * - 칼럼: 파일 타입 아이콘, 파일명, 크기, 연결일
 * - 헤더 아이콘 및 스타일 동일
 * - 페이지네이션, 정렬 기능 포함
 */

import React, { useCallback, useState, useMemo, useEffect, useRef } from 'react'
import { createPortal } from 'react-dom'
import { useAppleConfirm } from '@/contexts/AppleConfirmProvider'
import { useDevModeStore } from '@/shared/store/useDevModeStore'
import type { Customer } from '@/entities/customer/model'
import { Tooltip, Button, ContextMenu, useContextMenu, type ContextMenuSection, DocumentTypeCell, DocumentTypeBadge } from '@/shared/ui'
