import './CustomerDocumentExplorerView.css'

interface CustomerDocumentExplorerViewProps {
  visible: boolean
  customerId: string | null
  customerName: string | null
  customerType?: '개인' | '법인'
  onClose: () => void
  onCollapse: () => void
  /** 문서 클릭 시 RightPane 프리뷰 (App에서 handleDocumentClick 전달) */
  onDocumentClick?: (documentId: string) => void
  /** 문서 삭제 완료 핸들러 (삭제된 문서 ID 전달) */
  onDocumentDeleted?: (deletedIds: string | string[]) => void
  /** RP에서 보고 있는 문서 ID (프리뷰 하이라이트용) */
  previewDocumentId?: string | null
}

/** 소분류 그룹 */
interface SubTypeGroup {
  typeValue: string
  label: string
  documents: CustomerDocumentItem[]
}

/** 대분류 그룹 */
interface CategoryGroup {
  value: string
  label: string
  icon: string
  color: string
  subTypes: SubTypeGroup[]
  totalCount: number
}

/** 관계자/가족 그룹 */
interface RelatedPersonGroup {
  customerId: string
  name: string
  relationshipType: string
  relationshipLabel: string
  icon: string
  documents: CustomerDocumentItem[]
  categoryGroups: CategoryGroup[]
  totalCount: number
}

type TabType = 'my' | 'related'

/** 관계 유형 -> 아이콘 매핑 */
const RELATIONSHIP_ICONS: Record<string, string> = {
  ceo: '\uD83D\uDC54',       // 넥타이
  executive: '\uD83C\uDFAF', // 타겟
  employee: '\uD83D\uDC64',  // 사람
  spouse: '\u2764\uFE0F',    // 하트
  parent: '\uD83D\uDC68\u200D\uD83D\uDC69', // 부모
  child: '\uD83D\uDC76',     // 아기
}

/** 관계 유형 -> 한글 레이블 */
const RELATIONSHIP_LABELS: Record<string, string> = {
  ceo: '대표',
  executive: '임원',
  employee: '직원',
  spouse: '배우자',
  parent: '부모',
  child: '자녀',
  shareholder: '주주',
  director: '이사',
}

/** CustomerDocumentItem → Document 변환 (모달에서 _id로 API 조회하므로 최소 필드만) */
function customerDocToDocument(doc: CustomerDocumentItem): Document {
  return {
    _id: doc._id,
    originalName: doc.originalName,
    displayName: doc.displayName,
    mimeType: doc.mimeType,
    status: doc.status as Document['status'],
    fileSize: doc.fileSize,
  }
}

/**
 * 문서에서 실질적 document_type 값을 추출
 * - isAnnualReport/isCustomerReview 플래그도 반영
 */
function getEffectiveType(doc: CustomerDocumentItem): string {
  if (doc.document_type) return doc.document_type
  if (doc.isAnnualReport) return 'annual_report'
  return ''
}

/** 문서 목록을 2단 카테고리 트리로 변환 */
function buildCategoryGroups(documents: CustomerDocumentItem[]): CategoryGroup[] {
  if (!documents || documents.length === 0) return []

  // 1단계: document_type별로 문서 그룹화
  const typeGroups = new Map<string, CustomerDocumentItem[]>()
  for (const doc of documents) {
    const docType = getEffectiveType(doc) || 'unspecified'
    if (!typeGroups.has(docType)) typeGroups.set(docType, [])
    typeGroups.get(docType)!.push(doc)
  }

  // 2단계: 대분류별로 소분류 그룹을 모음
  const categoryMap = new Map<string, SubTypeGroup[]>()
  for (const [docType, docs] of typeGroups) {
    const cat = getCategoryForType(docType)
    if (!categoryMap.has(cat)) categoryMap.set(cat, [])
    categoryMap.get(cat)!.push({
      typeValue: docType,
      label: getDocumentTypeLabel(docType),
      documents: docs,
    })
  }

  // 3단계: DOCUMENT_CATEGORIES 순서대로 정렬, 소분류는 GT 폴더 순서 (1.1→1.2→...)
  return DOCUMENT_CATEGORIES
    .filter(cat => categoryMap.has(cat.value))
    .map(cat => {
      const subTypes = categoryMap.get(cat.value)!
      subTypes.sort((a, b) => getTypeDisplayOrder(a.typeValue) - getTypeDisplayOrder(b.typeValue))
      return {
        value: cat.value,
        label: cat.label,
        icon: cat.icon,
        color: cat.color,
        subTypes,
        totalCount: subTypes.reduce((sum, st) => sum + st.documents.length, 0),
      }
    })
}

/** 관계자 정보에서 이름 추출 */
function getRelatedCustomerName(customer: string | Customer): string {
  if (typeof customer === 'string') return customer
  return customer.personal_info?.name || '이름 없음'
}

/** 관계자 정보에서 ID 추출 */
function getRelatedCustomerId(customer: string | Customer): string {
  if (typeof customer === 'string') return customer
  return customer._id
}

export const CustomerDocumentExplorerView: React.FC<CustomerDocumentExplorerViewProps> = ({
  visible,
  customerId,
  customerName,
  customerType = '개인',
  onClose,
  onCollapse,
  onDocumentClick,
  onDocumentDeleted,
  previewDocumentId,
}) => {
  const [activeTab, setActiveTab] = usePersistedState<TabType>('cust-doc-explorer-tab', 'my')
  // 펼침 상태: "cat:insurance" 또는 "st:insurance/annual_report" 형식
  const [expandedNodesList, setExpandedNodesList] = usePersistedState<string[]>('cust-doc-explorer-expanded', [])
  const expandedNodes = useMemo(() => new Set(expandedNodesList), [expandedNodesList])
  const setExpandedNodes = useCallback((value: Set<string> | ((prev: Set<string>) => Set<string>)) => {
    if (typeof value === 'function') {
      setExpandedNodesList(prev => Array.from(value(new Set(prev))))
    } else {
      setExpandedNodesList(Array.from(value))
    }
  }, [setExpandedNodesList])
  // 파일명 모드: localStorage로 전역 동기화 (전체문서보기와 동일 키)
  const [filenameMode, setFilenameMode] = useState<'display' | 'original'>(() => {
    if (typeof window === 'undefined') return 'display'
    return (localStorage.getItem('aims-filename-mode') as 'display' | 'original') ?? 'display'
  })
  // 파일명 검색
  const [searchTerm, setSearchTerm] = usePersistedState('cust-doc-explorer-search', '')

  // 🍎 고객 전환 시 상태 초기화 (이전 고객의 UI 컨텍스트 오염 방지)
  const prevCustomerIdRef = useRef(customerId)
  useEffect(() => {
    if (prevCustomerIdRef.current !== customerId) {
      prevCustomerIdRef.current = customerId
      setActiveTab('my')
      setExpandedNodesList([])
      setSearchTerm('')
    }
  }, [customerId, setActiveTab, setExpandedNodesList, setSearchTerm])

  // 호버 액션: 문서 삭제/이름변경 — reload 대신 데이터 재조회로 UI 상태 유지
  const refreshDataRef = useRef<() => void>(() => {})
  const onRefreshData = useCallback(() => { refreshDataRef.current() }, [])
  const lastDeletedDocIdRef = useRef<string | null>(null)
  const onDeleteSuccessWithNotify = useCallback(() => {
    onRefreshData()
    if (lastDeletedDocIdRef.current) {
      onDocumentDeleted?.(lastDeletedDocIdRef.current)
      lastDeletedDocIdRef.current = null
    }
  }, [onRefreshData, onDocumentDeleted])
  const documentActions = useDocumentActions({
    onRenameSuccess: onRefreshData,
    onDeleteSuccess: onDeleteSuccessWithNotify,
  })
  const [renamingDoc, setRenamingDoc] = useState<{ _id: string; originalName: string; displayName?: string } | null>(null)

  const handleRenameClick = useCallback((doc: { _id?: string; displayName?: string; originalName?: string }) => {
    if (doc._id) setRenamingDoc({ _id: doc._id, originalName: doc.originalName || '', displayName: doc.displayName })
  }, [])

  const handleRenameConfirm = useCallback(async (newName: string) => {
    if (!renamingDoc) return
    setRenamingDoc(null)
    const field = filenameMode === 'original' ? 'originalName' as const : 'displayName' as const
    await documentActions.renameDocument(renamingDoc._id, newName, field)
  }, [documentActions, filenameMode, renamingDoc])

  const handleRenameCancel = useCallback(() => {
    setRenamingDoc(null)
  }, [])

  const handleHoverDeleteClick = useCallback((doc: { _id?: string; displayName?: string; originalName?: string }) => {
    const docName = doc.displayName || doc.originalName || ''
    if (doc._id) {
      lastDeletedDocIdRef.current = doc._id
      documentActions.deleteDocument(doc._id, docName)
    }
  }, [documentActions])

  // 모달 상태
  const [selectedDocument, setSelectedDocument] = useState<Document | null>(null)
  const [activeModal, setActiveModal] = useState<'summary' | 'fulltext' | null>(null)
  // 관계자 문서 탭 상태
  const [relatedGroups, setRelatedGroups] = useState<RelatedPersonGroup[]>([])
  const [relatedLoading, setRelatedLoading] = useState(false)
  const [relatedError, setRelatedError] = useState<string | null>(null)

  const {
    documents,
    isLoading,
    error,
    refresh,
    updateDocumentLocally,
  } = useCustomerDocumentsController(visible ? customerId : null)

  // 이름변경/삭제 성공 시 데이터 재조회 (UI 상태 유지)
  refreshDataRef.current = () => { refresh() }

  const { showAlert } = useAppleConfirm()
  const [updatingDocTypeId, setUpdatingDocTypeId] = useState<string | null>(null)

  /** 문서 유형 변경 핸들러 (낙관적 업데이트 + 자동 펼침) */
  const handleDocTypeChange = useCallback(async (documentId: string, newType: string, treePrefix: string = '') => {
    if (updatingDocTypeId) return

    const previousType = treePrefix
      ? relatedGroups.flatMap(p => p.documents).find(d => d._id === documentId)?.document_type
      : documents.find(d => d._id === documentId)?.document_type
    updateDocumentLocally(documentId, { document_type: newType === 'unspecified' ? undefined : newType })

    // 관계자 탭: relatedGroups 로컬 업데이트
    if (treePrefix) {
      setRelatedGroups(prev => prev.map(person => ({
        ...person,
        documents: person.documents.map(doc =>
          doc._id === documentId ? { ...doc, document_type: newType === 'unspecified' ? undefined : newType } : doc
        ),
        categoryGroups: buildCategoryGroups(
          person.documents.map(doc =>
            doc._id === documentId ? { ...doc, document_type: newType === 'unspecified' ? undefined : newType } : doc
          )
        ),
      })))
    }

    // 새 소분류 자동 펼침
    const newCat = getCategoryForType(newType)
    setExpandedNodes(prev => {
      const next = new Set(prev)
      next.add(`${treePrefix}cat:${newCat}`)
      next.add(`${treePrefix}st:${newCat}/${newType}`)
      return next
    })

    setUpdatingDocTypeId(documentId)
    try {
      await documentTypesService.updateDocumentType(documentId, newType)
      void refresh()
    } catch (error) {
      console.error('[DocumentExplorer] 문서 유형 변경 실패:', error)
      updateDocumentLocally(documentId, { document_type: previousType })
      if (treePrefix) {
        setRelatedGroups(prev => prev.map(person => ({
          ...person,
          documents: person.documents.map(doc =>
            doc._id === documentId ? { ...doc, document_type: previousType } : doc
          ),
          categoryGroups: buildCategoryGroups(
            person.documents.map(doc =>
              doc._id === documentId ? { ...doc, document_type: previousType } : doc
            )
          ),
        })))
      }
      await showAlert({
        title: '변경 실패',
        message: '문서 유형 변경에 실패했습니다.',
        confirmText: '확인'
      })
    } finally {
      setUpdatingDocTypeId(null)
    }
  }, [updatingDocTypeId, documents, relatedGroups, updateDocumentLocally, refresh, showAlert])

  // 검색어로 문서 필터링
  const filteredDocuments = useMemo(() => {
    if (!searchTerm.trim()) return documents
    const term = searchTerm.trim().toLowerCase()
    return documents.filter(doc =>
      doc.originalName?.toLowerCase().includes(term) ||
      doc.displayName?.toLowerCase().includes(term)
    )
  }, [documents, searchTerm])

  // 2단 트리 구성: 대분류 -> 소분류 -> 문서
  const categoryGroups = useMemo<CategoryGroup[]>(() => {
    return buildCategoryGroups(filteredDocuments)
  }, [filteredDocuments])

  // 초기 진입 시 대분류 모두 펼치기 / 검색 시 매칭 노드 자동 펼침
  useEffect(() => {
    if (categoryGroups.length > 0) {
      if (searchTerm.trim()) {
        // 검색 중: 대분류 + 소분류 모두 펼침
        const allKeys = new Set<string>()
        for (const g of categoryGroups) {
          allKeys.add(`cat:${g.value}`)
          for (const st of g.subTypes) {
            allKeys.add(`st:${g.value}/${st.typeValue}`)
          }
        }
        setExpandedNodes(allKeys)
      } else {
        setExpandedNodes(prev => {
          // 이미 노드가 있으면 사용자가 조작한 상태이므로 유지
          if (prev.size > 0) return prev
          return new Set(categoryGroups.map(g => `cat:${g.value}`))
        })
      }
    }
  }, [categoryGroups, searchTerm])

  // 관계자 탭 초기 진입 시 대분류 모두 펼치기
  useEffect(() => {
    if (activeTab !== 'related' || relatedGroups.length === 0 || searchTerm.trim()) return
    setExpandedNodes(prev => {
      // 이미 관계자 노드가 펼쳐져 있으면 사용자가 조작한 상태이므로 유지
      const hasRelatedNodes = [...prev].some(k => k.startsWith('person:'))
      if (hasRelatedNodes) return prev
      const allKeys = new Set(prev)
      relatedGroups.forEach(g => {
        allKeys.add(`person:${g.customerId}`)
        g.categoryGroups.forEach(cat => {
          allKeys.add(`p${g.customerId}:cat:${cat.value}`)
        })
      })
      return allKeys
    })
  }, [relatedGroups, activeTab, searchTerm])

  // 관계자 문서 검색 필터링
  const filteredRelatedGroups = useMemo<RelatedPersonGroup[]>(() => {
    if (!searchTerm.trim()) return relatedGroups
    const term = searchTerm.trim().toLowerCase()
    return relatedGroups.map(person => {
      const filtered = person.documents.filter(doc =>
        doc.originalName?.toLowerCase().includes(term) ||
        doc.displayName?.toLowerCase().includes(term)
      )
      if (filtered.length === 0) return null
      return {
        ...person,
        documents: filtered,
        categoryGroups: buildCategoryGroups(filtered),
        totalCount: filtered.length,
      }
    }).filter(Boolean) as RelatedPersonGroup[]
  }, [relatedGroups, searchTerm])

  // 관계자 탭 검색 시 자동 확장
  useEffect(() => {
    if (activeTab !== 'related' || !searchTerm.trim()) return
    if (filteredRelatedGroups.length === 0) return

    const allKeys = new Set<string>()
    for (const person of filteredRelatedGroups) {
      allKeys.add(`person:${person.customerId}`)
      const prefix = `p${person.customerId}:`
      for (const g of person.categoryGroups) {
        allKeys.add(`${prefix}cat:${g.value}`)
        for (const st of g.subTypes) {
          allKeys.add(`${prefix}st:${g.value}/${st.typeValue}`)
        }
      }
    }
    setExpandedNodes(allKeys)
  }, [filteredRelatedGroups, searchTerm, activeTab])

  // 관계자/가족 문서 로드
  useEffect(() => {
    if (!visible || !customerId || activeTab !== 'related') return

    let cancelled = false

    const loadRelatedDocuments = async () => {
      setRelatedLoading(true)
      setRelatedError(null)

      try {
        // 1. 관계 목록 조회
        const relationships = await RelationshipService.getCustomerRelationships(customerId)

        if (cancelled) return

        // 2. 각 관계자의 문서 조회 (중복 제거)
        const seenIds = new Set<string>()
        const groups: RelatedPersonGroup[] = []

        for (const rel of relationships) {
          // 관계에서 상대방 고객 정보 추출
          const fromId = getRelatedCustomerId(rel.from_customer)
          const toId = getRelatedCustomerId(rel.related_customer)
          const isFromMe = fromId === customerId
          const relatedCustomer = isFromMe ? rel.related_customer : rel.from_customer
          const relatedId = isFromMe ? toId : fromId

          // 중복 방지
          if (seenIds.has(relatedId)) continue
          seenIds.add(relatedId)

          // 관계 유형 결정
          const relType = rel.relationship_info?.relationship_type || 'employee'
          const relLabel = rel.display_relationship_label || RELATIONSHIP_LABELS[relType] || relType
          const relIcon = RELATIONSHIP_ICONS[relType] || '\uD83D\uDC64'

          try {
            // 관계자의 문서 조회 (includeRelated: 법인에서 업로드한 AR/CRS도 포함)
            const result = await DocumentService.getCustomerDocuments(relatedId, { includeRelated: true })
            if (cancelled) return

            if (result.documents.length > 0) {
              groups.push({
                customerId: relatedId,
                name: getRelatedCustomerName(relatedCustomer),
                relationshipType: relType,
                relationshipLabel: relLabel,
                icon: relIcon,
                documents: result.documents,
                categoryGroups: buildCategoryGroups(result.documents),
                totalCount: result.documents.length,
              })
            }
          } catch {
            // 개별 관계자 문서 조회 실패는 무시하고 계속 진행
          }
        }

        if (!cancelled) {
          setRelatedGroups(groups)
          // 관계자 탭 진입 시 관계자 + 대분류까지 자동 펼치기
          if (groups.length > 0) {
            setExpandedNodes(prev => {
              const personKeys = groups.map(g => `person:${g.customerId}`)
              const hasPersonKeys = personKeys.some(k => prev.has(k))
              if (hasPersonKeys) return prev
              const next = new Set(prev)
              for (const g of groups) {
                next.add(`person:${g.customerId}`)
                for (const cat of g.categoryGroups) {
                  next.add(`p${g.customerId}:cat:${cat.value}`)
                }
              }
              return next
            })
          }
        }
      } catch {
        if (!cancelled) {
          setRelatedError('관계자 문서를 불러올 수 없습니다')
        }
      } finally {
        if (!cancelled) {
          setRelatedLoading(false)
        }
      }
    }

    loadRelatedDocuments()
    return () => { cancelled = true }
  }, [visible, customerId, activeTab])

  const toggleNode = useCallback((nodeKey: string) => {
    setExpandedNodes(prev => {
      const next = new Set(prev)
      if (next.has(nodeKey)) {
        next.delete(nodeKey)
      } else {
        next.add(nodeKey)
      }
      return next
    })
  }, [])

  // 전체 펼침/접기: 대분류까지만 (소분류 폴더 헤더는 보이되 파일 목록은 접힌 상태)
  const toggleAll = useCallback(() => {
    if (activeTab === 'my') {
      setExpandedNodes(prev => {
        const catKeys = categoryGroups.map(g => `cat:${g.value}`)
        const allCatsExpanded = catKeys.every(k => prev.has(k))
        if (allCatsExpanded) {
          return new Set()
        }
        return new Set(catKeys)
      })
    } else {
      setExpandedNodes(prev => {
        const personKeys = relatedGroups.map(g => `person:${g.customerId}`)
        const allExpanded = personKeys.every(k => prev.has(k))
        if (allExpanded) {
          return new Set()
        }
        const allKeys = new Set<string>()
        relatedGroups.forEach(g => {
          allKeys.add(`person:${g.customerId}`)
          g.categoryGroups.forEach(cat => {
            allKeys.add(`p${g.customerId}:cat:${cat.value}`)
          })
        })
        return allKeys
      })
    }
  }, [categoryGroups, relatedGroups, activeTab])

  const handleDocClick = useCallback((doc: CustomerDocumentItem) => {
    if (onDocumentClick && doc._id) {
      onDocumentClick(doc._id)
    }
  }, [onDocumentClick])

  const handleSummaryClick = useCallback((doc: CustomerDocumentItem, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(customerDocToDocument(doc))
    setActiveModal('summary')
  }, [])

  const handleFullTextClick = useCallback((doc: CustomerDocumentItem, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedDocument(customerDocToDocument(doc))
    setActiveModal('fulltext')
  }, [])

  const handleModalClose = useCallback(() => {
    setActiveModal(null)
    setSelectedDocument(null)
  }, [])

  const allExpanded = activeTab === 'my'
    ? categoryGroups.length > 0 && categoryGroups.every(g => expandedNodes.has(`cat:${g.value}`))
    : relatedGroups.length > 0 && relatedGroups.every(g => expandedNodes.has(`person:${g.customerId}`))

  const relatedTabLabel = customerType === '법인' ? '관계자 문서' : '가족 문서'

  if (!visible) return null

  /** 카테고리 트리 렌더링 (내 문서 / 관계자 내부 공통) */
  const renderCategoryTree = (groups: CategoryGroup[], prefix: string = '') => (
    <>
      {groups.map(group => {
        const catKey = `${prefix}cat:${group.value}`
        const isCatExpanded = expandedNodes.has(catKey)

        return (
          <div key={catKey} className="cde-category" style={{ '--cde-cat-color': group.color } as React.CSSProperties}>
            {/* 대분류 헤더 */}
            <button
              type="button"
              className="cde-category__header"
              onClick={() => toggleNode(catKey)}
              aria-expanded={isCatExpanded ? "true" : "false"}
            >
              <span className="cde-category__chevron">
                <SFSymbol
                  name={isCatExpanded ? 'chevron.down' : 'chevron.right'}
                  size={SFSymbolSize.CAPTION_2}
                  weight={SFSymbolWeight.SEMIBOLD}
                  color={group.color}
                  decorative={true}
                />
              </span>
              <span className="cde-category__icon">
                <SFSymbol
                  name={group.icon}
                  size={SFSymbolSize.CAPTION_1}
                  weight={SFSymbolWeight.MEDIUM}
                  color={group.color}
                  decorative={true}
                />
              </span>
              <span className="cde-category__label">{group.label}</span>
              <span className="cde-category__count">{group.totalCount}</span>
            </button>

            {/* 소분류 목록 */}
            {isCatExpanded && (
              <div className="cde-subtypes">
                {group.subTypes.map(subType => {
                  const stKey = `${prefix}st:${group.value}/${subType.typeValue}`
                  const isStExpanded = expandedNodes.has(stKey)

                  return (
                    <div key={stKey} className="cde-subtype">
                      {/* 소분류 헤더 */}
                      <button
                        type="button"
                        className="cde-subtype__header"
                        onClick={() => toggleNode(stKey)}
                        aria-expanded={isStExpanded ? "true" : "false"}
                      >
                        <span className="cde-subtype__chevron">
                          <SFSymbol
                            name={isStExpanded ? 'chevron.down' : 'chevron.right'}
                            size={SFSymbolSize.CAPTION_2}
                            weight={SFSymbolWeight.MEDIUM}
                            color={group.color}
                            decorative={true}
                          />
                        </span>
                        <span className="cde-subtype__icon">
                          <SFSymbol
                            name="folder"
                            size={SFSymbolSize.CAPTION_2}
                            weight={SFSymbolWeight.MEDIUM}
                            color={group.color}
                            decorative={true}
                          />
                        </span>
                        <span className="cde-subtype__label">{subType.label}</span>
                        <span className="cde-subtype__count">{subType.documents.length}</span>
                      </button>

                      {/* 문서 목록 */}
                      {isStExpanded && (
                        <div className="cde-subtype__docs">
                          {subType.documents.map(doc => {
                            const fileIcon = DocumentUtils.getFileIcon(doc.mimeType, doc.originalName)
                            const fileClass = DocumentUtils.getFileTypeClass(doc.mimeType, doc.originalName)
                            const fileSize = doc.fileSize ? DocumentUtils.formatFileSize(doc.fileSize) : '-'
                            const hasDisplay = Boolean(doc.displayName)
                            const isAlias = filenameMode === 'display' && hasDisplay
                            const showName = isAlias
                              ? doc.displayName!
                              : doc.originalName
                            const altName = isAlias
                              ? `원본: ${doc.originalName}`
                              : (hasDisplay ? `별칭: ${doc.displayName}` : '')
                            return (
                              <div
                                key={doc._id}
                                className={`cde-doc-row${previewDocumentId === doc._id ? ' cde-doc-row--preview' : ''}`}
                                onClick={() => handleDocClick(doc)}
                              >
                                <span className={`cde-doc-row__icon ${fileClass}`}>
                                  <SFSymbol
                                    name={fileIcon}
                                    size={SFSymbolSize.CAPTION_2}
                                    weight={SFSymbolWeight.MEDIUM}
                                    decorative={true}
                                  />
                                </span>
                                <span className="cde-doc-row__name-cell">
                                    <>
                                      {altName ? (
                                        <Tooltip content={altName}>
                                          <span className={`cde-doc-row__name${isAlias ? ' document-name--alias' : ''}`}>{showName}</span>
                                        </Tooltip>
                                      ) : (
                                        <Tooltip content={doc.originalName || ''} showOnlyWhenTruncated>
                                          <span className={`cde-doc-row__name${isAlias ? ' document-name--alias' : ''}`}>{showName}</span>
                                        </Tooltip>
                                      )}
                                      <span className="cde-doc-row__hover-actions" onClick={(e) => e.stopPropagation()}>
                                        <Tooltip content="이름 변경">
                                          <button
                                            type="button"
                                            className="cde-doc-row__hover-btn cde-doc-row__hover-btn--rename"
                                            aria-label="이름 변경"
                                            onClick={(e) => { e.stopPropagation(); handleRenameClick(doc) }}
                                          >
                                            <svg width="11" height="11" viewBox="0 0 16 16" fill="none">
                                              <path d="M11.5 1.5l3 3L5 14H2v-3L11.5 1.5z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                                            </svg>
                                          </button>
                                        </Tooltip>
                                        <Tooltip content="삭제">
                                          <button
                                            type="button"
                                            className="cde-doc-row__hover-btn cde-doc-row__hover-btn--delete"
                                            aria-label="삭제"
                                            onClick={(e) => { e.stopPropagation(); handleHoverDeleteClick(doc) }}
                                          >
                                            <svg width="11" height="11" viewBox="0 0 16 16" fill="none">
                                              <path d="M2 4h12M5.33 4V2.67a1.33 1.33 0 011.34-1.34h2.66a1.33 1.33 0 011.34 1.34V4m2 0v9.33a1.33 1.33 0 01-1.34 1.34H4.67a1.33 1.33 0 01-1.34-1.34V4h9.34z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
                                            </svg>
                                          </button>
                                        </Tooltip>
                                      </span>
                                    </>
                                  {doc.relatedCustomerId && !prefix && (
                                    <Tooltip content={`${relatedGroups.find(g => g.customerId === doc.relatedCustomerId)?.name || '관계자'}에게 링크됨`}>
                                      <span className="cde-doc-row__origin-badge">
                                        <SFSymbol name="link" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} decorative={true} />
                                      </span>
                                    </Tooltip>
                                  )}
                                  {doc.relatedCustomerId && prefix && (
                                    <Tooltip content={`원본: ${customerName} ${group.label} > ${subType.label}`}>
                                      <span className="cde-doc-row__linked-badge">
                                        <SFSymbol name="arrow.up.right.square" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} decorative={true} />
                                      </span>
                                    </Tooltip>
                                  )}
                                </span>
                                <span className="cde-doc-row__doctype" onClick={(e) => e.stopPropagation()}>
                                  <DocumentTypeCell
                                    documentType={doc.document_type}
                                    isAnnualReport={doc.isAnnualReport}
                                    isCustomerReview={doc.document_type === 'customer_review'}
                                    onChange={(newType) => {
                                      if (doc._id) {
                                        handleDocTypeChange(doc._id, newType, prefix)
                                      }
                                    }}
                                    isUpdating={updatingDocTypeId === doc._id}
                                  />
                                </span>
                                <span className="cde-doc-row__size">{fileSize}</span>
                                <span className="cde-doc-row__date">
                                  {doc.linkedAt ? formatDateTimeCompact(doc.linkedAt) : '-'}
                                </span>
                                <span className="cde-doc-row__actions">
                                  <Tooltip content="요약 보기">
                                    <button
                                      type="button"
                                      className="cde-doc-row__action-btn"
                                      onClick={(e) => handleSummaryClick(doc, e)}
                                      aria-label="요약 보기"
                                    >
                                      <SummaryIcon />
                                    </button>
                                  </Tooltip>
                                  <Tooltip content="전체 텍스트 보기">
                                    <button
                                      type="button"
                                      className="cde-doc-row__action-btn"
                                      onClick={(e) => handleFullTextClick(doc, e)}
                                      aria-label="전체 텍스트 보기"
                                    >
                                      <DocumentIcon />
                                    </button>
                                  </Tooltip>
                                </span>
                              </div>
                            )
                          })}
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            )}
          </div>
        )
      })}
    </>
  )

  /** 관계자/가족 문서 탭 콘텐츠 */
  const renderRelatedTab = () => {
    if (relatedLoading) {
      return (
        <div className="cde-state">
          <SFSymbol name="arrow.clockwise" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
          <span>{relatedTabLabel}을 불러오는 중...</span>
        </div>
      )
    }

    if (relatedError) {
      return (
        <div className="cde-state cde-state--error">
          <SFSymbol name="exclamationmark" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
          <span>{relatedError}</span>
        </div>
      )
    }

    if (relatedGroups.length === 0) {
      return (
        <div className="cde-state">
          <SFSymbol name="person.2" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
          <span>{customerType === '법인' ? '관계자가 없거나 관계자 문서가 없습니다' : '가족이 없거나 가족 문서가 없습니다'}</span>
        </div>
      )
    }

    const totalDocs = relatedGroups.reduce((sum, g) => sum + g.totalCount, 0)
    const filteredTotalDocs = filteredRelatedGroups.reduce((sum, g) => sum + g.totalCount, 0)

    return (
      <div className="cde-tree">
        <div className="cde-summary">
          <span>
            {searchTerm.trim()
              ? <>검색 결과 <strong>{filteredTotalDocs}</strong>건 / 전체 {totalDocs}건</>
              : <>{relatedGroups.length}명 · 총 <strong>{totalDocs}</strong>건</>
            }
          </span>
          <div className="cde-summary__actions">
            <div className="cde-search__input-wrap">
              <SFSymbol name="magnifyingglass" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} color="var(--color-primary-500)" className="cde-search__icon" decorative={true} />
              <input
                type="text"
                className="cde-search__input"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="파일명 검색"
              />
              {searchTerm && (
                <button type="button" className="cde-search__clear" onClick={() => setSearchTerm('')} aria-label="지우기">
                  <SFSymbol name="xmark.circle.fill" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} decorative={true} />
                </button>
              )}
            </div>
            <button
              type="button"
              className="cde-expand-all-btn"
              onClick={toggleAll}
              aria-label={allExpanded ? '모두 접기' : '모두 펼치기'}
            >
              <SFSymbol
                name={allExpanded ? 'chevron.up' : 'chevron.down'}
                size={SFSymbolSize.CAPTION_2}
                weight={SFSymbolWeight.MEDIUM}
                color="var(--color-text-secondary)"
                decorative={true}
              />
              <span>{allExpanded ? '모두 접기' : '모두 펼치기'}</span>
            </button>
          </div>
        </div>

        {/* 검색 결과 없음 */}
        {filteredRelatedGroups.length === 0 && searchTerm.trim() && (
          <div className="cde-state">
            <SFSymbol name="magnifyingglass" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
            <span>"{searchTerm.trim()}" 검색 결과가 없습니다</span>
          </div>
        )}

        {filteredRelatedGroups.map(person => {
          const personKey = `person:${person.customerId}`
          const isPersonExpanded = expandedNodes.has(personKey)

          return (
            <div key={person.customerId} className="cde-person">
              {/* 관계자 헤더 */}
              <button
                type="button"
                className="cde-person__header"
                onClick={() => toggleNode(personKey)}
                aria-expanded={isPersonExpanded ? "true" : "false"}
              >
                <span className="cde-person__chevron">
                  <SFSymbol
                    name={isPersonExpanded ? 'chevron.down' : 'chevron.right'}
                    size={SFSymbolSize.CAPTION_2}
                    weight={SFSymbolWeight.SEMIBOLD}
                    decorative={true}
                  />
                </span>
                <span className="cde-person__icon">{person.icon}</span>
                <span className="cde-person__name">{person.name}</span>
                <span className="cde-person__relation">{person.relationshipLabel}</span>
                <span className="cde-person__count">{person.totalCount}</span>
              </button>

              {/* 관계자 내 카테고리 트리 */}
              {isPersonExpanded && (
                <div className="cde-person__content">
                  {renderCategoryTree(person.categoryGroups, `p${person.customerId}:`)}
                </div>
              )}
            </div>
          )
        })}
      </div>
    )
  }

  return (
    <CenterPaneView
      visible={visible}
      suppressAutoBackButton
      title={`${customerName || '고객'} 문서 분류함`}
      titleIcon={
        <SFSymbol
          name="doc"
          size={SFSymbolSize.CALLOUT}
          weight={SFSymbolWeight.MEDIUM}
          decorative={true}
        />
      }
      titleAccessory={
        <BackButton label="목록" onClick={onCollapse} />
      }
      onClose={onClose}
      className="customer-document-explorer"
    >
      {/* 탭 헤더 */}
      <div className="cde-tabs">
        <div className="cde-tabs__segment">
          <button
            type="button"
            className={`cde-tabs__tab ${activeTab === 'my' ? 'cde-tabs__tab--active' : ''}`}
            onClick={() => setActiveTab('my')}
          >
            <SFSymbol name="doc" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} color="var(--color-primary-500)" decorative={true} />
            내 문서
          </button>
          <button
            type="button"
            className={`cde-tabs__tab ${activeTab === 'related' ? 'cde-tabs__tab--active' : ''}`}
            onClick={() => setActiveTab('related')}
          >
            <SFSymbol name="person.2" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} decorative={true} />
            {relatedTabLabel}
          </button>
        </div>
        <FilenameModeToggle filenameMode={filenameMode} onModeChange={(next) => {
          setFilenameMode(next)
          localStorage.setItem('aims-filename-mode', next)
        }} />
      </div>

      {/* 내 문서 탭 */}
      {activeTab === 'my' && (
        <>
          {isLoading && (
            <div className="cde-state">
              <SFSymbol name="arrow.clockwise" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
              <span>문서를 불러오는 중...</span>
            </div>
          )}

          {error && !isLoading && (
            <div className="cde-state cde-state--error">
              <SFSymbol name="exclamationmark" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
              <span>문서를 불러올 수 없습니다</span>
            </div>
          )}

          {!isLoading && !error && documents.length === 0 && (
            <div className="cde-state">
              <SFSymbol name="doc" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
              <span>문서가 없습니다</span>
            </div>
          )}

          {!isLoading && !error && documents.length > 0 && (
            <div className="cde-tree">
              {/* 요약 + 검색 도구 바 */}
              <div className="cde-summary">
                <span>
                  {searchTerm.trim()
                    ? <>검색 결과 <strong>{filteredDocuments.length}</strong>건 / 전체 {documents.length}건</>
                    : <>총 <strong>{documents.length}</strong>건 · {categoryGroups.length}개 분류</>
                  }
                </span>
                <div className="cde-summary__actions">
                  <div className="cde-search__input-wrap">
                    <SFSymbol name="magnifyingglass" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} color="var(--color-primary-500)" className="cde-search__icon" decorative={true} />
                    <input
                      type="text"
                      className="cde-search__input"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      placeholder="파일명 검색"
                    />
                    {searchTerm && (
                      <button type="button" className="cde-search__clear" onClick={() => setSearchTerm('')} aria-label="지우기">
                        <SFSymbol name="xmark.circle.fill" size={SFSymbolSize.CAPTION_2} weight={SFSymbolWeight.MEDIUM} decorative={true} />
                      </button>
                    )}
                  </div>
                  <button
                    type="button"
                    className="cde-expand-all-btn"
                    onClick={toggleAll}
                    aria-label={allExpanded ? '모두 접기' : '모두 펼치기'}
                  >
                    <SFSymbol
                      name={allExpanded ? 'chevron.up' : 'chevron.down'}
                      size={SFSymbolSize.CAPTION_2}
                      weight={SFSymbolWeight.MEDIUM}
                      color="var(--color-text-secondary)"
                      decorative={true}
                    />
                    <span>{allExpanded ? '모두 접기' : '모두 펼치기'}</span>
                  </button>
                </div>
              </div>

              {/* 검색 결과 없음 */}
              {categoryGroups.length === 0 && searchTerm.trim() && (
                <div className="cde-state">
                  <SFSymbol name="magnifyingglass" size={SFSymbolSize.BODY} weight={SFSymbolWeight.MEDIUM} decorative={true} />
                  <span>"{searchTerm.trim()}" 검색 결과가 없습니다</span>
                </div>
              )}

              {/* 트리 */}
              {renderCategoryTree(categoryGroups)}
            </div>
          )}
        </>
      )}

      {/* 관계자/가족 문서 탭 */}
      {activeTab === 'related' && renderRelatedTab()}

      {/* 요약 / 전체 텍스트 모달 */}
      <DocumentSummaryModal
        visible={activeModal === 'summary'}
        onClose={handleModalClose}
        document={selectedDocument}
      />
      <DocumentFullTextModal
        visible={activeModal === 'fulltext'}
        onClose={handleModalClose}
        document={selectedDocument}
      />
      {/* 이름 변경 모달 */}
      <RenameModal
        visible={renamingDoc !== null}
        onClose={handleRenameCancel}
        onConfirm={handleRenameConfirm}
        editField={filenameMode === 'original' ? 'originalName' : 'displayName'}
        originalName={renamingDoc?.originalName || ''}
        displayName={renamingDoc?.displayName}
      />
    </CenterPaneView>
  )
}

export default CustomerDocumentExplorerView

/**
 * AIMS UIX-3 Customer Registration - Basic Info Section
 * @since 2025-10-04
 * @version 2.1.0
 *
 * 🍎 애플 iOS Settings 스타일 완벽 구현
 * - List Item Row 형태의 깔끔한 레이아웃
 * - Progressive Disclosure 패턴 적용
 * - 서브틀한 호버 효과
 *
 * @modified 2025-12-11 - 고객명 실시간 중복검사 추가
 */

import React, { useState, useEffect, useRef } from 'react';
import type { CustomerRegistrationFormData } from '../../../controllers/useCustomerRegistrationController';
import { checkDuplicateName } from '@/services/customerService';

export type BasicInfoFormData = Pick<CustomerRegistrationFormData, 'name' | 'name_en' | 'birth_date' | 'gender'>;

// 중복 검사 상태 타입
type DuplicateCheckStatus = 'idle' | 'checking' | 'duplicate' | 'available';

// Debounce 시간 (ms)
const DUPLICATE_CHECK_DELAY = 500;

interface BasicInfoSectionProps {
  formData: BasicInfoFormData;
  errors: Record<string, string>;
  onChange: (field: keyof BasicInfoFormData, value: BasicInfoFormData[keyof BasicInfoFormData]) => void;
  /** 수정 모드일 때 현재 고객 ID (자기 자신은 중복으로 표시하지 않음) */
  editingCustomerId?: string;
}

export const BasicInfoSection: React.FC<BasicInfoSectionProps> = ({
  formData,
  errors,
  onChange,
  editingCustomerId,
}) => {
  // 중복 검사 상태
  const [duplicateStatus, setDuplicateStatus] = useState<DuplicateCheckStatus>('idle');
  const [duplicateCustomer, setDuplicateCustomer] = useState<{
    _id: string;
    name: string;
    customer_type: string;
    status: string;
  } | null>(null);

  // Debounce 타이머 ref
  const checkTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // 이름 변경 시 중복 검사
  useEffect(() => {
    // 기존 타이머 취소
    if (checkTimerRef.current) {
      clearTimeout(checkTimerRef.current);
    }

    const name = formData.name?.trim();

    // 이름이 비어있으면 idle 상태
    if (!name) {
      setDuplicateStatus('idle');
      setDuplicateCustomer(null);
      return;
    }

    // 이름이 2자 미만이면 검사 안함
    if (name.length < 2) {
      setDuplicateStatus('idle');
      setDuplicateCustomer(null);
      return;
    }

    // checking 상태로 변경
    setDuplicateStatus('checking');

    // Debounced 중복 검사
    checkTimerRef.current = setTimeout(async () => {
      try {
        const result = await checkDuplicateName(name);

        // 수정 모드에서 자기 자신은 중복으로 표시하지 않음
        const isSelf = editingCustomerId && result.customer?._id === editingCustomerId;

        if (result.exists && result.customer && !isSelf) {
          setDuplicateStatus('duplicate');
          setDuplicateCustomer(result.customer);
        } else {
          setDuplicateStatus('available');
          setDuplicateCustomer(null);
        }
      } catch (error) {
        // 에러 시 idle로 (백엔드에서 최종 검증)
        setDuplicateStatus('idle');
        setDuplicateCustomer(null);
      }
    }, DUPLICATE_CHECK_DELAY);

    // Cleanup
    return () => {
      if (checkTimerRef.current) {
        clearTimeout(checkTimerRef.current);
      }
    };
  }, [formData.name, editingCustomerId]);

  // 중복 상태에 따른 클래스
  const getNameFieldClass = () => {
    if (errors['personal_info.name']) return 'form-row--error';
    if (duplicateStatus === 'duplicate') return 'form-row--warning';
    return '';
  };

  return (
    <div className="form-section">
      <h3 className="form-section__title form-section__title--basic">
        <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
          <circle cx="8" cy="5" r="2.5"/>
          <path d="M8 9c-2.5 0-4.5 1.5-4.5 3v1.5h9V12c0-1.5-2-3-4.5-3z"/>
        </svg>
        <span>기본</span>
      </h3>

      <div className="form-section__content">
        {/* 이름 */}
        <div className={`form-row ${getNameFieldClass()}`}>
          <label className="form-row__label form-row__label--required">
            이름
          </label>
          <div className="form-row__input form-row__input--with-status">
            <input
              type="text"
              value={formData.name}
              onChange={(e) => onChange('name', e.target.value)}
              placeholder="홍길동"
              aria-label="이름"
              aria-required="true"
              aria-invalid={!!errors['personal_info.name'] || duplicateStatus === 'duplicate'}
            />
            {/* 중복 검사 상태 표시 */}
            {duplicateStatus === 'checking' && (
              <span className="form-row__status form-row__status--checking" aria-label="중복 확인 중">
                ⏳
              </span>
            )}
            {duplicateStatus === 'available' && (
              <span className="form-row__status form-row__status--available" aria-label="사용 가능">
                ✓
              </span>
            )}
            {duplicateStatus === 'duplicate' && (
              <span className="form-row__status form-row__status--duplicate" aria-label="중복된 이름">
                !
              </span>
            )}
          </div>
        </div>
        {errors['personal_info.name'] && (
          <div className="form-row__error" role="alert">
            {errors['personal_info.name']}
          </div>
        )}
        {duplicateStatus === 'duplicate' && duplicateCustomer && !errors['personal_info.name'] && (
          <div className="form-row__warning" role="alert">
            이미 등록된 고객입니다 ({duplicateCustomer.customer_type})
          </div>
        )}

        {/* 이름 (영문) */}
        <div className={`form-row ${errors['personal_info.name_en'] ? 'form-row--error' : ''}`}>
          <label className="form-row__label">
            이름 (영문)
          </label>
          <div className="form-row__input">
            <input
              type="text"
              value={formData.name_en || ''}
              onChange={(e) => onChange('name_en', e.target.value)}
              placeholder="Hong Gildong"
              aria-label="이름 (영문)"
              aria-invalid={!!errors['personal_info.name_en']}
            />
          </div>
        </div>
        {errors['personal_info.name_en'] && (
          <div className="form-row__error" role="alert">
            {errors['personal_info.name_en']}
          </div>
        )}

        {/* 생년월일 */}
        <div className={`form-row ${errors['personal_info.birth_date'] ? 'form-row--error' : ''}`}>
          <label className="form-row__label">
            생년월일
          </label>
          <div className="form-row__input form-row__input--date">
            <input
              type="date"
              value={formData.birth_date || ''}
              onChange={(e) => onChange('birth_date', e.target.value)}
              aria-label="생년월일"
              aria-invalid={!!errors['personal_info.birth_date']}
            />
            <span className="date-icon">📅</span>
          </div>
        </div>
        {errors['personal_info.birth_date'] && (
          <div className="form-row__error" role="alert">
            {errors['personal_info.birth_date']}
          </div>
        )}

        {/* 성별 */}
        <div className="form-row">
          <label className="form-row__label">
            성별
          </label>
          <div className="radio-group">
            <label className="radio-option">
              <input
                type="radio"
                name="gender"
                value="M"
                checked={formData.gender === 'M'}
                onChange={(e) => onChange('gender', e.target.value as 'M' | 'F')}
                aria-label="남성"
              />
              <span>남성</span>
            </label>
            <label className="radio-option">
              <input
                type="radio"
                name="gender"
                value="F"
                checked={formData.gender === 'F'}
                onChange={(e) => onChange('gender', e.target.value as 'M' | 'F')}
                aria-label="여성"
              />
              <span>여성</span>
            </label>
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * useBatchId Hook Tests
 * @since 2026-02-05
 *
 * sessionStorage의 batchId를 실시간으로 추적하는 훅 테스트
 * - sessionStorage 읽기/쓰기
 * - 구독자 알림
 * - 교차 탭 이벤트 처리
 * - SSR 호환성
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook, act } from '@testing-library/react'
import { useBatchId, setBatchId, clearBatchId, getBatchId, getLastBatchSetTime } from '../useBatchId'

describe('useBatchId', () => {
  const BATCH_ID_KEY = 'aims-current-batch-id'

  beforeEach(() => {
    // sessionStorage 초기화
    sessionStorage.clear()
    vi.clearAllMocks()
  })

  afterEach(() => {
    sessionStorage.clear()
  })

  describe('useBatchId 훅', () => {
    it('초기값이 sessionStorage에 없으면 null을 반환해야 함', () => {
      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBeNull()
    })

    it('sessionStorage에 값이 있으면 그 값을 반환해야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'batch-123')

      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBe('batch-123')
    })

    it('setBatchId 호출 시 값이 업데이트되어야 함', () => {
      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBeNull()

      act(() => {
        setBatchId('new-batch-456')
      })

      expect(result.current).toBe('new-batch-456')
      expect(sessionStorage.getItem(BATCH_ID_KEY)).toBe('new-batch-456')
    })

    it('clearBatchId 호출 시 값이 null이 되어야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'batch-to-clear')

      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBe('batch-to-clear')

      act(() => {
        clearBatchId()
      })

      expect(result.current).toBeNull()
      expect(sessionStorage.getItem(BATCH_ID_KEY)).toBeNull()
    })

    it('여러 훅 인스턴스가 동기화되어야 함', () => {
      const { result: result1 } = renderHook(() => useBatchId())
      const { result: result2 } = renderHook(() => useBatchId())

      expect(result1.current).toBeNull()
      expect(result2.current).toBeNull()

      act(() => {
        setBatchId('shared-batch')
      })

      expect(result1.current).toBe('shared-batch')
      expect(result2.current).toBe('shared-batch')
    })
  })

  describe('setBatchId', () => {
    it('sessionStorage에 값을 저장해야 함', () => {
      setBatchId('test-batch')

      expect(sessionStorage.getItem(BATCH_ID_KEY)).toBe('test-batch')
    })

    it('기존 값을 덮어써야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'old-batch')

      setBatchId('new-batch')

      expect(sessionStorage.getItem(BATCH_ID_KEY)).toBe('new-batch')
    })

    it('구독자들에게 알림을 보내야 함', () => {
      const { result } = renderHook(() => useBatchId())

      act(() => {
        setBatchId('notified-batch')
      })

      expect(result.current).toBe('notified-batch')
    })
  })

  describe('clearBatchId', () => {
    it('sessionStorage에서 값을 삭제해야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'batch-to-remove')

      clearBatchId()

      expect(sessionStorage.getItem(BATCH_ID_KEY)).toBeNull()
    })

    it('값이 없어도 에러가 발생하지 않아야 함', () => {
      expect(() => clearBatchId()).not.toThrow()
    })

    it('구독자들에게 알림을 보내야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'batch-to-clear')

      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBe('batch-to-clear')

      act(() => {
        clearBatchId()
      })

      expect(result.current).toBeNull()
    })
  })

  describe('getBatchId', () => {
    it('sessionStorage의 현재 값을 반환해야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'current-batch')

      const value = getBatchId()

      expect(value).toBe('current-batch')
    })

    it('값이 없으면 null을 반환해야 함', () => {
      const value = getBatchId()

      expect(value).toBeNull()
    })

    it('React 외부에서도 사용 가능해야 함', () => {
      sessionStorage.setItem(BATCH_ID_KEY, 'external-batch')

      // 훅 없이 직접 호출
      expect(getBatchId()).toBe('external-batch')
    })
  })

  describe('교차 탭 동기화 (storage 이벤트)', () => {
    it('다른 탭에서 storage 이벤트가 발생하면 업데이트되어야 함', () => {
      const { result } = renderHook(() => useBatchId())

      expect(result.current).toBeNull()

      // 다른 탭에서 변경 시뮬레이션
      act(() => {
        // sessionStorage 직접 변경 (다른 탭처럼)
        sessionStorage.setItem(BATCH_ID_KEY, 'other-tab-batch')

        // storage 이벤트 발생
        window.dispatchEvent(new StorageEvent('storage', {
          key: BATCH_ID_KEY,
          newValue: 'other-tab-batch'
        }))
      })

      expect(result.current).toBe('other-tab-batch')
    })

    it('다른 키의 storage 이벤트는 무시해야 함', () => {
      const { result } = renderHook(() => useBatchId())

      act(() => {
        sessionStorage.setItem('other-key', 'other-value')

        window.dispatchEvent(new StorageEvent('storage', {
          key: 'other-key',
          newValue: 'other-value'
        }))
      })

      expect(result.current).toBeNull()
    })
  })

  describe('언마운트 정리', () => {
    it('언마운트 시 구독이 해제되어야 함', () => {
      const { result, unmount } = renderHook(() => useBatchId())

      // 초기 상태 확인
      expect(result.current).toBeNull()

      unmount()

      // 언마운트 후 setBatchId는 에러 없이 동작해야 함
      expect(() => setBatchId('after-unmount')).not.toThrow()
    })

    it('여러 훅 중 하나가 언마운트되어도 다른 훅은 계속 동작해야 함', () => {
      const { result: result1, unmount: unmount1 } = renderHook(() => useBatchId())
      const { result: result2 } = renderHook(() => useBatchId())

      unmount1()

      act(() => {
        setBatchId('still-working')
      })

      expect(result2.current).toBe('still-working')
    })
  })

  describe('타입 안정성', () => {
    it('반환 타입이 string | null이어야 함', () => {
      const { result } = renderHook(() => useBatchId())

      // null 케이스
      expect(result.current).toBeNull()

      act(() => {
        setBatchId('typed-batch')
      })

      // string 케이스
      expect(typeof result.current).toBe('string')
    })
  })

  describe('UX 시나리오', () => {
    it('업로드 시작 → 배치 ID 설정 → 완료 → 정리 시나리오', () => {
      const { result } = renderHook(() => useBatchId())

      // 1. 초기: 배치 없음
      expect(result.current).toBeNull()

      // 2. 업로드 시작: 배치 ID 설정
      act(() => {
        setBatchId('upload-batch-2024')
      })
      expect(result.current).toBe('upload-batch-2024')

      // 3. 업로드 진행 중: 배치 ID 유지
      expect(getBatchId()).toBe('upload-batch-2024')

      // 4. 업로드 완료: 배치 정리
      act(() => {
        clearBatchId()
      })
      expect(result.current).toBeNull()
    })

    it('새 업로드로 배치 전환 시나리오', () => {
      const { result } = renderHook(() => useBatchId())

      // 첫 번째 배치
      act(() => {
        setBatchId('first-batch')
      })
      expect(result.current).toBe('first-batch')

      // 새 업로드 시작 (새 배치로 즉시 전환)
      act(() => {
        setBatchId('second-batch')
      })
      expect(result.current).toBe('second-batch')
    })

    it('진행 중 새 업로드 시 기존 배치 재사용 시나리오', () => {
      // AR 업로드 시작
      act(() => {
        setBatchId('batch-ar')
      })
      expect(getBatchId()).toBe('batch-ar')
      const timeAfterAr = getLastBatchSetTime()

      // CRS 업로드 시작 (기존 배치 재사용)
      const existingBatchId = getBatchId()
      expect(existingBatchId).toBe('batch-ar')

      act(() => {
        setBatchId(existingBatchId!)
      })
      // batchId 동일하게 유지
      expect(getBatchId()).toBe('batch-ar')
      // lastSetTime은 갱신됨
      expect(getLastBatchSetTime()).toBeGreaterThanOrEqual(timeAfterAr)
    })
  })

  describe('getLastBatchSetTime', () => {
    it('setBatchId 호출 전에는 이전 호출 시각 또는 0을 반환', () => {
      // 모듈 레벨 변수이므로 다른 테스트에서 이미 설정되었을 수 있음
      expect(typeof getLastBatchSetTime()).toBe('number')
    })

    it('setBatchId 호출 후 현재 시각 이상의 값을 반환해야 함', () => {
      const before = Date.now()
      setBatchId('timing-test')
      const after = Date.now()

      const lastSetTime = getLastBatchSetTime()
      expect(lastSetTime).toBeGreaterThanOrEqual(before)
      expect(lastSetTime).toBeLessThanOrEqual(after)
    })

    it('연속 setBatchId 호출 시 마지막 호출 시각을 반환해야 함', () => {
      setBatchId('first')
      const firstTime = getLastBatchSetTime()

      setBatchId('second')
      const secondTime = getLastBatchSetTime()

      expect(secondTime).toBeGreaterThanOrEqual(firstTime)
    })

    it('clearBatchId는 lastSetTime에 영향을 주지 않아야 함', () => {
      setBatchId('before-clear')
      const timeBeforeClear = getLastBatchSetTime()

      clearBatchId()

      expect(getLastBatchSetTime()).toBe(timeBeforeClear)
    })

    it('cleanup 타이머 경쟁 조건 가드: 타이머 시작 후 setBatchId → snapshotTime 비교로 감지', () => {
      // 시나리오: 배치 100% 완료 → 타이머 시작 → 새 업로드 시작(기존 batchId 재사용)
      setBatchId('batch-complete')
      const snapshotTime = Date.now() // 타이머 시작 시각

      // 새 업로드 시작 (기존 batchId 재사용 — setBatchId 다시 호출)
      setBatchId('batch-complete')
      const lastSetAfterReuse = getLastBatchSetTime()

      // 가드 조건: getLastBatchSetTime() > snapshotTime
      // → lastSetTime이 snapshotTime 이후이므로 clearBatchId 차단
      expect(lastSetAfterReuse).toBeGreaterThanOrEqual(snapshotTime)
    })
  })
})

/**
 * useCustomerDocument Hook 테스트
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { renderHook, waitFor, act } from '@testing-library/react';
import { useCustomerDocument } from '../useCustomerDocument';
import { CustomerDocument } from '@/stores/CustomerDocument';
import type { Customer } from '@/entities/customer';

// Mock CustomerDocument
vi.mock('@/stores/CustomerDocument', () => {
  const mockSubscribers: Array<() => void> = [];
  let mockCustomers: Customer[] = [];
  let mockTotal = 0;
  let mockHasMore = false;
  let mockIsLoading = false;
  let mockError: string | null = null;
  let mockLastUpdated = 0;

  // Create persistent mock functions
  const loadCustomersFn = vi.fn();
  const createCustomerFn = vi.fn();
  const updateCustomerFn = vi.fn();
  const deleteCustomerFn = vi.fn();
  const refreshFn = vi.fn();
  const resetFn = vi.fn();
  const debugFn = vi.fn();
  const subscribeFn = vi.fn();

  const mockInstance = {
    // Getters
    getCustomers: vi.fn(() => mockCustomers),
    getTotal: vi.fn(() => mockTotal),
    getHasMore: vi.fn(() => mockHasMore),
    getIsLoading: vi.fn(() => mockIsLoading),
    getError: vi.fn(() => mockError),
    getLastUpdated: vi.fn(() => mockLastUpdated),
    getCustomerById: vi.fn((id: string) => mockCustomers.find(c => c._id === id)),

    // Subscribe/Unsubscribe
    subscribe: subscribeFn.mockImplementation((callback: () => void) => {
      mockSubscribers.push(callback);
      return () => {
        const index = mockSubscribers.indexOf(callback);
        if (index > -1) mockSubscribers.splice(index, 1);
      };
    }),

    // CRUD Methods
    loadCustomers: loadCustomersFn.mockImplementation(async () => {
          mockIsLoading = true;
          mockSubscribers.forEach(cb => cb());

          // Simulate async operation
          await new Promise(resolve => setTimeout(resolve, 10));

          mockCustomers = [
            {
              _id: '1',
              personal_info: { name: '홍길동', birth_date: '1990-01-01', gender: 'M' },
              insurance_info: { customer_type: '개인' },
              contracts: [],
              documents: [],
              consultations: [],
              meta: {
                created_at: '2025-01-01T00:00:00.000Z',
                updated_at: '2025-01-01T00:00:00.000Z',
                status: 'active',
              },
              tags: [],
            },
          ] as Customer[];
          mockTotal = 1;
          mockHasMore = false;
          mockIsLoading = false;
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
        }),

    createCustomer: createCustomerFn.mockImplementation(async data => {
          const newCustomer: Customer = {
            _id: 'new-customer-id',
            personal_info: data.personal_info,
            insurance_info: data.insurance_info || { customer_type: '개인' },
            contracts: data.contracts || [],
            documents: data.documents || [],
            consultations: data.consultations || [],
            meta: {
              created_at: new Date().toISOString(),
              updated_at: new Date().toISOString(),
              status: 'active',
            },
            tags: [],
          };
          mockCustomers = [...mockCustomers, newCustomer];
          mockTotal += 1;
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
          return newCustomer;
        }),

    updateCustomer: updateCustomerFn.mockImplementation(async (id: string, data) => {
          const index = mockCustomers.findIndex(c => c._id === id);
          if (index === -1) {
            mockError = '고객을 찾을 수 없습니다';
            mockSubscribers.forEach(cb => cb());
            throw new Error(mockError);
          }

          const existingCustomer = mockCustomers[index];
          if (!existingCustomer) {
            mockError = '고객을 찾을 수 없습니다';
            mockSubscribers.forEach(cb => cb());
            throw new Error(mockError);
          }

          const updatedCustomer: Customer = {
            ...existingCustomer,
            personal_info: { ...existingCustomer.personal_info, ...data.personal_info },
            meta: {
              ...existingCustomer.meta,
              updated_at: new Date().toISOString(),
            },
          };
          mockCustomers = [
            ...mockCustomers.slice(0, index),
            updatedCustomer,
            ...mockCustomers.slice(index + 1),
          ];
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
          return updatedCustomer;
        }),

    deleteCustomer: deleteCustomerFn.mockImplementation(async (id: string) => {
          const index = mockCustomers.findIndex(c => c._id === id);
          if (index === -1) {
            mockError = '고객을 찾을 수 없습니다';
            mockSubscribers.forEach(cb => cb());
            throw new Error(mockError);
          }

          mockCustomers = mockCustomers.filter(c => c._id !== id);
          mockTotal -= 1;
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
        }),

    refresh: refreshFn.mockImplementation(async () => {
          mockIsLoading = true;
          mockSubscribers.forEach(cb => cb());

          await new Promise(resolve => setTimeout(resolve, 10));

          // Refresh reloads the same data
          mockIsLoading = false;
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
        }),

    reset: resetFn.mockImplementation(() => {
          mockCustomers = [];
          mockTotal = 0;
          mockHasMore = false;
          mockIsLoading = false;
          mockError = null;
          mockLastUpdated = Date.now();
          mockSubscribers.forEach(cb => cb());
        }),

    debug: debugFn.mockImplementation(() => {
      console.log('Debug called');
    }),

    // Helper for tests to manually trigger state changes
    __triggerStateChange: () => {
      mockSubscribers.forEach(cb => cb());
    },
    __setError: (error: string | null) => {
      mockError = error;
      mockSubscribers.forEach(cb => cb());
    },
  };

  return {
    CustomerDocument: {
      getInstance: vi.fn(() => mockInstance),
    },
  };
});

