  tags: [],
  ...overrides,
})

const mockCustomer1 = createMockCustomer()
const mockCustomer2 = createMockCustomer({
  _id: 'cust-002',
  personal_info: {
    name: '김영희',
    mobile_phone: '010-9876-5432',
