      await waitFor(() => {
        expect(
          vi.mocked(DocumentStatusService.DocumentStatusService.getRecentDocuments).mock.calls.length
        ).toBeGreaterThan(initialCallCount)
      })
    })
  })
})

/**
 * AIMS UIX-3 Document Service Layer
 * @since 2025-09-30
 * @version 1.1.0
 *
 * 문서 관련 비즈니스 로직 및 API 호출을 담당하는 서비스 레이어
 * ARCHITECTURE.md의 Service Layer 패턴을 따름
 * 바이러스 검사 통합 (ClamAV)
 */

import { api, getAuthToken, getCurrentUserId } from '@/shared/lib/api';
import { utcNowISO } from '@/shared/lib/timeUtils';
import { scanFile, isScanAvailable } from '@/shared/lib/fileValidation/virusScanApi';
import { checkSystemDuplicate } from '@/shared/lib/fileValidation/duplicateChecker';
import {
  Document,
  CreateDocumentData,
  UpdateDocumentData,
  DocumentSearchQuery,
  DocumentSearchResponse,
  DocumentUtils,
} from '@/entities/document';

/**
 * 문서 API 엔드포인트
 */
const ENDPOINTS = {
  DOCUMENTS: '/api/documents',
  DOCUMENT: (id: string) => `/api/documents/${id}`,
  DOCUMENT_SEARCH: '/api/documents/search',

  DOCUMENT_STATS: '/api/documents/stats',
  DOCUMENT_STATISTICS: '/api/documents/statistics',
  DOCUMENT_UPLOAD: '/api/documents/upload',
  DOCUMENT_DOWNLOAD: (id: string) => `/api/documents/${id}/download`,
  CUSTOMER_DOCUMENTS: (customerId: string) => `/api/customers/${customerId}/documents`,
  CUSTOMER_DOCUMENT: (customerId: string, documentId: string) =>
    `/api/customers/${customerId}/documents/${documentId}`,
} as const;

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null

const toString = (value: unknown): string | undefined =>
  typeof value === 'string' ? value : undefined

const toNumber = (value: unknown): number | undefined => {
  if (typeof value === 'number') {
    return Number.isFinite(value) ? value : undefined
  }
  if (typeof value === 'string') {
    const parsed = Number(value)
    return Number.isFinite(parsed) ? parsed : undefined
  }
  return undefined
}

/**
 * 문서 처리 단계 정보
 */
export interface DocumentStages {
  ocr?: {
    status?: string;
    message?: string;
    started_at?: string;
    completed_at?: string;
  };
  embedding?: {
    status?: string;
    message?: string;
  };
  [key: string]: unknown;
}

/**
 * 고객 문서 연결 정보
 */
export interface CustomerDocumentItem {
  _id: string;
  originalName?: string;
  displayName?: string;  // CR 등 파싱 후 생성된 사용자 친화적 이름
  uploadedAt?: string;
  fileSize?: number;
  mimeType?: string;
  relationship?: string;
  notes?: string;
  linkedAt?: string;
  status?: string;
  progress?: number;
  isAnnualReport?: boolean;
  ocrConfidence?: number | string;
  stages?: DocumentStages;
  badgeType?: 'TXT' | 'OCR' | 'BIN';  // 🔥 백엔드에서 계산된 뱃지 타입
  ar_metadata?: {
    issue_date?: string;
    customer_name?: string;
    fsr_name?: string | null;
    report_title?: string;
  };
  // PDF 변환 상태 필드
  conversionStatus?: 'pending' | 'processing' | 'completed' | 'failed' | 'not_required' | null;
  isConvertible?: boolean;
  // 문서 유형 필드
  document_type?: string;
  document_type_auto?: boolean;
  document_type_confidence?: number;
  // Annual Report 분석 상태
  ar_parsing_status?: 'pending' | 'processing' | 'completed' | 'failed';
  // 문서 소유 고객 ID (원본/링크 구분용)
  customerId?: string;
  // 관계자 연결 고객 ID (AR/CRS에서 피보험자로 감지된 고객)
  relatedCustomerId?: string;
}

export interface CustomerDocumentsResult {
  customer_id: string;
  customer_name?: string;
  documents: CustomerDocumentItem[];
  total: number;
}

export interface DocumentCustomerLinkPayload {
  document_id: string;
  relationship_type: string;
  notes?: string;
  assigned_by?: string | null;
}

/**
 * 문서 서비스 클래스
 * 모든 문서 관련 비즈니스 로직과 API 호출을 중앙화
 */
export class DocumentService {
  /**
   * 문서 목록 조회
   */
  static async getDocuments(
    query: Partial<DocumentSearchQuery> = {}
  ): Promise<DocumentSearchResponse> {
    // 백엔드 페이지네이션 파라미터 구성
    const params = new URLSearchParams();
    if (query.limit) params.append('limit', String(query.limit));
    if (query.offset !== undefined) params.append('offset', String(query.offset));

    // 검색어 파라미터 추가 (백엔드 검색 기능 사용)
    if (query.q) params.append('search', query.q);

    // 백엔드는 'sort' 파라미터를 조합 형식으로 받음
    // 예: 'uploadTime_desc', 'filename_asc', 'size_desc', 'fileType_asc'
    if (query.sortBy && query.sortOrder) {
      const sortByMap: Record<string, string> = {
        'time': 'uploadTime',
        'name': 'filename',
        'size': 'size',
        'uploadDate': 'uploadTime',
        'filename': 'filename',
        'createdAt': 'uploadTime',
        'updatedAt': 'uploadTime',
        'fileType': 'fileType',  // 파일 형식 정렬 추가
      };
      const backendSortBy = sortByMap[query.sortBy] || 'uploadTime';
      const sortValue = `${backendSortBy}_${query.sortOrder}`;
      params.append('sort', sortValue);
    }

    const url = params.toString() ? `${ENDPOINTS.DOCUMENTS}?${params.toString()}` : ENDPOINTS.DOCUMENTS;
    const response = await api.get<unknown>(url);

    const extractDocuments = (input: unknown): {
      documents: Record<string, unknown>[];
      pagination?: Record<string, unknown>;
    } => {
      if (!isRecord(input)) {
        return { documents: [] };
      }

      const dataRecord = isRecord(input['data']) ? (input['data'] as Record<string, unknown>) : undefined;
      const dataDocs = dataRecord?.['documents'];
      const rootDocs = input['documents'];

      const documentsSource = Array.isArray(dataDocs)
        ? dataDocs
        : Array.isArray(rootDocs)
          ? rootDocs
          : [];

      const documents = documentsSource.filter((doc): doc is Record<string, unknown> => isRecord(doc));

      const pagination =
        (dataRecord && isRecord(dataRecord['pagination'])
          ? (dataRecord['pagination'] as Record<string, unknown>)
          : isRecord(input['pagination'])
            ? (input['pagination'] as Record<string, unknown>)
            : undefined);

      if (pagination) {
        return { documents, pagination };
      }

      return { documents };
    };

    const { documents: rawDocuments, pagination } = extractDocuments(response);

    const documents: Document[] = rawDocuments.map((doc) => {
      const record = doc as Record<string, unknown>;
      // 🔒 보안: crypto.randomUUID 사용 (Math.random은 예측 가능)
      const generatedId = `temp-${Date.now()}-${crypto.randomUUID().slice(0, 8)}`;

      const id =
        toString(record['_id']) ??
        toString(record['id']) ??
        generatedId;

      const filename = toString(record['filename']) ?? '이름 없는 문서';
      const originalName = toString(record['originalName']) ?? filename;
      const mimeType = toString(record['mimeType']);
      const uploadTimeRaw =
        toString(record['uploadTime']) ??
        toString(record['uploaded_at']) ??
        utcNowISO();
      const uploadDate = uploadTimeRaw.includes('xxx')
        ? uploadTimeRaw.replace('xxx', '000Z')
        : uploadTimeRaw;
      const fileSize = toNumber(record['fileSize']);

      const rawStatus = toString(record['status']);
      const status: Document['status'] =
        rawStatus === 'archived' || rawStatus === 'deleted' ? rawStatus : 'active';

      const rawOcrStatus = toString(record['ocrStatus']);
      const ocrStatus: Document['ocrStatus'] =
        rawOcrStatus === 'processing' || rawOcrStatus === 'completed' || rawOcrStatus === 'failed'
          ? rawOcrStatus
          : 'pending';

      const document: Document = {
        _id: id,
        filename,
        originalName,
        uploadDate,
        status,
        ocrStatus,
        createdAt: uploadDate,
        updatedAt: uploadDate,
        tags: []
      };

      if (mimeType) {
        document.mimeType = mimeType;
      }

      if (typeof fileSize === 'number') {
        document.size = fileSize;
      }

      // Annual Report 정보 추가
      if (typeof record['is_annual_report'] === 'boolean') {
        document.is_annual_report = record['is_annual_report'];
      }

      return document;
    });

    const total = toNumber(pagination ? pagination['totalCount'] : undefined) ?? documents.length;
    const hasMore = Boolean(pagination ? pagination['hasNext'] : undefined);
    return {
      documents,
      total,
      hasMore,
      offset: query.offset || 0,
      limit: query.limit || 10
    };
  }

  /**
   * 문서 상세 조회
   */
  static async getDocument(id: string): Promise<Document> {
    if (!id.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    const response = await api.get<unknown>(ENDPOINTS.DOCUMENT(id));

    // 응답 검증
    return DocumentUtils.validate(response);
  }

  /**
   * 문서 생성
   */
  static async createDocument(data: CreateDocumentData): Promise<Document> {
    // 입력 데이터 검증
    const validatedData = DocumentUtils.validateCreateData(data);

    const response = await api.post<unknown>(ENDPOINTS.DOCUMENTS, validatedData);

    // 응답 검증
    return DocumentUtils.validate(response);
  }

  /**
   * 문서 정보 수정
   */
  static async updateDocument(
    id: string,
    data: UpdateDocumentData
  ): Promise<Document> {
    if (!id.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    // 입력 데이터 검증
    const validatedData = DocumentUtils.validateUpdateData(data);

    const response = await api.put<unknown>(ENDPOINTS.DOCUMENT(id), validatedData);

    // 응답 검증
    return DocumentUtils.validate(response);
  }

  /**
   * 문서 삭제 (소프트 삭제)
   */
  static async deleteDocument(id: string): Promise<void> {
    if (!id.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    // 실제로는 status를 'deleted'로 변경
    await DocumentService.updateDocument(id, { status: 'deleted' });
  }

  /**
   * 문서 검색 (텍스트 검색)
   */
  static async searchDocuments(
    searchTerm: string,
    options: Partial<DocumentSearchQuery> = {}
  ): Promise<DocumentSearchResponse> {
    if (!searchTerm.trim()) {
      // 빈 검색어인 경우 전체 목록 반환
      return DocumentService.getDocuments(options);
    }

    const validatedOptions = DocumentUtils.validateSearchQuery(options);
    const query: DocumentSearchQuery = {
      ...validatedOptions,
      q: searchTerm.trim(),
    };

    return DocumentService.getDocuments(query);
  }

  /**
   * 고객별 문서 조회
   */
  static async getDocumentsByCustomer(
    customerId: string,
    options: Partial<DocumentSearchQuery> = {}
  ): Promise<DocumentSearchResponse> {
    if (!customerId.trim()) {
      throw new Error('고객 ID가 필요합니다');
    }

    const validatedOptions = DocumentUtils.validateSearchQuery(options);
    const query: DocumentSearchQuery = {
      ...validatedOptions,
      customerId: customerId.trim(),
    };

    return DocumentService.getDocuments(query);
  }

  /**
   * 특정 고객과 연결된 문서 목록 조회
   */
  static async getCustomerDocuments(customerId: string, options?: { includeRelated?: boolean }): Promise<CustomerDocumentsResult> {
    if (!customerId.trim()) {
      throw new Error('고객 ID가 필요합니다');
    }

    const url = options?.includeRelated
      ? `${ENDPOINTS.CUSTOMER_DOCUMENTS(customerId)}?includeRelated=true`
      : ENDPOINTS.CUSTOMER_DOCUMENTS(customerId);
    const response = await api.get<unknown>(url);

    const collectDocuments = (value: unknown): CustomerDocumentItem[] => {
      if (!Array.isArray(value)) {
        return [];
      }

      return value
        .map((item): CustomerDocumentItem | null => {
          if (!isRecord(item)) {
            return null;
          }

          const id = toString(item['_id']) ?? toString(item['id']);
          if (!id) {
            return null;
          }

          const originalName = toString(item['originalName']) ?? toString(item['filename']);
          const displayName = toString(item['displayName']);  // 🍎 CR 파싱 후 생성된 사용자 친화적 이름
          const uploadedAt = toString(item['uploadedAt']) ?? toString(item['linkedAt']);
          const fileSize = toNumber(item['fileSize']);
          const mimeType = toString(item['mimeType']);
          const relationship = toString(item['relationship']);
          const notes = toString(item['notes']);
          const linkedAt = toString(item['linkedAt']);
          const status = toString(item['status']) ?? undefined;
          const progress = toNumber(item['progress']);

          // Annual Report 판단: relationship === "annual_report"
          const isAnnualReport = relationship === 'annual_report';

          // stages 필드 추출 (DocumentUtils.getDocumentType이 사용)
          const stages = isRecord(item['stages']) ? item['stages'] : undefined;

          // OCR 신뢰도 추출: stages.ocr.message에서 파싱
          let ocrConfidence: number | undefined;
          if (stages && isRecord(stages['ocr'])) {
            const ocrStage = stages['ocr'] as Record<string, unknown>;
            const ocrMessage = toString(ocrStage['message']);
            if (ocrMessage) {
              // "OCR 완료 (신뢰도: 0.9817)" 형식에서 숫자 추출
              const match = ocrMessage.match(/신뢰도:\s*([\d.]+)/);
              if (match && match[1]) {
                const parsed = parseFloat(match[1]);
                if (!isNaN(parsed)) {
                  ocrConfidence = parsed;
                }
              }
            }
          }

          // badgeType 추출
          const badgeType = toString(item['badgeType']) as 'TXT' | 'OCR' | 'BIN' | undefined;

          // 🍎 PDF 변환 관련 필드 추출 (git 748bb43e 참조)
          const conversionStatus = toString(item['conversionStatus']) as CustomerDocumentItem['conversionStatus'];
          const isConvertible = item['isConvertible'] === true;

          const result: CustomerDocumentItem = {
            _id: id
          };

          if (originalName) result.originalName = originalName;
          if (displayName) result.displayName = displayName;  // 🍎 CR 파싱 후 생성된 사용자 친화적 이름
          if (uploadedAt) result.uploadedAt = uploadedAt;
          if (typeof fileSize === 'number') result.fileSize = fileSize;
          if (mimeType) result.mimeType = mimeType;
          if (relationship) result.relationship = relationship;
          if (notes) result.notes = notes;
          if (linkedAt) result.linkedAt = linkedAt;
          if (status) result.status = status;
          if (typeof progress === 'number') result.progress = progress;
          if (isAnnualReport) result.isAnnualReport = true;
          if (typeof ocrConfidence === 'number') result.ocrConfidence = ocrConfidence;
          if (stages) result.stages = stages as any;
          if (badgeType) result.badgeType = badgeType;  // 🔥 백엔드 badgeType 추가
          if (conversionStatus) result.conversionStatus = conversionStatus;  // 🍎 PDF 변환 상태
          if (isConvertible) result.isConvertible = isConvertible;  // 🍎 PDF 변환 대상 여부

          // 🍎 문서 유형 필드 추출 (CustomerFullDetailView 문서 카드에서 사용)
          const documentType = toString(item['document_type']);
          const documentTypeAuto = item['document_type_auto'] === true;
          const documentTypeConfidence = toNumber(item['document_type_confidence']);
          if (documentType) result.document_type = documentType;
          if (documentTypeAuto) result.document_type_auto = documentTypeAuto;
          if (typeof documentTypeConfidence === 'number') result.document_type_confidence = documentTypeConfidence;

          // 🍎 Annual Report 분석 상태 추출
          const arParsingStatus = toString(item['ar_parsing_status']) as CustomerDocumentItem['ar_parsing_status'];
          if (arParsingStatus) result.ar_parsing_status = arParsingStatus;

          // 문서 소유 고객 ID (원본/링크 구분용)
          const docCustomerId = toString(item['customerId']);
          if (docCustomerId) result.customerId = docCustomerId;

          // 관계자 연결 고객 ID
          const docRelatedCustomerId = toString(item['relatedCustomerId']);
          if (docRelatedCustomerId) result.relatedCustomerId = docRelatedCustomerId;

          return result;
        })
        .filter((item): item is CustomerDocumentItem => item !== null);
    };

    const responseRecord = isRecord(response) ? response : null;
    const dataRecord = responseRecord && isRecord(responseRecord['data'])
      ? (responseRecord['data'] as Record<string, unknown>)
      : undefined;
    const topLevelDocuments = responseRecord ? responseRecord['documents'] : undefined;
    const documents = collectDocuments(
      (dataRecord ? dataRecord['documents'] : undefined) ?? topLevelDocuments
    );

    const total =
      toNumber((dataRecord ? dataRecord['total'] : undefined) ?? (responseRecord ? responseRecord['total'] : undefined)) ??
      documents.length;

    const derivedCustomerId =
      toString(dataRecord ? dataRecord['customer_id'] : undefined) ??
      toString(responseRecord ? responseRecord['customer_id'] : undefined) ??
      customerId;

    return {
      customer_id: derivedCustomerId,
      documents,
      total,
    };
  }

  /**
   * 문서를 고객에게 연결
   */
  static async linkDocumentToCustomer(
    customerId: string,
    payload: DocumentCustomerLinkPayload
  ): Promise<void> {
    if (!customerId.trim()) {
      throw new Error('고객 ID가 필요합니다');
    }

    if (!payload.document_id?.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    await api.post(ENDPOINTS.CUSTOMER_DOCUMENTS(customerId), payload);
  }

  /**
   * 고객과 문서 연결 해제
   */
  static async unlinkDocumentFromCustomer(customerId: string, documentId: string): Promise<void> {
    if (!customerId.trim()) {
      throw new Error('고객 ID가 필요합니다');
    }

    if (!documentId.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    await api.delete(ENDPOINTS.CUSTOMER_DOCUMENT(customerId, documentId));
  }

  /**
   * 고객 문서 메모 수정
   */
  static async updateDocumentNotes(
    customerId: string,
    documentId: string,
    notes: string
  ): Promise<void> {
    if (!customerId.trim()) {
      throw new Error('고객 ID가 필요합니다');
    }

    if (!documentId.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    await api.patch(ENDPOINTS.CUSTOMER_DOCUMENT(customerId, documentId), { notes });
  }

  /**
   * 문서 통계 조회
   */
  static async getDocumentStats(): Promise<DocumentStats> {
    const response = await api.get<DocumentStats>(ENDPOINTS.DOCUMENT_STATS);

    // 기본 구조 검증
    if (!response || typeof response !== 'object') {
      throw new Error('Invalid stats response format');
    }

    return {
      total: Number(response.total) || 0,
      active: Number(response.active) || 0,
      archived: Number(response.archived) || 0,
      deleted: Number(response.deleted) || 0,
      totalSize: Number(response.totalSize) || 0,
      ocrCompleted: Number(response.ocrCompleted) || 0,
      ocrPending: Number(response.ocrPending) || 0,
    };
  }

  /**
   * 문서 처리 통계 조회 (백엔드 /api/documents/statistics)
   * 문서 처리 상태별 통계를 반환
   */
  static async getDocumentStatistics(): Promise<DocumentStatistics> {
    // 현재 사용자 ID 가져오기 (dev override 우선)
    const userId = getCurrentUserId() || 'tester';

    const response = await api.get<{ success: boolean; data: DocumentStatistics }>(
      ENDPOINTS.DOCUMENT_STATISTICS,
      {
        headers: {
          'x-user-id': userId
        }
      }
    );

    // 응답 구조 검증
    if (!response || !response.data || typeof response.data !== 'object') {
      throw new Error('Invalid statistics response format');
    }

    const stats = response.data;

    return {
      total: Number(stats.total) || 0,
      completed: Number(stats.completed) || 0,
      processing: Number(stats.processing) || 0,
      error: Number(stats.error) || 0,
      pending: Number(stats.pending) || 0,
      completed_with_skip: Number(stats.completed_with_skip) || 0,
      stages: {
        upload: Number(stats.stages?.upload) || 0,
        meta: Number(stats.stages?.meta) || 0,
        ocr_prep: Number(stats.stages?.ocr_prep) || 0,
        ocr: Number(stats.stages?.ocr) || 0,
        docembed: Number(stats.stages?.docembed) || 0,
      },
      badgeTypes: {
        TXT: Number(stats.badgeTypes?.TXT) || 0,
        OCR: Number(stats.badgeTypes?.OCR) || 0,
        BIN: Number(stats.badgeTypes?.BIN) || 0,
      },
      fileTypeDistribution: Array.isArray(stats.fileTypeDistribution) ? stats.fileTypeDistribution : [],
    };
  }

  /**
   * 문서 업로드 (중복 체크 + 바이러스 검사 포함, n8n webhook 사용)
   * 새문서 등록(uploadService)과 동일한 방식으로 업로드
   */
  static async uploadDocument(file: File, metadata?: Partial<CreateDocumentData>): Promise<UploadDocumentResult> {
    if (!file) {
      throw new Error('파일이 필요합니다');
    }

    // 🔴 해당 고객에게 파일 해시 중복 검사 (E11000 에러 방지)
    console.log(`[DocumentService] 🔍 중복 검사 중: ${file.name}`);
    const duplicateResult = await checkSystemDuplicate(file, metadata?.customerId);
    if (duplicateResult.isDuplicate && duplicateResult.existingDocument) {
      const existing = duplicateResult.existingDocument;
      const errorMessage = existing.customerName
        ? `이미 등록된 파일입니다. (고객: ${existing.customerName}, 파일: ${existing.fileName})`
        : `이미 등록된 파일입니다. (파일: ${existing.fileName})`;
      console.warn(`[DocumentService] ⚠️ 중복 파일 감지: ${file.name}`);
      throw new Error(errorMessage);
    }
    console.log(`[DocumentService] ✅ 중복 검사 통과: ${file.name}`);

    // 🛡️ 바이러스 검사 (ClamAV 활성화된 경우만)
    const scanAvailable = await isScanAvailable();
    if (scanAvailable) {
      console.log(`[DocumentService] 🔍 바이러스 검사 중: ${file.name}`);
      const scanResult = await scanFile(file);

      if (scanResult.infected) {
        // 바이러스 감지됨 - 업로드 차단
        const errorMessage = `🛡️ 바이러스 감지: ${scanResult.virusName || '알 수 없는 위협'}`;
        console.warn(`[DocumentService] ⚠️ ${errorMessage} - 파일: ${file.name}`);
        throw new Error(errorMessage);
      }

      if (scanResult.scanned) {
        console.log(`[DocumentService] ✅ 바이러스 검사 통과: ${file.name}`);
      }
    }

    // userId 가져오기 (dev override 우선)
    const userId = getCurrentUserId() || 'tester';

    const formData = new FormData();
    formData.append('file', file);
    formData.append('userId', userId);

    // 메타데이터가 있으면 추가
    if (metadata) {
      Object.entries(metadata).forEach(([key, value]) => {
        if (value !== undefined) {
          if (Array.isArray(value)) {
            formData.append(key, JSON.stringify(value));
          } else {
            formData.append(key, String(value));
          }
        }
      });
    }

    // Shadow Mode 경유 업로드 (n8n + FastAPI 병렬 비교, n8n 응답 반환)
    // 상대 경로 사용: 개발환경에서는 Vite 프록시, 프로덕션에서는 직접 접근
    const UPLOAD_URL = '/shadow/docprep-main';

    console.log(`[DocumentService] 📤 업로드 시작: ${file.name} (userId: ${userId})`);

    // 🔒 보안: getAuthToken()으로 토큰 통합 관리 (v1/v2 호환)
    const token = getAuthToken();

    // XMLHttpRequest 사용 (새문서 등록과 동일하게)
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();

      xhr.addEventListener('load', () => {
        try {
          const result = xhr.responseText ? JSON.parse(xhr.responseText) : {};

          if (xhr.status >= 200 && xhr.status < 300) {
            console.log(`[DocumentService] ✅ 업로드 성공: ${file.name}`, result);

            resolve({
              success: true,
              document: {
                _id: result.doc_id || result.id || result._id || '',
                filename: file.name,
                originalName: file.name,
                uploadDate: new Date().toISOString(),
                status: 'active',
                ocrStatus: 'pending',
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
                tags: []
              }
            });
          } else if (xhr.status === 415) {
            // 지원하지 않는 파일 형식 (경고로 처리)
            console.warn(`[DocumentService] ⚠️ 지원하지 않는 파일 형식: ${file.name}`);
            resolve({
              success: true,
              document: {
                _id: '',
                filename: file.name,
                originalName: file.name,
                uploadDate: new Date().toISOString(),
                status: 'active',
                ocrStatus: 'pending',
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
                tags: []
              },
              error: result.userMessage || '지원하지 않는 파일 형식입니다'
            });
          } else {
            reject(new Error(`업로드 실패: HTTP ${xhr.status}`));
          }
        } catch {
          if (xhr.status >= 200 && xhr.status < 300) {
            // JSON 파싱 실패해도 HTTP 성공이면 OK
            resolve({
              success: true,
              document: {
                _id: '',
                filename: file.name,
                originalName: file.name,
                uploadDate: new Date().toISOString(),
                status: 'active',
                ocrStatus: 'pending',
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
                tags: []
              }
            });
          } else {
            reject(new Error(`업로드 실패: HTTP ${xhr.status}`));
          }
        }
      });

      xhr.addEventListener('error', () => {
        reject(new Error('네트워크 오류가 발생했습니다'));
      });

      xhr.addEventListener('timeout', () => {
        reject(new Error('업로드 시간이 초과되었습니다'));
      });

      xhr.open('POST', UPLOAD_URL);
      xhr.timeout = 5 * 60 * 1000; // 5분 타임아웃

      // JWT 인증 헤더 추가 (uploadService와 동일)
      if (token) {
        xhr.setRequestHeader('Authorization', `Bearer ${token}`);
      }

      xhr.send(formData);
    });
  }

  /**
   * 문서 다운로드
   */
  static async downloadDocument(id: string): Promise<Blob> {
    if (!id.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    const response = await api.get<Blob>(ENDPOINTS.DOCUMENT_DOWNLOAD(id));

    return response;
  }

  /**
   * 문서 일괄 삭제 (하드 삭제 - DB + 물리적 파일)
   */
  static async deleteDocuments(ids: string[]): Promise<DeleteDocumentsResult> {
    if (ids.length === 0) {
      throw new Error('삭제할 문서 ID가 필요합니다');
    }

    // 🔒 보안: getAuthToken()으로 토큰 통합 관리 (v1/v2 호환)
    const token = getAuthToken();

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    // JWT 토큰이 있으면 Authorization 헤더 추가
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    // DELETE 요청은 body를 직접 전달
    const response = await fetch(`/api/documents`, {
      method: 'DELETE',
      headers,
      body: JSON.stringify({ document_ids: ids })
    });

    if (!response.ok) {
      throw new Error(`삭제 실패: ${response.statusText}`);
    }

    const data: DeleteDocumentsResponse = await response.json();

    return {
      success: data.success,
      message: data.message,
      deletedCount: data.deleted_count,
      failedCount: data.failed_count,
      errors: data.errors || []
    };
  }

  /**
   * 개발 환경 전용: 문서 삭제 (고객 필터 지원)
   * @param customerId 특정 고객의 문서만 삭제 (생략 시 전체 삭제)
   */
  static async deleteAllDocuments(customerId?: string): Promise<{ deletedCount: number }> {
    const url = customerId
      ? `/api/dev/documents/all?customerId=${encodeURIComponent(customerId)}`
      : '/api/dev/documents/all';
    const response = await api.delete<{ success: boolean; deletedCount: number }>(url);
    return { deletedCount: response.deletedCount };
  }

  /**
   * 문서 보관 처리
   */
  static async archiveDocument(id: string): Promise<Document> {
    if (!id.trim()) {
      throw new Error('문서 ID가 필요합니다');
    }

    return DocumentService.updateDocument(id, { status: 'archived' });
  }

  /**
   * 문서 일괄 보관
   */
  static async archiveDocuments(ids: string[]): Promise<Document[]> {
    if (ids.length === 0) {
      throw new Error('보관할 문서 ID가 필요합니다');
    }

    // 병렬로 보관 처리
    return Promise.all(ids.map(id => DocumentService.archiveDocument(id)));
  }
}

