      isDuplicate: true,
      existingDocument: {
        documentId: 'existing-doc-id',
        fileName: '미분류파일.pdf',
        customerId: null,
        customerName: null,
        uploadedAt: null,
      },
      fileHash: 'def456',
    });

    const testFile = new File(['test'], '미분류파일.pdf', { type: 'application/pdf' });

    // When & Then
