            address1: '서울시 강남구 테헤란로 123',
            address2: '456호',
          },
          changed_at: '2025-01-15T10:30:00.000Z',
          changed_by: 'admin',
        },
        {
          address: {
            postal_code: '06123',
            address1: '서울시 서초구 반포대로 456',
          },
          changed_at: '2024-12-01T09:00:00.000Z',
          changed_by: 'system',
