}

/**
 * RightClickGuide Component
 *
 * 첫 방문 사용자에게 마우스 우클릭 기능을 안내하는 가이드
 * 컨텍스트별로 다른 메뉴가 표시됨을 시각적으로 안내
 */

import React, { useState, useEffect, useCallback } from 'react'
import { createPortal } from 'react-dom'
import Button from '@/shared/ui/Button'
import { hasCompletedOnboarding } from '../OnboardingTour'
import './RightClickGuide.css'

const STORAGE_KEY = 'aims_rightclick_guide_shown'

interface RightClickGuideProps {
  /** 강제로 가이드 표시 (개발용) */
  forceShow?: boolean
  /** 가이드 닫힘 콜백 */
  onClose?: () => void
}

/**
 * 컨텍스트별 우클릭 메뉴 정보
 */
const CONTEXT_MENUS = [
  {
    id: 'customer',
    title: '고객 목록',
    icon: '👤',
    color: '#007AFF',
    items: ['상세 보기', '전화하기', '문자 보내기', '휴면 전환', '삭제']
  },
  {
    id: 'document',
    title: '문서',
    icon: '📄',
    color: '#34C759',
    items: ['미리보기', 'AI 요약', '다운로드', '삭제']
  },
  {
    id: 'files',
    title: '내 보관함',
    icon: '📁',
    color: '#FF9500',
    items: ['이름 변경', '이동', '새 폴더', '삭제']
  },
  {
    id: 'chat',
    title: 'AI 채팅',
    icon: '💬',
    color: '#AF52DE',
    items: ['메시지 복사']
  }
]

export const RightClickGuide: React.FC<RightClickGuideProps> = ({
  forceShow = false,
  onClose
}) => {
  const [isVisible, setIsVisible] = useState(false)
  const [activeContext, setActiveContext] = useState(0)

  useEffect(() => {
    if (forceShow) {
      setIsVisible(true)
      return
    }

    // 이미 본 적 있으면 표시 안 함
    const hasShown = localStorage.getItem(STORAGE_KEY)
    if (hasShown) return

    // OnboardingTour가 이미 완료된 경우 바로 표시
    if (hasCompletedOnboarding()) {
      const timer = setTimeout(() => {
        setIsVisible(true)
      }, 500)
      return () => clearTimeout(timer)
    }

    // OnboardingTour가 아직 완료되지 않은 경우, 완료될 때까지 폴링
    const checkOnboardingComplete = setInterval(() => {
      if (hasCompletedOnboarding()) {
        clearInterval(checkOnboardingComplete)
        // OnboardingTour 완료 후 잠시 대기 후 표시
        setTimeout(() => {
          setIsVisible(true)
        }, 800)
      }
    }, 500)

    return () => clearInterval(checkOnboardingComplete)
  }, [forceShow])

  // 'show-rightclick-guide' 이벤트 리스너 (다시 보기 기능)
  useEffect(() => {
    const handleShowGuide = () => {
      setIsVisible(true)
    }

    window.addEventListener('show-rightclick-guide', handleShowGuide)
    return () => window.removeEventListener('show-rightclick-guide', handleShowGuide)
  }, [])

  // 컨텍스트 자동 순환 애니메이션
  useEffect(() => {
    if (!isVisible) return

    const interval = setInterval(() => {
      setActiveContext(prev => (prev + 1) % CONTEXT_MENUS.length)
    }, 2500)

    return () => clearInterval(interval)
  }, [isVisible])

  const handleClose = useCallback(() => {
    localStorage.setItem(STORAGE_KEY, 'true')
    setIsVisible(false)
    onClose?.()
  }, [onClose])

  if (!isVisible) return null

  const currentContext = CONTEXT_MENUS[activeContext]

  return createPortal(
    <div className="rightclick-guide" role="dialog" aria-modal="true" aria-label="우클릭 가이드">
      {/* 오버레이 */}
      <div className="rightclick-guide__overlay" onClick={handleClose} />

      {/* 모달 */}
      <div className="rightclick-guide__modal">
        {/* 헤더 */}
        <div className="rightclick-guide__header">
          <h2 className="rightclick-guide__title">마우스 우클릭을 활용하세요</h2>
          <p className="rightclick-guide__subtitle">
            화면마다 다른 메뉴가 나타납니다
          </p>
        </div>

        {/* 메인 비주얼: 마우스 + 컨텍스트 메뉴 */}
        <div className="rightclick-guide__visual">
          {/* 마우스 */}
          <div className="rightclick-guide__mouse">
            <svg viewBox="0 0 80 130" className="rightclick-guide__mouse-svg">
              {/* 마우스 본체 */}
              <rect
                x="5" y="25"
                width="70" height="100"
                rx="35" ry="35"
                className="rightclick-guide__mouse-body"
              />
              {/* 좌클릭 */}
              <path
                d="M5 60 L5 45 Q5 25 40 25 L40 60 Z"
                className="rightclick-guide__mouse-left"
              />
              {/* 우클릭 (하이라이트) */}
              <path
                d="M40 25 Q75 25 75 45 L75 60 L40 60 Z"
                className="rightclick-guide__mouse-right"
              />
              {/* 휠 */}
              <rect x="34" y="35" width="12" height="20" rx="6" className="rightclick-guide__mouse-wheel" />
              {/* 구분선 */}
              <line x1="40" y1="25" x2="40" y2="60" className="rightclick-guide__mouse-divider" />
            </svg>
            {/* 클릭 이펙트 */}
            <div className="rightclick-guide__click-effect" />
          </div>

          {/* 화살표 */}
          <div className="rightclick-guide__arrow">→</div>

          {/* 컨텍스트 메뉴 프리뷰 */}
          <div
            className="rightclick-guide__menu-preview"
            style={{ '--context-color': currentContext.color } as React.CSSProperties}
          >
            <div className="rightclick-guide__menu-header">
              <span className="rightclick-guide__menu-icon">{currentContext.icon}</span>
              <span className="rightclick-guide__menu-title">{currentContext.title}</span>
            </div>
            <div className="rightclick-guide__menu-items">
              {currentContext.items.map((item, idx) => (
                <div
                  key={idx}
                  className={`rightclick-guide__menu-item ${idx === 0 ? 'rightclick-guide__menu-item--highlight' : ''}`}
                >
                  {item}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* 컨텍스트 인디케이터 */}
        <div className="rightclick-guide__contexts">
          {CONTEXT_MENUS.map((ctx, idx) => (
            <button
              key={ctx.id}
              type="button"
              className={`rightclick-guide__context-btn ${idx === activeContext ? 'rightclick-guide__context-btn--active' : ''}`}
              onClick={() => setActiveContext(idx)}
              style={{ '--btn-color': ctx.color } as React.CSSProperties}
            >
              <span className="rightclick-guide__context-icon">{ctx.icon}</span>
              <span className="rightclick-guide__context-label">{ctx.title}</span>
            </button>
          ))}
        </div>

        {/* 팁 */}
        <div className="rightclick-guide__tip">
          <span className="rightclick-guide__tip-icon">💡</span>
          <span className="rightclick-guide__tip-text">
            도움말 → 사용 가이드에서 언제든 다시 볼 수 있습니다
          </span>
        </div>

        {/* 액션 버튼 */}
        <div className="rightclick-guide__actions">
          <Button variant="primary" size="md" onClick={handleClose}>
            알겠습니다
          </Button>
        </div>
      </div>
    </div>,
    document.body
  )
}

/**
 * 가이드 표시 상태 초기화 (설정에서 다시 보기용)
 */
export const resetRightClickGuide = () => {
  localStorage.removeItem(STORAGE_KEY)
}

/**
 * 가이드를 이미 봤는지 확인
 */
export const hasSeenRightClickGuide = () => {
  return localStorage.getItem(STORAGE_KEY) === 'true'
}

/**
 * 가이드 강제 표시 (설정에서 호출)
 */
export const showRightClickGuide = () => {
  localStorage.removeItem(STORAGE_KEY)
  // 컴포넌트가 다시 마운트되도록 이벤트 발생
  window.dispatchEvent(new CustomEvent('show-rightclick-guide'))
}

/**
 * PinInput 컴포넌트 단독 테스트
 * @description PIN dot 렌더링, 입력 처리, 에러 흔들림, disabled 상태 검증
 */

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent, act } from '@testing-library/react'
import PinInput from '../PinInput'

/** onInput 이벤트를 시뮬레이션하는 헬퍼 (InputEvent.data 포함) */
function simulateInput(input: HTMLInputElement, data: string) {
  for (const char of data) {
    // React onInput은 native 'input' 이벤트를 리슨
    const event = new InputEvent('input', {
      data: char,
      inputType: 'insertText',
      bubbles: true,
    })
    act(() => {
      input.dispatchEvent(event)
    })
  }
}

describe('PinInput', () => {
  const mockOnComplete = vi.fn()

  beforeEach(() => {
    vi.clearAllMocks()
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  describe('렌더링', () => {
    it('기본 4개 dot이 렌더링됨', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const dots = screen.getAllByTestId('pin-dot')
      expect(dots).toHaveLength(4)
    })

    it('length=6 설정 시 6개 dot 렌더링', () => {
      render(<PinInput onComplete={mockOnComplete} length={6} />)
      const dots = screen.getAllByTestId('pin-dot')
      expect(dots).toHaveLength(6)
    })

    it('초기 상태에서 모든 dot이 비어있음', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const dots = screen.getAllByTestId('pin-dot')
      dots.forEach(dot => {
        expect(dot).not.toHaveClass('pin-dot--filled')
      })
    })

    it('숨겨진 input이 numeric inputMode를 가짐', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const input = document.querySelector('input[inputmode="numeric"]')
      expect(input).not.toBeNull()
    })
  })

  describe('입력 처리', () => {
    it('숫자 입력 시 해당 dot이 filled됨', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const input = document.querySelector('input[inputmode="numeric"]') as HTMLInputElement
      simulateInput(input, '12')
      const dots = screen.getAllByTestId('pin-dot')
      expect(dots[0]).toHaveClass('pin-dot--filled')
      expect(dots[1]).toHaveClass('pin-dot--filled')
      expect(dots[2]).not.toHaveClass('pin-dot--filled')
      expect(dots[3]).not.toHaveClass('pin-dot--filled')
    })

    it('4자리 입력 완료 시 onComplete 호출', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const input = document.querySelector('input[inputmode="numeric"]') as HTMLInputElement
      simulateInput(input, '1234')
      expect(mockOnComplete).toHaveBeenCalledWith('1234')
    })

    it('5자리 이상 입력 시 4자리로 truncate', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const input = document.querySelector('input[inputmode="numeric"]') as HTMLInputElement
      simulateInput(input, '12345')
      expect(mockOnComplete).toHaveBeenCalledWith('1234')
    })
  })

  describe('에러 처리', () => {
    it('에러 발생 시 shake 클래스 추가', () => {
      const { rerender } = render(<PinInput onComplete={mockOnComplete} />)
      rerender(<PinInput onComplete={mockOnComplete} error="틀렸습니다" />)
      const dotsContainer = document.querySelector('.pin-dots')
      expect(dotsContainer).toHaveClass('pin-dots--shake')
    })

    it('에러 발생 후 400ms 뒤 shake 해제 + 값 초기화', () => {
      const { rerender } = render(<PinInput onComplete={mockOnComplete} />)
      const input = document.querySelector('input[inputmode="numeric"]') as HTMLInputElement
      simulateInput(input, '12')

      rerender(<PinInput onComplete={mockOnComplete} error="틀렸습니다" />)

      act(() => { vi.advanceTimersByTime(400) })

      const dotsContainer = document.querySelector('.pin-dots')
      expect(dotsContainer).not.toHaveClass('pin-dots--shake')
      const dots = screen.getAllByTestId('pin-dot')
      dots.forEach(dot => {
        expect(dot).not.toHaveClass('pin-dot--filled')
      })
    })
  })

  describe('disabled 상태', () => {
    it('disabled=true 시 input이 비활성화됨', () => {
      render(<PinInput onComplete={mockOnComplete} disabled />)
      const input = document.querySelector('input[inputmode="numeric"]') as HTMLInputElement
      expect(input.disabled).toBe(true)
    })
  })

  describe('접근성', () => {
    it('aria-label에 입력 상태가 표시됨', () => {
      render(<PinInput onComplete={mockOnComplete} />)
      const group = screen.getByRole('group')
      expect(group).toHaveAttribute('aria-label', '간편 비밀번호 입력, 4자리 중 0자리 입력됨')
    })
  })
})

/**
 * Document Status List SSE 실시간 업데이트 훅
 * SharedWorker 기반으로 리팩토링 - 멀티탭 연결 공유
 * @since 2025-01-04
 */

import { useEffect, useRef, useCallback } from 'react'
import { useSSESubscription } from './useSSESubscription'
import { errorReporter } from '@/shared/lib/errorReporter'

interface DocumentListChangeEvent {
  type: 'uploaded' | 'deleted' | 'status-changed' | 'linked' | 'unlinked' | 'updated' | 'progress-update'
  documentId: string
  documentName?: string
  status?: string
  progress?: number
  stage?: string
  timestamp: string
}

interface UseDocumentStatusListSSEOptions {
  /** SSE 활성화 여부 (기본: true) */
  enabled?: boolean
  /** 문서 변경 시 호출할 콜백 */
  onDocumentChange?: (event: DocumentListChangeEvent) => void
}

/**
 * Document Status List SSE 훅
 * SharedWorker를 통해 연결을 공유하여 멀티탭 HTTP 연결 제한 문제 해결
 * @param onRefresh 문서 목록 새로고침 함수
 * @param options 옵션
 */
export function useDocumentStatusListSSE(
  onRefresh: () => void,
  options: UseDocumentStatusListSSEOptions = {}
) {
  const { enabled = true, onDocumentChange } = options

  // 콜백을 ref로 저장하여 의존성 문제 해결
  const onRefreshRef = useRef(onRefresh)
  const onDocumentChangeRef = useRef(onDocumentChange)
  // 📊 debounce 타이머 (SSE 이벤트 폭격 방지)
  const refreshTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // 최신 콜백 참조 유지
  useEffect(() => {
    onRefreshRef.current = onRefresh
  }, [onRefresh])

  useEffect(() => {
    onDocumentChangeRef.current = onDocumentChange
  }, [onDocumentChange])

  // 📊 debounced refresh: 500ms 내 중복 호출을 하나로 병합
  const debouncedRefresh = useCallback((delay: number = 500) => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current)
    }
    refreshTimerRef.current = setTimeout(() => {
      refreshTimerRef.current = null
      onRefreshRef.current()
    }, delay)
  }, [])

  // cleanup
  useEffect(() => {
    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current)
      }
    }
  }, [])

  // 이벤트 핸들러
  const handleEvent = useCallback((eventType: string, data: unknown) => {
    // 1. 문서 목록 변경 이벤트 (업로드, 삭제, 상태변경 등)
    if (eventType === 'document-list-change') {
      try {
        const eventData = data as DocumentListChangeEvent
        if (import.meta.env.DEV) {
          console.log('[DocumentStatusListSSE] 문서 목록 변경:', eventData)
        }

        // 콜백 호출
        onDocumentChangeRef.current?.(eventData)

        // 🔄 webhook에서 overallStatus를 직접 업데이트하므로 새로고침
        // 📊 debounce로 연속 이벤트 시 API 호출 병합
        if (import.meta.env.DEV) {
          console.log('[DocumentStatusListSSE] fetchDocuments debounced 호출')
        }
        debouncedRefresh(500)

        // 전체 문서 보기(DocumentExplorerView)도 갱신 트리거
        window.dispatchEvent(new Event('refresh-document-library'))
      } catch (error) {
        console.error('[DocumentStatusListSSE] document-list-change 이벤트 처리 실패:', error)
        errorReporter.reportApiError(error as Error, { component: 'useDocumentStatusListSSE.documentListChange' })
      }
    }

    // 2. 문서 진행률 업데이트 이벤트 (폴링 대체)
    if (eventType === 'document-progress') {
      try {
        const eventData = data as DocumentListChangeEvent
        if (import.meta.env.DEV) {
          console.log('[DocumentStatusListSSE] 진행률 업데이트:', eventData.documentId, `${eventData.progress}%`, eventData.stage)
        }

        // 🔧 FIX: SSE 이벤트에서 받은 progress 값을 직접 상태에 반영
        // onDocumentChange 콜백이 있으면 직접 상태 업데이트 (API 호출 없이 즉시 반영)
        // 없으면 기존 방식대로 전체 새로고침 (300ms 딜레이로 MongoDB 동기화 보장)
        if (onDocumentChangeRef.current) {
          onDocumentChangeRef.current(eventData)
          // 🛡️ 안전장치: 3초 후 최종 상태 확인 (SSE 누락/불일치 자동 복구)
          // 📊 debounce로 연속 progress 이벤트 시 API 호출 병합
          debouncedRefresh(3000)
        } else {
          // fallback: 콜백이 없으면 debounce 후 새로고침
          debouncedRefresh(500)
        }
      } catch (error) {
        console.error('[DocumentStatusListSSE] document-progress 이벤트 처리 실패:', error)
        errorReporter.reportApiError(error as Error, { component: 'useDocumentStatusListSSE.documentProgress' })
      }
    }
  }, [])

  // 연결 성공 핸들러
  // 🔧 근본 해결: SSE 연결/재연결 시 즉시 DB에서 최신 상태 조회
  // - 페이지 이동 중 놓친 이벤트가 있어도 최신 상태 반영
  // - SSE 이벤트만 의존하지 않고 DB 상태를 신뢰
  const handleConnect = useCallback((data: unknown) => {
    if (import.meta.env.DEV) {
      console.log('[DocumentStatusListSSE] 연결됨:', data)
    }
    // 연결 즉시 최신 상태 조회 (놓친 이벤트 복구, 짧은 debounce)
    debouncedRefresh(300)
  }, [])

  // 오류 핸들러
  const handleError = useCallback((error: Error) => {
    console.error('[DocumentStatusListSSE] 연결 오류:', error)
    errorReporter.reportApiError(error, { component: 'useDocumentStatusListSSE.onerror' })
  }, [])

  // SharedWorker 기반 SSE 구독
  const { isConnected, disconnect, reconnect } = useSSESubscription<DocumentListChangeEvent>({
    streamKey: 'documents:status-list',
    endpoint: '/api/documents/status-list/stream',
    enabled,
    onEvent: handleEvent,
    onConnect: handleConnect,
    onError: handleError
  })

  return {
    isConnected,
    disconnect,
    reconnect,
  }
}

/**
 * SSE Subscription Hook
 * SharedWorker 기반 SSE 구독 공통 훅
 * @since 2025-01-04
 */

import { useEffect, useRef, useState, useCallback, useMemo } from 'react'
import { sseClient, type SSEEvent } from '../lib/sseWorkerClient'
import { logger } from '../lib/logger'

export interface UseSSESubscriptionOptions<T = unknown> {
  /** 스트림 고유 키 (예: 'documents:status-list', 'customer:123:documents') */
  streamKey: string
  /** SSE 엔드포인트 (예: '/api/documents/status-list/stream') */
  endpoint: string
  /** 추가 파라미터 */
  params?: Record<string, string>
  /** SSE 활성화 여부 (기본: true) */
  enabled?: boolean
  /** 이벤트 수신 시 콜백 */
  onEvent?: (eventType: string, data: T) => void
  /** 연결 성공 시 콜백 */
  onConnect?: (data?: unknown) => void
  /** 연결 해제 시 콜백 */
  onDisconnect?: () => void
  /** 오류 발생 시 콜백 */
  onError?: (error: Error) => void
}

export interface UseSSESubscriptionReturn {
  /** 연결 상태 */
  isConnected: boolean
  /** 수동 재연결 */
  reconnect: () => void
  /** 수동 연결 해제 */
  disconnect: () => void
}

/**
 * SSE 구독 훅
 * SharedWorker를 통해 SSE 연결을 공유하여 HTTP 연결 제한 문제 해결
 */
export function useSSESubscription<T = unknown>(
  options: UseSSESubscriptionOptions<T>
): UseSSESubscriptionReturn {
  const {
    streamKey,
    endpoint,
    params,
    enabled = true,
    onEvent,
    onConnect,
    onDisconnect,
    onError
  } = options

  const [isConnected, setIsConnected] = useState(false)

  // params를 안정화 (JSON 직렬화로 비교)
  const paramsKey = useMemo(() => JSON.stringify(params || {}), [params])
  const stableParams = useMemo(() => params || {}, [paramsKey])

  // 콜백을 ref로 저장하여 의존성 문제 해결
  const onEventRef = useRef(onEvent)
  const onConnectRef = useRef(onConnect)
  const onDisconnectRef = useRef(onDisconnect)
  const onErrorRef = useRef(onError)

  // endpoint와 params를 ref로 저장 (connect 함수 안정화)
  const endpointRef = useRef(endpoint)
  const paramsRef = useRef(stableParams)

  // 최신 콜백/값 참조 유지
  useEffect(() => {
    onEventRef.current = onEvent
  }, [onEvent])

  useEffect(() => {
    onConnectRef.current = onConnect
  }, [onConnect])

  useEffect(() => {
    onDisconnectRef.current = onDisconnect
  }, [onDisconnect])

  useEffect(() => {
    onErrorRef.current = onError
  }, [onError])

  useEffect(() => {
    endpointRef.current = endpoint
  }, [endpoint])

  useEffect(() => {
    paramsRef.current = stableParams
  }, [stableParams])

  // 구독 해제 함수
  const disconnect = useCallback(() => {
    sseClient.unsubscribe(streamKey)
    setIsConnected(false)
  }, [streamKey])

  // 구독 함수 (ref 사용으로 의존성 최소화)
  const connect = useCallback(() => {
    if (!enabled || !streamKey) return

    logger.debug('useSSESubscription', `연결 시작 - streamKey: ${streamKey}, endpoint: ${endpointRef.current}`)

    // 인증 토큰 동기화
    sseClient.syncAuthToken()

    // 이벤트 리스너 등록
    const unsubscribe = sseClient.on(streamKey, (event: SSEEvent) => {
      const { eventType, data } = event

      logger.debug('useSSESubscription', `이벤트 수신 - streamKey: ${streamKey}, eventType: ${eventType}`, data)

      if (eventType === 'connected') {
        logger.debug('useSSESubscription', `연결 성공 - streamKey: ${streamKey}`)
        setIsConnected(true)
        onConnectRef.current?.(data)
      } else if (eventType === 'error') {
        logger.debug('useSSESubscription', `연결 오류 - streamKey: ${streamKey}`)
        setIsConnected(false)
        onErrorRef.current?.(new Error((data as { message?: string })?.message || 'SSE error'))
        // 재연결은 SharedWorker가 exponential backoff로 무한 재시도
      } else {
        // 일반 이벤트
        logger.debug('useSSESubscription', `일반 이벤트 전달 - eventType: ${eventType}`)
        onEventRef.current?.(eventType, data as T)
      }
    })

    // 구독 요청 (ref 사용)
    sseClient.subscribe(streamKey, endpointRef.current, paramsRef.current)

    return unsubscribe
  }, [enabled, streamKey])

  // 재연결 함수
  const reconnect = useCallback(() => {
    disconnect()
    setTimeout(() => {
      connect()
    }, 100)
  }, [disconnect, connect])

  // SSE 연결 관리 (streamKey, enabled 변경 시만 재연결)
  // 🔧 SharedWorker는 모든 탭에서 연결을 공유하므로 탭 비활성화 시에도 연결 유지
  useEffect(() => {
    if (!enabled || !streamKey) return

    // 초기 연결
    const unsubscribe = connect()

    // 탭 활성화 시 토큰 동기화 + 데이터 새로고침
    const handleVisibilityChange = () => {
      if (!document.hidden) {
        sseClient.syncAuthToken()
        // SSE 끊김 동안 놓친 변경사항 복구 (onConnect로 fetchDocuments/fetchStatistics 트리거)
        onConnectRef.current?.({ reason: 'visibility-change' })
      }
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)

    return () => {
      unsubscribe?.()
      sseClient.unsubscribe(streamKey)
      document.removeEventListener('visibilitychange', handleVisibilityChange)
    }
  }, [enabled, streamKey, connect])

  return {
    isConnected,
    reconnect,
    disconnect
  }
}

